B.V1=s(["\uac00\uaca9\uc758 \ubd80\ub2f9\ud55c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd","\ucd9c\uace0\uc870\uc808","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uc2e0\uaddc \uc9c4\uc785 \ubc29\ud574","\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"],t.s)
B.Qs=s(['"\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1\uc801\uc73c\ub85c \ud589\ud558\ub294 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c'],t.s)
B.X3=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ub0a8\uc6a9\ud589\uc704 \uc720\ud615"],t.s)
B.aj3=new A.c("q1","economic_law","\uacf5\uc815\uac70\ub798\ubc95",null,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.V1,3,'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ub0a8\uc6a9\ud589\uc704\ub97c \u2460 \uac00\uaca9\uc758 \ubd80\ub2f9\ud55c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \ub610\ub294 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc6b0\ub824 \ud589\uc704\ub85c \uc720\ud615\ud654\ud558\uace0 \uc788\ub2e4. \ubc18\uba74 \u2463 "\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1\uc801\uc73c\ub85c \ud589\ud558\ub294 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uadf8 \uc790\uccb4\ub85c\ub294 \ubd80\ub2f9\uc131\uc774 \uc778\uc815\ub418\uc9c0 \uc54a\uc544 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4. \ub530\ub77c\uc11c \ub2e4\ub978 \uc120\ud0dd\uc9c0\ub4e4\uc774 \ubaa8\ub450 \ubc95\uc5d0 \uba85\uc2dc\ub41c \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc778 \uac83\uacfc \ub2ec\ub9ac, \uc774 \uc120\ud0dd\uc9c0\ub9cc \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Qs,B.X3,"2024")
B.N8=s(["\ubb34\ud6a8\uc778 \ubc95\ub960\ud589\uc704\ub294 \ucd94\uc778\ud574\ub3c4 \ud6a8\ub825\uc774 \uc0dd\uae30\uc9c0 \uc54a\ub294 \uac83\uc774 \uc6d0\uce59","\ucde8\uc18c\ud560 \uc218 \uc788\ub294 \ubc95\ub960\ud589\uc704\ub294 \ucde8\uc18c\ub418\uae30 \uc804\uae4c\uc9c0\ub294 \uc720\ud6a8","\uc81c\ud55c\ub2a5\ub825\uc790\uc758 \ubc95\ub960\ud589\uc704\ub294 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4","\ubb34\ud6a8\uc640 \ucde8\uc18c\ub294 \ud56d\uc0c1 \ud568\uaed8 \ubc1c\uc0dd\ud55c\ub2e4"],t.s)
B.a1x=s(["\ub450 \uc81c\ub3c4\ub294 \ubc1c\uc0dd \uc6d0\uc778\uacfc \ud6a8\uacfc \ubc1c\uc0dd \uc2dc\uc810\uc774 \uc804\ud600 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\ub3c4"],t.s)
B.MB=s(["\ubc95\ub960\ud589\uc704 \ubb34\ud6a8","\ubc95\ub960\ud589\uc704 \ucde8\uc18c"],t.s)
B.amw=new A.c("q2","civil_law","\ubbfc\ubc95\ucd1d\uce59",null,"\ubbfc\ubc95\uc0c1 \ubc95\ub960\ud589\uc704\uc758 \ubb34\ud6a8\uc640 \ucde8\uc18c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.N8,3,'\ubb34\ud6a8(\u7121\u6548)\ub294 \ubc95\ub960\ud589\uc704\uac00 \uc131\ub9bd \ub2f9\uc2dc\ubd80\ud130 \ub2f9\uc5f0\ud788 \ud6a8\ub825\uc774 \uc5c6\ub294 \uac83\uc744 \ub9d0\ud558\uace0, \ucde8\uc18c(\u53d6\u6d88)\ub294 \uc77c\ub2e8 \uc720\ud6a8\ud558\uac8c \uc131\ub9bd\ud55c \ubc95\ub960\ud589\uc704\ub97c \ucde8\uc18c\uad8c\uc790\uc758 \uc758\uc0ac\ud45c\uc2dc\ub85c \uc18c\uae09\ud558\uc5ec \ubb34\ud6a8\ub85c \ub9cc\ub4dc\ub294 \uac83\uc744 \ub9d0\ud55c\ub2e4. \uc989 \ubb34\ud6a8\ub294 \ubcc4\ub3c4\uc758 \uc758\uc0ac\ud45c\uc2dc \uc5c6\uc774\ub3c4 \ucc98\uc74c\ubd80\ud130 \ud6a8\ub825\uc774 \uc5c6\uc9c0\ub9cc, \ucde8\uc18c\ub294 \ucde8\uc18c\uad8c\uc790\uac00 \ucde8\uc18c\uad8c\uc744 \ud589\uc0ac\ud558\uae30 \uc804\uae4c\uc9c0\ub294 \uc720\ud6a8\ud55c \ubc95\ub960\ud589\uc704\ub85c \ucde8\uae09\ub41c\ub2e4. \uc774\ucc98\ub7fc \ub450 \uc81c\ub3c4\ub294 \ubc1c\uc0dd \uc6d0\uc778\uacfc \ud6a8\uacfc \ubc1c\uc0dd \uc2dc\uc810\uc774 \uc804\ud600 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ubbc0\ub85c, "\ud56d\uc0c1 \ud568\uaed8 \ubc1c\uc0dd\ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub2e4\ub9cc \uc608\uc678\uc801\uc73c\ub85c \ubb34\ud6a8\ud589\uc704\uc640 \ucde8\uc18c\ud560 \uc218 \uc788\ub294 \ud589\uc704\uac00 \ub3d9\uc2dc\uc5d0 \uc131\ub9bd\ud558\ub294 \uacbd\uc6b0(\uc774\uc911\ud6a8)\uac00 \uc788\uc744 \uc218\ub294 \uc788\uc73c\ub098, \uc774\ub294 \ud56d\uc0c1 \uadf8\ub7f0 \uac83\uc774 \uc544\ub2c8\ub77c \ud2b9\uc815 \uc694\uac74\uc774 \uacb9\uce60 \ub54c\uc5d0 \ud55c\ud55c\ub2e4.',B.a1x,B.MB,"2023")
B.ZF=s(["\uac15\uc810(Strength), \uc57d\uc810(Weakness)","\uae30\ud68c(Opportunity), \uc704\ud611(Threat)","\uac15\uc810, \uae30\ud68c","\uc57d\uc810, \uc704\ud611"],t.s)
B.LE=s(["\uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9"],t.s)
B.Ob=s(["SWOT \ubd84\uc11d","\ub0b4\ubd80/\uc678\ubd80 \uc694\uc778 \uad6c\ubd84"],t.s)
B.aoU=new A.c("q3","business_admin","\uacbd\uc601\ud559",null,"SWOT \ubd84\uc11d\uc5d0\uc11c \uae30\uc5c5 \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub974\uba74?",B.ZF,0,"SWOT \ubd84\uc11d\uc740 \uae30\uc5c5\uc758 \uacbd\uc601\ud658\uacbd\uc744 \ub0b4\ubd80 \uc694\uc778\uacfc \uc678\ubd80 \uc694\uc778\uc73c\ub85c \ub098\ub204\uc5b4 \ubd84\uc11d\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc804\ub7b5 \uc218\ub9bd \ub3c4\uad6c\uc774\ub2e4. \uc774 \uc911 \uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9(\uc790\uae08\ub825, \uae30\uc220\ub825, \uc870\uc9c1\ubb38\ud654, \ube0c\ub79c\ub4dc \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\uace0, \uae30\ud68c(Opportunity)\uc640 \uc704\ud611(Threat)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud558\uae30 \uc5b4\ub824\uc6b4 \uc678\ubd80 \ud658\uacbd(\uc2dc\uc7a5 \uc131\uc7a5\ub960, \uacbd\uc7c1 \uac15\ub3c4, \uaddc\uc81c, \uac70\uc2dc\uacbd\uc81c \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\ub2e4. \ub530\ub77c\uc11c \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740 \uac15\uc810\uacfc \uc57d\uc810\uc774\uba70, \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c SO(\uac15\uc810-\uae30\ud68c) \uc804\ub7b5, WT(\uc57d\uc810-\uc704\ud611) \uc804\ub7b5\ucc98\ub7fc \ub0b4\ubd80-\uc678\ubd80 \uc694\uc778\uc744 \uad50\ucc28 \ubd84\uc11d\ud558\uc5ec \uc804\ub7b5\uc744 \ub3c4\ucd9c\ud558\ub294 \uac83\uc774 SWOT \ubd84\uc11d\uc758 \ud575\uc2ec\uc774\ub2e4.",B.LE,B.Ob,"2025")
B.Hm=s(["\uc0ac\uc5c5\uc790\ub294 \uacc4\uc57d\uccb4\uacb0 \uc2dc \uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uba85\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc0ac\uc5c5\uc790\ub294 \uace0\uac1d\uc758 \uc694\uccad\uc774 \uc788\uc73c\uba74 \uc57d\uad00\uc758 \uc0ac\ubcf8\uc744 \uace0\uac1d\uc5d0\uac8c \uad50\ubd80\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4 \ubc0f \uc218\ub3c4\uc0ac\uc5c5\uc758 \uacbd\uc6b0 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub294 \uba74\uc81c\ub418\ub098 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0, \ud574\ub2f9 \uc57d\uad00\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4","\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Uy=s(['"\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4'],t.s)
B.WS=s(["\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34","\uc124\uba85\uc758\ubb34 \uba74\uc81c\uc0ac\uc720"],t.s)
B.anK=new A.c("gen_al_1","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Hm,4,'\uc57d\uad00\ubc95 \uc81c3\uc870\uc5d0 \ub530\ub974\uba74 \uc0ac\uc5c5\uc790\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc5ec\uc57c \ud558\uc9c0\ub9cc, "\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4(\uc81c3\uc870 \uc81c3\ud56d \ub2e8\uc11c). \ub530\ub77c\uc11c "\uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"\uace0 \ub2e8\uc815\ud55c \uc120\ud0dd\uc9c0\uac00 \uc633\uc9c0 \uc54a\uc740 \uc124\uba85\uc774\ub2e4. \ud55c\ud3b8 \uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4\xb7\uc218\ub3c4\uc0ac\uc5c5, \uc6b0\ud3b8\uc5c5 \ub4f1\uc740 \uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d \ub2e8\uc11c\uc5d0 \ub530\ub77c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub9cc \uba74\uc81c\ub420 \ubfd0, \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uc790\ub3d9\uc73c\ub85c \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc2e4\uc81c\ub85c \uc633\uc740 \uc124\uba85\uc774\ubbc0\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\ub3c4\ub85d \uc8fc\uc758\ud574\uc57c \ud55c\ub2e4. \uc989 "\uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uba74\uc81c \uc5c5\uc885"\uacfc "\uc124\uba85\uc758\ubb34 \uba74\uc81c \uc0ac\uc720"\ub294 \uc11c\ub85c \ub2e4\ub978 \uc870\ud56d\uc5d0 \uadfc\uac70\ud55c \ubcc4\uac1c\uc758 \uc608\uc678\ub77c\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub2e4.',B.Uy,B.WS,null)
B.a6R=s(["\uace0\uac1d\uc774 \uc694\uccad\ud558\uc9c0 \uc54a\uc73c\uba74 \uc5b4\ub5a0\ud55c \ubc29\ubc95\uc73c\ub85c\ub3c4 \uba85\uc2dc\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uadf8 \ub0b4\uc6a9\uc744 \uc54c\ub9ac\uba74 \ub41c\ub2e4","\ubc18\ub4dc\uc2dc \uace0\uac1d\uacfc \ub300\uba74\ud558\uc5ec \uad6c\ub450\ub85c \uc57d\uad00 \uc804\uccb4\ub97c \ub0ad\ub3c5\ud574\uc57c \ud55c\ub2e4","\uc57d\uad00\uc744 \ud648\ud398\uc774\uc9c0\uc5d0 \uac8c\uc2dc\ud558\ub294 \uac83\uc740 \uba85\uc2dc\uc758\ubb34\uc758 \uc774\ud589 \ubc29\ubc95\uc73c\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4","\uba85\uc2dc\uc758\ubb34\ub294 \uacc4\uc57d \uccb4\uacb0 \uc774\ud6c4 \uc5b8\uc81c\ub4e0 \uc774\ud589\ud558\uba74 \ucda9\ubd84\ud558\ub2e4"],t.s)
B.a6m=s(["\uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c \uc54c\ub824\uc57c"],t.s)
B.a4u=s(["\uba85\uc2dc\uc758\ubb34 \uc774\ud589\ubc29\ubc95"],t.s)
B.aoA=new A.c("gen_al_expl_2","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 "\uba85\uc2dc\uc758\ubb34"\uc758 \uc774\ud589 \ubc29\ubc95\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a6R,1,'\uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d\uc740 \uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c \uc54c\ub824\uc57c \ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ubc18\ub4dc\uc2dc \uad6c\ub450 \ub0ad\ub3c5\uc774 \ud544\uc694\ud55c \uac83\uc740 \uc544\ub2c8\uba70, \uc5c5\uc885\uc758 \ud2b9\uc131\uc5d0 \ub9de\ub294 \ud569\ub9ac\uc801\uc778 \ubc29\ubc95(\ub9e4\uc7a5 \uac8c\uc2dc, \ud648\ud398\uc774\uc9c0 \uac8c\uc2dc, \uacc4\uc57d\uc11c \ucca8\ubd80 \ub4f1)\uc774\uba74 \ucda9\ubd84\ud558\ub2e4. \ub2e4\ub9cc \uacc4\uc57d \uccb4\uacb0 "\uc774\uc804"\uc5d0 \uc774\ud589\ub418\uc5b4\uc57c \ud558\ubbc0\ub85c \uccb4\uacb0 \uc774\ud6c4 \uc784\uc758\uc758 \uc2dc\uc810\uc5d0 \uc774\ud589\ud574\ub3c4 \ub41c\ub2e4\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.a6m,B.a4u,null)
B.Q1=s(["\uc0ac\uc5c5\uc790\ub294 \uacc4\uc57d \uccb4\uacb0 \uc2dc \uace0\uac1d\uc758 \uc694\uccad\uc774 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \uc57d\uad00 \uc0ac\ubcf8\uc744 \uad50\ubd80\ud558\uc5ec\uc57c \ud55c\ub2e4","\uace0\uac1d\uc774 \uc57d\uad00\uc758 \uc0ac\ubcf8 \uad50\ubd80\ub97c \uc694\uccad\ud558\uba74 \uc0ac\uc5c5\uc790\ub294 \uc774\uc5d0 \uc751\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc5ec\uac1d\uc6b4\uc1a1\uc5c5 \ub4f1 \uc77c\ubd80 \uc5c5\uc885\uc740 \uad50\ubd80\uc758\ubb34\uac00 \uba74\uc81c\ub420 \uc218 \uc788\ub2e4","\uc804\uc790\ubb38\uc11c\ub85c \uc57d\uad00\uc744 \uc81c\uacf5\ud558\ub294 \uac83\ub3c4 \uad50\ubd80\uc758 \ud55c \ubc29\ubc95\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\uad50\ubd80\uc758\ubb34\ub294 \uba85\uc2dc\uc758\ubb34\uc640 \ubcc4\uac1c\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\ub2e4"],t.s)
