B.ahS=new A.c("gen_al_expl_3","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 "\uad50\ubd80\uc758\ubb34"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?',B.Q1,0,'\uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d\uc740 \uace0\uac1d\uc774 "\uc694\uccad"\ud558\uba74 \uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc0ac\ubcf8\uc744 \uad50\ubd80\ud558\ub3c4\ub85d \uaddc\uc815\ud558\uace0 \uc788\uc5b4, \uc694\uccad\uc774 \uc5c6\ub294\ub370\ub3c4 \ud56d\uc0c1 \uad50\ubd80\ud574\uc57c \ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \uad50\ubd80\uc758\ubb34\ub294 \uba85\uc2dc\uc758\ubb34\uc640 \ud568\uaed8 \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0\ub9cc \ubcc4\uac1c\uc758 \uc758\ubb34\uc774\uba70, \uc5ec\uac1d\uc6b4\uc1a1\uc5c5\xb7\uc804\uae30\xb7\uac00\uc2a4\xb7\uc218\ub3c4\uc0ac\uc5c5 \ub4f1 \uc77c\ubd80 \uc5c5\uc885\uc740 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\uac00 \uba74\uc81c\ub420 \uc218 \uc788\ub2e4. \ucd5c\uadfc\uc5d0\ub294 \uc804\uc790\ubb38\uc11c \uc81c\uacf5\ub3c4 \uad50\ubd80 \ubc29\ubc95\uc73c\ub85c \ub110\ub9ac \uc778\uc815\ub41c\ub2e4.',B.abu,B.TI,null)
