B.ali=new A.c("gen_al_expl_7","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uacbd\uc6b0\uc758 \ubc95\uc801 \ud6a8\uacfc\ub85c \uc633\uc740 \uac83\uc740?",B.IE,1,'\uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c4\ud56d\uc740 \uc0ac\uc5c5\uc790\uac00 \uba85\uc2dc\xb7\uad50\ubd80\xb7\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud558\uc5ec \uacc4\uc57d\uc744 \uccb4\uacb0\ud55c \uacbd\uc6b0, \ud574\ub2f9 \uc57d\uad00\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c "\uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4"\uace0 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uacc4\uc57d \uc804\uccb4\ub97c \ubb34\ud6a8\ub85c \ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \ubb38\uc81c\ub41c \uc870\ud56d\uc774 \uacc4\uc57d \ub0b4\uc6a9\uc5d0 \ud3b8\uc785\ub418\uc9c0 \ubabb\ud558\ub3c4\ub85d \ud558\ub294 \ud6a8\uacfc\uc774\uba70, \ubcc4\ub3c4\uc758 \ucde8\uc18c\uad8c \ud589\uc0ac\ub098 \uc2dc\uc815\uba85\ub839 \uc5c6\uc774\ub3c4 \ubc95\ub960\uc0c1 \ub2f9\uc5f0\ud788 \ubc1c\uc0dd\ud558\ub294 \ud6a8\uacfc\ub77c\ub294 \uc810\uc774 \ud575\uc2ec\uc774\ub2e4.',B.R5,B.a_9,null)
B.TF=s(["\ud648\ud398\uc774\uc9c0\uc5d0 \uc57d\uad00\uc744 \uac8c\uc2dc\ud558\uace0 \uace0\uac1d\uc774 \ud655\uc778\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uac83\uc740 \uba85\uc2dc\uc758\ubb34 \uc774\ud589 \ubc29\ubc95\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\uc804\uc790\uc801 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc744 \uc81c\uacf5\ud558\ub294 \uac83\ub3c4 \uad50\ubd80\uc758\ubb34 \uc774\ud589\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\uc628\ub77c\uc778 \uac70\ub798\ub77c\ub294 \uc774\uc720\ub9cc\uc73c\ub85c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uc790\uccb4\uac00 \ub2f9\uc5f0\ud788 \uba74\uc81c\ub41c\ub2e4","\uace0\uac1d\uc774 \uc57d\uad00 \ub0b4\uc6a9\uc5d0 \ub3d9\uc758\ud558\ub294 \uc808\ucc28(\uccb4\ud06c\ubc15\uc2a4 \ub4f1)\ub97c \ub450\ub294 \uac83\uc740 \uba85\uc2dc\uc758\ubb34 \uc774\ud589\uc5d0 \ub3c4\uc6c0\uc774 \ub41c\ub2e4","\ube44\ub300\uba74 \uac70\ub798\uc5d0\uc11c\ub3c4 \uc124\uba85\uc758\ubb34\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \uc911\uc694\ud55c \ub0b4\uc6a9\uc740 \ubcc4\ub3c4\ub85c \uc124\uba85\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.J5=s(["\uc628\ub77c\uc778 \uac70\ub798\ub77c\ub294 \uc774\uc720\ub9cc\uc73c\ub85c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uc790\uccb4\uac00 \ub2f9\uc5f0\ud788 \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8"],t.s)
B.a9Z=s(["\ube44\ub300\uba74 \uac70\ub798\uc640 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34"],t.s)
B.akH=new A.c("gen_al_expl_8","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\ube44\ub300\uba74(\uc778\ud130\ub137\xb7\ubaa8\ubc14\uc77c) \uac70\ub798\uc5d0\uc11c \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uc774\ud589\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.TF,2,"\uc628\ub77c\uc778\xb7\ubaa8\ubc14\uc77c \ub4f1 \ube44\ub300\uba74 \uac70\ub798\ubc29\uc2dd\uc774\ub77c\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\uac00 \ub2f9\uc5f0\ud788 \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uc0ac\uc5c5\uc790\ub294 \ud648\ud398\uc774\uc9c0 \uac8c\uc2dc, \uc804\uc790\ubb38\uc11c \uc81c\uacf5, \ub3d9\uc758 \uccb4\ud06c\ubc15\uc2a4 \ub4f1 \ud574\ub2f9 \uac70\ub798\ubc29\uc2dd\uc5d0 \ub9de\ub294 \ud569\ub9ac\uc801\uc778 \ubc29\ubc95\uc73c\ub85c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub97c \uc774\ud589\ud574\uc57c \ud55c\ub2e4. \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34 \uc5ed\uc2dc \ube44\ub300\uba74 \uac70\ub798\ub77c \ud558\uc5ec \ub2f9\uc5f0\ud788 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.J5,B.a9Z,null)
B.a8D=s(["\uc57d\uad00\uc758 \ubb38\uc5b8\uc744 \uadf8\ub300\ub85c \ub0ad\ub3c5\ud558\uae30\ub9cc \ud558\uba74 \ud56d\uc0c1 \uc124\uba85\uc758\ubb34\ub97c \ub2e4\ud55c \uac83\uc73c\ub85c \ubcf8\ub2e4","\uace0\uac1d\uc774 \uc774\ubbf8 \uc54c\uace0 \uc788\uc5c8\ub358 \ub0b4\uc6a9\uc774\ub77c\ub3c4 \uc608\uc678 \uc5c6\uc774 \ubc18\ub4dc\uc2dc \ub2e4\uc2dc \uc124\uba85\ud574\uc57c \ud55c\ub2e4","\uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \uad6c\uccb4\uc801\uc774\uace0 \uc0c1\uc138\ud558\uac8c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc5ec\uc57c \ud558\uba70, \ub2e8\uc21c\ud788 \uc870\ud56d\uc744 \uc18c\uac1c\ud558\ub294 \uc815\ub3c4\ub85c\ub294 \ubd80\uc871\ud558\ub2e4","\uc124\uba85\uc758\ubb34\ub294 \uc11c\uba74\uc73c\ub85c \ud655\uc778\uc11c\ub97c \ubc1b\ub294 \uac83\ub9cc\uc73c\ub85c \ud56d\uc0c1 \ucda9\uc871\ub41c\ub2e4","\uc124\uba85\uc758\ubb34 \uc774\ud589 \uc5ec\ubd80\ub294 \uc0ac\uc5c5\uc790\uc758 \uc8fc\uc7a5\ub9cc\uc73c\ub85c \uc778\uc815\ub41c\ub2e4"],t.s)
B.Zw=s(["\uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \uad6c\uccb4\uc801\uc774\uace0 \uc0c1\uc138\ud558\uac8c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85"],t.s)
B.a18=s(["\uc124\uba85\uc758\ubb34 \uc774\ud589\uc758 \uc815\ub3c4"],t.s)
B.aim=new A.c("gen_al_expl_9","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc124\uba85\uc758\ubb34\uc758 \uc774\ud589 \uc815\ub3c4\uc5d0 \uad00\ud55c \ud310\ub840\uc758 \uc785\uc7a5\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a8D,2,"\ud310\ub840\ub294 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uc600\ub2e4\uace0 \ud558\ub824\uba74 \uace0\uac1d\uc774 \uadf8 \uc57d\uad00\uc5d0 \uc815\ud558\uc5ec\uc9c4 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \ucda9\ubd84\ud788 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc5ec\uc57c \ud558\uace0, \ub2e8\uc21c\ud788 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uc18c\uac1c\ud558\uac70\ub098 \uac1c\uad04\uc801\xb7\ud615\uc2dd\uc801\uc73c\ub85c \uc5b8\uae09\ud558\ub294 \uc815\ub3c4\ub85c\ub294 \ubd80\uc871\ud558\ub2e4\uace0 \ubcf8\ub2e4. \ub2e4\ub9cc \uace0\uac1d\uc774 \uc774\ubbf8 \uc54c\uace0 \uc788\uc5c8\ub358 \uc0ac\ud56d\uae4c\uc9c0 \uc608\uc678 \uc5c6\uc774 \uc7ac\uc124\uba85\ud574\uc57c \ud558\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uc124\uba85\uc758\ubb34 \uc774\ud589 \uc5ec\ubd80\uc5d0 \ub300\ud55c \uc99d\uba85\ucc45\uc784\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc788\ub2e4.",B.Zw,B.a18,null)
B.a3y=s(["\uace0\uac1d\uc774 \uc124\uba85\uc744 \ub4e3\uc9c0 \ubabb\ud588\ub2e4\ub294 \uc0ac\uc2e4\uc744 \uc99d\uba85\ud574\uc57c \ud55c\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uc600\ub2e4\ub294 \uc0ac\uc2e4\uc744 \uc99d\uba85\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \ud56d\uc0c1 \ubc95\uc6d0\uc758 \uc9c1\uad8c\uc870\uc0ac \uc0ac\ud56d\uc774\ub2e4","\uc99d\uba85\ucc45\uc784 \ubd84\ubc30\ub294 \ubc95\uc5d0 \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc544 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ubd80\ub2f4\ud55c\ub2e4"],t.s)
B.L9=s(["\uc0ac\uc5c5\uc790\uac00 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uc600\ub2e4\ub294 \uc0ac\uc2e4\uc744 \uc99d\uba85\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
B.acy=s(["\uc124\uba85\uc758\ubb34 \uc99d\uba85\ucc45\uc784"],t.s)
B.ahw=new A.c("gen_al_expl_10","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc5d0 \ub300\ud55c \uc99d\uba85\ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a3y,1,"\ud310\ub840\ub294 \uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \uad00\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \uad6c\uccb4\uc801\uc774\uace0 \uc0c1\uc138\ud558\uac8c \uba85\uc2dc\xb7\uc124\uba85\ud558\uc600\ub2e4\ub294 \uc0ac\uc2e4\uc5d0 \ub300\ud55c \uc99d\uba85\ucc45\uc784\uc740 \uc774\ub97c \uc8fc\uc7a5\ud558\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc788\ub2e4\uace0 \ubcf8\ub2e4. \uc774\ub294 \uc815\ubcf4\uc758 \ube44\ub300\uce6d \uc0c1\ud0dc\uc5d0 \uc788\ub294 \uace0\uac1d\uc744 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \ucde8\uc9c0\ub85c, \uc0ac\uc5c5\uc790\uac00 \uc124\uba85\uc758\ubb34\ub97c \ub2e4\ud558\uc600\uc74c\uc744 \uc2a4\uc2a4\ub85c \uc99d\uba85\ud558\uc9c0 \ubabb\ud558\uba74 \ud574\ub2f9 \uc870\ud56d\uc744 \uacc4\uc57d \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\uac8c \ub41c\ub2e4.",B.L9,B.acy,null)
B.a_2=s(["\ub300\ub9ac\uc778\uc5d0\uac8c\ub294 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\ub300\ub9ac\uc778\uc5d0\uac8c \uc124\uba85\ud55c \uac83\uc73c\ub85c\ub294 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud55c \uac83\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc5c6\ub2e4","\uc6d0\uce59\uc801\uc73c\ub85c \ub300\ub9ac\uc778\uc5d0\uac8c \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc124\uba85\ud558\uba74 \ubcf8\uc778\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud55c \uac83\uc73c\ub85c \ubcfc \uc218 \uc788\ub2e4","\ub300\ub9ac\uc778\uc774 \uc788\ub294 \uacbd\uc6b0 \uc124\uba85\uc758\ubb34 \uc790\uccb4\uac00 \uba74\uc81c\ub41c\ub2e4","\ub300\ub9ac\uc778\uc5d0\uac8c\ub294 \uba85\uc2dc\uc758\ubb34\ub9cc \uc774\ud589\ud558\uba74 \ucda9\ubd84\ud558\ub2e4"],t.s)
B.Ns=s(["\uadf8 \ub300\ub9ac\uc778\uc5d0\uac8c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uad6c\uccb4\uc801\uc774\uace0 \uc0c1\uc138\ud558\uac8c \uc124\uba85\ud558\uc600\ub2e4\uba74 \uc6d0\uce59\uc801\uc73c\ub85c \ubcf8\uc778\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud55c \uac83"],t.s)
B.aac=s(["\ub300\ub9ac\uc778\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34"],t.s)
B.ai9=new A.c("gen_al_expl_11","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uace0\uac1d\uc758 \ub300\ub9ac\uc778\uacfc \uacc4\uc57d\uc744 \uccb4\uacb0\ud55c \uacbd\uc6b0 \uc57d\uad00\uc758 \uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_2,2,"\uacc4\uc57d\uc774 \ub300\ub9ac\uc778\uc744 \ud1b5\ud574 \uccb4\uacb0\ub418\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\uac00 \uadf8 \ub300\ub9ac\uc778\uc5d0\uac8c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uad6c\uccb4\uc801\uc774\uace0 \uc0c1\uc138\ud558\uac8c \uc124\uba85\ud558\uc600\ub2e4\uba74 \uc6d0\uce59\uc801\uc73c\ub85c \ubcf8\uc778\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud55c \uac83\uc73c\ub85c \ubcfc \uc218 \uc788\ub2e4. \ub300\ub9ac\uc778 \uc81c\ub3c4\uc758 \ucde8\uc9c0\uc0c1 \ub300\ub9ac\uc778\uc774 \uc218\ub839\ud55c \uc815\ubcf4\uc758 \ud6a8\uacfc\ub294 \ubcf8\uc778\uc5d0\uac8c \uadc0\uc18d\ub418\uae30 \ub54c\ubb38\uc774\ub2e4.",B.Ns,B.aac,null)
B.a1C=s(["\ud45c\uc900\uc57d\uad00\uc744 \uadf8\ub300\ub85c \uc0ac\uc6a9\ud558\uba74 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc790\uccb4\uac00 \uc644\uc804\ud788 \uba74\uc81c\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub354\ub77c\ub3c4 \uc0ac\uc5c5\uc790\ub294 \uc5ec\uc804\ud788 \uc77c\ubc18 \uc57d\uad00\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \ubd80\ub2f4\ud55c\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \ubc95\ub960\uc774\ubbc0\ub85c \ubcc4\ub3c4\ub85c \uace0\uac1d\uc5d0\uac8c \uc54c\ub9b4 \ud544\uc694\uac00 \uc5c6\ub2e4","\ud45c\uc900\uc57d\uad00\uc744 \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \uc124\uba85\uc758\ubb34 \ub300\uc2e0 \uad11\uace0\ub9cc \ud558\uba74 \ucda9\ubd84\ud558\ub2e4","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0 \uc0ac\uc6a9 \uc5ec\ubd80\uc640 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ub2e4"],t.s)
B.Yd=s(["\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub354\ub77c\ub3c4 \uc0ac\uc5c5\uc790\ub294 \uc5ec\uc804\ud788 \uc77c\ubc18 \uc57d\uad00\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \ubd80\ub2f4"],t.s)
B.Yw=s(["\ud45c\uc900\uc57d\uad00\uacfc \uc124\uba85\uc758\ubb34\uc758 \uad00\uacc4"],t.s)
B.aoY=new A.c("gen_al_expl_12","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1C,1,"\ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\ub294 \ubd88\uacf5\uc815\ud55c \uc57d\uad00 \uc0ac\uc6a9\uc744 \uc608\ubc29\ud558\uae30 \uc704\ud55c \uac83\uc77c \ubfd0, \ud45c\uc900\uc57d\uad00\uc744 \uc0ac\uc6a9\ud55c\ub2e4\uace0 \ud558\uc5ec \uc0ac\uc5c5\uc790\uac00 \uac1c\ubcc4 \uace0\uac1d\uc5d0 \ub300\ud55c \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uba74\uc81c\ubc1b\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \ud45c\uc900\uc57d\uad00\uc744 \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub3c4 \uc77c\ubc18 \uc0ac\uc5c5\uc790\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uacc4\uc57d \uccb4\uacb0 \uc2dc \uc57d\uad00\uc744 \uba85\uc2dc\ud558\uace0 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc124\uba85\ud574\uc57c \ud55c\ub2e4.",B.Yd,B.Yw,null)
B.a4L=s(["\ucd5c\ucd08 \uacc4\uc57d \uc2dc \uc124\uba85\ud558\uc600\ub2e4\uba74 \uc774\ud6c4 \uc57d\uad00\uc774 \ubcc0\uacbd\ub418\uc5b4\ub3c4 \ub2e4\uc2dc \uc124\uba85\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4",u.mB,"\uc57d\uad00 \ubcc0\uacbd\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc77c\ubc29\uc801 \uad8c\ud55c\uc774\ubbc0\ub85c \uace0\uac1d\uc5d0\uac8c \uc54c\ub9b4 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc57d\uad00\uc774 \ubcc0\uacbd\ub418\uba74 \uc885\uc804 \uacc4\uc57d\uc740 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ubcc0\uacbd\ub41c \uc57d\uad00\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc744 \ubc1b\uc73c\uba74 \uc124\uba85 \uc5c6\uc774 \ubc14\ub85c \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.GB=s([u.mB],t.s)
B.a1J=s(["\uc57d\uad00 \ubcc0\uacbd \uc2dc \uc124\uba85\uc758\ubb34"],t.s)
B.ajq=new A.c("gen_al_expl_13","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00 \ub0b4\uc6a9\uc774 \ubcc0\uacbd\ub41c \uacbd\uc6b0 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a4L,1,"\uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc774 \ubcc0\uacbd\ub418\uc5b4 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc601\ud5a5\uc744 \ubbf8\uce60 \uc218 \uc788\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub294 \ubcc0\uacbd\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud574\uc11c\ub3c4 \uc6d0\uce59\uc801\uc73c\ub85c \ub2e4\uc2dc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uc5ec\uc57c \ud55c\ub2e4. \ucd5c\ucd08 \uacc4\uc57d \uc2dc \uc124\uba85\uc744 \uc774\ud589\ud558\uc600\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uc774\ud6c4\uc758 \ubd88\ub9ac\ud55c \ubcc0\uacbd \uc0ac\ud56d\uae4c\uc9c0 \ub2f9\uc5f0\ud788 \uace0\uac1d\uc5d0\uac8c \ud6a8\ub825\uc774 \ubbf8\uce5c\ub2e4\uace0 \ubcfc \uc218\ub294 \uc5c6\ub2e4.",B.GB,B.a1J,null)
B.Z2=s(["\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uc870\ud56d\uc740 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \ud3b8\uc785\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb38\uc81c\ub41c \uc870\ud56d\ub9cc \uacc4\uc57d \ub0b4\uc6a9\uc5d0\uc11c \ubc30\uc81c\ub418\uace0 \ub098\uba38\uc9c0 \uc870\ud56d\uc740 \uc720\ud6a8\ud560 \uc218 \uc788\ub2e4","\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uc870\ud56d\uc774 \ubc30\uc81c\ub41c \uacb0\uacfc \uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uac8c \ub418\uba74 \uacc4\uc57d \uc804\uccb4\uac00 \ubb34\ud6a8\ub85c \ub420 \uc218 \uc788\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \ud615\uc0ac\ucc98\ubc8c\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \ubc94\uc8c4\ud589\uc704\uc774\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc788\uc5b4\ub3c4 \uace0\uac1d\uc774 \uadf8 \ub0b4\uc6a9\uc744 \uc2e4\uc81c\ub85c \uc54c\uace0 \uacc4\uc57d\uc744 \uccb4\uacb0\ud588\ub2e4\uba74 \uacb0\ub860\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\ub2e4"],t.s)
B.Iv=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \ud615\uc0ac\ucc98\ubc8c\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \ubc94\uc8c4\ud589\uc704\uc774\ub2e4"],t.s)
B.Rg=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc758 \ud6a8\uacfc","\uc77c\ubd80\ubb34\ud6a8 \ubc95\ub9ac"],t.s)
B.alb=new A.c("gen_al_expl_14","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc758 \ud6a8\uacfc\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Z2,3,"\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud574\ub2f9 \uc870\ud56d\uc774 \uacc4\uc57d \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ub420 \uc218 \uc5c6\ub2e4\ub294 \uc0ac\ubc95(\u79c1\u6cd5)\uc0c1\uc758 \ud6a8\uacfc\ub97c \uac00\uc838\uc62c \ubfd0\uc774\uba70, \uadf8 \uc790\uccb4\ub85c \ud615\uc0ac\ucc98\ubc8c\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \ubc94\uc8c4\ud589\uc704\ub294 \uc544\ub2c8\ub2e4. \ub2e4\ub9cc \ubb38\uc81c\ub41c \uc870\ud56d\uc774 \ube60\uc9d0\uc73c\ub85c\uc368 \uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uac8c \ub418\ub294 \uacbd\uc6b0\uc5d0\ub294 \uacc4\uc57d \uc804\uccb4\uac00 \ubb34\ud6a8\ub85c \ub420 \uc218\ub3c4 \uc788\uace0, \uace0\uac1d\uc774 \uc2e4\uc81c\ub85c \uadf8 \ub0b4\uc6a9\uc744 \uc54c\uace0 \uc788\uc5c8\ub2e4\uba74 \uacb0\ub860\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\ub2e4\ub294 \uc810\ub3c4 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4.",B.Iv,B.Rg,null)
B.acz=s(["\uc0ac\uc5c5\uc790\uc758 \uacc4\uc57d \uccb4\uacb0 \ud3b8\uc758\ub97c \uadf9\ub300\ud654\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \ucda9\ubd84\ud788 \uc778\uc9c0\ud55c \uc0c1\ud0dc\uc5d0\uc11c \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub3c4\ub85d \ud558\uc5ec \uc815\ubcf4 \ube44\ub300\uce6d\uc744 \uc644\ud654\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc57d\uad00\uc758 \uc0ac\uc6a9 \uc790\uccb4\ub97c \uae08\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uac10\ub3c5 \uad8c\ud55c\uc744 \ud655\ub300\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uace0\uac1d\uc5d0\uac8c \uacc4\uc57d \uccb4\uacb0 \uc5ec\ubd80\uc5d0 \ub300\ud55c \ucd5c\uc885 \uc2b9\uc778\uad8c\uc744 \ubd80\uc5ec\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4"],t.s)
B.GG=s(["\uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \ucda9\ubd84\ud788 \uc778\uc9c0\ud55c \uc0c1\ud0dc\uc5d0\uc11c \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub3c4\ub85d \ud558\uc5ec \uc815\ubcf4 \ube44\ub300\uce6d\uc744 \uc644\ud654"],t.s)
