B.akY=new A.c("gen_al_expl_15","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c3\uc870(\uc57d\uad00\uc758 \uc791\uc131 \ubc0f \uc124\uba85\uc758\ubb34 \ub4f1)\uc758 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.acz,1,"\uc57d\uad00\ubc95 \uc81c3\uc870\ub294 \uc815\ud615\ud654\ub41c \uc57d\uad00\uc744 \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \uc791\uc131\ud558\ub294 \uac70\ub798 \uad6c\uc870\uc0c1 \ubc1c\uc0dd\ud558\uae30 \uc26c\uc6b4 \uc815\ubcf4\uc758 \ube44\ub300\uce6d\uc744 \uc644\ud654\ud558\uace0, \uace0\uac1d\uc774 \uacc4\uc57d\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \ucda9\ubd84\ud788 \uc778\uc9c0\ud55c \uc0c1\ud0dc\uc5d0\uc11c \uc790\uc720\ub86d\uac8c \uacc4\uc57d\uccb4\uacb0 \uc5ec\ubd80\ub97c \uacb0\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \ucde8\uc9c0\uc758 \uaddc\uc815\uc774\ub2e4.",B.GG,B.a7_,null)
B.a1i=s(["\uac1c\ubcc4 \ubc95\ub960\uc758 \ud2b9\uce59\uc740 \uc57d\uad00\ubc95\uc758 \uc801\uc6a9\uc744 \uc644\uc804\ud788 \ubc30\uc81c\ud55c\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc5d0 \ud2b9\uce59\uc774 \uc788\ub354\ub77c\ub3c4 \uc57d\uad00\ubc95\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \ucde8\uc9c0\uc640 \uae30\ubcf8 \ubc95\ub9ac\ub294 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uacfc \uc57d\uad00\ubc95\uc774 \ucda9\ub3cc\ud558\uba74 \ud56d\uc0c1 \uc57d\uad00\ubc95\uc774 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc5d0 \ud2b9\uce59\uc774 \uc788\ub294 \ubd84\uc57c\uc5d0\ub294 \uc57d\uad00\uc774\ub77c\ub294 \uac1c\ub150 \uc790\uccb4\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc758 \ud2b9\uce59\uc740 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ubc29\ud5a5\uc73c\ub85c\ub9cc \uc791\uc6a9\ud55c\ub2e4"],t.s)
B.a9L=s(["\uc57d\uad00\ubc95\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \ucde8\uc9c0\uc640 \uae30\ubcf8 \ubc95\ub9ac\ub294 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4"],t.s)
B.Im=s(["\uac1c\ubcc4 \ubc95\ub960\uacfc \uc57d\uad00\ubc95\uc758 \uad00\uacc4"],t.s)
B.alk=new A.c("gen_al_expl_16","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\ubcf4\ud5d8\uacc4\uc57d\uacfc \uac19\uc774 \uac1c\ubcc4 \ubc95\ub960\uc5d0 \uc57d\uad00 \uc124\uba85\uc5d0 \uad00\ud55c \ud2b9\uce59\uc774 \uc788\ub294 \uacbd\uc6b0, \uc57d\uad00\ubc95\uacfc\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1i,1,"\ubcf4\ud5d8\uc5c5\ubc95 \ub4f1 \uac1c\ubcc4 \ubc95\ub960\uc5d0 \uc57d\uad00 \uc124\uba85\uc5d0 \uad00\ud55c \ud2b9\uce59\uc774 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub3c4, \uc57d\uad00\ubc95\uc774 \uc815\ud558\ub294 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uae30\ubcf8 \ucde8\uc9c0\u2014\uace0\uac1d\uc774 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \ucda9\ubd84\ud788 \uc774\ud574\ud558\uace0 \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub3c4\ub85d \ud558\ub294 \uac83\u2014\ub294 \ud568\uaed8 \uace0\ub824\ub418\ub294 \uac83\uc774 \ud310\ub840\uc758 \uc77c\ubc18\uc801 \ud0dc\ub3c4\uc774\ub2e4. \ud2b9\ubcc4\ubc95\uacfc \uc77c\ubc18\ubc95\uc758 \uad00\uacc4\uc774\uc9c0\ub9cc, \uc0c1\ud638 \ubc30\ud0c0\uc801\uc73c\ub85c \uc644\uc804\ud788 \ubd84\ub9ac\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.a9L,B.Im,null)
B.OR=s(["\uc2dc\uc815\uad8c\uace0","\uc2dc\uc815\uba85\ub839","\uacfc\ud0dc\ub8cc \ubd80\uacfc","\ud574\ub2f9 \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c","\uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c"],t.s)
B.a2s=s(["\uc2dc\uc815\uad8c\uace0, \uc2dc\uc815\uba85\ub839, \uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c, \uacfc\ud0dc\ub8cc \ubd80\uacfc \ub4f1 \ud589\uc815\uc801 \uc81c\uc7ac\uc218\ub2e8\uc744 \ud65c\uc6a9"],t.s)
B.PF=s(["\uc57d\uad00\ubc95 \uc704\ubc18\uc5d0 \ub300\ud55c \uc81c\uc7ac\uc218\ub2e8"],t.s)
B.arP=new A.c("gen_al_expl_17","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uce58\ub85c \uac00\uc7a5 \uad00\ub828\uc774 \uc801\uc740 \uac83\uc740?",B.OR,3,"\uc57d\uad00\ubc95 \uc704\ubc18\uc5d0 \ub300\ud574 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc2dc\uc815\uad8c\uace0, \uc2dc\uc815\uba85\ub839, \uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c, \uacfc\ud0dc\ub8cc \ubd80\uacfc \ub4f1 \ud589\uc815\uc801 \uc81c\uc7ac\uc218\ub2e8\uc744 \ud65c\uc6a9\ud55c\ub2e4. \ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c\ub294 \uc218\uc0ac\uae30\uad00\uc774 \ud615\uc0ac\uc18c\uc1a1\ubc95\uc5d0 \ub530\ub77c \ud589\ud558\ub294 \uac15\uc81c\uc218\uc0ac \uc808\ucc28\ub85c\uc11c, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud1b5\uc0c1\uc801\uc778 \uc57d\uad00\ubc95 \uc9d1\ud589 \uc218\ub2e8\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub835\ub2e4.",B.a2s,B.PF,null)
B.Ot=s(["\uac1c\ubcc4\uc57d\uc815\uc774 \uc788\uc73c\uba74 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc804\ud600 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc57d\uad00\uacfc \ub2e4\ub978 \ub0b4\uc6a9\uc744 \uac1c\ubcc4\uc801\uc73c\ub85c \ud569\uc758\ud55c \uc0ac\ud56d(\uac1c\ubcc4\uc57d\uc815)\uc740 \uc57d\uad00\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub418\uba70, \uc774\ub294 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc640\ub294 \ubcc4\uac1c\uc758 \uc6d0\uce59\uc774\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \ud56d\uc0c1 \uc57d\uad00\uc5d0 \uc885\uc18d\ub418\uc5b4 \ud6a8\ub825\uc774 \uc5c6\ub2e4","\uac1c\ubcc4\uc57d\uc815\uacfc \uba85\uc2dc\uc758\ubb34\ub294 \ub3d9\uc77c\ud55c \uac1c\ub150\uc774\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc774 \uc788\uc73c\uba74 \uc0ac\uc5c5\uc790\ub294 \uc5b4\ub5a0\ud55c \uc124\uba85\uc758\ubb34\ub3c4 \ubd80\ub2f4\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Sv=s(["\uac1c\ubcc4\uc57d\uc815\uc774 \uc57d\uad00\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4\uace0 \uaddc\uc815"],t.s)
B.o4=s(["\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59"],t.s)
B.ao3=new A.c("gen_al_expl_18","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uacfc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Ot,1,"\uc57d\uad00\ubc95 \uc81c4\uc870\ub294 \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uacfc \ub2e4\ub974\uac8c \ud569\uc758\ud55c \uc0ac\ud56d(\uac1c\ubcc4\uc57d\uc815)\uc774 \uc788\uc73c\uba74 \uadf8 \uac1c\ubcc4\uc57d\uc815\uc774 \uc57d\uad00\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34(\uc81c3\uc870)\uc640\ub294 \ubcc4\uac1c\uc758 \uc6d0\uce59\uc73c\ub85c, \uac1c\ubcc4\uc57d\uc815\uc758 \uc874\uc7ac\uac00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uc774\ud589 \uc5ec\ubd80\uc640 \uc9c1\uc811 \uc5f0\uacb0\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Sv,B.o4,null)
B.a66=s(["\uc774 \uacbd\uc6b0\uc5d0\ub3c4 \uc608\uc678 \uc5c6\uc774 \uc0ac\uc5c5\uc790\ub294 \ub2e4\uc2dc \uc124\uba85\ud574\uc57c \ud55c\ub2e4",u.aS,"\uace0\uac1d\uc774 \uc54c\uace0 \uc788\uc5c8\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0 \uba85\uc2dc\uc758\ubb34\uae4c\uc9c0 \ud568\uaed8 \uba74\uc81c\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \uacc4\uc57d\uc774 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4"],t.s)
B.PI=s([u.aS],t.s)
B.ZP=s(["\uace0\uac1d\uc758 \uc778\uc2dd\uacfc \uc124\uba85\uc758\ubb34"],t.s)
B.apB=new A.c("gen_al_expl_19","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uc774\ubbf8 \ub2e4\ub978 \uacbd\ub85c\ub85c \ucda9\ubd84\ud788 \uc54c\uace0 \uc788\uc5c8\ub358 \uacbd\uc6b0, \uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a66,1,"\ud310\ub840\ub294 \uace0\uac1d\uc774 \uc774\ubbf8 \uc54c\uace0 \uc788\ub294 \uc0ac\ud56d\uc774\uac70\ub098 \uac70\ub798\uc0c1 \ub2f9\uc5f0\uc2dc\ub418\uc5b4 \ubcc4\ub3c4\uc758 \uc124\uba85 \uc5c6\uc774\ub3c4 \ucda9\ubd84\ud788 \uc608\uc0c1\ud560 \uc218 \uc788\uc5c8\ub358 \uc0ac\ud56d\uc5d0 \ub300\ud574\uc11c\ub294 \uc0ac\uc5c5\uc790\uac00 \uadf8 \uc0ac\ud56d\uc744 \ubcc4\ub3c4\ub85c \uc124\uba85\ud558\uc9c0 \uc54a\uc558\ub2e4\uace0 \ud558\uc5ec \uace7\ubc14\ub85c \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ubcf8\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc608\uc678\uc801\uc778 \uacbd\uc6b0\ub85c, \uc6d0\uce59\uc740 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc774\ub2e4.",B.PI,B.ZP,null)
B.S7=s(["\uba85\uc2dc\uc758\ubb34\uc640 \uc124\uba85\uc758\ubb34\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac1c\ub150\uc73c\ub85c \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uba85\uc2dc\uc758\ubb34\ub294 \uc57d\uad00\uc758 \uc874\uc7ac\uc640 \ub0b4\uc6a9\uc744 \uc54c \uc218 \uc788\uac8c \ud558\ub294 \uac83\uc774\uace0, \uc124\uba85\uc758\ubb34\ub294 \uadf8\uc911 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc54c\ub9ac\ub294 \uac83\uc73c\ub85c \uc11c\ub85c \uad6c\ubcc4\ub41c\ub2e4","\uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uba74 \uba85\uc2dc\uc758\ubb34\ub294 \ubcc4\ub3c4\ub85c \uc774\ud589\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uba85\uc2dc\uc758\ubb34\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc124\uba85\uc758\ubb34\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc9c1\uc6d0\ub9cc \uc774\ud589\ud560 \uc218 \uc788\ub2e4"],t.s)
B.a9F=s(["\uba85\uc2dc\uc758\ubb34\ub294 \uc57d\uad00\uc758 \uc874\uc7ac\uc640 \ub0b4\uc6a9\uc744 \uc54c \uc218 \uc788\uac8c \ud558\ub294 \uac83\uc774\uace0, \uc124\uba85\uc758\ubb34\ub294 \uadf8\uc911 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc54c\ub9ac\ub294 \uac83\uc73c\ub85c \uc11c\ub85c \uad6c\ubcc4"],t.s)
B.Ub=s(["\uba85\uc2dc\uc758\ubb34\uc640 \uc124\uba85\uc758\ubb34\uc758 \uad6c\ubcc4"],t.s)
B.apR=new A.c("gen_al_expl_20","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \ub2e4\uc74c \uc124\uba85 \uc911 \uc633\uc740 \uac83\uc740?",B.S7,1,'\uba85\uc2dc\uc758\ubb34\ub294 \uace0\uac1d\uc774 \uc57d\uad00\uc758 \uc874\uc7ac\uc640 \ub300\ub7b5\uc801\uc778 \ub0b4\uc6a9\uc744 \uc54c \uc218 \uc788\ub3c4\ub85d \uac8c\uc2dc\xb7\uace0\uc9c0\ud558\ub294 \uc758\ubb34\uc774\uace0, \uc124\uba85\uc758\ubb34\ub294 \uadf8\uc911\uc5d0\uc11c\ub3c4 \uace0\uac1d\uc758 \uad8c\ub9ac\xb7\uc758\ubb34\uc5d0 \uc911\ub300\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 "\uc911\uc694\ud55c \ub0b4\uc6a9"\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uad6c\uccb4\uc801\uc73c\ub85c \uc54c\ub9ac\ub294 \uc758\ubb34\ub85c, \uc11c\ub85c \uad6c\ubcc4\ub418\ub294 \uac1c\ub150\uc774\ub2e4. \ub450 \uc758\ubb34 \ubaa8\ub450 \ub3c5\uc790\uc801\uc73c\ub85c \uc774\ud589\ub418\uc5b4\uc57c \ud558\uba70 \uc5b4\ub290 \ud558\ub098\uc758 \uc774\ud589\uc774 \ub2e4\ub978 \ud558\ub098\ub97c \ub300\uccb4\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.a9F,B.Ub,null)
B.II=s(["\uc57d\uad00\uc5d0 \ud3ec\ud568\ub41c \ubaa8\ub4e0 \uc870\ud56d\uc744 \uc608\uc678 \uc5c6\uc774 \ub3d9\uc77c\ud55c \ube44\uc911\uc73c\ub85c \uc124\uba85\ud574\uc57c \ud55c\ub2e4","\uace0\uac1d\uc758 \uad8c\ub9ac\xb7\uc758\ubb34\uc5d0 \uc911\ub300\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc870\ud56d\uc778\uc9c0 \uc5ec\ubd80\ub97c \uae30\uc900\uc73c\ub85c \uc124\uba85 \ub300\uc0c1\uc744 \uac00\ub824\ub0b8\ub2e4","\uc870\ud56d\uc758 \uae00\uc790 \uc218\uac00 \ub9ce\uc744\uc218\ub85d \uc124\uba85 \ub300\uc0c1\uc774 \ub41c\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uc815\ud55c \uc870\ud56d\ub9cc \uc124\uba85 \ub300\uc0c1\uc774 \ub41c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc0ac\uc804\uc5d0 \uc9c0\uc815\ud55c \uc870\ud56d\ub9cc \uc124\uba85 \ub300\uc0c1\uc774 \ub41c\ub2e4"],t.s)
B.a9k=s(["\uace0\uac1d\uc758 \uad8c\ub9ac\xb7\uc758\ubb34\uc5d0 \uc911\ub300\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc870\ud56d\uc778\uc9c0 \uc5ec\ubd80\ub97c \uae30\uc900\uc73c\ub85c"],t.s)
B.a5B=s(["\uc911\uc694\ud55c \ub0b4\uc6a9\uc758 \ud310\ub2e8\uae30\uc900"],t.s)
B.akZ=new A.c("gen_al_expl_21","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00 \uc870\ud56d\uc774 \uc5ec\ub7ec \uac1c\uc77c \ub54c \uc124\uba85\uc758\ubb34\uc758 \ub300\uc0c1 \ud310\ub2e8 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.II,1,'\uc124\uba85\uc758\ubb34\uc758 \ub300\uc0c1\uc774 \ub418\ub294 "\uc911\uc694\ud55c \ub0b4\uc6a9"\uc778\uc9c0 \uc5ec\ubd80\ub294 \uc870\ud56d\uc758 \ubd84\ub7c9\uc774\ub098 \uc0ac\uc5c5\uc790\uc758 \uc784\uc758\uc801 \uc120\ud0dd\uc774 \uc544\ub2c8\ub77c, \uadf8 \uc870\ud56d\uc774 \uace0\uac1d\uc758 \uad8c\ub9ac\ub97c \uc81c\ud55c\ud558\uac70\ub098 \uc0c8\ub85c\uc6b4 \uc758\ubb34\ub97c \ubd80\uacfc\ud558\ub294 \ub4f1 \uace0\uac1d\uc758 \uad8c\ub9ac\xb7\uc758\ubb34\uc5d0 \uc911\ub300\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \uac1c\ubcc4\uc801\xb7\uad6c\uccb4\uc801\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4.',B.a9k,B.a5B,null)
B.QJ=s(["\uc11c\uba85\uc774 \uc788\uc73c\uba74 \uc2e4\uc81c \uc124\uba85 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud55c \uac83\uc73c\ub85c \ud655\uc815\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\uc11c\uba85\uc740 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc758 \uc815\ud669\uc99d\uac70\uac00 \ub420 \uc218 \uc788\uc73c\ub098, \uc2e4\uc81c\ub85c \uad6c\uccb4\uc801\uc778 \uc124\uba85\uc774 \uc788\uc5c8\ub294\uc9c0\ub294 \ubcc4\ub3c4\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\ub2e4","\uc11c\uba85\uc774 \uc5c6\uc73c\uba74 \uacc4\uc57d \uc790\uccb4\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc11c\uba85\uc740 \uba85\uc2dc\uc758\ubb34\uc640\ub9cc \uad00\ub828\uc774 \uc788\uace0 \uc124\uba85\uc758\ubb34\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc11c\uba85\uc774 \uc788\uc73c\uba74 \uac1c\ubcc4\uc57d\uc815\uc73c\ub85c \uc804\ud658\ub418\uc5b4 \uc57d\uad00 \uaddc\uc81c\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.RI=s(["\uc2e4\uc81c\ub85c \uad6c\uccb4\uc801\uc778 \uc124\uba85\uc774 \uc788\uc5c8\ub294\uc9c0\ub294 \ubcc4\ub3c4\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a8G=s(["\ud655\uc778\uc11c \uc11c\uba85\uc758 \uc99d\uba85\ub825"],t.s)
B.aq7=new A.c("gen_al_expl_22","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uace0\uac1d\uc774 \uc124\uba85\uc744 \ub4e4\uc5c8\ub2e4\ub294 \ud655\uc778\uc11c\uc5d0 \uc11c\uba85\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.QJ,1,'\uace0\uac1d\uc774 "\uc124\uba85\uc744 \ub4e4\uc5c8\ub2e4"\ub294 \ub0b4\uc6a9\uc758 \ud655\uc778\uc11c\uc5d0 \uc11c\uba85\ud558\uc600\ub2e4\ub294 \uc0ac\uc2e4\uc740 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc744 \ub4b7\ubc1b\uce68\ud558\ub294 \uc720\ub825\ud55c \uc815\ud669\uc774 \ub420 \uc218 \uc788\uc73c\ub098, \uadf8\uac83\ub9cc\uc73c\ub85c \uc2e4\uc81c \uad6c\uccb4\uc801\xb7\uac1c\ubcc4\uc801\uc778 \uc124\uba85\uc774 \uc788\uc5c8\ub294\uc9c0 \uc5ec\ubd80\uac00 \uc790\ub3d9\uc73c\ub85c \ud655\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \ubc95\uc6d0\uc740 \uacc4\uc57d \uccb4\uacb0 \uacbd\uc704, \uc870\ud56d\uc758 \uc131\uc9c8 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uc5ec \uc2e4\uc9c8\uc801\uc778 \uc124\uba85\uc758\ubb34 \uc774\ud589 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud55c\ub2e4.',B.RI,B.a8G,null)
B.Pu=s(["\ub450 \ubc95\ub960\uc740 \uc11c\ub85c \ubb34\uad00\ud558\uba70 \ud558\ub098\uac00 \uc801\uc6a9\ub418\uba74 \ub2e4\ub978 \ud558\ub098\ub294 \uc801\uc6a9\ub420 \uc5ec\uc9c0\uac00 \uc5c6\ub2e4","\ub450 \ubc95\ub960 \ubaa8\ub450 \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d(\uc18c\ube44\uc790) \uac04 \uc815\ubcf4\uc758 \ube44\ub300\uce6d\uc744 \uc644\ud654\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uacf5\uc720\ud558\uba70 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc774 \ud56d\uc0c1 \uc57d\uad00\ubc95\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uc57d\uad00\ubc95\uc740 \uc0ac\uc5c5\uc790\uc5d0\uac8c, \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc740 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\ub450 \ubc95\ub960\uc758 \uc801\uc6a9 \ub300\uc0c1\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4"],t.s)
B.NQ=s(["\uc815\ubcf4\uc758 \ube44\ub300\uce6d\uc744 \uc644\ud654\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uacf5\uc720\ud558\uba70 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a7o=s(["\uc57d\uad00\ubc95\uacfc \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc758 \uad00\uacc4"],t.s)
B.aqN=new A.c("gen_al_expl_23","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc640 \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc0c1 \uc815\ubcf4\uc81c\uacf5\uc758\ubb34\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Pu,1,"\uc57d\uad00\ubc95\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc640 \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc815\ubcf4\uc81c\uacf5\uc758\ubb34\ub294 \ubaa8\ub450 \uac70\ub798\uc0c1 \uc815\ubcf4 \ube44\ub300\uce6d \uc0c1\ud0dc\uc5d0 \uc788\ub294 \uace0\uac1d(\uc18c\ube44\uc790)\uc744 \ubcf4\ud638\ud558\ub824\ub294 \uacf5\ud1b5\uc758 \ucde8\uc9c0\ub97c \uac00\uc9c0\uace0 \uc788\uc5b4, \uad6c\uccb4\uc801 \uc0ac\uc548\uc5d0\uc11c \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \ub450 \ubc95\ub960\uc740 \uaddc\uc728 \ubc29\uc2dd\uacfc \uc801\uc6a9 \ubc94\uc704\uac00 \ub2e4\ub978 \ubcc4\uac1c\uc758 \ubc95\ub960\uc774\ub2e4.",B.NQ,B.a7o,null)
B.a9J=s(["\uc804\ud654 \ud1b5\ud654 \ubc29\uc2dd\uc73c\ub85c\ub294 \uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud560 \uc218 \uc5c6\ub2e4","\ud1b5\ud654 \ub179\ucde8 \ub4f1\uc744 \ud1b5\ud574 \uace0\uac1d\uc774 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc2e4\uc81c\ub85c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uad6c\uccb4\uc801\uc73c\ub85c \uc124\uba85\ud558\uc600\uc74c\uc774 \ud655\uc778\ub418\uba74 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\uc804\ud654\ub85c \uc124\uba85\ud558\uba74 \uba85\uc2dc\uc758\ubb34\uae4c\uc9c0 \uc790\ub3d9\uc73c\ub85c \uc774\ud589\ub41c \uac83\uc73c\ub85c \ubcf8\ub2e4","\ucf5c\uc13c\ud130 \uc0c1\ub2f4\uc6d0\uc758 \uc124\uba85\uc740 \ubc95\uc801 \ud6a8\ub825\uc774 \uc804\ud600 \uc5c6\ub2e4","\uc804\ud654 \uc124\uba85\uc740 \ubc18\ub4dc\uc2dc \uc11c\uba74\uc73c\ub85c \uc7ac\ud655\uc778\ubc1b\uc544\uc57c\ub9cc \uc720\ud6a8\ud558\ub2e4"],t.s)
B.a4J=s(["\uace0\uac1d\uc774 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc2e4\uc81c\ub85c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uad6c\uccb4\uc801\uc73c\ub85c \uc124\uba85\ud558\uc600\uc74c\uc774 \ud655\uc778\ub418\uba74 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4"],t.s)
B.aaM=s(["\ube44\ub300\uba74 \uc124\uba85 \ubc29\uc2dd\uc758 \uc778\uc815"],t.s)
B.apT=new A.c("gen_al_expl_24","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\ucf5c\uc13c\ud130 \ud1b5\ud654\ub85c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc124\uba85\ud55c \uacbd\uc6b0, \uc124\uba85\uc758\ubb34 \uc774\ud589 \uc778\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a9J,1,"\uc124\uba85\uc758 \ubc29\uc2dd\uc774 \ub300\uba74\uc778\uc9c0 \ube44\ub300\uba74(\uc804\ud654 \ub4f1)\uc778\uc9c0 \uc790\uccb4\uac00 \uc124\uba85\uc758\ubb34 \uc774\ud589 \uc5ec\ubd80\ub97c \uc88c\uc6b0\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uc911\uc694\ud55c \uac83\uc740 \uace0\uac1d\uc774 \uadf8 \ub0b4\uc6a9\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uad6c\uccb4\uc801\uc73c\ub85c \uc124\uba85\ud558\uc600\ub294\uc9c0\uc774\ub2e4. \ud1b5\ud654 \ub179\ucde8 \ub4f1\uc758 \uc790\ub8cc\ub85c \uadf8\ub7ec\ud55c \uc124\uba85\uc774 \uc788\uc5c8\uc74c\uc774 \ud655\uc778\ub41c\ub2e4\uba74 \uc804\ud654\ub97c \ud1b5\ud55c \uc124\uba85\ub3c4 \uc124\uba85\uc758\ubb34 \uc774\ud589\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4.",B.a4J,B.aaM,null)
B.WP=s(["\ub450 \uc81c\ub3c4\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc81c\ub3c4\uc774\ub2e4","\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \uc870\ud56d\uc758 \uacc4\uc57d \ud3b8\uc785\uc744 \ubd80\uc815\ud558\ub294 \ud6a8\uacfc\ub97c, \uccad\uc57d\ucca0\ud68c\uad8c\uc740 \uc77c\uc815 \uae30\uac04 \ub0b4 \uacc4\uc57d\uc744 \ud574\uc18c\ud560 \uc218 \uc788\ub294 \ubcc4\uac1c\uc758 \uad8c\ub9ac\ub97c \ub2e4\ub8e8\ub294 \uc81c\ub3c4\ub85c \uc11c\ub85c \ub2e4\ub974\ub2e4","\uccad\uc57d\ucca0\ud68c\uad8c\uc774 \uc778\uc815\ub418\uba74 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc544\uc608 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uba74 \uccad\uc57d\ucca0\ud68c\uad8c\uc740 \ub2f9\uc5f0\ud788 \uc18c\uba78\ud55c\ub2e4","\uccad\uc57d\ucca0\ud68c\uad8c\uc740 \uc57d\uad00\ubc95\uc5d0\ub9cc \uaddc\uc815\ub418\uc5b4 \uc788\ub2e4"],t.s)
B.No=s(["\uc11c\ub85c \ub2e4\ub978 \ucde8\uc9c0\uc640 \uc694\uac74\uc744 \uac00\uc9c4 \ubcc4\uac1c\uc758 \uc81c\ub3c4"],t.s)
B.a3_=s(["\uc124\uba85\uc758\ubb34\uc640 \uccad\uc57d\ucca0\ud68c\uad8c\uc758 \uad6c\ubcc4"],t.s)
B.aiP=new A.c("gen_al_expl_25","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc704\ubc18\uacfc \uccad\uc57d\ucca0\ud68c\uad8c\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.WP,1,"\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc758 \ud6a8\uacfc\ub294 \ubb38\uc81c\ub41c \uc57d\uad00 \uc870\ud56d\uc774 \uacc4\uc57d \ub0b4\uc6a9\uc73c\ub85c \ud3b8\uc785\ub418\uc9c0 \ubabb\ud558\uac8c \ud558\ub294 \uac83\uc778 \ubc18\uba74, \uccad\uc57d\ucca0\ud68c\uad8c\uc740 \uc804\uc790\uc0c1\uac70\ub798\ubc95 \ub4f1 \uac1c\ubcc4 \ubc95\ub960\uc5d0\uc11c \uc77c\uc815 \uae30\uac04 \ub0b4\uc5d0 \ubcc4\ub3c4\uc758 \uc0ac\uc720 \uc5c6\uc774 \uacc4\uc57d\uc744 \ud574\uc18c\ud560 \uc218 \uc788\ub3c4\ub85d \uc778\uc815\ud558\ub294 \uc18c\ube44\uc790 \ubcf4\ud638 \uc81c\ub3c4\ub85c, \uc11c\ub85c \ub2e4\ub978 \ucde8\uc9c0\uc640 \uc694\uac74\uc744 \uac00\uc9c4 \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ub2e4.",B.No,B.a3_,null)
B.Pb=s(["\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc0ac\uc5c5\uc790\uac00 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f4\ud558\ub294 \uc758\ubb34\uc774\ub2e4","\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uc774\ud589 \uc5ec\ubd80\ub294 \uac1c\ubcc4 \uacc4\uc57d\uc758 \uad6c\uccb4\uc801 \uc0ac\uc815\uc744 \uace0\ub824\ud558\uc5ec \ud310\ub2e8\ub41c\ub2e4","\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \ubaa8\ub4e0 \uc5c5\uc885\uc5d0 \uc608\uc678 \uc5c6\uc774 \ub3d9\uc77c\ud55c \ubc29\uc2dd\uc73c\ub85c \uc801\uc6a9\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc124\uba85\uc758\ubb34\uc758 \ub300\uc0c1\uc740 \uc57d\uad00 \uc804\uccb4\uac00 \uc544\ub2c8\ub77c \uadf8\uc911 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ud55c\uc815\ub41c\ub2e4","\uba85\uc2dc\uc758\ubb34 \uc704\ubc18\uacfc \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \ubcc4\ub3c4\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4"],t.s)
B.V_=s(["\uc5c5\uc885\uc758 \ud2b9\uc131, \uac70\ub798\ubc29\uc2dd(\ub300\uba74\xb7\ube44\ub300\uba74) \ub4f1\uc5d0 \ub530\ub77c \uadf8 \uad6c\uccb4\uc801\uc778 \uc774\ud589 \ubc29\ubc95\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\uc73c\uba70"],t.s)
B.OD=s(["\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uc801\uc6a9 \ubc29\uc2dd"],t.s)
B.am9=new A.c("gen_al_expl_26","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \ub2e4\uc74c \uc124\uba85 \uc911 \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Pb,2,"\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uacc4\uc57d\uc758 \uc885\ub958\xb7\uc131\uc9c8, \uc5c5\uc885\uc758 \ud2b9\uc131, \uac70\ub798\ubc29\uc2dd(\ub300\uba74\xb7\ube44\ub300\uba74) \ub4f1\uc5d0 \ub530\ub77c \uadf8 \uad6c\uccb4\uc801\uc778 \uc774\ud589 \ubc29\ubc95\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\uc73c\uba70, \uc77c\ubd80 \uc5c5\uc885\uc5d0 \ub300\ud574\uc11c\ub294 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\uac00 \uba74\uc81c\ub418\uae30\ub3c4 \ud55c\ub2e4. \ub530\ub77c\uc11c \ubaa8\ub4e0 \uc5c5\uc885\uc5d0 \uc608\uc678 \uc5c6\uc774 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ubc29\uc2dd\uc73c\ub85c \uc801\uc6a9\ub418\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.",B.V_,B.OD,null)
B.Jj=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc788\ub294 \uc870\ud56d\uc774\ub77c\ub3c4 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \uc791\uc6a9\ud558\ub294 \uacbd\uc6b0\uae4c\uc9c0 \ub2f9\uc5f0\ud788 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4","\uc124\uba85\uc758\ubb34\ub294 \uc0ac\uc5c5\uc790\uac00 \uc790\uc2e0\uc5d0\uac8c \uc720\ub9ac\ud55c \uc870\ud56d\uc77c\uc218\ub85d \ub354\uc6b1 \ucca0\uc800\ud788 \uc774\ud589\ud560 \uc720\uc778\uc774 \uc788\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18 \uc5ec\ubd80\uc758 \ud310\ub2e8\uc5d0\ub294 \uacc4\uc57d \uccb4\uacb0 \ub2f9\uc2dc\uc758 \uad6c\uccb4\uc801 \uc815\ud669\uc774 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4","\uc124\uba85\uc758\ubb34\ub294 \uacc4\uc57d \uccb4\uacb0 \uc774\uc804\uc5d0 \uc774\ud589\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc778\uc815\ub418\uba74 \uc0ac\uc5c5\uc790\ub294 \uadf8 \uc870\ud56d\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.Ib=s(["\uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc77c\uc218\ub85d \uc5c4\uaca9\ud55c \uc124\uba85\uc774 \uc694\uad6c\ub418\ub294 \uac83\uc774 \ud310\ub840\uc758 \uacbd\ud5a5"],t.s)
B.St=s(["\uc124\uba85\uc758\ubb34\uc758 \uac15\ud589\ubc95\uaddc\uc801 \uc131\uaca9"],t.s)
B.amp=new A.c("gen_al_expl_27","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc640 \uad00\ub828\ud558\uc5ec \uac00\uc7a5 \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Jj,1,'\uc124\uba85\uc758\ubb34\ub294 \uace0\uac1d \ubcf4\ud638\ub97c \uc704\ud55c \uac15\ud589\uaddc\uc815\uc801 \uc131\uaca9\uc744 \uac00\uc9c0\ubbc0\ub85c, \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud55c \uc870\ud56d\uc774\ub77c \ud558\uc5ec \uc124\uba85\uc744 \ub354 \ucca0\uc800\ud788 \ud558\uac70\ub098 \uc18c\ud640\ud788 \ud560 \uc7ac\ub7c9\uc774 \uc788\ub294 \uac83\uc774 \uc544\ub2c8\ub2e4. \uc624\ud788\ub824 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc77c\uc218\ub85d \uc5c4\uaca9\ud55c \uc124\uba85\uc774 \uc694\uad6c\ub418\ub294 \uac83\uc774 \ud310\ub840\uc758 \uacbd\ud5a5\uc774\uba70, "\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud560\uc218\ub85d \ub354 \ucca0\uc800\ud788 \uc774\ud589\ud560 \uc720\uc778\uc774 \uc788\ub2e4"\ub294 \uc124\uba85\uc740 \uc81c\ub3c4\uc758 \ucde8\uc9c0\uc640 \ub9de\uc9c0 \uc54a\ub294 \uc633\uc9c0 \uc54a\uc740 \uc9c4\uc220\uc774\ub2e4.',B.Ib,B.St,null)
B.Py=s(["\uba85\uc2dc\uc758\ubb34, \uad50\ubd80\uc758\ubb34, \uc124\uba85\uc758\ubb34\ub294 \ubaa8\ub450 \uc57d\uad00\ubc95 \uc81c3\uc870\uc5d0 \ud568\uaed8 \uaddc\uc815\ub418\uc5b4 \uc788\uc73c\uba70 \uc11c\ub85c \uad6c\ubcc4\ub418\ub294 \ubcc4\uac1c\uc758 \uc758\ubb34\uc774\ub2e4","\uc138 \uc758\ubb34\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \ud558\ub098\ub9cc \uc774\ud589\ud558\uba74 \ucda9\ubd84\ud558\ub2e4","\uc138 \uc758\ubb34 \ubaa8\ub450 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc0ac\uc5c5\uc790\ub97c \ub300\uc2e0\ud558\uc5ec \uc774\ud589\ud55c\ub2e4","\uc138 \uc758\ubb34\ub294 \uacc4\uc57d \uccb4\uacb0 \uc774\ud6c4\uc5d0\ub9cc \ubb38\uc81c\ub41c\ub2e4","\uc138 \uc758\ubb34 \uc911 \uc124\uba85\uc758\ubb34\ub9cc \ubc95\ub960\uc5d0 \uba85\uc2dc\uc801\uc73c\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\ub2e4"],t.s)
B.aax=s(["\uc11c\ub85c \uad6c\ubcc4\ub418\ub294 \ubcc4\uac1c\uc758 \uc758\ubb34"],t.s)
B.UM=s(["\uba85\uc2dc\xb7\uad50\ubd80\xb7\uc124\uba85\uc758\ubb34\uc758 \uccb4\uacc4"],t.s)
B.ak6=new A.c("gen_al_expl_28","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uad00\ub828 \uc885\ud569 \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Py,0,"\uc57d\uad00\ubc95 \uc81c3\uc870\ub294 \uba85\uc2dc\uc758\ubb34(\uc57d\uad00 \ub0b4\uc6a9\uc744 \uc54c \uc218 \uc788\uac8c \ud558\ub294 \uac83), \uad50\ubd80\uc758\ubb34(\uace0\uac1d \uc694\uccad \uc2dc \uc0ac\ubcf8 \uc81c\uacf5), \uc124\uba85\uc758\ubb34(\uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85)\ub97c \ud568\uaed8 \uaddc\uc815\ud558\uace0 \uc788\uc73c\uba70, \uc774\ub4e4\uc740 \uac01\uac01 \ub3c5\uc790\uc801\uc778 \uc694\uac74\uacfc \ud6a8\uacfc\ub97c \uac00\uc9c4 \ubcc4\uac1c\uc758 \uc758\ubb34\ub85c\uc11c \uc5b4\ub290 \ud558\ub098\uc758 \uc774\ud589\uc774 \ub2e4\ub978 \uc758\ubb34\uc758 \uc774\ud589\uc744 \ub300\uccb4\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.aax,B.UM,null)
B.Hr=s(["\uc870\ud56d\uc758 \ub0b4\uc6a9\uc774 \uace0\uac1d\uc5d0\uac8c \ubbf8\uce58\ub294 \uc601\ud5a5\uc758 \uc815\ub3c4","\uacc4\uc57d \uccb4\uacb0 \ub2f9\uc2dc \uc124\uba85\uc774 \uc774\ub8e8\uc5b4\uc9c4 \uad6c\uccb4\uc801\uc778 \ubc29\uc2dd\uacfc \uc815\ub3c4","\uace0\uac1d\uc774 \ud574\ub2f9 \uc5c5\uc885 \uac70\ub798\uc5d0 \ub300\ud574 \uac00\uc9c0\uace0 \uc788\ub358 \uc0ac\uc804 \uc9c0\uc2dd\uc774\ub098 \uacbd\ud5d8","\uc0ac\uc5c5\uc790\uc758 \uc5f0\uac04 \ub9e4\ucd9c\uc561 \uaddc\ubaa8","\uc124\uba85\uc758\ubb34 \uc774\ud589\uc5d0 \uad00\ud55c \uc99d\uba85\uc790\ub8cc(\ub179\ucde8, \uc11c\uba74 \ub4f1)\uc758 \uc874\uc7ac \uc5ec\ubd80"],t.s)
B.Yi=s(["\uc0ac\uc5c5\uc790\uc758 \uc5f0\uac04 \ub9e4\ucd9c\uc561 \uaddc\ubaa8"],t.s)
B.a6q=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18 \ud310\ub2e8 \uc2dc \uace0\ub824\uc694\uc18c"],t.s)
B.aq0=new A.c("gen_al_expl_29","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \ubb38\uc81c\ub41c \uc0ac\uc548\uc5d0\uc11c \ubc95\uc6d0\uc774 \uace0\ub824\ud558\ub294 \uc694\uc18c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.Hr,3,"\ubc95\uc6d0\uc740 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \uc704\ubc18 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c \uc870\ud56d\uc774 \uace0\uac1d\uc5d0\uac8c \ubbf8\uce58\ub294 \uc601\ud5a5, \uc2e4\uc81c \uc124\uba85\uc774 \uc774\ub8e8\uc5b4\uc9c4 \ubc29\uc2dd\uacfc \uc815\ub3c4, \uace0\uac1d\uc758 \uac70\ub798 \uacbd\ud5d8\xb7\uc9c0\uc2dd, \uc124\uba85 \uc774\ud589\uc744 \ub4b7\ubc1b\uce68\ud558\ub294 \uc99d\uba85\uc790\ub8cc\uc758 \uc874\uc7ac \uc5ec\ubd80 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud55c\ub2e4. \ubc18\uba74 \uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub294 \uadf8 \uc790\uccb4\ub85c \uc124\uba85\uc758\ubb34 \uc774\ud589 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \uc9c1\uc811\uc801\uc778 \uace0\ub824\uc694\uc18c\uac00 \uc544\ub2c8\ub2e4.",B.Yi,B.a6q,null)
B.Vl=s(["\uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\uc11c \uc5ec\ubc31\uc5d0 \uc791\uc740 \uae00\uc528\ub85c \uc911\uc694\ud55c \uba74\ucc45\uc870\ud56d\uc744 \uc801\uc5b4\ub450\uace0 \ubcc4\ub3c4 \uc124\uba85 \uc5c6\uc774 \uc11c\uba85\ub9cc \ubc1b\uc740 \uacbd\uc6b0","\uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d \uc804 \uace0\uac1d\uc5d0\uac8c \uc911\uc694\ud55c \ud574\uc9c0\uc0ac\uc720 \uc870\ud56d\uc744 \uad6c\ub450\ub85c \uad6c\uccb4\uc801\uc73c\ub85c \uc124\uba85\ud558\uace0 \uc11c\uba74\uc73c\ub85c\ub3c4 \uc548\ub0b4\ud55c \uacbd\uc6b0","\uc0ac\uc5c5\uc790\uac00 \ud45c\uc900\uc57d\uad00\uacfc \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uadf8\ub300\ub85c \uc0ac\uc6a9\ud558\uba70 \uace0\uac1d\uc5d0\uac8c \ucda9\ubd84\ud788 \uc124\uba85\ud55c \uacbd\uc6b0","\uace0\uac1d\uc774 \ub3d9\uc885 \uac70\ub798 \uacbd\ud5d8\uc774 \ub9ce\uc544 \ud574\ub2f9 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \uc774\ubbf8 \uc798 \uc54c\uace0 \uc788\uc5c8\ub358 \uacbd\uc6b0","\ubc95\ub839\uc5d0 \uadf8\ub300\ub85c \uaddc\uc815\ub41c \ub0b4\uc6a9\uc744 \uacc4\uc57d\uc11c\uc5d0 \uc778\uc6a9\ub9cc \ud55c \uacbd\uc6b0"],t.s)
B.Ol=s(["\uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ucda9\ubd84\ud788 \uc774\ud574\ud560 \uae30\ud68c\ub97c \uac16\uc9c0 \ubabb\ud588\ub2e4\uace0 \ubcfc \uc5ec\uc9c0\uac00 \ucee4\uc11c \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc778\uc815\ub420 \uac00\ub2a5\uc131\uc774 \ub192\ub2e4"],t.s)
B.Ry=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18 \uc0ac\ub840 \ud310\ub2e8"],t.s)
B.aje=new A.c("gen_al_expl_30","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc0ac\ub840 \uc911, \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc778\uc815\ub420 \uac00\ub2a5\uc131\uc774 \uac00\uc7a5 \ub192\uc740 \uacbd\uc6b0\ub294?",B.Vl,0,"\uc911\uc694\ud55c \uba74\ucc45\uc870\ud56d\uacfc \uac19\uc774 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc870\ud56d\uc744 \uc791\uc740 \uae00\uc528\ub85c\ub9cc \uae30\uc7ac\ud558\uace0 \uad6c\uccb4\uc801\uc778 \uc124\uba85 \uc5c6\uc774 \uc11c\uba85\ub9cc \ubc1b\uc740 \uacbd\uc6b0\ub294, \uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ucda9\ubd84\ud788 \uc774\ud574\ud560 \uae30\ud68c\ub97c \uac16\uc9c0 \ubabb\ud588\ub2e4\uace0 \ubcfc \uc5ec\uc9c0\uac00 \ucee4\uc11c \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc778\uc815\ub420 \uac00\ub2a5\uc131\uc774 \ub192\ub2e4. \ubc18\uba74 \uad6c\uccb4\uc801 \uc124\uba85\uc774 \uc788\uc5c8\uac70\ub098, \uace0\uac1d\uc774 \uc774\ubbf8 \ub0b4\uc6a9\uc744 \uc54c\uace0 \uc788\uc5c8\uac70\ub098, \ubc95\ub839\uc744 \uadf8\ub300\ub85c \uc778\uc6a9\ud55c \uacbd\uc6b0\ub294 \uc124\uba85\uc758\ubb34 \uc704\ubc18\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uc0ac\uc815\ub4e4\uc774\ub2e4.",B.Ol,B.Ry,null)
B.abj=s(["\uadf8 \uba85\uce6d\uc774\ub098 \ud615\ud0dc \ub610\ub294 \ubc94\uc704\uc640 \uad00\uacc4\uc5c6\uc774 \uacc4\uc57d\uc758 \ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \uc5ec\ub7ec \uba85\uc758 \uc0c1\ub300\ubc29\uacfc \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\uae30 \uc704\ud558\uc5ec \uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \ubbf8\ub9ac \ub9c8\ub828\ud55c \uacc4\uc57d\uc758 \ub0b4\uc6a9","\ubc18\ub4dc\uc2dc \uc11c\uba74\uc73c\ub85c \uc791\uc131\ub418\uc5b4 \uc778\uc1c4\ub41c \uac83\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc640 \uc0ac\uc5c5\uc790 \uc0ac\uc774\uc758 \uacc4\uc57d\uc5d0\ub9cc \uc0ac\uc6a9\ub418\ub294 \ubb38\uc11c\ub97c \uc758\ubbf8\ud55c\ub2e4","\uad6d\uac00\uac00 \uc9c1\uc811 \uc791\uc131\ud558\uc5ec \uace0\uc2dc\ud55c \ubc95\ub839\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uac1c\ubcc4 \ud611\uc0c1\uc744 \ud1b5\ud574 \uadf8\ub54c\uadf8\ub54c \uc791\uc131\ub418\ub294 \uacc4\uc57d\uc11c\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4"],t.s)
B.a7v=s(["\uacc4\uc57d\uc758 \ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \uc5ec\ub7ec \uba85\uc758 \uc0c1\ub300\ubc29\uacfc \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\uae30 \uc704\ud558\uc5ec \uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \ubbf8\ub9ac \ub9c8\ub828\ud55c \uacc4\uc57d\uc758 \ub0b4\uc6a9"],t.s)
B.Za=s(["\uc57d\uad00\uc758 \uc815\uc758"],t.s)
B.ano=new A.c("gen_ai_def_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc57d\uad00"\uc758 \uc815\uc758\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.abj,0,'\uc57d\uad00\ubc95\uc0c1 "\uc57d\uad00"\uc740 \uadf8 \uba85\uce6d\uc774\ub098 \ud615\ud0dc, \ubc94\uc704\uc640 \uad00\uacc4\uc5c6\uc774 \uacc4\uc57d\uc758 \ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \ub2e4\uc218\uc758 \uc0c1\ub300\ubc29\uacfc \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\uae30 \uc704\ud574 \uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \ubbf8\ub9ac \ub9c8\ub828\ud55c \uacc4\uc57d\ub0b4\uc6a9\uc744 \uc758\ubbf8\ud55c\ub2e4. \uc11c\uba74 \uc5ec\ubd80, \uc0ac\uc5c5\uc790 \uac04 \uacc4\uc57d\uc778\uc9c0 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \uc774\ub7ec\ud55c \uc815\ud615\uc131\xb7\uc0ac\uc804 \ub9c8\ub828\uc131\uc744 \uac16\ucd94\uba74 \uc57d\uad00\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.',B.a7v,B.Za,null)
B.O3=s([u.C5,"\uac1c\ubcc4\uad50\uc12d \uc5ec\ubd80\uc640 \uad00\uacc4\uc5c6\uc774 \uacc4\uc57d\uc11c\uc5d0 \ud3ec\ud568\ub418\uba74 \ubaa8\ub450 \uc57d\uad00\uc774 \ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d\ub41c \uc870\ud56d\ub3c4 \ubc18\ub4dc\uc2dc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \ub300\uc0c1\uc774 \ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d\ub41c \uc870\ud56d\uc740 \ud56d\uc0c1 \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d \uc5ec\ubd80\ub294 \uc57d\uad00 \ud574\ub2f9\uc131 \ud310\ub2e8\uacfc \ubb34\uad00\ud558\ub2e4"],t.s)
