B.O_=s(["\uac1c\ubcc4\uad50\uc12d\uacfc \uc57d\uad00 \ud574\ub2f9\uc131"],t.s)
B.alX=new A.c("gen_ai_def_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uacc4\uc57d\ub2f9\uc0ac\uc790\uac00 \ud2b9\uc815 \uc870\ud56d\uc5d0 \uad00\ud558\uc5ec \uac1c\ubcc4\uc801\uc73c\ub85c \uad50\uc12d\ud558\uc5ec \uacc4\uc57d\ub0b4\uc6a9\uc5d0 \ubc18\uc601\ud55c \uacbd\uc6b0, \uadf8 \uc870\ud56d\uc774 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc778 "\uc57d\uad00"\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.O3,0,'\uc57d\uad00\uc740 \uc0ac\uc5c5\uc790\uac00 \ub2e4\uc218\uc758 \uc0c1\ub300\ubc29\uc744 \uc0c1\ub300\ub85c "\ubbf8\ub9ac" \ub9c8\ub828\ud574 \ub454 \uc815\ud615\uc801 \uacc4\uc57d\ub0b4\uc6a9\uc744 \uaddc\uc728 \ub300\uc0c1\uc73c\ub85c \ud558\ubbc0\ub85c, \ub2f9\uc0ac\uc790\uac00 \ud2b9\uc815 \uc870\ud56d\uc5d0 \uad00\ud574 \uc2e4\uc9c8\uc801\uc73c\ub85c \uac1c\ubcc4\uad50\uc12d\uc744 \uac70\uccd0 \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \ubc18\uc601\ud55c \uacbd\uc6b0\uc5d0\ub294 \uadf8 \uc870\ud56d\uc774 \ub354 \uc774\uc0c1 \uc77c\ubc29\uc801\uc73c\ub85c \ubbf8\ub9ac \ub9c8\ub828\ub41c \uc57d\uad00\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6cc \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc5d0\uc11c \ubc97\uc5b4\ub098\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4.',B.aan,B.O_,null)
B.OH=s([u.zc,"\uc57d\uad00\ubc95\uc740 \uc624\uc9c1 \uc18c\ube44\uc790\uc640\uc758 \uacc4\uc57d\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \uc0ac\uc5c5\uc790 \uac04 \uacc4\uc57d\uc5d0\ub294 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc57d\uad00\ubc95\uc740 \uad6d\ub0b4 \uacc4\uc57d\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \uad6d\uc81c\uacc4\uc57d\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc57d\uad00\ubc95\uc740 \uc11c\uba74\uacc4\uc57d\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \uc804\uc790\uc801 \ud615\ud0dc\uc758 \uc57d\uad00\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc57d\uad00\ubc95\uc740 \ubb34\uc0c1\uacc4\uc57d\uc5d0\ub294 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
