B.ajH=new A.c("gen_ai_def_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)","\uc57d\uad00\ubc95\uc758 \uc801\uc6a9\ub300\uc0c1\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.OH,0,"\uc57d\uad00\ubc95\uc740 \uc18c\ube44\uc790\uc640\uc758 \uacc4\uc57d\ubfd0 \uc544\ub2c8\ub77c \uc0ac\uc5c5\uc790 \uac04 \uacc4\uc57d\uc5d0\uc11c \uc0ac\uc6a9\ub418\ub294 \uc57d\uad00\uc5d0\ub3c4 \uc6d0\uce59\uc801\uc73c\ub85c \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uad6d\uc81c\uc801\uc73c\ub85c \ud1b5\uc6a9\ub418\ub294 \uc57d\uad00\uc774\ub098 \ub2e4\ub978 \ubc95\ub960\uc5d0 \ub530\ub77c \uc778\uac00\xb7\uc2b9\uc778\ubc1b\uc740 \uc57d\uad00 \ub4f1 \uc77c\ubd80 \uc608\uc678\uac00 \uc778\uc815\ub420 \uc218 \uc788\uc73c\ub098, \uc11c\uba74\xb7\uc804\uc790\uc801 \ud615\ud0dc\ub098 \uc720\uc0c1\xb7\ubb34\uc0c1 \uc5ec\ubd80\ub9cc\uc73c\ub85c \uc801\uc6a9 \uc790\uccb4\uac00 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.a8W,B.If,null)
B.abJ=s([u.nK,"\uace0\uac1d\uc740 \ubc18\ub4dc\uc2dc \uac1c\uc778(\uc790\uc5f0\uc778) \uc18c\ube44\uc790\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc0ac\uc5c5\uc790\ub294 \ubc18\ub4dc\uc2dc \ub300\uae30\uc5c5\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uace0\uac1d\uc774 \ub420 \uc218 \uc788\ub294 \uc790\ub294 \ubc95\ub960\uc0c1 \ud2b9\ubcc4\ud788 \uc81c\ud55c\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uc0c1\ub300\ubc29\uc744 \uc758\ubbf8\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uc640 \uace0\uac1d\uc758 \uad6c\ubcc4\uc740 \uacc4\uc57d\uae08\uc561\uc758 \ud06c\uae30\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4"],t.s)
B.RB=s([u.nK],t.s)
B.Jx=s(["\uc0ac\uc5c5\uc790\xb7\uace0\uac1d\uc758 \uc815\uc758"],t.s)
B.akF=new A.c("gen_ai_def_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uc57d\uad00\ubc95\uc0c1 "\uc0ac\uc5c5\uc790"\uc640 "\uace0\uac1d"\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.abJ,0,'\uc57d\uad00\ubc95\uc0c1 "\uc0ac\uc5c5\uc790"\ub294 \uc57d\uad00\uc744 \ubbf8\ub9ac \ub9c8\ub828\ud558\uc5ec \uc0c1\ub300\ubc29\uc5d0\uac8c \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \uc81c\uc2dc\ud558\ub294 \ub2f9\uc0ac\uc790\ub97c \ub9d0\ud558\uace0, "\uace0\uac1d"\uc740 \uadf8 \uc0c1\ub300\ubc29\uc744 \uc758\ubbf8\ud55c\ub2e4. \uace0\uac1d\uc740 \ubc18\ub4dc\uc2dc \uac1c\uc778 \uc18c\ube44\uc790\uc5d0 \ud55c\uc815\ub418\uc9c0 \uc54a\uace0 \ub2e4\ub978 \uc0ac\uc5c5\uc790\ub3c4 \uace0\uac1d\uc758 \uc9c0\uc704\uc5d0 \uc788\uc744 \uc218 \uc788\uc73c\uba70, \uc0ac\uc5c5\uc790 \uc5ed\uc2dc \uae30\uc5c5 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uc81c\uc2dc\ud558\ub294 \uc790\ub77c\uba74 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.',B.RB,B.Jx,null)
B.Ja=s([u.BJ,"\uc804\uc790\uc801\uc73c\ub85c \ud45c\uc2dc\ub41c \uc57d\uad00\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc628\ub77c\uc778 \uc774\uc6a9\uc57d\uad00\uc740 \uc0ac\uc5c5\uc790\uac00 \uc6d0\ud558\ub294 \uacbd\uc6b0\uc5d0\ub9cc \uc57d\uad00\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uc628\ub77c\uc778 \uc774\uc6a9\uc57d\uad00\uc740 \ubc18\ub4dc\uc2dc \ubcc4\ub3c4 \ubc95\ub960\ub85c\ub9cc \uaddc\uc728\ub418\uace0 \uc57d\uad00\ubc95\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\uc774\uc6a9\uc57d\uad00\uc740 \uace0\uac1d\uc774 \ud074\ub9ad\ud558\uc9c0 \uc54a\uc73c\uba74 \uc874\uc7ac \uc790\uccb4\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
