B.arF=new A.c("gen_ai_def_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uc628\ub77c\uc778 \uc11c\ube44\uc2a4 \uac00\uc785 \uc2dc \ud654\uba74\uc5d0 \ub178\ucd9c\ub418\ub294 \uc774\uc6a9\uc57d\uad00\uc774 \uc57d\uad00\ubc95\uc0c1 "\uc57d\uad00"\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Ja,0,"\uc57d\uad00\uc758 \uc815\uc758\ub294 \uba85\uce6d\xb7\ud615\ud0dc\uc640 \ubb34\uad00\ud558\uac8c \ub2e4\uc218 \uc0c1\ub300\ubc29\uc5d0\uac8c \ubbf8\ub9ac \ub9c8\ub828\ub418\uc5b4 \uc81c\uc2dc\ub418\ub294 \uc815\ud615\uc801 \uacc4\uc57d\ub0b4\uc6a9\uc778\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \ud558\ubbc0\ub85c, \uc628\ub77c\uc778 \uc11c\ube44\uc2a4 \uac00\uc785 \uc2dc \ub178\ucd9c\ub418\ub294 \uc774\uc6a9\uc57d\uad00\ub3c4 \uc774\ub7ec\ud55c \uc694\uac74\uc744 \ucda9\uc871\ud558\uba74 \uc57d\uad00\ubc95\uc0c1 \uc57d\uad00\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc11c\uba74\uc774 \uc544\ub2cc \uc804\uc790\uc801 \ud615\ud0dc\ub77c\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uaddc\uc728 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.a51,B.a3b,null)
B.K5=s(["\ubc18\ub4dc\uc2dc \uad00\ud560 \ud589\uc815\uccad\uc758 \uc0ac\uc804 \uc778\uac00\ub97c \ubc1b\uc544\uc57c \ud55c\ub2e4","\ub2e4\uc218\uc758 \uc0c1\ub300\ubc29\uc744 \ub300\uc0c1\uc73c\ub85c \ud560 \uac83\uc744 \uc608\uc815\ud558\uace0 \uc788\uc744 \uac83","\uacc4\uc57d\uccb4\uacb0 \uc804\uc5d0 \ubbf8\ub9ac \ub9c8\ub828\ub418\uc5b4 \uc788\uc744 \uac83","\uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \uc815\ud615\ud654\ub418\uc5b4 \uc788\uc744 \uac83","\ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \uc774\ub97c \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \uc81c\uc2dc\ud560 \uac83"],t.s)
B.aaA=s(["\ubc18\ub4dc\uc2dc \uad00\ud560 \ud589\uc815\uccad\uc758 \uc0ac\uc804 \uc778\uac00\ub97c \ubc1b\uc544\uc57c \ud55c\ub2e4"],t.s)
B.Pg=s(["\uc57d\uad00\uc758 \uc131\ub9bd\uc694\uac74"],t.s)
B.anm=new A.c("gen_ai_def_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uc57d\uad00\ubc95\uc774 \uaddc\uc728\ud558\ub294 "\uc57d\uad00"\uc5d0 \ud574\ub2f9\ud558\uae30 \uc704\ud55c \uc694\uac74\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?',B.K5,0,'\uc57d\uad00\uc5d0 \ud574\ub2f9\ud558\uae30 \uc704\ud574\uc11c\ub294 \ub2e4\uc218 \uc0c1\ub300\ubc29\uc744 \ub300\uc0c1\uc73c\ub85c \uc608\uc815\ud560 \uac83, \uacc4\uc57d\uccb4\uacb0 \uc804 \ubbf8\ub9ac \ub9c8\ub828\ub418\uc5b4 \uc788\uc744 \uac83, \uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \uc815\ud615\ud654\ub418\uc5b4 \uc788\uc744 \uac83, \ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \uc774\ub97c \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \uc81c\uc2dc\ud560 \uac83 \ub4f1\uc758 \uc694\uc18c\uac00 \uc694\uad6c\ub41c\ub2e4. \ubc18\uba74 "\uad00\ud560 \ud589\uc815\uccad\uc758 \uc0ac\uc804 \uc778\uac00"\ub294 \uc57d\uad00 \ud574\ub2f9\uc131 \ud310\ub2e8\uacfc \ubb34\uad00\ud55c \uc694\uc18c\ub85c, \uc778\uac00 \uc5ec\ubd80\uc640 \uad00\uacc4\uc5c6\uc774 \uc57d\uad00\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.',B.aaA,B.Pg,null)
B.MI=s([u.ah,"\uc57d\uad00\uc740 \uac1c\ubcc4\uc57d\uc815\ubcf4\ub2e4 \ud56d\uc0c1 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \ubc18\ub4dc\uc2dc \uc11c\uba74\uc73c\ub85c\ub9cc \uc778\uc815\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uacfc \uc57d\uad00\uc774 \ub2e4\ub974\uba74 \ud56d\uc0c1 \uc57d\uad00 \ub0b4\uc6a9\ub300\ub85c \uacc4\uc57d\uc774 \uc131\ub9bd\ud55c\ub2e4","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a5s=s([u.ah],t.s)
B.amy=new A.c("gen_ai_special_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c4\uc870(\uac1c\ubcc4\uc57d\uc815\uc758 \uc6b0\uc120)\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.MI,0,"\uc57d\uad00\ubc95 \uc81c4\uc870\ub294 \uc57d\uad00\uc5d0 \uc815\ud558\uace0 \uc788\ub294 \uc0ac\ud56d\uc5d0 \uad00\ud558\uc5ec \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uacfc \ub2e4\ub974\uac8c \uac1c\ubcc4\uc801\uc73c\ub85c \ud569\uc758\ud55c \uc0ac\ud56d\uc774 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub294 \uadf8 \ud569\uc758\uc0ac\ud56d\uc774 \uc57d\uad00\ubcf4\ub2e4 \uc6b0\uc120\ud55c\ub2e4\ub294 \uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc744 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \ub2f9\uc0ac\uc790\uc758 \uc2e4\uc81c \uc758\uc0ac\ub97c \uc57d\uad00\uc774\ub77c\ub294 \uc815\ud615\uc801 \uc870\ud56d\ubcf4\ub2e4 \uc6b0\uc120\uc2dc\ud558\ub824\ub294 \ucde8\uc9c0\uc774\ub2e4.",B.a5s,B.o4,null)
B.Oy=s([u.oN,"\uac1c\ubcc4\uc57d\uc815\uc740 \ubc18\ub4dc\uc2dc \uacc4\uc57d\uc11c \ub9e8 \uc55e\uc5d0 \uae30\uc7ac\ub418\uc5b4\uc57c \ud55c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \ubc18\ub4dc\uc2dc \uacf5\uc99d\uc744 \ubc1b\uc544\uc57c \ud6a8\ub825\uc774 \uc788\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \uc0ac\uc5c5\uc790 \ub2e8\ub3c5\uc73c\ub85c \uc791\uc131\ud558\uba74 \ucda9\ubd84\ud558\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \uace0\uac1d\uc774 \uc0ac\uc5c5\uc790\uac00 \uc544\ub2c8\uc5b4\uc57c\ub9cc \uc778\uc815\ub41c\ub2e4"],t.s)
B.Ho=s([u.oN],t.s)
B.a6Z=s(["\uac1c\ubcc4\uc57d\uc815 \uc778\uc815\uc694\uac74"],t.s)
B.aj2=new A.c("gen_ai_special_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uae30 \uc704\ud55c \uc694\uac74\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Oy,0,"\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\ub824\uba74 \ub2e8\uc21c\ud788 \uc11c\ub958\uc0c1 \ubcc4\ub3c4 \uc870\ud56d\uc774 \uc788\ub2e4\ub294 \ud615\uc2dd\ubcf4\ub2e4, \ub2f9\uc0ac\uc790 \uc0ac\uc774\uc5d0 \uc57d\uad00\uacfc \ub2e4\ub978 \ub0b4\uc6a9\uc5d0 \uad00\ud558\uc5ec \uc2e4\uc9c8\uc801\uc778 \uad50\uc12d\uacfc \ud569\uc758\uac00 \uc774\ub8e8\uc5b4\uc84c\ub2e4\uace0 \uc778\uc815\ub420 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4. \uacc4\uc57d\uc11c\uc0c1 \uc704\uce58, \uacf5\uc99d \uc5ec\ubd80, \uc0ac\uc5c5\uc790 \ub2e8\ub3c5 \uc791\uc131 \uc5ec\ubd80\ub294 \uac1c\ubcc4\uc57d\uc815 \uc778\uc815\uc758 \ubcf8\uc9c8\uc801 \uc694\uac74\uc774 \uc544\ub2c8\ub2e4.",B.Ho,B.a6Z,null)
B.a6f=s([u.sd,"\uac1c\ubcc4\uc57d\uc815\uc740 \uadf8 \ub0b4\uc6a9\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc720\ud6a8\ud558\uac8c \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc774 \ubd88\ub9ac\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \uc57d\uad00 \ub0b4\uc6a9\uc774 \ubd80\ud65c\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc744 \uc815\ud560 \uc218 \uc5c6\ub3c4\ub85d \ubc95\ub960\uc0c1 \uc804\uba74 \uae08\uc9c0\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc758 \ubd88\ub9ac\ud55c \uc815\ub3c4\ub294 \ud310\ub2e8 \uae30\uc900\uc5d0\uc11c \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.I3=s([u.sd],t.s)
B.a8e=s(["\uac1c\ubcc4\uc57d\uc815\uc758 \ud55c\uacc4"],t.s)
B.aoC=new A.c("gen_ai_special_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)","\uac1c\ubcc4\uc57d\uc815\uc774 \uace0\uac1d\uc5d0\uac8c \uc57d\uad00\ubcf4\ub2e4 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc77c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a6f,0,"\uac1c\ubcc4\uc57d\uc815\uc774 \uc57d\uad00\ubcf4\ub2e4 \uc6b0\uc120\ud55c\ub2e4\ub294 \uc6d0\uce59\uc774 \uc788\ub354\ub77c\ub3c4, \uadf8 \uac1c\ubcc4\uc57d\uc815 \uc790\uccb4\uc758 \ub0b4\uc6a9\uc774 \uac15\ud589\ubc95\uaddc\uc5d0 \uc704\ubc18\ub418\uac70\ub098 \uc57d\uad00\ubc95\uc774 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc815\ub3c4\ub85c \ubd88\uacf5\uc815\ud558\ub2e4\uba74, \uac1c\ubcc4\uc57d\uc815 \uc5ed\uc2dc \ubcc4\ub3c4\ub85c \ubb34\ud6a8\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\ub2e4. \uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc774 \ubaa8\ub4e0 \ub0b4\uc6a9\ud1b5\uc81c\ub97c \ubc30\uc81c\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.I3,B.a8e,null)
B.a7c=s([u.lk,"\uc774 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\ub9cc\uc744 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc57d\uad00\ubc95\uc758 \ub2e4\ub978 \uaddc\uc815\ub4e4\uc744 \uc804\ubd80 \ubb34\ub825\ud654\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \uace0\uac1d\uc5d0\uac8c \uc5b4\ub5a0\ud55c \uc774\uc775\ub3c4 \uc8fc\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc624\uc9c1 \uad6d\uc81c\uacc4\uc57d\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a0S=s([u.lk],t.s)
B.abn=s(["\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120 \uc6d0\uce59\uc758 \uc758\uc758"],t.s)
B.akL=new A.c("gen_ai_special_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc774 \uc2e4\ubb34\uc0c1 \uac00\uc9c0\ub294 \uc758\uc758\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a7c,0,"\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \uc57d\uad00\uc774\ub77c\ub294 \uc815\ud615\uc801\xb7\uc77c\ubc29\uc801 \uacc4\uc57d\ub0b4\uc6a9\ubcf4\ub2e4 \ub2f9\uc0ac\uc790\uac00 \uc2e4\uc81c\ub85c \ud611\uc758\ud558\uc5ec \ud569\uc758\ud55c \ub0b4\uc6a9\uc744 \uc6b0\uc120\uc2dc\ud568\uc73c\ub85c\uc368, \uc57d\uad00\uc5d0 \ub300\ud55c \ub0b4\uc6a9\ud1b5\uc81c\uc640 \uacc4\uc57d\uc790\uc720\uc758 \uc6d0\uce59(\uc0ac\uc801\uc790\uce58) \uc0ac\uc774\uc758 \uc870\ud654\ub97c \ub3c4\ubaa8\ud558\ub294 \uc2e4\ubb34\uc801 \uc758\uc758\ub97c \uac00\uc9c4\ub2e4.",B.a0S,B.abn,null)
B.a4M=s([u.lz,"\uc644\uc804\ud569\uc758\uc870\ud56d\uc774 \uc788\uc73c\uba74 \uc5b4\ub5a0\ud55c \uac1c\ubcc4 \uad6c\ub450\ud569\uc758\ub3c4 \uc608\uc678 \uc5c6\uc774 \ubb34\ud6a8\uc774\ub2e4","\uc644\uc804\ud569\uc758\uc870\ud56d\uc740 \ud56d\uc0c1 \ubb34\ud6a8\uc774\ubbc0\ub85c \uc804\ud600 \uace0\ub824\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc644\uc804\ud569\uc758\uc870\ud56d\uc774 \uc788\uc73c\uba74 \uc57d\uad00\ubc95 \uc790\uccb4\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc644\uc804\ud569\uc758\uc870\ud56d\uc758 \ud6a8\ub825\uc740 \ubc95\uc6d0\uc758 \ud310\ub2e8\uacfc \ubb34\uad00\ud558\uac8c \uc808\ub300\uc801\uc774\ub2e4"],t.s)
