B.aoT=new A.c("gen_ai_special_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)",'\uacc4\uc57d\uc11c\uc5d0 "\ubcf8 \uacc4\uc57d\uacfc \ub2e4\ub978 \uad6c\ub450\uc0c1 \ud569\uc758\ub294 \ud6a8\ub825\uc774 \uc5c6\ub2e4"\ub294 \uc870\ud56d(\uc644\uc804\ud569\uc758\uc870\ud56d)\uc774 \uc788\ub294 \uacbd\uc6b0, \uc2e4\uc81c\ub85c \uc774\ub8e8\uc5b4\uc9c4 \uac1c\ubcc4 \uad6c\ub450\ud569\uc758\uc758 \ud6a8\ub825\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a4M,0,"\uc644\uc804\ud569\uc758\uc870\ud56d(\ub2e4\ub978 \ud569\uc758\ub294 \ud6a8\ub825\uc774 \uc5c6\ub2e4\ub294 \ucde8\uc9c0\uc758 \uc57d\uad00\uc870\ud56d) \uc790\uccb4\ub3c4 \ud558\ub098\uc758 \uc57d\uad00\uc870\ud56d\uc73c\ub85c\uc11c \uc2ec\uc0ac \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\uc73c\uba70, \uc2e4\uc81c\ub85c \uac1c\ubcc4\uc57d\uc815\uc774\ub77c\uace0 \ubcfc \uc218 \uc788\ub294 \uc0ac\uc815\uc774 \uc778\uc815\ub41c\ub2e4\uba74 \uadf8\ub7ec\ud55c \uc870\ud56d\uc758 \uc874\uc7ac\ub9cc\uc73c\ub85c \uadf8 \ud6a8\ub825\uc774 \ub2f9\uc5f0\ud788 \ubc30\uc81c\ub41c\ub2e4\uace0 \ub2e8\uc815\ud558\uae30\ub294 \uc5b4\ub835\ub2e4\ub294 \uac83\uc774 \uc77c\ubc18\uc801 \ub17c\uc758\uc774\ub2e4. \uad6c\uccb4\uc801 \uacb0\ub860\uc740 \uc0ac\uc548\uc758 \uc0ac\uc815\uc5d0 \ub530\ub77c \ub2ec\ub77c\uc9c8 \uc218 \uc788\ub2e4.",B.a9q,B.XM,null)
B.Us=s([u.ai,"\uac1c\ubcc4\uc57d\uc815\uc5d0\ub3c4 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uac00 \uc544\ubb34 \ucc28\uc774 \uc5c6\uc774 \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc640 \uc804\ud600 \uad00\ub828\uc774 \uc5c6\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc624\ud788\ub824 \uc57d\uad00\ubcf4\ub2e4 \ub354 \uc5c4\uaca9\ud55c \uc124\uba85\uc758\ubb34\uac00 \ubd80\uacfc\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uacfc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc11c\ub85c \ubc18\ub300\ub418\ub294 \uac1c\ub150\uc73c\ub85c \ub3d9\uc2dc\uc5d0 \uc131\ub9bd\ud560 \uc218 \uc5c6\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc774 \uc778\uc815\ub418\uba74 \uacc4\uc57d \uc790\uccb4\uac00 \ubb34\ud6a8\uac00 \ub41c\ub2e4"],t.s)
