B.a8f=s(["\ud3c9\uade0\uc801 \uace0\uac1d \uae30\uc900 \ud574\uc11d"],t.s)
B.aoV=new A.c("gen_ai_good_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ubd88\uba85\ud655\ud55c \uacbd\uc6b0 \ud574\uc11d \ubc29\ubc95\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_y,0,"\uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ubd88\uba85\ud655\ud55c \uacbd\uc6b0\uc5d0\ub294 \ud2b9\uc815 \uac1c\uc778\uc774 \uc544\ub2c8\ub77c \ud3c9\uade0\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc744 \uc5b4\ub5bb\uac8c \uc774\ud574\ud560 \uac83\uc778\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \uac1d\uad00\uc801\uc774\uace0 \ud1b5\uc77c\uc801\uc73c\ub85c \ud574\uc11d\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub418\ub294 \uc57d\uad00\uc758 \uc131\uaca9\uc5d0 \ubd80\ud569\ud558\ub294 \ud574\uc11d\ubc29\ubc95\uc774\ub2e4.",B.Tk,B.a8f,null)
B.Kk=s([u.EV,"\uc774\ub7ec\ud55c \uac00\ub2a5\uc131\uc740 \ud1b5\uc77c\uc801 \ud574\uc11d \uc6d0\uce59\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubc95\uc6d0\uc740 \ub3d9\uc77c \uc870\ud56d\uc5d0 \ub300\ud574 \ud56d\uc0c1 \uae30\uacc4\uc801\uc73c\ub85c \ub3d9\uc77c\ud55c \uacb0\ub860\ub9cc \ub0b4\ub824\uc57c \ud558\uba70 \uc0ac\uc2e4\uad00\uacc4\ub294 \uc804\ud600 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\ud1b5\uc77c\uc801 \ud574\uc11d \uc6d0\uce59\uc774 \uc788\uc73c\ubbc0\ub85c \ubc95\uc6d0\uc758 \ud310\ub2e8\uc740 \uc808\ub300\ub85c \ub2ec\ub77c\uc9c8 \uc218 \uc5c6\ub2e4","\uc774 \ubb38\uc81c\ub294 \uc57d\uad00\ubc95\uacfc \ubb34\uad00\ud55c \uc18c\uc1a1\ubc95\uc0c1 \ubb38\uc81c\uc77c \ubfd0\uc774\ub2e4"],t.s)
B.acx=s([u.EV],t.s)
B.YB=s(["\ud1b5\uc77c\uc801 \ud574\uc11d\uacfc \uac1c\ubcc4 \uc0ac\uc548\uc758 \uad00\uacc4"],t.s)
B.apN=new A.c("gen_ai_good_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\ub3d9\uc77c\ud55c \uc57d\uad00 \uc870\ud56d\uc5d0 \ub300\ud574 \uc11c\ub85c \ub2e4\ub978 \uc18c\uc1a1\uc5d0\uc11c \ubc95\uc6d0\uc774 \ub2e4\ub974\uac8c \ud310\ub2e8\ud560 \uac00\ub2a5\uc131\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Kk,0,'\ud1b5\uc77c\uc801 \ud574\uc11d\uc758 \uc6d0\uce59\uc740 \ub3d9\uc77c\ud55c \uc57d\uad00 \uc870\ud56d\uc758 "\uc758\ubbf8" \uc790\uccb4\ub97c \uace0\uac1d\uc5d0 \ub530\ub77c \uc790\uc758\uc801\uc73c\ub85c \ub2ec\ub9ac \ud574\uc11d\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4\ub294 \uac83\uc774\uc9c0, \uad6c\uccb4\uc801 \uc0ac\uac74\ub9c8\ub2e4 \ub2e4\ub978 \uc0ac\uc2e4\uad00\uacc4(\uacc4\uc57d\uacbd\uc704, \ud2b9\uc57d \uc874\ubd80 \ub4f1)\uae4c\uc9c0 \uc644\uc804\ud788 \ubb34\uc2dc\ud558\uace0 \ud56d\uc0c1 \ub3d9\uc77c\ud55c \uacb0\ub860\uc744 \ub0b4\ub824\uc57c \ud55c\ub2e4\ub294 \uc758\ubbf8\ub294 \uc544\ub2c8\ub2e4. \ub2e4\ub9cc \uc870\ud56d\uc758 \ud574\uc11d \uc790\uccb4\uac00 \uc0ac\uc548\ub9c8\ub2e4 \ub2ec\ub77c\uc9c0\ub294 \uac83\uc740 \ud1b5\uc77c\uc801 \ud574\uc11d\uc758 \ucde8\uc9c0\uc5d0 \ube44\ucd94\uc5b4 \ubc14\ub78c\uc9c1\ud558\uc9c0 \uc54a\ub2e4.',B.acx,B.YB,null)
B.IG=s([u.o0,"\uc81c5\uc870\uc640 \uc81c6\uc870~\uc81c14\uc870\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uc911\ubcf5 \uaddc\uc815\ud55c \uac83\uc774\ub2e4","\uc81c5\uc870\uac00 \uc801\uc6a9\ub418\uba74 \uc81c6\uc870~\uc81c14\uc870\ub294 \uc801\uc6a9\ub420 \uc5ec\uc9c0\uac00 \uc5c6\ub2e4","\uc81c6\uc870~\uc81c14\uc870\uac00 \uc801\uc6a9\ub418\uba74 \uc81c5\uc870\ub294 \uc804\ufffd\ud5a5 \ubd88\ud544\uc694\ud558\ub2e4","\ub450 \uaddc\uc815\uc740 \uc11c\ub85c \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uc18d\ud55c\ub2e4"],t.s)
