B.a0b=s(["\ud574\uc11d\uaddc\uc815\uacfc \ubb34\ud6a8\uaddc\uc815\uc758 \uad00\uacc4"],t.s)
B.akd=new A.c("gen_ai_good_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\uc57d\uad00 \ud574\uc11d\uc5d0 \uad00\ud55c \uc81c5\uc870 \uc81c1\ud56d\uacfc \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720(\uc81c6\uc870~\uc81c14\uc870)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.IG,0,'\uc81c5\uc870\ub294 \uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \uc5b4\ub5bb\uac8c "\ud574\uc11d"\ud560 \uac83\uc778\uc9c0\uc5d0 \uad00\ud55c \ubc29\ubc95\ub860\uc744 \uaddc\uc815\ud558\ub294 \ubc18\uba74, \uc81c6\uc870\ubd80\ud130 \uc81c14\uc870\uae4c\uc9c0\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc57d\uad00 \uc870\ud56d\uc758 "\ub0b4\uc6a9" \uc790\uccb4\uac00 \ubd88\uacf5\uc815\ud558\uc5ec \ubb34\ud6a8\uc778\uc9c0\ub97c \ud310\ub2e8\ud558\ub294 \uaddc\uc815\uc774\ub2e4. \uc2e4\ubb34\uc0c1 \uba3c\uc800 \ud574\uc11d\uc744 \ud1b5\ud574 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ud655\uc815\ud55c \ub4a4, \uadf8 \ub0b4\uc6a9\uc774 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\ub97c \uac80\ud1a0\ud558\ub294 \uc21c\uc11c\ub85c \ub450 \uaddc\uc815\uc774 \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4.',B.NW,B.a0b,null)
B.Ys=s(["\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc73c\uba74 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub41c\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \uc801\uc6a9\ub41c\ub2e4","\uc774 \uc6d0\uce59\uc740 \uace0\uac1d\uc774 \uc0ac\uc5c5\uc790\uc778 \uacbd\uc6b0\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uac00 \uc791\uc131\ud55c \ubaa8\ub4e0 \ubb38\uc11c\uc5d0 \uc608\uc678 \uc5c6\uc774 \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a9w=s(["\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.Ih=s(["\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"],t.s)
B.aii=new A.c("gen_ai_contra_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)",'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870 \uc81c2\ud56d\uc774 \uc815\ud558\ub294 "\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Ys,0,'\uc57d\uad00\ubc95 \uc81c5\uc870 \uc81c2\ud56d\uc740 \uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc740 \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc774\ub978\ubc14 "\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"(contra proferentem)\uc744 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uc57d\uad00\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc791\uc131\ud55c \uc0ac\uc5c5\uc790\uac00 \uadf8 \ubd88\uba85\ud655\uc131\uc5d0 \ub530\ub978 \uc704\ud5d8\uc744 \ubd80\ub2f4\ud558\ub3c4\ub85d \ud558\ub824\ub294 \ucde8\uc9c0\uc774\uba70, \uc57d\uad00\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub294 \ubcc4\ub3c4\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.a9w,B.Ih,null)
B.HY=s([u.Eq,"\uc870\ud56d\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4","\uace0\uac1d\uc774 \uc0ac\uc5c5\uc790\ubcf4\ub2e4 \uc6b0\uc6d4\ud55c \uc9c0\uc704\uc5d0 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uacc4\uc57d\uae08\uc561\uc774 \uc77c\uc815 \uaddc\ubaa8 \uc774\uc0c1\uc778 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \ubcc4\ub3c4\uc758 \uc804\uc81c \uc5c6\uc774 \ubaa8\ub4e0 \uc57d\uad00 \ubd84\uc7c1\uc5d0 \uc790\ub3d9 \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.PC=s([u.Eq],t.s)
B.Yv=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uc801\uc6a9\uc804\uc81c"],t.s)
B.ah1=new A.c("gen_ai_contra_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uae30 \uc704\ud55c \uc804\uc81c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.HY,0,'\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \uc5b4\ub514\uae4c\uc9c0\ub098 "\ubcf4\ucda9\uc801" \ud574\uc11d\uc6d0\uce59\uc73c\ub85c, \ubb38\uc5b8\xb7\ubaa9\uc801\xb7\uccb4\uacc4 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud55c \ud1b5\uc0c1\uc801\uc778 \ud574\uc11d\ubc29\ubc95\uc744 \ub2e4 \ub3d9\uc6d0\ud574\ub3c4 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud788 \ud655\uc815\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\uc5d0 \ube44\ub85c\uc18c \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ud1b5\uc0c1\uc758 \ud574\uc11d\ubc29\ubc95\uc73c\ub85c \uba85\ubc31\ud788 \ud655\uc815\ub41c\ub2e4\uba74 \uc774 \uc6d0\uce59\uc774 \uac1c\uc785\ud560 \uc5ec\uc9c0\ub294 \uc5c6\ub2e4.',B.PC,B.Yv,null)
B.Ok=s([u.gK,"\uace0\uac1d\uc774 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\ubcf4\ub2e4 \ubc95\ub960\uc9c0\uc2dd\uc774 \ubd80\uc871\ud558\uae30 \ub54c\ubb38\uc5d0 \ubb34\uc870\uac74 \uace0\uac1d\uc774 \uc774\uae34\ub2e4\ub294 \ucde8\uc9c0\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\uc744 \uc6b0\uc120 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \ubc95\uc6d0\uc758 \uc5c5\ubb34 \ubd80\ub2f4\uc744 \uc904\uc774\uae30 \uc704\ud55c \uc784\uc758\uc801 \uad00\ud589\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc774 \uc6d0\uce59\uc740 \uad6d\uc81c\uc870\uc57d\uc5d0 \ub530\ub77c \uac15\uc81c\ub41c \uac83\uc77c \ubfd0 \uc815\ucc45\uc801 \uadfc\uac70\uac00 \uc5c6\ub2e4"],t.s)
B.aaO=s([u.gK],t.s)
B.X7=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uadfc\uac70"],t.s)
B.ajB=new A.c("gen_ai_contra_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc758 \uc815\ucc45\uc801 \uadfc\uac70\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ok,0,"\uc57d\uad00\uc740 \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \ub9c8\ub828\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \uc81c\uc2dc\ud558\ub294 \uac83\uc774\ubbc0\ub85c, \uadf8 \ubb38\uc5b8\uc774 \ubd88\uba85\ud655\ud558\uac8c \uc791\uc131\ub41c \ub370 \ub530\ub978 \uc704\ud5d8\uacfc \ubd88\uc774\uc775\uc740 \uc774\ub97c \uc791\uc131\ud55c \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud558\ub294 \uac83\uc774 \ud615\ud3c9\uc5d0 \ubd80\ud569\ud55c\ub2e4\ub294 \uc815\ucc45\uc801 \uace0\ub824\uac00 \uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uadfc\uac70\uc774\ub2e4.",B.aaO,B.X7,null)
B.a4G=s([u.zA,"\ubcf4\ud5d8\uc57d\uad00\uc740 \uc560\ucd08\uc5d0 \uc57d\uad00\ubc95\uc758 \uc801\uc6a9\ub300\uc0c1\uc774 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uc57d\uad00\uc740 \ud56d\uc0c1 \uba85\ud655\ud558\uac8c \uc791\uc131\ub418\uc5b4 \uc774 \uc6d0\uce59\uc774 \uc801\uc6a9\ub420 \uc77c\uc774 \uc5c6\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uacc4\uc57d\uc790\ub294 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc9c0\uc704\uc5d0 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uc57d\uad00\uc5d0\ub294 \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \ubc95\ub960\uc0c1 \uba85\uc2dc\uc801\uc73c\ub85c \ubc30\uc81c\ub418\uc5b4 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
