B.WA=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uc2e4\ubb34\uc0c1 \uc801\uc6a9\ub840"],t.s)
B.ak9=new A.c("gen_ai_contra_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\ubcf4\ud5d8\uc57d\uad00\uacfc \uac19\uc774 \uc804\ubb38\uc801\uc774\uace0 \ubcf5\uc7a1\ud55c \uc57d\uad00\uc5d0\uc11c \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \ud2b9\ud788 \uc790\uc8fc \ubb38\uc81c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a4G,0,"\ubcf4\ud5d8\uc57d\uad00\uc740 \ubcf4\uc7a5\ubc94\uc704\xb7\uba74\ucc45\uc0ac\uc720 \ub4f1\uc744 \uc815\ud558\ub294 \uc804\ubb38\uc801\uc774\uace0 \ubcf5\uc7a1\ud55c \uc870\ud56d\uc774 \ub9ce\uc544, \ubb38\uc5b8\uc758 \ub2e4\uc758\uc801 \ud574\uc11d \uac00\ub2a5\uc131\uc774 \uc0c1\ub300\uc801\uc73c\ub85c \ud06c\uac8c \ub098\ud0c0\ub098\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4. \uc774 \ub54c\ubb38\uc5d0 \uc2e4\ubb34\uc0c1 \ubcf4\ud5d8\uc57d\uad00 \uad00\ub828 \ubd84\uc7c1\uc5d0\uc11c \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc790\uc8fc \ubb38\uc81c\ub418\uace0 \ud65c\uc6a9\ub41c\ub2e4.",B.acp,B.WA,null)
B.I7=s(['\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\ufffd\uce59\uc740 "\ud574\uc11d"\uc758 \ubb38\uc81c\uc774\uace0, \ubb34\ud6a8 \ubc95\ub9ac\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc870\ud56d "\ub0b4\uc6a9"\uc758 \ud6a8\ub825 \ubb38\uc81c\ub85c \uc11c\ub85c \ub2e8\uacc4\uac00 \ub2e4\ub974\ub2e4',"\ub450 \ubc95\ub9ac\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uba74 \uadf8 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ubb34\ud6a8 \ubc95\ub9ac\uac00 \uc801\uc6a9\ub418\uba74 \ud574\uc11d\uc758 \ubb38\uc81c\ub294 \uc544\uc608 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\ub294\ub2e4","\ub450 \ubc95\ub9ac\ub294 \uc11c\ub85c \uc591\ub9bd\ud560 \uc218 \uc5c6\ub294 \ubaa8\uc21c \uad00\uacc4\uc5d0 \uc788\ub2e4"],t.s)
B.a1H=s(['\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 "\ud574\uc11d"\uc758 \ubb38\uc81c\uc774\uace0, \ubb34\ud6a8 \ubc95\ub9ac\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc870\ud56d "\ub0b4\uc6a9"\uc758 \ud6a8\ub825 \ubb38\uc81c\ub85c \uc11c\ub85c \ub2e8\uacc4\uac00 \ub2e4\ub974\ub2e4'],t.s)
B.Ml=s(["\ud574\uc11d\uacfc \ubb34\ud6a8\ud310\ub2e8\uc758 \ub2e8\uacc4 \uad6c\ubd84"],t.s)
B.ang=new A.c("gen_ai_contra_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uacfc \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8 \ubc95\ub9ac\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.I7,0,'\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \uc870\ud56d\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc744 \ub54c "\uc5b4\ub5bb\uac8c \ud574\uc11d\ud560 \uac83\uc778\uac00"\uc758 \ubb38\uc81c\uc778 \ubc18\uba74, \ubb34\ud6a8 \ubc95\ub9ac(\uc81c6\uc870~\uc81c14\uc870)\ub294 \ud574\uc11d\uc744 \ud1b5\ud574 \ud655\uc815\ub41c \uc870\ud56d\uc758 "\ub0b4\uc6a9" \uc790\uccb4\uac00 \ubd88\uacf5\uc815\ud558\uc5ec \ud6a8\ub825\uc744 \uc778\uc815\ud560 \uc218 \uc5c6\ub294\uc9c0\uc758 \ubb38\uc81c\uc774\ub2e4. \ub450 \ubc95\ub9ac\ub294 \uc21c\ucc28\uc801\uc73c\ub85c \uac80\ud1a0\ub420 \uc218 \uc788\ub294 \uc11c\ub85c \ub2e4\ub978 \ub2e8\uacc4\uc758 \uc7c1\uc810\uc774\ub2e4.',B.a1H,B.Ml,null)
B.HC=s([u.q2,"\uc774\ub7ec\ud55c \uacb0\uacfc\ub294 \ud56d\uc0c1 \ubd80\ub2f9\ud558\ubbc0\ub85c \ubc95\uc6d0\uc774 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \uc7ac\ud574\uc11d\ud574\uc57c \ud55c\ub2e4","\uc774 \uacbd\uc6b0 \uacc4\uc57d \uc790\uccb4\uac00 \ucc98\uc74c\ubd80\ud130 \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uc774 \uacbd\uc6b0 \uace0\uac1d\uc774 \uc624\ud788\ub824 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc744 \uc9c4\ub2e4","\uc774 \uc6d0\uce59\uc774 \uc801\uc6a9\ub41c \uacb0\uacfc\ub294 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4"],t.s)
