B.aqc=new A.c("gen_ai_contra_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub41c \uacb0\uacfc, \uc0ac\uc5c5\uc790\uac00 \uc758\ub3c4\ud588\ub358 \uac83\ubcf4\ub2e4 \ub113\uc740 \ubc94\uc704\uc758 \ucc45\uc784\uc744 \ubd80\ub2f4\ud558\uac8c \ub418\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.HC,0,"\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uc5b4 \uc0ac\uc5c5\uc790\uac00 \uc560\ucd08\uc5d0 \uc758\ub3c4\ud588\ub358 \uac83\ubcf4\ub2e4 \ub113\uc740 \ubc94\uc704\uc758 \ucc45\uc784\uc744 \uc9c0\uac8c \ub418\ub294 \uacb0\uacfc\uac00 \ub098\uc624\ub354\ub77c\ub3c4, \uc774\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \ubd88\uba85\ud655\ud558\uac8c \uc870\ud56d\uc744 \uc791\uc131\ud55c \ub370 \ub530\ub978 \uc704\ud5d8\uc744 \ubd80\ub2f4\ud558\ub294 \uac83\uc774\ubbc0\ub85c \uc6d0\uce59\uc801\uc73c\ub85c \uac10\uc218\ud574\uc57c \ud558\ub294 \uacb0\uacfc\ub85c \uc774\ud574\ub41c\ub2e4. \uc774\ub294 \uc0ac\uc5c5\uc790\ub85c \ud558\uc5ec\uae08 \uc57d\uad00\uc744 \ubcf4\ub2e4 \uba85\ud655\ud558\uac8c \uc791\uc131\ud558\ub3c4\ub85d \uc720\uc778\ud558\ub294 \ud6a8\uacfc\ub3c4 \uac16\ub294\ub2e4.",B.YI,B.Mm,null)
B.S4=s([u.z_,"\uba74\ucc45\uc870\ud56d\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ud574\uc57c \ud55c\ub2e4","\uba74\ucc45\uc870\ud56d\uc758 \ubb38\uc5b8\uc740 \ud574\uc11d\ud560 \ud544\uc694 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uac00 \ud1b5\ubcf4\ud558\ub294 \ub300\ub85c \ud655\uc815\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \ubc95\uc6d0\uc740 \uad00\uc5ec\ud560 \uc218 \uc5c6\uace0 \uc0ac\uc5c5\uc790\uac00 \ucd5c\uc885 \uacb0\uc815\ud55c\ub2e4","\uba74\ucc45\uc870\ud56d\uc740 \uace0\uac1d\uc774 \uacc4\uc57d\uc11c\uc5d0 \uc11c\uba85\ud588\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc720\ud6a8\ud558\uac8c \ud655\uc815 \ud574\uc11d\ub41c\ub2e4"],t.s)
