B.ahJ=new A.c("gen_ai_case_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840","\uc57d\uad00 \uc870\ud56d\uc758 \ubb38\uc5b8 \uc790\uccb4\ub294 \uba85\ud655\ud558\uc9c0\ub9cc \uadf8 \ubb38\uc5b8\ub300\ub85c \uc801\uc6a9\ud558\uba74 \uace0\uac1d\uc5d0\uac8c \uc9c0\ub098\uce58\uac8c \uac00\ud639\ud55c \uacb0\uacfc\uac00 \ubc1c\uc0dd\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Lg,0,'\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \ubb38\uc5b8\uc774 \ubd88\uba85\ud655\ud55c \uacbd\uc6b0\uc5d0 \uc801\uc6a9\ub418\ub294 "\ud574\uc11d"\uc758 \ubcf4\ucda9\uc6d0\uce59\uc774\ubbc0\ub85c, \ubb38\uc5b8 \uc790\uccb4\uac00 \uba85\ud655\ud558\ub2e4\uba74 \uc774 \uc6d0\ufffd\uc9c8\uc774 \uac1c\uc785\ud560 \uc5ec\uc9c0\ub294 \uc5c6\ub2e4. \ub2e4\ub9cc \ubb38\uc5b8\uc774 \uba85\ud655\ud558\ub354\ub77c\ub3c4 \uadf8 \ub0b4\uc6a9 \uc790\uccb4\uac00 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud558\ub2e4\uba74, \ubcc4\ub3c4\ub85c \uc81c6\uc870~\uc81c14\uc870\uc758 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\uac00 \uac80\ud1a0\ub420 \uc218 \uc788\uc5b4 \uace0\uac1d\uc774 \uc804\ud600 \uad6c\uc81c\ubc1b\uc9c0 \ubabb\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.',B.a_3,B.abW,null)
B.Kf=s([u.eX,"\ud648\ud398\uc774\uc9c0 \uc548\ub0b4\ubb38\uad6c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc57d\uad00 \ud574\uc11d\uacfc \ubb34\uad00\ud558\ub2e4","\ud648\ud398\uc774\uc9c0 \uc548\ub0b4\ubb38\uad6c\uac00 \uc788\uc73c\uba74 \uc57d\uad00\uc740 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ud648\ud398\uc774\uc9c0 \uc548\ub0b4\ubb38\uad6c\ub294 \ubc18\ub4dc\uc2dc \uc57d\uad00\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc808\ub300\uc801\uc73c\ub85c \uc801\uc6a9\ub41c\ub2e4","\ud648\ud398\uc774\uc9c0 \uc548\ub0b4\ubb38\uad6c\ub294 \uc0ac\uc5c5\uc790\uac00 \uc6d0\ud560 \ub54c\ub9cc \ud6a8\ub825\uc774 \uc788\ub2e4"],t.s)
B.Zd=s([u.eX],t.s)
