B.ahA=new A.c("gen_std_intro_4","economic_law","\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00\uc758 \uc758\uc758\xb7\uc81c\uc815 \uc808\ucc28","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc744 \uad8c\uace0\ud560 \uc218 \uc788\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ic,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc5c5\uc885\ubcc4\ub85c \ud45c\uc900\uc774 \ub420 \uc57d\uad00\uc774 \uc5c6\uac70\ub098, \ubd88\uacf5\uc815\ud55c \ub0b4\uc6a9\uc758 \uc57d\uad00\uc774 \ud1b5\uc6a9\ub418\uace0 \uc788\ub2e4\uace0 \ud310\ub2e8\ub418\ub294 \ub4f1 \ud544\uc694\ud558\ub2e4\uace0 \uc778\uc815\ub418\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub2e8\uccb4 \ub4f1\uc5d0 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uad8c\uace0\ud560 \uc218 \uc788\ub2e4.",B.Ur,B.Lc,null)
