B.am7=new A.c("gen_std_case_1","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\uc5ec\ud589\uc5c5, \uc774\uc0ac\ud654\ubb3c\uc6b4\uc1a1\uc5c5 \ub4f1 \uc77c\uc0c1\uc0dd\ud65c\uacfc \ubc00\uc811\ud55c \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\uc774 \ud65c\uc6a9\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.XH,0,"\uc5ec\ud589\uc5c5, \uc774\uc0ac\ud654\ubb3c\uc6b4\uc1a1\uc5c5 \ub4f1\uacfc \uac19\uc774 \uc18c\ube44\uc790\uc640\uc758 \uac70\ub798\uc5d0\uc11c \ubd84\uc7c1\uc774 \ube48\ubc88\ud558\uac8c \ubc1c\uc0dd\ud558\ub294 \uc5c5\uc885\uc5d0\uc11c\ub294, \ud45c\uc900\uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uc0ac\uc5c5\uc790\ub4e4\uc774 \uc0ac\uc6a9\ud558\ub3c4\ub85d \ud568\uc73c\ub85c\uc368 \uc18c\ube44\uc790 \ud53c\ud574\ub97c \uc608\ubc29\ud558\uace0 \uac70\ub798\uc758 \uacf5\uc815\uc131\uacfc \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub824\ub294 \ubaa9\uc801\uc73c\ub85c \ud45c\uc900\uc57d\uad00\uc774 \ud65c\ubc1c\ud558\uac8c \ud65c\uc6a9\ub41c\ub2e4.",B.a_R,B.HT,null)
B.aby=s([u.fP,"\ud45c\uc900\uc57d\uad00\uc758 \uc190\ud574\ubc30\uc0c1 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud558\uac8c \uc124\uacc4\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \uc190\ud574\ubc30\uc0c1\uc774\ub098 \uc704\uc57d\uae08\uc5d0 \uad00\ud55c \ub0b4\uc6a9\uc744 \uc804\ud600 \ub2e4\ub8e8\uc9c0 \uc54a\ub294\ub2e4","\ud45c\uc900\uc57d\uad00\uc758 \uc704\uc57d\uae08 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud558\ub2e4","\ud45c\uc900\uc57d\uad00\uc758 \uc190\ud574\ubc30\uc0c1 \uc870\ud56d\uc740 \ubc95\ub839\uacfc \ubb34\uad00\ud558\uac8c \uc784\uc758\ub85c \uc815\ud574\uc9c4\ub2e4"],t.s)
B.acF=s([u.fP],t.s)
B.Xe=s(["\ud45c\uc900\uc57d\uad00\uc0c1 \uc190\ud574\ubc30\uc0c1\xb7\uc704\uc57d\uae08 \uc870\ud56d\uc758 \ud2b9\uc9d5"],t.s)
B.arK=new A.c("gen_std_case_2","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud45c\uc900\uc57d\uad00\uc774 \uc815\ud558\ub294 \uc190\ud574\ubc30\uc0c1\uc561\uc774\ub098 \uc704\uc57d\uae08 \uad00\ub828 \uc870\ud56d\uc758 \uc77c\ubc18\uc801 \ud2b9\uc9d5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.aby,0,"\ud45c\uc900\uc57d\uad00\uc740 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8 \ubc95\ub9ac(\uacfc\uc911\ud55c \uc190\ud574\ubc30\uc0c1\uc561 \uc608\uc815 \uae08\uc9c0 \ub4f1)\uc5d0 \uc800\ucd09\ub418\uc9c0 \uc54a\ub3c4\ub85d, \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc758 \uc774\ud574\uad00\uacc4\ub97c \uace0\ub824\ud55c \uade0\ud615 \uc7a1\ud78c \uc190\ud574\ubc30\uc0c1\uc561\xb7\uc704\uc57d\uae08 \uae30\uc900\uc744 \uc81c\uc2dc\ud558\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544, \uc2e4\uc81c \uc57d\uad00 \uc791\uc131 \uc2dc \ucc38\uace0\uc790\ub8cc\ub85c\uc11c \uac00\uce58\ub97c \uac16\ub294\ub2e4.",B.acF,B.Xe,null)
B.a5Q=s([u.qR,"\uac00\ub9f9\ubcf8\ubd80\uac00 \uac00\ub9f9\uc810\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \ud1b5\uc81c\ud558\ub294 \uc218\ub2e8\uc73c\ub85c\ub9cc \ud65c\uc6a9\ub41c\ub2e4","\uac00\ub9f9\uc810\uc774 \uac00\ub9f9\ubcf8\ubd80\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \uc720\ub9ac\ud55c \uc870\uac74\uc744 \uac15\uc81c\ud558\ub294 \uc218\ub2e8\uc774\ub2e4","\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uac00\ub9f9\uc0ac\uc5c5\uc5d0\uc11c \uc544\ubb34\ub7f0 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uc624\uc9c1 \uc2e0\uaddc \ucc3d\uc5c5\uc790\ub9cc\uc744 \ub300\uc0c1\uc73c\ub85c \ud55c\ub2e4"],t.s)
B.ZK=s([u.qR],t.s)
B.M8=s(["\uac00\ub9f9\uc5c5\uc885\uc5d0\uc11c\uc758 \ud45c\uc900\uacc4\uc57d\uc11c \uae30\ub2a5"],t.s)
B.aq6=new A.c("gen_std_case_3","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud504\ub79c\ucc28\uc774\uc988(\uac00\ub9f9) \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\xb7\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\uac00 \uac16\ub294 \uc2e4\ubb34\uc801 \uae30\ub2a5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a5Q,0,"\ud504\ub79c\ucc28\uc774\uc988(\uac00\ub9f9) \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\xb7\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810 \uac04 \uacc4\uc57d \uc870\uac74\uc774 \uc5b4\ub290 \ud55c\ucabd\uc5d0 \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\ub9ac\ud558\uc9c0 \uc54a\ub3c4\ub85d, \uacc4\uc57d \uccb4\uacb0 \uc804\uc5d0 \uacf5\uc815\uc131\uc744 \uc810\uac80\ud560 \uc218 \uc788\ub294 \ucc38\uace0 \ud2c0\uc744 \uc81c\uacf5\ud558\ub294 \uc2e4\ubb34\uc801 \uae30\ub2a5\uc744 \ud55c\ub2e4.",B.ZK,B.M8,null)
B.Iw=s([u.g,"\ud45c\uc900\uc57d\uad00\uc740 \uc18c\uc1a1\uc5d0\uc11c \uc5b4\ub5a0\ud55c \uc99d\uac70\ub85c\ub3c4 \uc0ac\uc6a9\ub420 \uc218 \uc5c6\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \ubc95\uc6d0\uc744 \ud56d\uc0c1 \uc808\ub300\uc801\uc73c\ub85c \uad6c\uc18d\ud558\ub294 \ud310\uacb0\uacfc \ub3d9\uc77c\ud55c \ud6a8\ub825\uc744 \uac16\ub294\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \ubd84\uc7c1\uacfc \uc804\ud600 \ubb34\uad00\ud55c \ud589\uc815 \ub0b4\ubd80\uc790\ub8cc\uc5d0 \ubd88\uacfc\ud558\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \uc624\uc9c1 \ud615\uc0ac\uc7ac\ud310\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub41c\ub2e4"],t.s)
