B.ajL=new A.c("gen_std_case_4","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud45c\uc900\uc57d\uad00\uc774 \uc2e4\uc81c \uc18c\uc1a1\xb7\ubd84\uc7c1\uc5d0\uc11c \ud65c\uc6a9\ub418\ub294 \ubc29\uc2dd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Iw,0,"\ud45c\uc900\uc57d\uad00\uc740 \uadf8 \uc790\uccb4\ub85c \ubc95\uc6d0\uc744 \uc808\ub300\uc801\uc73c\ub85c \uad6c\uc18d\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uc9c0\ub9cc, \uc2e4\uc81c \uc18c\uc1a1\uc774\ub098 \ubd84\uc7c1 \uacfc\uc815\uc5d0\uc11c \ubb38\uc81c\ub41c \uac1c\ubcc4 \uc57d\uad00 \uc870\ud56d\uc774 \ud45c\uc900\uc801\uc778 \uc218\uc900\uc5d0 \ube44\ud574 \uc5bc\ub9c8\ub098 \ubd88\ub9ac\ud55c\uc9c0\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ube44\uad50\xb7\ucc38\uace0 \uc790\ub8cc\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.Hc,B.R8,null)
B.aaP=s([u.cB,"\uc624\uc9c1 \ud45c\uc900\uc57d\uad00\uc744 \uc81c\uc815\ud55c \uacf5\ubb34\uc6d0\uc758 \uac1c\uc778 \uc2e0\uc0c1\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00\uacfc \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ud45c\uc900\uc57d\uad00 \ubb38\uc11c\uc758 \ud398\uc774\uc9c0 \uc218\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
B.NT=s([u.cB],t.s)
B.ba=s(["\uc2dc\ud5d8 \ucd9c\uc81c \uacbd\ud5a5"],t.s)
B.apP=new A.c("gen_std_case_5","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \ud45c\uc900\uc57d\uad00 \uad00\ub828 \ubb38\uc81c\uac00 \uc8fc\ub85c \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.aaP,0,"\ud45c\uc900\uc57d\uad00 \uad00\ub828 \ubb38\uc81c\ub294 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815 \ubc0f \uad8c\uace0 \uc808\ucc28, \uadf8\ub9ac\uace0 \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0 \uc0ac\uc6a9\uc758 \ud6a8\uacfc(\ub2e4\ub974\uac8c \uc815\ud55c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc744 \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc9c0 \uc54a\uc740 \uacbd\uc6b0\uc758 \ucde8\uae09)\ub77c\ub294 \ub450 \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \uac1c\ub150 \uc774\ud574\ub97c \ud655\uc778\ud558\ub294 \ubc29\uc2dd\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.NT,B.ba,null)
B.GU=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ubc94\uc704\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uacac\ubcf8\uc774 \uc81c\uc2dc\ub41c \uacbd\uc6b0 \uadf8 \ubcf4\uc7a5\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d","\ubc95\ub960\uc5d0 \ub530\ub978 \uace0\uac1d\uc758 \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d","\uacc4\uc57d\ud574\uc9c0 \uc2dc \uacc4\uc57d\ub2f9\uc2dc\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d"],t.s)
B.Xp=s(["\uc5b4\ub290 \uc77c\ubc29\uc5d0\uac8c \ud3b8\uc911\ub41c \ubd88\uc774\uc775\uc744 \uc8fc\uc9c0 \uc54a\uace0 \ud615\ud3c9\uc5d0 \ub9de\uac8c \uad8c\ub9ac\xb7\uc758\ubb34\ub97c \ubc30\ubd84\ud55c \uac83"],t.s)
B.a8r=s(["\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720"],t.s)
B.aht=new A.c("gen_al_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubb34\ud6a8\uc778 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.GU,4,'\uc57d\uad00\ubc95\uc774 \ubb34\ud6a8\ub85c \uaddc\uc815\ud558\ub294 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\ub4e4\uc740 \uacf5\ud1b5\uc801\uc73c\ub85c "\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774" \ub610\ub294 "\ubd80\ub2f9\ud558\uac8c" \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uace0 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud558\uac8c \uc791\uc131\ub41c \uc870\ud56d\uc774\ub77c\ub294 \ud2b9\uc9d5\uc744 \uac00\uc9c4\ub2e4(\uc81c6\uc870~\uc81c14\uc870). \uc190\ud574\ubc30\uc0c1\ubc94\uc704 \uc81c\ud55c, \uacac\ubcf8\xb7\ud488\uc9c8 \uad00\ub828 \ucc45\uc784 \ubc30\uc81c, \uace0\uac1d\uc758 \ubc95\uc815 \ud574\uc81c\xb7\ud574\uc9c0\uad8c \uc81c\ud55c, \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ubd80\uacfc \ub4f1\uc740 \ubaa8\ub450 \uace0\uac1d\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \uc804\ud615\uc801 \ubd88\uacf5\uc815\uc870\ud56d\uc774\ub2e4. \ubc18\uba74 \uacc4\uc57d \ud574\uc9c0 \uc2dc "\uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4"\uc5d0\uc11c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d\uc740 \uc5b4\ub290 \uc77c\ubc29\uc5d0\uac8c \ud3b8\uc911\ub41c \ubd88\uc774\uc775\uc744 \uc8fc\uc9c0 \uc54a\uace0 \ud615\ud3c9\uc5d0 \ub9de\uac8c \uad8c\ub9ac\xb7\uc758\ubb34\ub97c \ubc30\ubd84\ud55c \uac83\uc774\ubbc0\ub85c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Xp,B.a8r,null)
B.a5p=s(["\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc5d0 \ubc18\ud558\uc5ec \uacf5\uc815\uc131\uc744 \uc783\uc740 \uc57d\uad00\uc870\ud56d\uc740 \ubb34\ud6a8\ub85c \ud55c\ub2e4","\uc57d\uad00\uc740 \uadf8 \ud615\uc2dd\uacfc \ubb34\uad00\ud558\uac8c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uc57d\uad00\uc758 \ud6a8\ub825 \ud310\ub2e8\uacfc \ubb34\uad00\ud558\ub2e4","\uacf5\uc815\uc131\uc744 \uc783\uc740 \uc57d\uad00\uc774\ub77c\ub3c4 \uc0ac\uc5c5\uc790\uac00 \uc6d0\ud558\uba74 \ud56d\uc0c1 \uc720\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4","\uc77c\ubc18\uc6d0\uce59 \uc870\ud56d\uc740 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc0ac\uc5c5\uc790 \uac04 \uc57d\uad00\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Pj=s(["\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc5d0 \ubc18\ud558\uc5ec \uacf5\uc815\uc131\uc744 \uc783\uc740 \uc57d\uad00\uc870\ud56d\uc740 \ubb34\ud6a8\ub85c \ud55c\ub2e4"],t.s)
B.UX=s(["\uc77c\ubc18\uc6d0\uce59"],t.s)
B.ap_=new A.c("gen_al_general_1","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c6\uc870\uac00 \uc815\ud558\ub294 \uc77c\ubc18\uc6d0\uce59\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a5p,0,"\uc57d\uad00\ubc95 \uc81c6\uc870 \uc81c1\ud56d\uc740 \uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc5d0 \ubc18\ud558\uc5ec \uacf5\uc815\uc131\uc744 \uc783\uc740 \uc57d\uad00\uc870\ud56d\uc740 \ubb34\ud6a8\ub85c \ud55c\ub2e4\ub294 \uc77c\ubc18\uc6d0\uce59\uc744 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uc774\ud6c4 \uc81c7\uc870\ubd80\ud130 \uc81c14\uc870\uae4c\uc9c0 \uc5f4\uac70\ub418\ub294 \uad6c\uccb4\uc801 \ubb34\ud6a8\uc0ac\uc720\ub4e4\uc758 \uae30\ucd08\uac00 \ub418\ub294 \uc6d0\uce59 \uaddc\uc815\uc73c\ub85c, \uc5f4\uac70\ub418\uc9c0 \uc54a\uc740 \uc0c8\ub85c\uc6b4 \uc720\ud615\uc758 \ubd88\uacf5\uc815\uc870\ud56d\ub3c4 \uc774 \uc77c\ubc18\uc6d0\uce59\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\ub294 \uadfc\uac70\uac00 \ub41c\ub2e4.",B.Pj,B.UX,null)
B.a3r=s(["\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uc870\ud56d","\uace0\uac1d\uc774 \uacc4\uc57d\uc758 \uac70\ub798\ud615\ud0dc \ub4f1 \uad00\ub828\ub41c \ubaa8\ub4e0 \uc0ac\uc815\uc5d0 \ube44\ucd94\uc5b4 \uc608\uc0c1\ud558\uae30 \uc5b4\ub824\uc6b4 \uc870\ud56d","\uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uc744 \uc815\ub3c4\ub85c \uacc4\uc57d\uc5d0 \ub530\ub974\ub294 \ubcf8\uc9c8\uc801 \uad8c\ub9ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uacfc \uc0ac\uc5c5\uc790 \uc30d\ubc29\uc758 \uc774\uc775\uc744 \uade0\ud615 \uc788\uac8c \ubc18\uc601\ud55c \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud558\uba74\uc11c \ub3d9\uc2dc\uc5d0 \uc608\uc0c1\ud558\uae30 \uc5b4\ub824\uc6b4 \uc870\ud56d"],t.s)
B.YN=s(["\uace0\uac1d\uacfc \uc0ac\uc5c5\uc790 \uc30d\ubc29\uc758 \uc774\uc775\uc744 \uade0\ud615 \uc788\uac8c \ubc18\uc601\ud55c \uc870\ud56d"],t.s)
B.I0=s(["\ubd88\uacf5\uc815 \ucd94\uc815 \uc0ac\uc720"],t.s)
B.akg=new A.c("gen_al_general_2","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)",'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c6\uc870 \uc81c2\ud56d\uc774 \uc815\ud558\ub294 "\ubd88\uacf5\uc815\ud55c \uac83\uc73c\ub85c \ucd94\uc815"\ub418\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?',B.a3r,3,"\uc57d\uad00\ubc95 \uc81c6\uc870 \uc81c2\ud56d\uc740 \u2460 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uc870\ud56d, \u2461 \uace0\uac1d\uc774 \uac70\ub798\ud615\ud0dc \ub4f1 \uad00\ub828\ub41c \ubaa8\ub4e0 \uc0ac\uc815\uc5d0 \ube44\ucd94\uc5b4 \uc608\uc0c1\ud558\uae30 \uc5b4\ub824\uc6b4 \uc870\ud56d, \u2462 \uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uc744 \uc815\ub3c4\ub85c \ubcf8\uc9c8\uc801 \uad8c\ub9ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc744 \ubd88\uacf5\uc815\ud55c \uac83\uc73c\ub85c \ucd94\uc815\ud55c\ub2e4. \ubc18\ub300\ub85c \uace0\uac1d\uacfc \uc0ac\uc5c5\uc790 \uc30d\ubc29\uc758 \uc774\uc775\uc744 \uade0\ud615 \uc788\uac8c \ubc18\uc601\ud55c \uc870\ud56d\uc740 \uc624\ud788\ub824 \uacf5\uc815\ud55c \uc870\ud56d\uc758 \uc608\uc2dc\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \ubd88\uacf5\uc815 \ucd94\uc815 \uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.YN,B.I0,null)
B.NU=s(["\uc81c7\uc870~\uc81c14\uc870\ub294 \uc77c\ubc18\uc6d0\uce59\uc744 \uad6c\uccb4\ud654\ud558\uc5ec \uc5f4\uac70\ud55c \uac83\uc73c\ub85c, \uc5f4\uac70\ub418\uc9c0 \uc54a\uc740 \uc720\ud615\ub3c4 \uc77c\ubc18\uc6d0\uce59\uc5d0 \ub530\ub77c \ubb34\ud6a8\uac00 \ub420 \uc218 \uc788\ub2e4","\uc81c7\uc870~\uc81c14\uc870\uc5d0 \uc5f4\uac70\ub41c \uc720\ud615\uc774 \uc544\ub2c8\uba74 \uc544\ubb34\ub9ac \ubd88\uacf5\uc815\ud574\ub3c4 \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc77c\ubc18\uc6d0\uce59\uacfc \uac1c\ubcc4 \ubb34\ud6a8\uc870\ud56d\uc740 \uc11c\ub85c \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ub2e4","\uac1c\ubcc4 \ubb34\ud6a8\uc870\ud56d\uc774 \uc788\uc73c\uba74 \uc77c\ubc18\uc6d0\uce59\uc740 \uc801\uc6a9\ub420 \uc5ec\uc9c0\uac00 \uc5c6\ub2e4","\uc77c\ubc18\uc6d0\uce59\uc740 \uac1c\ubcc4 \ubb34\ud6a8\uc870\ud56d\ubcf4\ub2e4 \ud558\uc704\uc758 \ubcf4\ucda9\uc801 \uaddc\uc815\uc5d0 \ubd88\uacfc\ud558\ub2e4"],t.s)
B.HF=s(["\uc5f4\uac70\ub418\uc9c0 \uc54a\uc740 \uc720\ud615\ub3c4 \uc77c\ubc18\uc6d0\uce59\uc5d0 \ub530\ub77c \ubb34\ud6a8\uac00 \ub420 \uc218 \uc788\ub2e4"],t.s)
B.a_m=s(["\uc77c\ubc18\uc6d0\uce59\uacfc \uac1c\ubcc4\uc870\ud56d\uc758 \uad00\uacc4"],t.s)
B.akN=new A.c("gen_al_general_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)","\uc57d\uad00\ubc95\uc0c1 \uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)\uacfc \uac1c\ubcc4 \ubb34\ud6a8\uc870\ud56d(\uc81c7\uc870~\uc81c14\uc870)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.NU,0,"\uc81c7\uc870\ubd80\ud130 \uc81c14\uc870\uae4c\uc9c0\uc758 \uac1c\ubcc4 \ubb34\ud6a8\uc870\ud56d\ub4e4\uc740 \uc81c6\uc870 \uc77c\ubc18\uc6d0\uce59\uc744 \uad6c\uccb4\uc801 \uc720\ud615\ubcc4\ub85c \uc608\uc2dc\xb7\uad6c\uccb4\ud654\ud55c \uac83\uc73c\ub85c \ubcfc \uc218 \uc788\ub2e4. \ub530\ub77c\uc11c \uc774\ub4e4 \uc870\ubb38\uc5d0 \uba85\uc2dc\uc801\uc73c\ub85c \uc5f4\uac70\ub418\uc9c0 \uc54a\uc740 \uc0c8\ub85c\uc6b4 \uc720\ud615\uc758 \uc870\ud56d\uc774\ub77c\ub3c4 \uc2e0\uc758\uc131\uc2e4 \uc6d0\uce59\uc5d0 \ubc18\ud558\uc5ec \uacf5\uc815\uc131\uc744 \uc783\uc5c8\ub2e4\uba74 \uc81c6\uc870 \uc77c\ubc18\uc6d0\uce59\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\uc5b4, \uac1c\ubcc4 \uc870\ud56d\uacfc \uc77c\ubc18\uc6d0\uce59\uc740 \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uc791\ub3d9\ud55c\ub2e4.",B.HF,B.a_m,null)
B.a7u=s(["\uace0\uac1d\uc5d0\uac8c \ubc1c\uc0dd\ud558\ub294 \ubd88\uc774\uc775\uc758 \uc815\ub3c4","\uac70\ub798\ud615\ud0dc \ub4f1 \uad00\ub828\ub41c \ubaa8\ub4e0 \uc0ac\uc815\uc5d0 \ube44\ucd94\uc5b4 \ubcfc \ub54c \uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc744 \uc608\uc0c1\ud560 \uc218 \uc788\uc5c8\ub294\uc9c0 \uc5ec\ubd80","\uacc4\uc57d\uc758 \ubaa9\uc801 \ub2ec\uc131\uc5d0 \ubcf8\uc9c8\uc801\uc778 \uad8c\ub9ac\uac00 \uc5b4\ub290 \uc815\ub3c4 \uc81c\ud55c\ub418\ub294\uc9c0 \uc5ec\ubd80","\uc0ac\uc5c5\uc790\uc758 \uac1c\uc778\uc801 \ucde8\ud5a5\uc774\ub098 \uc120\ud638","\uace0\uac1d\uacfc \uc0ac\uc5c5\uc790 \uc0ac\uc774\uc758 \uc774\uc775\uade0\ud615 \uc5ec\ubd80"],t.s)
B.Jc=s(["\uc0ac\uc5c5\uc790\uc758 \uac1c\uc778\uc801 \ucde8\ud5a5\uc774\ub098 \uc120\ud638"],t.s)
B.Wb=s(["\uacf5\uc815\uc131 \ud310\ub2e8 \uc694\uc18c"],t.s)
B.arQ=new A.c("gen_al_general_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)","\uc57d\uad00\uc870\ud56d\uc758 \uacf5\uc815\uc131 \ud310\ub2e8 \uc2dc \uace0\ub824\ub418\ub294 \uc694\uc18c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.a7u,3,"\uc57d\uad00\uc870\ud56d\uc758 \uacf5\uc815\uc131 \ud310\ub2e8\uc740 \uace0\uac1d\uc5d0\uac8c \ubc1c\uc0dd\ud558\ub294 \ubd88\uc774\uc775\uc758 \uc815\ub3c4, \uc608\uc0c1\uac00\ub2a5\uc131, \ubcf8\uc9c8\uc801 \uad8c\ub9ac\uc758 \uc81c\ud55c \uc815\ub3c4, \ub2f9\uc0ac\uc790 \uac04 \uc774\uc775\uade0\ud615 \ub4f1 \uac1d\uad00\uc801 \uc694\uc18c\ub97c \uc911\uc2ec\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4. \uc0ac\uc5c5\uc790\uc758 \uac1c\uc778\uc801 \ucde8\ud5a5\uc774\ub098 \uc120\ud638\ub294 \uc774\ub7ec\ud55c \uac1d\uad00\uc801 \uacf5\uc815\uc131 \ud310\ub2e8 \uae30\uc900\uacfc \ubb34\uad00\ud558\ub2e4.",B.Jc,B.Wb,null)
B.XB=s(["\uc6d0\uce59\uc801\uc73c\ub85c \ubb34\ud6a8\ub85c \ub41c \ubd80\ubd84\uc744 \uc81c\uc678\ud55c \ub098\uba38\uc9c0 \ubd80\ubd84\ub9cc\uc73c\ub85c \uacc4\uc57d\uc744 \uc720\uc9c0\ud558\ub418, \uc720\uc9c0\uac00 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uacbd\uc6b0 \ub4f1\uc5d0\ub294 \uacc4\uc57d \uc804\uccb4\ub97c \ubb34\ud6a8\ub85c \ud560 \uc218 \uc788\ub2e4","\uc57d\uad00\uc758 \uc77c\ubd80\uac00 \ubb34\ud6a8\uc774\uba74 \ud56d\uc0c1 \uacc4\uc57d \uc804\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uc57d\uad00\uc758 \uc77c\ubd80\uac00 \ubb34\ud6a8\uc774\ub354\ub77c\ub3c4 \uadf8 \ubb34\ud6a8 \ubd80\ubd84\ub9c8\uc800 \uadf8\ub300\ub85c \uc720\ud6a8\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4","\uc77c\ubd80\ubb34\ud6a8 \ubc95\ub9ac\ub294 \uc57d\uad00\uc5d0\ub294 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc77c\ubd80\ubb34\ud6a8 \uc5ec\ubd80\ub294 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc120\ud0dd\uc5d0 \ub2ec\ub824 \uc788\ub2e4"],t.s)
B.a_x=s(["\ubb34\ud6a8\ub85c \ub41c \ubd80\ubd84\uc744 \uc81c\uc678\ud55c \ub098\uba38\uc9c0 \ubd80\ubd84\ub9cc\uc73c\ub85c \uacc4\uc57d\uc744 \uc720\uc9c0\ud558\ub418, \uc720\uc9c0\uac00 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uacbd\uc6b0 \ub4f1\uc5d0\ub294 \uacc4\uc57d \uc804\uccb4\ub97c \ubb34\ud6a8\ub85c \ud560 \uc218 \uc788\ub2e4"],t.s)
B.RF=s(["\uc77c\ubd80\ubb34\ud6a8\uc758 \ud6a8\uacfc"],t.s)
B.aic=new A.c("gen_al_general_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)","\uc57d\uad00\uc870\ud56d \uc911 \uc77c\ubd80\uac00 \ubb34\ud6a8\uc778 \uacbd\uc6b0 \uacc4\uc57d \uc804\uccb4\uc758 \ud6a8\ub825\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.XB,0,"\uc57d\uad00\uc758 \uc77c\ubd80 \uc870\ud56d\uc774 \ubb34\ud6a8\uc778 \uacbd\uc6b0, \uc6d0\uce59\uc801\uc73c\ub85c \ub098\uba38\uc9c0 \ubd80\ubd84\ub9cc\uc73c\ub85c \uc720\ud6a8\ud558\uac8c \uacc4\uc57d\uc774 \uc874\uc18d\ud558\ub294 \uac83\uc73c\ub85c \ubcf4\ub418, \uadf8 \uc720\ud6a8\ud55c \ubd80\ubd84\ub9cc\uc73c\ub85c\ub294 \uacc4\uc57d\uc758 \ubaa9\uc801 \ub2ec\uc131\uc774 \ubd88\uac00\ub2a5\ud558\uac70\ub098 \ud55c \ub2f9\uc0ac\uc790\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uacbd\uc6b0 \ub4f1 \uc608\uc678\uc801\uc778 \uc0ac\uc815\uc774 \uc788\uc73c\uba74 \uacc4\uc57d \uc804\uccb4\ub97c \ubb34\ud6a8\ub85c \ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc77c\ubc18\uc801 \ubc95\ub9ac\uc774\ub2e4.",B.a_x,B.RF,null)
B.a3F=s(["\uc57d\uad00 \ubb34\ud6a8 \ud310\ub2e8\uc740 \uc870\ud56d \ub0b4\uc6a9\uc758 \uac1d\uad00\uc801 \ubd88\uacf5\uc815\uc131\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \uc0ac\uc5c5\uc790\uc758 \uace0\uc758 \uc785\uc99d\uc744 \uc694\uac74\uc73c\ub85c \ud558\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uc758 \uace0\uc758\uac00 \uc785\uc99d\ub418\uc9c0 \uc54a\uc73c\uba74 \uc5b4\ub5a0\ud55c \uc57d\uad00\uc870\ud56d\ub3c4 \ubb34\ud6a8\uac00 \ub420 \uc218 \uc5c6\ub2e4","\ubb34\ud6a8 \ud310\ub2e8\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc8fc\uad00\uc801 \uc758\ub3c4\ub9cc\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\ubb34\ud6a8 \ud310\ub2e8\uc5d0\ub294 \uace0\uac1d\uc758 \ub3d9\uc758 \uc5ec\ubd80\uac00 \uc720\uc77c\ud55c \uae30\uc900\uc774 \ub41c\ub2e4","\ubb34\ud6a8 \ud310\ub2e8\uc740 \uacc4\uc57d \uccb4\uacb0 \uc774\ud6c4\uc758 \uc0ac\uc815\ubcc0\uacbd\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4"],t.s)
B.Uf=s(["\uc870\ud56d \ub0b4\uc6a9\uc758 \uac1d\uad00\uc801 \ubd88\uacf5\uc815\uc131\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \uc0ac\uc5c5\uc790\uc758 \uace0\uc758 \uc785\uc99d\uc744 \uc694\uac74\uc73c\ub85c \ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.a9D=s(["\ubb34\ud6a8\ud310\ub2e8\uc758 \uac1d\uad00\uc801 \uae30\uc900"],t.s)
B.an9=new A.c("gen_al_general_6","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc77c\ubc18\uc6d0\uce59(\uc81c6\uc870)","\uc57d\uad00\uc870\ud56d\uc774 \ubb34\ud6a8\ub85c \ud310\ub2e8\ub418\uae30 \uc704\ud574 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc790\uc758 \uace0\uc758\uac00 \uc785\uc99d\ub418\uc5b4\uc57c \ud558\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a3F,0,"\uc57d\uad00\uc870\ud56d\uc758 \ubb34\ud6a8 \uc5ec\ubd80\ub294 \uadf8 \uc870\ud56d \ub0b4\uc6a9 \uc790\uccb4\uac00 \uc2e0\uc758\uc131\uc2e4 \uc6d0\uce59\uc5d0 \ubc18\ud574 \uacf5\uc815\uc131\uc744 \uc783\uc5c8\ub294\uc9c0\ub97c \uac1d\uad00\uc801\uc73c\ub85c \ud310\ub2e8\ud558\ub294 \uac83\uc774\uba70, \uc0ac\uc5c5\uc790\uc5d0\uac8c \uadf8\ub7ec\ud55c \uc870\ud56d\uc744 \ub123\uc740 \uace0\uc758\uac00 \uc788\uc5c8\ub294\uc9c0\ub97c \ubcc4\ub3c4\ub85c \uc785\uc99d\ud574\uc57c \ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \uc774\ub294 \uc57d\uad00\uc774 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ud68d\uc77c\uc801\uc73c\ub85c \uc801\uc6a9\ub418\ub294 \ud2b9\uc131\uc744 \uace0\ub824\ud574, \uac1d\uad00\uc801 \ub0b4\uc6a9\uc744 \uae30\uc900\uc73c\ub85c \ud1b5\uc81c\ud558\ub824\ub294 \ucde8\uc9c0\uc774\ub2e4.",B.Uf,B.a9D,null)
B.Ug=s(["\uc0ac\uc5c5\uc790, \uc774\ud589\ubcf4\uc870\uc790 \ub610\ub294 \ud53c\uc6a9\uc790\uc758 \uace0\uc758 \ub610\ub294 \uc911\ub300\ud55c \uacfc\uc2e4\ub85c \uc778\ud55c \ubc95\ub960\uc0c1\uc758 \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud558\uc5ec\uc57c \ud560 \uc704\ud5d8\uc744 \uace0\uac1d\uc5d0\uac8c \uc774\uc804\uc2dc\ud0a4\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ubc94\uc704\ub97c \uc81c\ud55c\ud558\uac70\ub098 \uadf8 \ubc30\uc0c1\uc561\uc744 \uc608\uc815\ud558\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \ub2f4\ubcf4\ucc45\uc784\uc744 \ubc30\uc81c \ub610\ub294 \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d"],t.s)
B.Vg=s(["\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d"],t.s)
B.XA=s(["\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0"],t.s)
B.ao5=new A.c("gen_al_exempt_1","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c7\uc870\uac00 \uae08\uc9c0\ud558\ub294 \uba74\ucc45\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Ug,4,'\uc81c7\uc870(\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0)\ub294 \uc0ac\uc5c5\uc790\xb7\uc774\ud589\ubcf4\uc870\uc790\xb7\ud53c\uc6a9\uc790\uc758 \uace0\uc758\xb7\uc911\uacfc\uc2e4 \ucc45\uc784 \ubc30\uc81c, \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uc704\ud5d8 \uc774\uc804, \uc190\ud574\ubc30\uc0c1\ubc94\uc704 \uc81c\ud55c\xb7\uc608\uc815, \ub2f4\ubcf4\ucc45\uc784 \ubc30\uc81c\xb7\uc81c\ud55c \ub4f1 \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud574\uc57c \ud560 \ucc45\uc784\uc744 \ubd80\ub2f9\ud558\uac8c \ud68c\ud53c\ud558\ub294 \uc870\ud56d\uc744 \ubb34\ud6a8\ub85c \ud55c\ub2e4. \ubc18\uba74 "\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc744 \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d"\uc740 \uc0ac\uc5c5\uc790\uc758 \uba74\ucc45\uc774 \uc544\ub2c8\ub77c \uace0\uac1d\uc5d0\uac8c \uacfc\ub3c4\ud55c \ubc30\uc0c1\uc758\ubb34\ub97c \uc9c0\uc6b0\ub294 \uc870\ud56d\uc73c\ub85c, \uc81c8\uc870(\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815)\uac00 \ubcc4\ub3c4\ub85c \uaddc\uc728\ud558\ub294 \uc720\ud615\uc774\ub2e4.',B.Vg,B.XA,null)
B.a0v=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uadf8\ub7ec\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\xb7\uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4","\uacac\ubcf8\uc774\ub098 \ud45c\uc2dc \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc740 \uc560\ucd08\uc5d0 \ubc95\uc801 \ucc45\uc784\uc758 \ub300\uc0c1\uc774 \uc544\ub2c8\ubbc0\ub85c \ubc30\uc81c \uc870\ud56d\uc774 \ud544\uc694 \uc5c6\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \ud56d\uc0c1 \uc720\ud6a8\ud558\uba70 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \uc18c\ube44\uc790\uac00 \uc544\ub2cc \uc0ac\uc5c5\uc790 \uac04 \uac70\ub798\uc5d0\uc11c\ub9cc \ubb34\ud6a8\uc774\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc758 \ud6a8\ub825\uc740 \uacc4\uc57d\uc11c\uc5d0 \uc11c\uba85\uc774 \uc788\uc73c\uba74 \ud56d\uc0c1 \uc720\ud6a8\ub85c \uc804\ud658\ub41c\ub2e4"],t.s)
B.I1=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uadf8\ub7ec\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\xb7\uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4"],t.s)
B.a3A=s(["\uacac\ubcf8\xb7\ud488\uc9c8\ud45c\uc2dc\uc5d0 \ub300\ud55c \ucc45\uc784"],t.s)
B.alL=new A.c("gen_al_exempt_2","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)","\uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uacac\ubcf8\uc744 \uc81c\uc2dc\ud558\uac70\ub098 \ud488\uc9c8\xb7\uc131\ub2a5 \ub4f1\uc5d0 \uad00\ud558\uc5ec \ud45c\uc2dc\ud55c \uacbd\uc6b0, \uadf8 \ubcf4\uc7a5\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\xb7\uc81c\ud55c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a0v,0,"\uc0ac\uc5c5\uc790\uac00 \uacac\ubcf8 \uc81c\uc2dc\ub098 \ud488\uc9c8\xb7\uc131\ub2a5 \ud45c\uc2dc\ub97c \ud1b5\ud574 \uc2e4\uc9c8\uc801\uc73c\ub85c \ubcf4\uc7a5\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ubc30\uc81c\ud558\uac70\ub098 \uc81c\ud55c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uc81c7\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc774\ub2e4. \uc774\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \ub0b4\uc138\uc6b4 \ud45c\uc2dc\xb7\ubcf4\uc7a5\uc744 \uc57d\uad00\uc744 \ud1b5\ud574 \uc0ac\ud6c4\uc801\uc73c\ub85c \ud68c\ud53c\ud558\ub294 \uac83\uc744 \ub9c9\uae30 \uc704\ud55c \uaddc\uc815\uc774\ub2e4.",B.I1,B.a3A,null)
B.Ox=s([u.E6,"\uace0\uac1d\uc774 \uc2a4\uc2a4\ub85c \uc120\ud0dd\ud55c \ubc30\uc1a1 \ubc29\ubc95\uc5d0 \ub530\ub978 \uc704\ud5d8\uc744 \uace0\uac1d\uc774 \ubd80\ub2f4\ud558\ub3c4\ub85d \uba85\ud655\ud788 \uc548\ub0b4\ud558\ub294 \uc870\ud56d","\ucc9c\uc7ac\uc9c0\ubcc0\uc73c\ub85c \uc778\ud55c \ubd88\uac00\ud56d\ub825\uc801 \uc190\ud574\uc5d0 \ub300\ud574 \ub2f9\uc0ac\uc790 \uc30d\ubc29\uc758 \ucc45\uc784\uc744 \ubaa8\ub450 \uba74\uc81c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc758 \uace0\uc758\uc801\uc778 \ubaa9\uc801\ubb3c \uc190\uad34\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \uace0\uac1d\uc5d0\uac8c \ubb3b\ub294 \uc870\ud56d","\uacc4\uc57d \uccb4\uacb0 \uc804 \ucda9\ubd84\ud788 \uc124\uba85\ub418\uace0 \ud611\uc758\ub41c \uc704\ud5d8 \ubd84\ub2f4 \uc870\ud56d"],t.s)
B.acG=s([u.E6],t.s)
B.a5J=s(["\uc704\ud5d8 \uc774\uc804 \uc870\ud56d \uc0ac\ub840"],t.s)
B.ap1=new A.c("gen_al_exempt_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)",'"\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud558\uc5ec\uc57c \ud560 \uc704\ud5d8\uc744 \uace0\uac1d\uc5d0\uac8c \uc774\uc804\uc2dc\ud0a4\ub294 \uc870\ud56d"\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \uc0ac\ub840\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Ox,0,"\uc0ac\uc5c5\uc790\uac00 \ubcf4\uad00\xb7\uad00\ub9ac\ud558\ub294 \ub3d9\uc548 \ubc1c\uc0dd\ud55c \ubaa9\uc801\ubb3c\uc758 \uba78\uc2e4\xb7\ud6fc\uc190\ucc98\ub7fc \ud1b5\uc0c1 \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud574\uc57c \ud560 \uc704\ud5d8\uc744, \ud569\ub9ac\uc801 \uadfc\uac70 \uc5c6\uc774 \uace0\uac1d\uc5d0\uac8c \ub5a0\ub118\uae30\ub294 \uc870\ud56d\uc774 \uc804\ud615\uc801\uc778 \uc704\ud5d8 \uc774\uc804 \uc870\ud56d\uc758 \uc0ac\ub840\uc774\ub2e4. \uace0\uac1d\uc774 \uc120\ud0dd\ud55c \ubc30\uc1a1\ubc29\ubc95\uc5d0 \ub530\ub978 \uc704\ud5d8, \ubd88\uac00\ud56d\ub825 \uba74\ucc45, \uace0\uac1d\uc758 \uace0\uc758\ub85c \uc778\ud55c \uc190\ud574, \ucda9\ubd84\ud788 \ud611\uc758\ub41c \uc870\ud56d \ub4f1\uc740 \uc0c1\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uac70\ub098 \uc560\ucd08\uc5d0 \uc704\ud5d8\uc774\uc804\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0\ub85c \ubcfc \uc218 \uc788\ub2e4.",B.acG,B.a5J,null)
B.a_K=s(["\uace0\uc758\xb7\uc911\uacfc\uc2e4\ub85c \uc778\ud55c \ubc95\ub960\uc0c1 \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d\uc740 \uc81c7\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc774\ub2e4","\uace0\uc758\xb7\uc911\uacfc\uc2e4\uc774\ub77c\ub3c4 \uc0ac\uc5c5\uc790\uac00 \ubbf8\ub9ac \uace0\uc9c0\ud588\ub2e4\uba74 \ubc30\uc81c \uc870\ud56d\uc740 \uc720\ud6a8\ud558\ub2e4","\uace0\uc758\xb7\uc911\uacfc\uc2e4 \uba74\ucc45 \uc870\ud56d\uc740 \uacbd\uacfc\uc2e4 \uba74\ucc45 \uc870\ud56d\ubcf4\ub2e4 \uc624\ud788\ub824 \ub354 \ub113\uac8c \ud5c8\uc6a9\ub41c\ub2e4","\uace0\uc758\xb7\uc911\uacfc\uc2e4 \uba74\ucc45 \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\ud55c \uacbd\uc6b0\uc5d0\ub9cc \ubb34\ud6a8\uc774\ub2e4","\uace0\uc758\xb7\uc911\uacfc\uc2e4 \uba74\ucc45 \uc870\ud56d\uc758 \ud6a8\ub825\uc740 \ubc95\uc6d0\uc758 \uc7ac\ub7c9\uc5d0 \ub530\ub77c \ud56d\uc0c1 \uc720\ud6a8\ub85c \uc778\uc815\ub41c\ub2e4"],t.s)
B.Hu=s(["\uace0\uc758\xb7\uc911\uacfc\uc2e4\ub85c \uc778\ud55c \ubc95\ub960\uc0c1 \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d\uc740 \uc81c7\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc774\ub2e4"],t.s)
B.a9H=s(["\uace0\uc758\xb7\uc911\uacfc\uc2e4 \uba74\ucc45\uc758 \uae08\uc9c0"],t.s)
B.anN=new A.c("gen_al_exempt_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)","\uc0ac\uc5c5\uc790\uc758 \uace0\uc758 \ub610\ub294 \uc911\ub300\ud55c \uacfc\uc2e4\ub85c \uc778\ud55c \uc190\ud574\uc5d0 \ub300\ud574\uc11c\ub3c4 \uadf8 \ucc45\uc784\uc744 \uc644\uc804\ud788 \ubc30\uc81c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc758 \ud6a8\ub825\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_K,0,"\uc0ac\uc5c5\uc790, \uc774\ud589\ubcf4\uc870\uc790 \ub610\ub294 \ud53c\uc6a9\uc790\uc758 \uace0\uc758 \ub610\ub294 \uc911\ub300\ud55c \uacfc\uc2e4\ub85c \uc778\ud55c \ubc95\ub960\uc0c1 \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uc81c7\uc870\uc5d0 \uc758\ud574 \ubb34\ud6a8\uc774\ub2e4. \uc774\ub294 \uac00\uc7a5 \uac15\ud558\uac8c \ubcf4\ud638\ub418\ub294 \uc720\ud615\uc73c\ub85c, \uc0ac\uc804 \uace0\uc9c0 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ubb34\ud6a8\ub85c \ucde8\uae09\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4.",B.Hu,B.a9H,null)
B.UT=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2f4\ubcf4\ucc45\uc784\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4","\ub2f4\ubcf4\ucc45\uc784\uc740 \uc57d\uad00\uc73c\ub85c \uc790\uc720\ub86d\uac8c \uc644\uc804\ud788 \ubc30\uc81c\ud560 \uc218 \uc788\ub294 \uc784\uc758\uaddc\uc815 \uc0ac\ud56d\uc774\ubbc0\ub85c \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\ub2f4\ubcf4\ucc45\uc784 \ubc30\uc81c \uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud55c \uc870\ud56d\uc73c\ub85c \ucde8\uae09\ub418\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\ub2f4\ubcf4\ucc45\uc784 \ubc30\uc81c\ub294 \uc624\uc9c1 \ubd80\ub3d9\uc0b0 \uac70\ub798\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uac1c\ub150\uc774\ub2e4","\ub2f4\ubcf4\ucc45\uc784 \ubc30\uc81c \uc870\ud56d\uc740 \ubc95\uc6d0\uc758 \uc2ec\uc0ac \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.aaf=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2f4\ubcf4\ucc45\uc784\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4"],t.s)
B.a8J=s(["\ub2f4\ubcf4\ucc45\uc784 \ubc30\uc81c\xb7\uc81c\ud55c \uae08\uc9c0"],t.s)
B.ao_=new A.c("gen_al_exempt_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)","\uc0ac\uc5c5\uc790\uc758 \ub2f4\ubcf4\ucc45\uc784\uc744 \ubc30\uc81c\xb7\uc81c\ud55c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.UT,0,"\ubbfc\ubc95 \ub4f1\uc5d0\uc11c \uc778\uc815\ub418\ub294 \uc0ac\uc5c5\uc790(\ub9e4\ub3c4\uc778 \ub4f1)\uc758 \ub2f4\ubcf4\ucc45\uc784\uc744 \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc57d\uad00\uc744 \ud1b5\ud574 \ubc30\uc81c\ud558\uac70\ub098 \uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud558\ubbc0\ub85c \uc81c7\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4. \ub2f4\ubcf4\ucc45\uc784 \uad00\ub828 \uaddc\uc815\uc774 \uc784\uc758\uaddc\uc815\uc801 \uc131\uaca9\uc744 \uac16\ub354\ub77c\ub3c4, \uc57d\uad00\uc744 \ud1b5\ud55c \uc77c\ubc29\uc801 \ubc30\uc81c\ub294 \ubcc4\ub3c4\ub85c \ud1b5\uc81c\ub41c\ub2e4.",B.aaf,B.a8J,null)
B.a6X=s(["\uc81c7\uc870\ub294 \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784\uc744 \ubd80\ub2f9\ud558\uac8c \ubc30\uc81c\xb7\uc81c\ud55c\xb7\uc774\uc804\ud558\ub294 \uc870\ud56d\uc744, \uc81c8\uc870\ub294 \uace0\uac1d\uc5d0\uac8c \uacfc\uc911\ud55c \ubc30\uc0c1\uc758\ubb34\ub97c \uc9c0\uc6b0\ub294 \uc870\ud56d\uc744 \uac01\uac01 \uaddc\uc728\ud558\ub294 \uac83\uc73c\ub85c \uad6c\ubd84\ub41c\ub2e4","\uc81c7\uc870\uc640 \uc81c8\uc870\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uc911\ubcf5 \uaddc\uc815\ud55c \uac83\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc81c7\uc870\ub294 \uace0\uac1d\uc744 \uaddc\uc728\ud558\uace0 \uc81c8\uc870\ub294 \uc0ac\uc5c5\uc790\ub9cc\uc744 \uaddc\uc728\ud55c\ub2e4","\uc81c7\uc870\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \uc81c8\uc870\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc81c7\uc870\uc640 \uc81c8\uc870 \uc911 \ud558\ub098\ub9cc \uc704\ubc18\ud574\ub3c4 \ub2e4\ub978 \ud558\ub098\ub294 \uc790\ub3d9\uc73c\ub85c \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.MQ=s(["\uc81c7\uc870\ub294 \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784\uc744 \ubd80\ub2f9\ud558\uac8c \ubc30\uc81c\xb7\uc81c\ud55c\xb7\uc774\uc804\ud558\ub294 \uc870\ud56d\uc744, \uc81c8\uc870\ub294 \uace0\uac1d\uc5d0\uac8c \uacfc\uc911\ud55c \ubc30\uc0c1\uc758\ubb34\ub97c \uc9c0\uc6b0\ub294 \uc870\ud56d\uc744 \uac01\uac01 \uaddc\uc728"],t.s)
B.ZR=s(["\uc81c7\uc870\uc640 \uc81c8\uc870\uc758 \uad6c\ubd84"],t.s)
B.amT=new A.c("gen_al_exempt_6","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)","\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0(\uc81c7\uc870)\uc640 \uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815(\uc81c8\uc870)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a6X,0,"\uc81c7\uc870(\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0)\ub294 \uc0ac\uc5c5\uc790 \uce21\uc758 \ucc45\uc784\uc744 \ubd80\ub2f9\ud558\uac8c \ubc30\uc81c\xb7\uc81c\ud55c\ud558\uac70\ub098 \uc704\ud5d8\uc744 \uace0\uac1d\uc5d0\uac8c \uc774\uc804\uc2dc\ud0a4\ub294 \uc870\ud56d\uc744 \uaddc\uc728\ud558\ub294 \ubc18\uba74, \uc81c8\uc870(\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815)\ub294 \ubc18\ub300\ub85c \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc190\ud574\ubc30\uc0c1\uc758\ubb34(\uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1)\ub97c \uc9c0\uc6b0\ub294 \uc870\ud56d\uc744 \uaddc\uc728\ud55c\ub2e4. \ub450 \uc870\ubb38\uc740 \uc11c\ub85c \ub2e4\ub978 \ubc29\ud5a5\uc758 \ubd88\uacf5\uc815\uc131\uc744 \uaddc\uc81c\ud558\ub294 \uac83\uc73c\ub85c, \uc0ac\uc548\uc5d0 \ub530\ub77c \ud568\uaed8 \ubb38\uc81c\ub420 \uc218\ub3c4 \uc788\ub2e4.",B.MQ,B.ZR,null)
B.Oo=s([u.xy,"\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815 \uc870\ud56d\uc740 \uadf8 \uae08\uc561\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc190\ud574\ubc30\uc0c1\uc561 \uc608\uc815\uc740 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c\ub9cc \uc815\ud574\uc838\uc57c \ud55c\ub2e4","\uc190\ud574\ubc30\uc0c1\uc561 \uc608\uc815 \uc870\ud56d\uc740 \uace0\uac1d\uc774 \uc11c\uba85\ub9cc \ud558\uba74 \uae08\uc561\uacfc \ubb34\uad00\ud558\uac8c \uc720\ud6a8\ud558\ub2e4","\uc774 \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc5d0\ub294 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.HG=s([u.xy],t.s)
B.a5Y=s(["\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815"],t.s)
B.arj=new A.c("gen_al_damages_1","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c8\uc870(\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815)\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Oo,0,"\uc81c8\uc870\ub294 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc57d\uad00\uc870\ud56d\uc744 \ubb34\ud6a8\ub85c \ud55c\ub2e4. \uc190\ud574\ubc30\uc0c1\uc561\uc744 \uc608\uc815\ud558\ub294 \uc870\ud56d \uc790\uccb4\uac00 \uae08\uc9c0\ub418\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uadf8 \uc561\uc218\uac00 \uc2e4\uc81c \uc190\ud574\uc5d0 \ube44\ucd94\uc5b4 \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uacbd\uc6b0\uc5d0 \ud1b5\uc81c\ub41c\ub2e4\ub294 \uc810\uc774 \ud575\uc2ec\uc774\ub2e4.",B.HG,B.a5Y,null)
B.PL=s([u.lo,"\uacc4\uc57d \uccb4\uacb0 \uc2dc \ud569\uc758\ub41c \uae09\ubd80 \ub0b4\uc6a9\uc744 \uba85\ud655\ud788 \uae30\uc7ac\ud558\ub294 \uc870\ud56d","\ucc9c\uc7ac\uc9c0\ubcc0 \ub4f1 \ubd88\uac00\ud56d\ub825 \uc0ac\uc720\ub85c \uc778\ud55c \uc774\ud589\uc9c0\uccb4\uc5d0 \ub300\ud574 \uc30d\ubc29\uc758 \ucc45\uc784\uc744 \ud569\ub9ac\uc801\uc73c\ub85c \uc870\uc815\ud558\ub294 \uc870\ud56d","\uc774\ud589\uae30\uc77c\uc744 \uba85\ud655\ud558\uac8c \ud2b9\uc815\ud558\uc5ec \uae30\uc7ac\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc774 \uc694\uccad\ud560 \uacbd\uc6b0 \uc774\ud589 \uc77c\uc815\uc744 \ud611\uc758\ud558\uc5ec \uc870\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d"],t.s)
B.abQ=s([u.lo],t.s)
B.a9C=s(["\ucc44\ubb34\uc758 \uc774\ud589"],t.s)
B.aog=new A.c("gen_al_damages_2","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c10\uc870(\ucc44\ubb34\uc758 \uc774\ud589)\uac00 \uae08\uc9c0\ud558\ub294 \uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740?",B.PL,0,"\uc81c10\uc870\ub294 \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uae09\ubd80(\uc81c\uacf5\ud560 \uc0c1\ud488\xb7\uc11c\ube44\uc2a4)\uc758 \ub0b4\uc6a9\uc744 \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \uacb0\uc815\ud558\uac70\ub098 \ubcc0\uacbd\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d, \ub610\ub294 \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \uc774\ud589 \uc2dc\uae30\ub97c \uc9c0\uc5f0\ud558\uac70\ub098 \uc774\ud589\uc744 \ubd80\ub2f9\ud558\uac8c \uc5f0\uae30\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d \ub4f1\uc744 \uaddc\uc81c\ud55c\ub2e4. \uae09\ubd80\ub0b4\uc6a9\uc744 \uba85\ud655\ud788 \uae30\uc7ac\ud558\uac70\ub098 \ud569\ub9ac\uc801\uc73c\ub85c \ud611\uc758\xb7\uc870\uc815\ud558\ub294 \uc870\ud56d\uc740 \uc624\ud788\ub824 \uacf5\uc815\ud55c \uc870\ud56d\uc73c\ub85c \ubcfc \uc218 \uc788\ub2e4.",B.abQ,B.a9C,null)
B.Or=s([u.hq,"\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\uc758 \ud3b8\uc758\ub97c \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ud56d\uc0c1 \ud5c8\uc6a9\ub41c\ub2e4","\uc774\ud589 \uc9c0\uc5f0\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc774\ud589 \uc2dc\uae30\uc5d0 \uad00\ud55c \uc870\ud56d\uc740 \uc5b8\uc81c\ub098 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\ubbc0\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc77c \ubfd0 \ubb34\ud6a8 \uc5ec\ubd80\uc640\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
B.Rc=s([u.hq],t.s)
B.SZ=s(["\uc774\ud589\uc9c0\uc5f0 \uc870\ud56d\uc758 \ud1b5\uc81c"],t.s)
B.anG=new A.c("gen_al_damages_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uac00 \uc774\ud589 \uc2dc\uae30\ub97c \uc9c0\uc5f0\ud558\uac70\ub098 \uc774\ud589\uc744 \ubd80\ub2f9\ud558\uac8c \uc5f0\uae30\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Or,0,"\uc0ac\uc5c5\uc790\uac00 \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc774\ud589 \uc2dc\uae30\ub97c \uc9c0\uc5f0\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uc5f0\uae30\ud560 \uc218 \uc788\uac8c \ud558\ub294 \uc870\ud56d\uc740 \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \uc774\ud589\uccad\uad6c\uad8c\uacfc \uacc4\uc57d\uc0c1 \uae30\ub300\ub97c \uc0ac\uc2e4\uc0c1 \ubb34\ub825\ud654\uc2dc\ud0ac \uc218 \uc788\uc5b4, \uc81c10\uc870\uac00 \uc815\ud558\ub294 \ubd88\uacf5\uc815 \uc870\ud56d\uc73c\ub85c \ubb34\ud6a8 \ud310\ub2e8\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.Rc,B.SZ,null)
B.Ky=s([u.b,"\uc704\uc57d\ubc8c\uc774\ub098 \uc9c0\uc5f0\uc190\ud574\uae08\uc740 \uadf8 \uc561\uc218\uc640 \ubb34\uad00\ud558\uac8c \uacc4\uc57d\uc790\uc720\uc758 \uc6d0\ufffd\uc81c \ud558\uc5d0 \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc704\uc57d\ubc8c\xb7\uc9c0\uc5f0\uc190\ud574\uae08 \uc870\ud56d\uc740 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc5d0\uc11c \uba85\uc2dc\uc801\uc73c\ub85c \uc81c\uc678\ub41c\ub2e4","\uc704\uc57d\ubc8c \uc870\ud56d\uc740 \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc774\ubbc0\ub85c \uc57d\uad00\ubc95\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\uc9c0\uc5f0\uc190\ud574\uae08\uc740 \uc2e4\uc81c \uc190\ud574\uc561\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.L4=s([u.b],t.s)
B.Pv=s(["\uacfc\ub2e4\ud55c \uc704\uc57d\ubc8c\xb7\uc9c0\uc5f0\uc190\ud574\uae08"],t.s)
B.anH=new A.c("gen_al_damages_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc2e4\uc81c \uc190\ud574\uc561\uc5d0 \ube44\ud574 \ud604\uc800\ud788 \uacfc\ub2e4\ud55c \uc704\uc57d\ubc8c \ub610\ub294 \uc9c0\uc5f0\uc190\ud574\uae08\uc744 \uc815\ud55c \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Ky,0,"\uc2e4\uc81c \ubc1c\uc0dd \uac00\ub2a5\ud55c \uc190\ud574\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uacfc\ub2e4\ud55c \uc704\uc57d\ubc8c\uc774\ub098 \uc9c0\uc5f0\uc190\ud574\uae08\uc744 \uc815\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \ubc30\uc0c1\uc758\ubb34\ub97c \uc9c0\uc6b0\ub294 \uac83\uc73c\ub85c \ud3c9\uac00\ub418\uc5b4 \uc81c8\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uac00 \ub420 \uc218 \uc788\ub2e4. \uacc4\uc57d\uc790\uc720\uc758 \uc6d0\uce59\uc774 \uc788\ub354\ub77c\ub3c4 \uc57d\uad00\uc744 \ud1b5\ud55c \uc77c\ubc29\uc801\xb7\uc815\ud615\uc801 \uc870\ud56d\uc5d0 \ub300\ud574\uc11c\ub294 \uc774\ub7ec\ud55c \ub0b4\uc6a9\ud1b5\uc81c\uac00 \uc774\ub8e8\uc5b4\uc9c4\ub2e4.",B.L4,B.Pv,null)
B.a8n=s([u.l9,"\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ud3b8\uc758\ub9cc\uc744 \uadf9\ub300\ud654\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uace0\uac1d\uc758 \uacc4\uc57d \ud574\uc9c0\uad8c\uc744 \uc644\uc804\ud788 \ubc15\ud0c8\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc774\ud589\ud558\uc9c0 \uc54a\uc744 \uad8c\ub9ac\ub97c \uc804\uba74 \ubcf4\uc7a5\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uace0\uac1d\uc758 \uc694\uccad\uc744 \ud56d\uc0c1 \ubb34\uc2dc\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uae30 \uc704\ud568\uc774\ub2e4"],t.s)
B.Uh=s([u.l9],t.s)
B.Xk=s(["\ucc44\ubb34\uc774\ud589 \uc870\ud56d \uaddc\uc81c \ucde8\uc9c0"],t.s)
B.am0=new A.c("gen_al_damages_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc57d\uad00\ubc95 \uc81c10\uc870\uac00 \ucc44\ubb34 \uc774\ud589 \uad00\ub828 \uc870\ud56d\uc744 \uaddc\uc81c\ud558\ub294 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a8n,0,"\uc81c10\uc870\ub294 \uc0ac\uc5c5\uc790\uac00 \uae09\ubd80\ub0b4\uc6a9\uc774\ub098 \uc774\ud589\uc2dc\uae30\ub97c \uc77c\ubc29\uc801\uc73c\ub85c \uacb0\uc815\xb7\ubcc0\uacbd\xb7\uc9c0\uc5f0\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d\uc744 \ud1b5\uc81c\ud568\uc73c\ub85c\uc368, \uace0\uac1d\uc774 \uacc4\uc57d\uc744 \ud1b5\ud574 \uc815\ub2f9\ud558\uac8c \uae30\ub300\ud560 \uc218 \uc788\ub294 \uae09\ubd80\uc640 \uc774\ud589\uc2dc\uae30\uc5d0 \ub300\ud55c \uc9c0\uc704\uac00 \uc0ac\uc5c5\uc790\uc758 \uc77c\ubc29\uc801 \uc758\uc0ac\uc5d0 \ub530\ub77c \ud615\ud574\ud654\ub418\uc9c0 \uc54a\ub3c4\ub85d \ubcf4\ud638\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4.",B.Uh,B.Xk,null)
B.Yr=s(["\uc190\ud574\ubc30\uc0c1\uc561\uc744 \uc608\uc815\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uadf8 \uc790\uccb4\ub85c \uc5b8\uc81c\ub098 \uc804\ubd80 \ubb34\ud6a8\uc774\ub2e4","\uacfc\uc911\ud55c \ubc30\uc0c1\uc758\ubb34\ub97c \uc9c0\uc6b0\ub294 \ubd80\ubd84\uc5d0 \ud55c\ud574 \ubb34\ud6a8\ub85c \ud310\ub2e8\ub420 \uc218 \uc788\ub2e4",'\ubb34\ud6a8\ub85c \ud310\ub2e8\ub418\ub294 \uae30\uc900\uc740 \uace0\uac1d\uc5d0\uac8c "\ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c\uc9c0" \uc5ec\ubd80\uc774\ub2e4',"\uc9c0\uc5f0\uc190\ud574\uae08\ubfd0 \uc544\ub2c8\ub77c \uc774\uc640 \uc720\uc0ac\ud55c \uc190\ud574\ubc30\uc0c1 \uc608\uc815 \uc870\ud56d\ub3c4 \uaddc\uc728 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\uc774 \uc870\ud56d\uc758 \ucde8\uc9c0\ub294 \uace0\uac1d \ubcf4\ud638\uc5d0 \uc788\ub2e4"],t.s)
B.acl=s(["\uc190\ud574\ubc30\uc0c1\uc561\uc744 \uc608\uc815\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uadf8 \uc790\uccb4\ub85c \uc5b8\uc81c\ub098 \uc804\ubd80 \ubb34\ud6a8\uc774\ub2e4"],t.s)
B.Z0=s(["\uc190\ud574\ubc30\uc0c1\uc561 \uc608\uc815 \uc870\ud56d\uc758 \ud6a8\ub825"],t.s)
B.alh=new A.c("gen_al_damages_6","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815\xb7\ucc44\ubb34\uc758 \uc774\ud589","\uc190\ud574\ubc30\uc0c1\uc561\uc758 \uc608\uc815(\uc81c8\uc870)\uc5d0 \uad00\ud55c \ub2e4\uc74c \uc124\uba85 \uc911 \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Yr,0,'\uc190\ud574\ubc30\uc0c1\uc561\uc744 \uc608\uc815\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc774 \uc874\uc7ac\ud55c\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uadf8 \uc870\ud56d\uc774 \ub2f9\uc5f0\ud788 \uc804\ubd80 \ubb34\ud6a8\uac00 \ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \uadf8 \uc608\uc815\ub41c \ubc30\uc0c1\uc561\uc774 \uace0\uac1d\uc5d0\uac8c "\ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c" \uacbd\uc6b0\uc5d0 \ud55c\ud558\uc5ec \ubb34\ud6a8\ub85c \ud310\ub2e8\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \uc774\ub294 \uc9c0\uc5f0\uc190\ud574\uae08\ubfd0 \uc544\ub2c8\ub77c \uc720\uc0ac\ud55c \uc190\ud574\ubc30\uc0c1 \uc608\uc815 \uc870\ud56d \uc804\ubc18\uc5d0 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4.',B.acl,B.Z0,null)
B.Ui=s(["\ubc95\ub960\uc5d0 \ub530\ub978 \uace0\uac1d\uc758 \ud574\uc81c\uad8c \ub610\ub294 \ud574\uc9c0\uad8c\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uc0ac\uc5c5\uc790\uc5d0\uac8c \ubc95\ub960\uc5d0 \uaddc\uc815\uc774 \uc5c6\ub294 \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \ubd80\uc5ec\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\uc774\uc775\uc744 \uc904 \uc6b0\ub824\uac00 \uc788\ub294 \uc870\ud56d","\uacc4\uc57d\uc774 \ud574\uc81c\xb7\ud574\uc9c0\ub41c \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub098 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f9\ud558\uac8c \uacbd\uac10\ud558\ub294 \uc870\ud56d","\uacc4\uc57d \ud574\uc81c\ub85c \uc778\ud55c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\uc758 \ubc94\uc704\ub97c \ubd80\ub2f9\ud558\uac8c \ud655\uc7a5\ud558\uac70\ub098 \uace0\uac1d\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub9cc\uc744 \uac00\uc911\ud558\ub294 \uc870\ud56d",u.uY],t.s)
B.Xs=s([u.uY],t.s)
B.ZI=s(["\uacc4\uc57d \ud574\uc81c\xb7\ud574\uc9c0 \ubb34\ud6a8\uc0ac\uc720"],t.s)
B.amk=new A.c("gen_al_termination_1","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c9\uc870\uac00 \uc815\ud558\ub294 \uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0 \uad00\ub828 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Ui,4,"\uc81c9\uc870\ub294 \uace0\uac1d\uc758 \ubc95\uc815 \ud574\uc81c\xb7\ud574\uc9c0\uad8c \ubc30\uc81c\xb7\uc81c\ud55c, \uc0ac\uc5c5\uc790\uc5d0\uac8c \ubc95\ub960\uc5d0 \uc5c6\ub294 \ud574\uc81c\xb7\ud574\uc9c0\uad8c \ubd80\uc5ec, \ud574\uc81c\xb7\ud574\uc9c0 \uc2dc \uc0ac\uc5c5\uc790 \ucc45\uc784\uc758 \ubd80\ub2f9\ud55c \uacbd\uac10\uc774\ub098 \uace0\uac1d \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\uc758 \ubd80\ub2f9\ud55c \uac00\uc911 \ub4f1\uc744 \ubb34\ud6a8\uc0ac\uc720\ub85c \uaddc\uc815\ud55c\ub2e4. \ubc18\uba74 \ub2f9\uc0ac\uc790\uac00 \uc0ac\uc804\uc5d0 \ud569\uc758\ud55c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \ud574\uc9c0 \uc808\ucc28\ub97c \uba85\ud655\ud788 \uc815\ud558\ub294 \uc870\ud56d\uc740 \uc624\ud788\ub824 \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub294 \uacf5\uc815\ud55c \uc870\ud56d\uc5d0 \ud574\ub2f9\ud55c\ub2e4.",B.Xs,B.ZI,null)
B.Z8=s([u.oe,"\uacc4\uc18d\uc801 \uacc4\uc57d\uc758 \uc874\uc18d\uae30\uac04\uc740 \uc0ac\uc5c5\uc790\uac00 \uc6d0\ud558\ub294 \ub300\ub85c \ubb34\uc81c\ud55c \uc815\ud560 \uc218 \uc788\ub2e4","\ud574\uc9c0\ud1b5\uace0\uae30\uac04\uc740 \uc9e7\uc744\uc218\ub85d \ud56d\uc0c1 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\ubbc0\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb35\uc2dc\uc801 \uac31\uc2e0 \uc870\ud56d\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc874\uc18d\uae30\uac04\uc5d0 \uad00\ud55c \uc870\ud56d\uc740 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4"],t.s)
B.KO=s([u.oe],t.s)
B.a5e=s(["\uacc4\uc18d\uc801 \uacc4\uc57d\uc758 \uc874\uc18d\uae30\uac04\xb7\uac31\uc2e0"],t.s)
B.apC=new A.c("gen_al_termination_2","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\uacc4\uc18d\uc801 \ucc44\uad8c\uad00\uacc4\uc758 \ubc1c\uc0dd\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \uacc4\uc57d\uc5d0\uc11c, \uc874\uc18d\uae30\uac04\uc774\ub098 \uac31\uc2e0\xb7\ud574\uc9c0\ud1b5\uace0\uae30\uac04\uc5d0 \uad00\ud55c \uc57d\uad00\uc870\ud56d\uc758 \ud1b5\uc81c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Z8,0,"\uc81c9\uc870\ub294 \uacc4\uc18d\uc801 \ucc44\uad8c\uad00\uacc4 \ubc1c\uc0dd\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \uacc4\uc57d\uc5d0\uc11c \uc874\uc18d\uae30\uac04\uc744 \ubd80\ub2f9\ud558\uac8c \ub2e8\uae30 \ub610\ub294 \uc7a5\uae30\ub85c \uc815\ud558\uac70\ub098, \ubb35\uc2dc\uc801 \uac31\uc2e0 \uc870\uac74\xb7\ud574\uc9c0\ud1b5\uace0\uae30\uac04\uc744 \ubd80\ub2f9\ud558\uac8c \uc9e7\uac8c \uc815\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \ubd88\uc774\uc775\uc744 \uc904 \uc6b0\ub824\uac00 \uc788\ub294 \uc870\ud56d\uc744 \ubb34\ud6a8\uc0ac\uc720\ub85c \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uace0\uac1d\uc774 \uacc4\uc57d\uad00\uacc4\uc5d0\uc11c \uc608\uce21\ud558\uc9c0 \ubabb\ud55c \ucc44 \uc7a5\uae30\uac04 \uad6c\uc18d\ub418\uac70\ub098 \ubd88\ub9ac\ud55c \uac31\uc2e0\uc744 \uac15\uc694\ubc1b\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud568\uc774\ub2e4.",B.KO,B.a5e,null)
B.ab9=s(["\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc81c9\uc870\uac00 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4","\uc0ac\uc5c5\uc790\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\ub4e0 \ubc95\ub960\uc5d0 \uc5c6\ub294 \ud574\uc9c0\uad8c\uc744 \uc57d\uad00\uc73c\ub85c \uc790\uc720\ub86d\uac8c \ucc3d\uc124\ud560 \uc218 \uc788\uace0 \uc774\ub294 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \uace0\uac1d\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ud574\uc9c0\uad8c\uc758 \ud589\uc0ac\uc694\uac74 \uc644\ud654\ub294 \ud56d\uc0c1 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud55c \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uc774 \uc870\ud56d\uc740 \uc81c7\uc870(\uba74\ucc45\uc870\ud56d\uc758 \uae08\uc9c0)\uc5d0\uc11c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c0\uace0 \uc81c9\uc870\uc640\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
B.a1K=s(["\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc81c9\uc870\uac00 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4"],t.s)
B.a80=s(["\uc0ac\uc5c5\uc790 \ud574\uc9c0\uad8c \ub0a8\uc6a9 \ud1b5\uc81c"],t.s)
B.amQ=new A.c("gen_al_termination_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\uc0ac\uc5c5\uc790\uc5d0\uac8c \ubc95\ub960\uc5d0 \uaddc\uc815\ub418\uc9c0 \uc54a\uc740 \uc784\uc758\uc758 \ud574\uc9c0\uad8c\uc744 \ubd80\uc5ec\ud558\uba74\uc11c, \uadf8 \ud589\uc0ac\uc694\uac74\uc744 \uc644\ud654\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \ubd88\uc774\uc775\uc744 \uc904 \uc6b0\ub824\uac00 \uc788\ub294 \uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.ab9,0,"\ubc95\ub960\uc5d0 \uaddc\uc815\uc774 \uc5c6\ub294 \ud574\uc81c\xb7\ud574\uc9c0\uad8c\uc744 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd80\uc5ec\ud558\uac70\ub098, \ubc95\ub960\uc0c1 \uc815\ud574\uc9c4 \ud574\uc9c0\uad8c \ud589\uc0ac\uc694\uac74\ubcf4\ub2e4 \uc644\ud654\ub41c \uc694\uac74\uc73c\ub85c \uc0ac\uc5c5\uc790\uac00 \ud574\uc9c0\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\uc774\uc775\uc744 \uc904 \uc6b0\ub824\uac00 \uc788\ub294 \uc870\ud56d\uc740 \uc81c9\uc870\uac00 \uc815\ud558\ub294 \ub300\ud45c\uc801 \ubb34\ud6a8\uc0ac\uc720 \uc911 \ud558\ub098\uc774\ub2e4.",B.a1K,B.a80,null)
B.UQ=s([u.Ce,"\ud574\uc81c \uc2dc \ub2f9\uc0ac\uc790 \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d","\ud574\uc81c\uc758 \ud6a8\uacfc\ub97c \ubc95\ub960\uc5d0\uc11c \uc815\ud55c \ub300\ub85c \uba85\ud655\ud788 \uc548\ub0b4\ud558\ub294 \uc870\ud56d","\ud574\uc81c \uc0ac\uc720\ub97c \uc0ac\uc804\uc5d0 \uad6c\uccb4\uc801\uc73c\ub85c \uc5f4\uac70\ud558\uc5ec \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub294 \uc870\ud56d","\ud574\uc81c \uc808\ucc28\uc5d0 \uad00\ud55c \uc11c\uba74 \ud1b5\uc9c0 \ubc29\ubc95\uc744 \uba85\uc2dc\ud558\ub294 \uc870\ud56d"],t.s)
B.KV=s([u.Ce],t.s)
B.On=s(["\uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\uc758 \ubd80\ub2f9\ud55c \uac00\uc911"],t.s)
B.akV=new A.c("gen_al_termination_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\uacc4\uc57d \ud574\uc81c\xb7\ud574\uc9c0 \uc2dc \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\uc5d0 \uad00\ud55c \uc57d\uad00\uc870\ud56d \uc911 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740?",B.UQ,0,"\uacc4\uc57d \ud574\uc81c\ub85c \uc778\ud55c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\uc758 \ubc94\uc704\ub97c \ubd80\ub2f9\ud558\uac8c \ud655\uc7a5\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c\ub9cc \uac00\uc911\uc2dc\ud0a4\ub294 \uc870\ud56d\uc740 \uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ubc18\uba74 \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \uade0\ud615\uc788\uac8c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \ubd80\uc5ec\ud558\uac70\ub098, \ud574\uc81c \ud6a8\uacfc\xb7\uc0ac\uc720\xb7\uc808\ucc28\ub97c \uba85\ud655\ud788 \uc548\ub0b4\ud558\ub294 \uc870\ud56d\uc740 \uc608\uce21\uac00\ub2a5\uc131\uacfc \ud615\ud3c9\uc131\uc744 \ub192\uc774\ub294 \uac83\uc73c\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.KV,B.On,null)
B.R4=s(["\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \ubc95\uc801 \uad8c\ub9ac\ub97c \uc57d\uad00\uc744 \ud1b5\ud574 \uc0ac\uc2e4\uc0c1 \ubc15\ud0c8\ud558\ub294 \uac83\uc774\uc5b4\uc11c \uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4","\uace0\uac1d\uc758 \ud574\uc81c\xb7\ud574\uc9c0\uad8c\uc740 \uc57d\uad00\uc744 \ud1b5\ud574 \uc0ac\uc5c5\uc790\uac00 \uc790\uc720\ub86d\uac8c \uc81c\ud55c\ud560 \uc218 \uc788\ub294 \uc784\uc758\uc0ac\ud56d\uc774\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\ud55c \uacbd\uc6b0\uc5d0\ub9cc \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uace0\uac1d\uc758 \ubc95\uc815 \ud574\uc81c\uad8c \uc81c\ud55c\uc740 \uc18c\ube44\uc790 \ubcf4\ud638\uc640 \ubb34\uad00\ud55c \ubb38\uc81c\uc774\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uacc4\uc57d\uc11c\uc5d0 \uace0\uac1d\uc774 \uc11c\uba85\ud558\uba74 \ud56d\uc0c1 \uc720\ud6a8\ub85c \uc804\ud658\ub41c\ub2e4"],t.s)
B.WM=s(["\uace0\uac1d\uc758 \uc815\ub2f9\ud55c \ubc95\uc801 \uad8c\ub9ac\ub97c \uc57d\uad00\uc744 \ud1b5\ud574 \uc0ac\uc2e4\uc0c1 \ubc15\ud0c8\ud558\ub294 \uac83\uc774\uc5b4\uc11c \uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4"],t.s)
B.aa0=s(["\uace0\uac1d\uc758 \ubc95\uc815 \ud574\uc81c\xb7\ud574\uc9c0\uad8c \ubcf4\ud638"],t.s)
B.aiM=new A.c("gen_al_termination_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\ubc95\ub960\uc5d0 \ub530\ub978 \uace0\uac1d\uc758 \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.R4,0,"\ubc95\ub960\uc774 \uace0\uac1d\uc5d0\uac8c \ubd80\uc5ec\ud55c \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \uc57d\uad00\uc744 \ud1b5\ud574 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d\uc740, \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \ubc95\uc801 \uad8c\ub9ac\ub97c \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \ub9c8\ub828\ud55c \uc57d\uad00\uc73c\ub85c \uc0ac\uc2e4\uc0c1 \ubc15\ud0c8\ud558\ub294 \uac83\uc774\uc5b4\uc11c \uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4. \uace0\uac1d\uc758 \uc11c\uba85 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \uadf8 \ub0b4\uc6a9 \uc790\uccb4\uac00 \ubd88\uacf5\uc815\ud558\uba74 \ubb34\ud6a8\ub77c\ub294 \uc810\uc774 \ud575\uc2ec\uc774\ub2e4.",B.WM,B.aa0,null)
B.a44=s(["\uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4","\uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub294 \uc57d\uad00\uc744 \ud1b5\ud574 \ud56d\uc0c1 \uc790\uc720\ub86d\uac8c \uc644\uc804\ud788 \uba74\uc81c\ub420 \uc218 \uc788\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc77c \ubfd0 \ubb34\ud6a8 \uc5ec\ubd80\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\ubbc0\ub85c \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4"],t.s)
B.Is=s(["\uc81c9\uc870\uc5d0 \ub530\ub77c \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4"],t.s)
B.a5A=s(["\uc0ac\uc5c5\uc790 \ucc45\uc784\uc758 \ubd80\ub2f9\ud55c \uacbd\uac10"],t.s)
B.akm=new A.c("gen_al_termination_6","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uacc4\uc57d\uc758 \ud574\uc81c\xb7\ud574\uc9c0(\uc81c9\uc870)","\uacc4\uc57d \ud574\uc81c\xb7\ud574\uc9c0 \uc2dc \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f9\ud558\uac8c \uacbd\uac10\ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a44,0,"\uacc4\uc57d\uc774 \ud574\uc81c\xb7\ud574\uc9c0\ub41c \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud574\uc57c \ud560 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub098 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f9\ud558\uac8c \uacbd\uac10\uc2dc\ud0a4\ub294 \uc57d\uad00\uc870\ud56d\uc740 \uc81c9\uc870\uac00 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720 \uc911 \ud558\ub098\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uacc4\uc57d\uad00\uacc4 \uc885\ub8cc \uc2dc\uc5d0\ub3c4 \ub2f9\uc0ac\uc790 \uac04 \ud615\ud3c9\uc744 \uc720\uc9c0\ud558\ub824\ub294 \ucde8\uc9c0\uc774\ub2e4.",B.Is,B.a5A,null)
B.Y0=s(["\ubc95\ub960\uc5d0 \ub530\ub77c \uc778\uc815\ub418\ub294 \uace0\uac1d\uc758 \uad8c\uc775\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc704\uc57d\uae08\uc744 \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d","\uace0\uac1d\uc758 \uc815\ub2f9\ud55c \uc774\uc775 \ubc0f \ud569\ub9ac\uc801\uc778 \uae30\ub300\uc5d0 \ubc18\ud558\uc5ec \uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uac8c \ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc758 \uc11c\uba74 \ub3d9\uc758 \uc808\ucc28\ub97c \uba85\ud655\ud788 \uaddc\uc815\ud558\uc5ec \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub294 \uc870\ud56d","\uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\ub0b4\uc6a9\uc744 \ubd80\ub2f9\ud558\uac8c \ubcc0\uacbd\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc870\ud56d"],t.s)
B.Wj=s(["\uace0\uac1d\uc758 \uc11c\uba74 \ub3d9\uc758 \uc808\ucc28\ub97c \uba85\ud655\ud788 \uaddc\uc815\ud558\uc5ec \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub294 \uc870\ud56d"],t.s)
B.a13=s(["\uace0\uac1d\uc758 \uad8c\uc775 \ubcf4\ud638"],t.s)
B.apS=new A.c("gen_al_etc_1","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c11\uc870(\uace0\uac1d\uc758 \uad8c\uc775 \ubcf4\ud638)\uac00 \uaddc\uc728\ud558\ub294 \uc870\ud56d\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?",B.Y0,3,"\uc81c11\uc870\ub294 \ubc95\ub960\uc0c1 \uace0\uac1d\uc758 \uad8c\uc775 \ubc30\uc81c\xb7\uc81c\ud55c, \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc704\uc57d\uae08 \ubd80\ub2f4, \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \uc774\uc775\xb7\ud569\ub9ac\uc801 \uae30\ub300\uc5d0 \ubc18\ud574 \uacc4\uc57d\ubaa9\uc801 \ub2ec\uc131\uc744 \uc5b4\ub835\uac8c \ud558\ub294 \uc870\ud56d, \uc0ac\uc5c5\uc790\uc758 \uc77c\ubc29\uc801 \uacc4\uc57d\ub0b4\uc6a9 \ubcc0\uacbd \ub4f1\uc744 \uaddc\uc728\ud55c\ub2e4. \ubc18\uba74 \uace0\uac1d\uc758 \uc11c\uba74 \ub3d9\uc758 \uc808\ucc28\ub97c \uba85\ud655\ud788 \uaddc\uc815\ud558\uc5ec \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub294 \uc870\ud56d\uc740 \uc624\ud788\ub824 \uace0\uac1d \ubcf4\ud638\uc5d0 \ubd80\ud569\ud558\ub294 \uacf5\uc815\ud55c \uc870\ud56d\uc774\ub2e4.",B.Wj,B.a13,null)
B.Nu=s(["\uace0\uac1d\uc758 \uc791\uc704\xb7\ubd80\uc791\uc704\ub97c \ubd80\ub2f9\ud558\uac8c \uace0\uac1d\uc758 \uc758\uc0ac\ud45c\uc2dc\ub85c \uc758\uc81c\ud558\ub294 \ub4f1, \uc77c\uc815\ud55c \uc0ac\uc2e4\uc774 \uc788\uc73c\uba74 \uace0\uac1d\uc758 \uc758\uc0ac\ud45c\uc2dc\uac00 \ud45c\uba85\xb7\ubcc0\uacbd\xb7\ucca0\ud68c\ub41c \uac83\uc73c\ub85c \ubcf4\ub294 \uc870\ud56d","\uace0\uac1d\uc774 \uba85\uc2dc\uc801\uc73c\ub85c \uc11c\uba74 \ub3d9\uc758\ud55c \uc0ac\ud56d\ub9cc\uc744 \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \uc778\uc815\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc758 \uc758\uc0ac\ud45c\uc2dc \ubc29\ubc95\uc744 \ub2e4\uc591\ud558\uac8c \uc778\uc815\ud558\uc5ec \ud3b8\uc758\ub97c \uc81c\uacf5\ud558\ub294 \uc870\ud56d","\uc0ac\uc5c5\uc790\uc758 \uc758\uc0ac\ud45c\uc2dc \ubc29\ubc95\ub9cc\uc744 \uaddc\uc728\ud560 \ubfd0 \uace0\uac1d\uacfc\ub294 \ubb34\uad00\ud55c \uc870\ud56d","\uace0\uac1d\uc758 \uc758\uc0ac\ud45c\uc2dc \ub3c4\ub2ec \uc2dc\uae30\ub97c \ubc95\ub960\uacfc \ub3d9\uc77c\ud558\uac8c \uc815\ud558\ub294 \uc870\ud56d"],t.s)
B.NZ=s(["\uc77c\uc815\ud55c \uc0ac\uc2e4\uc774 \uc788\uc73c\uba74 \uace0\uac1d\uc758 \uc758\uc0ac\ud45c\uc2dc\uac00 \ud45c\uba85\xb7\ubcc0\uacbd\xb7\ucca0\ud68c\ub41c \uac83\uc73c\ub85c \ubcf4\ub294 \uc870\ud56d"],t.s)
B.ZZ=s(["\uc758\uc0ac\ud45c\uc2dc\uc758 \uc758\uc81c"],t.s)
B.akX=new A.c("gen_al_etc_2","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c12\uc870(\uc758\uc0ac\ud45c\uc2dc\uc758 \uc758\uc81c)\uac00 \uaddc\uc728\ud558\ub294 \uc870\ud56d \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Nu,0,"\uc81c12\uc870\ub294 \uc0ac\uc5c5\uc790\uac00 \uace0\uac1d\uc5d0\uac8c \uc811\uc218 \uc5ec\ubd80\ub97c \ud1b5\uc9c0\ud558\uc9c0 \uc54a\uac70\ub098, \uace0\uac1d\uc774 \uc758\uc0ac\ud45c\uc2dc\ub97c \ud558\ub294 \ub370 \ud544\uc694\ud55c \uc0c1\ub2f9\ud55c \uae30\uac04\uc744 \uc8fc\uc9c0 \uc54a\uac70\ub098, \uace0\uac1d\uc758 \uc791\uc704\xb7\ubd80\uc791\uc704\ub97c \ubd80\ub2f9\ud558\uac8c \uadf8\uc758 \uc758\uc0ac\ud45c\uc2dc\ub85c \uc758\uc81c\ud558\uac70\ub098, \uace0\uac1d \uc758\uc0ac\ud45c\uc2dc\uc758 \ub3c4\ub2ec\uc2dc\uae30\ub97c \ubd80\ub2f9\ud558\uac8c \ub2a6\ucd94\uac70\ub098 \uc55e\ub2f9\uae30\ub294 \ub4f1\uc758 \uc870\ud56d\uc744 \uaddc\uc728\ud55c\ub2e4. \uc774\ub294 \uace0\uac1d\uc774 \uc2e4\uc81c\ub85c \uc6d0\ud558\uc9c0 \uc54a\ub294 \uc758\uc0ac\ud45c\uc2dc\ub97c \ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud568\uc774\ub2e4.",B.NZ,B.ZZ,null)
B.a8P=s(["\uace0\uac1d\uc758 \ub300\ub9ac\uc778\uc5d0 \uc758\ud558\uc5ec \uacc4\uc57d\uc774 \uccb4\uacb0\ub41c \uacbd\uc6b0, \uace0\uac1d\uc774 \uadf8 \ucc44\ubb34\ub97c \uc774\ud589\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \uacbd\uc6b0 \ub300\ub9ac\uc778\uc5d0\uac8c \uadf8 \uc758\ubb34\uc758 \uc804\ubd80 \ub610\ub294 \uc77c\ubd80\ub97c \uc774\ud589\ud560 \ucc45\uc784\uc744 \uc9c0\uc6b0\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4","\ub300\ub9ac\uc778\uc740 \ud56d\uc0c1 \ubcf8\uc778\uacfc \ub3d9\uc77c\ud55c \uacc4\uc57d\uc0c1 \ucc45\uc784\uc744 \ubd80\ub2f4\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ubbc0\ub85c \uc774\ub7ec\ud55c \uc870\ud56d\uc740 \ub2f9\uc5f0\ud788 \uc720\ud6a8\ud558\ub2e4","\ub300\ub9ac\uc778\uc758 \ucc45\uc784 \uac00\uc911 \uc870\ud56d\uc740 \ub300\ub9ac\uc778\uc774 \ub3d9\uc758\ud558\uba74 \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc774 \uc870\ud56d\uc740 \uc624\uc9c1 \ubc95\uc778 \ub300\ub9ac\uc778\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\ub300\ub9ac\uc778\uc758 \ucc45\uc784 \uac00\uc911\uc740 \uc57d\uad00\ubc95\uc774 \uc544\ub2c8\ub77c \ud615\ubc95\uc73c\ub85c\ub9cc \uaddc\uc728\ub41c\ub2e4"],t.s)
B.a9S=s(["\ub300\ub9ac\uc778\uc5d0\uac8c \uadf8 \uc758\ubb34\uc758 \uc804\ubd80 \ub610\ub294 \uc77c\ubd80\ub97c \uc774\ud589\ud560 \ucc45\uc784\uc744 \uc9c0\uc6b0\ub294 \uc870\ud56d\uc740 \ubb34\ud6a8\uc774\ub2e4"],t.s)
B.a56=s(["\ub300\ub9ac\uc778\uc758 \ucc45\uc784 \uac00\uc911 \uae08\uc9c0"],t.s)
B.ahM=new A.c("gen_al_etc_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c13\uc870(\ub300\ub9ac\uc778\uc758 \ucc45\uc784 \uac00\uc911)\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a8P,0,"\uc81c13\uc870\ub294 \uace0\uac1d\uc758 \ub300\ub9ac\uc778\uc5d0 \uc758\ud574 \uacc4\uc57d\uc774 \uccb4\uacb0\ub41c \uacbd\uc6b0, \uace0\uac1d(\ubcf8\uc778)\uc774 \ucc44\ubb34\ub97c \uc774\ud589\ud558\uc9c0 \uc54a\uc744 \ub54c \ub300\ub9ac\uc778\uc5d0\uac8c \uadf8 \uc758\ubb34\uc758 \uc804\ubd80 \ub610\ub294 \uc77c\ubd80\ub97c \uc774\ud589\ud558\ub3c4\ub85d \ucc45\uc784\uc744 \uc9c0\uc6b0\ub294 \uc57d\uad00\uc870\ud56d\uc744 \ubb34\ud6a8\ub85c \ud55c\ub2e4. \ub300\ub9ac\uc778\uc740 \ubcf8\ub798 \ubcf8\uc778\uc744 \uc704\ud574 \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \uc9c0\uc704\uc5d0 \uc788\uc744 \ubfd0 \uacc4\uc57d\uc0c1 \ucc44\ubb34\uc790\uac00 \ub418\ub294 \uac83\uc740 \uc544\ub2c8\ubbc0\ub85c, \uc774\ub7ec\ud55c \ucc45\uc784 \uc804\uac00\ub294 \ub300\ub9ac\uc778\uc5d0\uac8c \ubd80\ub2f9\ud558\ub2e4\ub294 \ucde8\uc9c0\uc774\ub2e4.",B.a9S,B.a56,null)
B.Jl=s([u.y,"\uace0\uac1d\uc774 \uc18c\uc1a1\uc744 \uc81c\uae30\ud560 \uad8c\ub9ac\ub97c \uc624\ud788\ub824 \uba85\ud655\ud788 \ud655\uc778\ud574\uc8fc\ub294 \uc870\ud56d","\ubd84\uc7c1 \ubc1c\uc0dd \uc2dc \uc870\uc815\uc808\ucc28\ub97c \uc784\uc758\ub85c \uc774\uc6a9\ud560 \uc218 \uc788\uc74c\uc744 \uc548\ub0b4\ud558\ub294 \uc870\ud56d","\uad00\ud560\ubc95\uc6d0\uc744 \ubc95\ub960\uc774 \uc815\ud55c \ub300\ub85c \uba85\uc2dc\ud558\ub294 \uc870\ud56d","\uc785\uc99d\ucc45\uc784\uc758 \ubc95\ub960\uc0c1 \ubd84\ubc30\ub97c \uadf8\ub300\ub85c \ud655\uc778\ud558\ub294 \uc870\ud56d"],t.s)
B.Xr=s([u.y],t.s)
B.a6x=s(["\uc18c\uc1a1\uc81c\uae30\uc758 \uae08\uc9c0 \ub4f1"],t.s)
B.alF=new A.c("gen_al_etc_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c14\uc870(\uc18c\uc1a1\uc81c\uae30\uc758 \uae08\uc9c0 \ub4f1)\uac00 \uaddc\uc728\ud558\ub294 \uc870\ud56d\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Jl,0,"\uc81c14\uc870\ub294 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uc7ac\ud310\uad00\ud560 \ud569\uc758 \uc870\ud56d\uc774\ub098, \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ubc95\ub960\uc0c1 \uc6d0\uce59\uacfc \ub2ec\ub9ac \uace0\uac1d\uc5d0\uac8c \uc785\uc99d\ucc45\uc784\uc744 \uc804\uac00\ud558\ub294 \uc870\ud56d \ub4f1\uc744 \ubb34\ud6a8\uc0ac\uc720\ub85c \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uc18c\uc1a1\xb7\ubd84\uc7c1\ud574\uacb0 \uacfc\uc815\uc5d0\uc11c \uace0\uac1d\uc774 \ubd88\ub9ac\ud55c \uc9c0\uc704\uc5d0 \ub193\uc774\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4.",B.Xr,B.a6x,null)
B.a07=s([u.ax,"\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00 \ubcf4\ud638\ub97c \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\ud55c \uacbd\uc6b0\uc5d0\ub9cc \ubb34\ud6a8\uc774\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc18c\uc1a1\uc744 \ud1b5\ud574\uc11c\ub9cc \ub2e4\ud234 \uc218 \uc788\uace0 \uc57d\uad00\ubc95\uc0c1 \ubb34\ud6a8 \ub300\uc0c1\uc740 \uc544\ub2c8\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud55c \uc870\ud56d\uc73c\ub85c \ubd84\ub958\ub418\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4"],t.s)
B.a2E=s([u.ax],t.s)
B.N7=s(["\uc81c3\uc790 \uac70\ub798 \uc81c\ud55c \uae08\uc9c0"],t.s)
B.ale=new A.c("gen_al_etc_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uace0\uac1d\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uc81c3\uc790\uc640 \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \uac83\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\uac70\ub098, \uc774\ub97c \uc774\uc720\ub85c \uace0\uac1d\uc5d0\uac8c \uacfc\uc911\ud55c \uc704\uc57d\uae08\uc744 \ubb3c\uac8c \ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a07,0,"\uace0\uac1d\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uacfc \uad00\ub828\ud558\uc5ec \uc81c3\uc790\uc640 \uc790\uc720\ub86d\uac8c \uac70\ub798\ud560 \uc218 \uc788\ub294 \uad8c\ub9ac\ub97c \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\uac70\ub098, \uc774\ub97c \uc774\uc720\ub85c \uacfc\uc911\ud55c \uc704\uc57d\uae08\uc744 \ubd80\uacfc\ud558\ub294 \uc870\ud56d\uc740 \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \uad8c\uc775\uc744 \ubd80\ub2f9\ud558\uac8c \uce68\ud574\ud558\ub294 \uac83\uc73c\ub85c \uc81c11\uc870\uac00 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.",B.a2E,B.N7,null)
B.R3=s([u.Fz,"\uc870\uc0ac\ub294 \uc624\uc9c1 \uac80\ucc30\uc758 \uc694\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc870\uc0ac\ub294 \ubc18\ub4dc\uc2dc \ud53c\uc870\uc0ac\uc778\uc758 \uc0ac\uc804 \ub3d9\uc758\ub97c \ubc1b\uc544\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc2e0\uace0\uc5d0 \uc758\ud55c \uc870\uc0ac\ub294 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uc9c1\uad8c\uc870\uc0ac\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc870\uc0ac \uac1c\uc2dc\uc5d0\ub294 \uad6d\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc774 \ud544\uc694\ud558\ub2e4"],t.s)
B.Rn=s([u.Fz],t.s)
B.a4W=s(["\uc870\uc0ac \uac1c\uc2dc \ubc29\uc2dd"],t.s)
B.ai1=new A.c("gen_iv_start_1","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc704\ubc18\ud589\uc704 \uc870\uc0ac \uac1c\uc2dc\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.R3,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc95 \uc704\ubc18 \ud610\uc758\uac00 \uc788\ub2e4\uace0 \uc778\uc9c0\ud558\uba74 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\uace0, \uc774\ud574\uad00\uacc4\uc778\xb7\uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc758 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c\ub3c4 \uc870\uc0ac\uc5d0 \ucc29\uc218\ud560 \uc218 \uc788\ub2e4. \uc870\uc0ac \uac1c\uc2dc\uc5d0 \ud53c\uc870\uc0ac\uc778\uc758 \uc0ac\uc804 \ub3d9\uc758\ub098 \uad6d\ud68c \uc2b9\uc778, \uac80\ucc30\uc758 \uc694\uccad\uc774 \ud544\uc694\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Rn,B.a4W,null)
B.Vt=s(["\ub204\uad6c\ub4e0\uc9c0 \ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4","\uc2e0\uace0\ub294 \ubc18\ub4dc\uc2dc \ud53c\ud574 \ub2f9\uc0ac\uc790 \ubcf8\uc778\ub9cc \ud560 \uc218 \uc788\ub2e4","\uc2e0\uace0\ub294 \ubc18\ub4dc\uc2dc \ubcc0\ud638\uc0ac\ub97c \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc2e0\uace0\uac00 \uc788\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc18\ub4dc\uc2dc \uadf8 \uc2e0\uace0 \ub0b4\uc6a9\ub300\ub85c\ub9cc \ucc98\ubd84\ud574\uc57c \ud55c\ub2e4","\uc2e0\uace0\uc790\ub294 \uc2e0\uace0 \uc774\ud6c4 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc775\uba85\uc744 \uc720\uc9c0\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.L5=s(["\ub204\uad6c\ub4e0\uc9c0 \ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Vf=s(["\uc2e0\uace0 \uc81c\ub3c4"],t.s)
B.ahZ=new A.c("gen_iv_start_2","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uc790\uc758 \uc2e0\uace0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Vt,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uc790\ub294 \ub204\uad6c\ub4e0\uc9c0 \uadf8 \uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4. \uc2e0\uace0\uc790\uac00 \ubc18\ub4dc\uc2dc \ud53c\ud574 \ub2f9\uc0ac\uc790 \ubcf8\uc778\uc77c \ud544\uc694\ub294 \uc5c6\uc73c\uba70, \uc2e0\uace0\uac00 \uc788\ub2e4\uace0 \ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc2e0\uace0 \ub0b4\uc6a9 \uadf8\ub300\ub85c \uad6c\uc18d\ub418\uc5b4 \ucc98\ubd84\ud574\uc57c \ud558\ub294 \uac83\ub3c4 \uc544\ub2c8\uace0 \uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \ubcc4\ub3c4\ub85c \ud310\ub2e8\ud55c\ub2e4.",B.L5,B.Vf,null)
B.ST=s([u.j4,"\uc2e0\uace0\uc790\uc758 \uc7ac\uc0b0 \uaddc\ubaa8","\ud53c\uc2e0\uace0\uc778\uc758 \uc815\uce58\uc801 \uc131\ud5a5","\uc2e0\uace0\uc790\uc758 \uad6d\uc801","\ud53c\uc2e0\uace0\uc778\uc758 \uc784\uc9c1\uc6d0 \uc218\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4"],t.s)
