B.apd=new A.c("gen_iv_start_5","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc9c1\uad8c\uc73c\ub85c \uc778\uc9c0\ud558\uc5ec \uc870\uc0ac\ub97c \uac1c\uc2dc\ud558\ub294 \ub300\ud45c\uc801\uc778 \uacc4\uae30\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.ab5,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc5b8\ub860\ubcf4\ub3c4, \ub2e4\ub978 \uc0ac\uac74\uc744 \uc870\uc0ac\ud558\ub294 \uacfc\uc815\uc5d0\uc11c \ubc1c\uacac\ub41c \ub2e8\uc11c, \uc2dc\uc7a5\ub3d9\ud5a5 \ubaa8\ub2c8\ud130\ub9c1 \uacb0\uacfc \ub4f1 \ub2e4\uc591\ud55c \uacbd\ub85c\ub85c \ubc95 \uc704\ubc18 \ud610\uc758\ub97c \uc778\uc9c0\ud558\uc5ec \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uc2e0\uace0\uac00 \uc5c6\ub354\ub77c\ub3c4 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ub2a5\ub3d9\uc801\uc73c\ub85c \ubc95 \uc9d1\ud589\uc5d0 \ub098\uc124 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uae30\ub2a5\uc744 \ud55c\ub2e4.",B.abp,B.NI,null)
B.P4=s([u.wB,"\uc5b4\ub5a0\ud55c \uc2e0\uace0\ub4e0 \uc811\uc218\ub418\uba74 \uc608\uc678 \uc5c6\uc774 \uc989\uc2dc \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c4\ub2e4","\ubb34\uae30\uba85 \uc2e0\uace0\ub294 \ubc95\ub960\uc0c1 \uc804\ud600 \uc811\uc218\ub420 \uc218 \uc5c6\ub2e4","\ud5c8\uc704\uc2e0\uace0\ub85c \ubc1d\ud600\uc9c0\uba74 \ud53c\uc2e0\uace0\uc778\uc5d0\uac8c \uc790\ub3d9\uc73c\ub85c \uc2b9\uc18c \ud310\uacb0\uc774 \ub0b4\ub824\uc9c4\ub2e4","\uc2e0\uace0\uc758 \uc9c4\uc704\uc640 \ubb34\uad00\ud558\uac8c \uc2e0\uace0\uc790\uc5d0\uac8c \ud56d\uc0c1 \ubcf4\uc0c1\uae08\uc774 \uc9c0\uae09\ub41c\ub2e4"],t.s)
