B.ahV=new A.c("gen_iv_start_6","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\ubb34\uae30\uba85 \ub610\ub294 \ud5c8\uc704 \uc0ac\uc2e4\ub85c \uc774\ub8e8\uc5b4\uc9c4 \uc2e0\uace0\uc5d0 \ub300\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ub300\uc751\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.P4,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc811\uc218\ub41c \uc2e0\uace0 \ub0b4\uc6a9\uc758 \uc2e0\ube59\uc131\uacfc \uadfc\uac70\ub97c \uac80\ud1a0\ud55c \ud6c4 \uc870\uc0ac \uac1c\uc2dc \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\uba70, \uadfc\uac70\uac00 \ubd80\uc871\ud558\uac70\ub098 \ud5c8\uc704\ub85c \ud310\ub2e8\ub418\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc870\uc0ac\ub97c \uac1c\uc2dc\ud558\uc9c0 \uc54a\uac70\ub098 \uc870\uc0ac \uc5c6\uc774 \uc0ac\uac74\uc744 \uc885\uacb0\ud560 \uc218 \uc788\ub2e4. \uc2e0\uace0\uac00 \uc811\uc218\ub418\uc5c8\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \uc790\ub3d9\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub098 \ud310\uacb0\uc774 \ub0b4\ub824\uc9c0\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Pp,B.ON,null)
B.a1I=s([u.oF,"\uc5b4\ub5a0\ud55c \uc0ac\uc804 \ud1b5\uc9c0\ub098 \ubb38\uc11c \uc81c\uc2dc \uc5c6\uc774\ub3c4 \ud56d\uc0c1 \ubb34\uc81c\ud55c\uc73c\ub85c \uc870\uc0ac\ud560 \uc218 \uc788\ub2e4","\ud604\uc7a5\uc870\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc7a5 \ub300\ud45c\uc758 \uc11c\uba74 \ucd08\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \uac1c\uc2dc\ub41c\ub2e4","\ud604\uc7a5\uc870\uc0ac\ub294 \uc624\uc9c1 \uc57c\uac04\uc5d0\ub9cc \uc2e4\uc2dc\ud560 \uc218 \uc788\ub2e4","\ud604\uc7a5\uc870\uc0ac\ub294 \uc0ac\uc804 \uc608\uace0 \uc5c6\uc774 \ud3ed\ub825\uc744 \uc218\ubc18\ud574\uc11c \uc9c4\ud589\ud560 \uc218 \uc788\ub2e4"],t.s)
B.acK=s([u.oF],t.s)
