B.akf=new A.c("gen_iv_method_1","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ubc95\xb7\uc870\uc0ac\uad8c\ud55c","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uc18d \uacf5\ubb34\uc6d0\uc774 \ud604\uc7a5\uc870\uc0ac\ub97c \uc2e4\uc2dc\ud560 \ub54c \uc9c0\ucf1c\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1I,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uc18d \uacf5\ubb34\uc6d0\uc774 \ud604\uc7a5\uc870\uc0ac\ub97c \uc2e4\uc2dc\ud560 \ub54c\uc5d0\ub294 \uc870\uc0ac\uc758 \ubaa9\uc801, \uae30\uac04, \uc870\uc0ac\uc6d0\uc758 \uc131\uba85\uacfc \uc9c1\uc704 \ub4f1\uc774 \uae30\uc7ac\ub41c \ubb38\uc11c(\uc870\uc0ac\uacf5\ubb38 \ub4f1)\ub97c \uc0c1\ub300\ubc29\uc5d0\uac8c \uc81c\uc2dc\ud558\uc5ec\uc57c \ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \uc870\uc0ac\uc758 \uc801\ubc95\uc131\uacfc \ud53c\uc870\uc0ac\uc778\uc758 \ubc29\uc5b4\uad8c\uc744 \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \uc808\ucc28\uc801 \uc7a5\uce58\uc774\ub2e4.",B.acK,B.a3s,null)
B.ne=s(["\u3131, \u3134, \u3137, \u3139 \ubaa8\ub450","\u3131, \u3134\ub9cc","\u3137, \u3139\ub9cc","\u3131\ub9cc","\u3139\ub9cc"],t.s)
