B.amb=new A.c("gen_iv_right_6","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc870\uc0ac \ub300\uc0c1\uc774 \ub41c \uc0ac\uc5c5\uc790\uac00 \uc790\ub8cc\uc81c\ucd9c\uc694\uad6c\uc5d0 \ub300\ud574 \uc601\uc5c5\ube44\ubc00\uc744 \uc774\uc720\ub85c \uc81c\ucd9c\uc744 \uac70\ubd80\ud560 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.RL,0,"\uc601\uc5c5\ube44\ubc00\uc5d0 \ud574\ub2f9\ud55c\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uc815\ub2f9\ud55c \uc870\uc0ac\uc5d0 \ub300\ud55c \uc790\ub8cc\uc81c\ucd9c\uc744 \uc804\uba74 \uac70\ubd80\ud560 \uc218 \uc788\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \uc54c\uac8c \ub41c \ube44\ubc00\uc744 \ub204\uc124\ud558\uc9c0 \uc54a\uc744 \uc758\ubb34\ub97c \uc9c0\ub294 \uac83\uacfc \uac19\uc740 \ubcf4\ud638\uc7a5\uce58 \ud558\uc5d0\uc11c \ud544\uc694\ud55c \ubc94\uc704\uc758 \uc790\ub8cc \uc81c\ucd9c\uc774 \uc694\uad6c\ub420 \uc218 \uc788\ub2e4.",B.Zn,B.N2,null)
