B.ao6=new A.c("gen_iv_obstruct_4","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ud574\uc5d0 \ub300\ud55c \uc81c\uc7ac","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ucd9c\uc11d\uc694\uad6c\xb7\uc790\ub8cc\uc81c\ucd9c\uc694\uad6c\uc5d0 \uc751\ud558\uc9c0 \uc54a\ub294 \uc790\uc5d0 \ub300\ud574 \ubd80\uacfc\ub420 \uc218 \uc788\ub294 \uc81c\uc7ac\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.OC,0,"\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucd9c\uc11d\uc694\uad6c\ub098 \uc790\ub8cc\uc81c\ucd9c\uc694\uad6c\uc5d0 \uc751\ud558\uc9c0 \uc54a\ub294 \uc790\uc5d0 \ub300\ud574\uc11c\ub294 \ubc95\ub839\uc774 \uc815\ud558\ub294 \ubc14\uc5d0 \ub530\ub77c \uacfc\ud0dc\ub8cc \ub4f1\uc758 \ud589\uc815\uc801 \uc81c\uc7ac\uac00 \ubd80\uacfc\ub420 \uc218 \uc788\ub2e4. \uc774\ub294 \uc870\uc0ac\uc5d0 \ub300\ud55c \ud611\uc870\ub97c \ud655\ubcf4\ud558\uae30 \uc704\ud55c \uc2e4\ud6a8\uc801 \uc218\ub2e8\uc73c\ub85c \ub9c8\ub828\ub418\uc5b4 \uc788\ub2e4.",B.Ht,B.a52,null)
