B.aia=new A.c("gen_iv_obstruct_6","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ud574\uc5d0 \ub300\ud55c \uc81c\uc7ac","\uc870\uc0ac\ubc29\ud574 \ud589\uc704\uc640 \uad00\ub828\ud558\uc5ec \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \uc870\uc0ac \ube44\ud611\uc870\ub97c \uc9c0\uc2dc\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Mw,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \uc870\uc9c1\uc801\uc73c\ub85c \uc870\uc0ac \ube44\ud611\uc870\ub97c \uc9c0\uc2dc\ud558\ub294 \uacbd\uc6b0, \uc774\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \ucc28\uc6d0\uc758 \uc870\uc0ac\ubc29\ud574\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\uc744 \ubfd0 \uc544\ub2c8\ub77c \uc774\ub97c \ub530\ub978 \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \uac01\uc790\uc758 \uad00\uc5ec \uc815\ub3c4\uc5d0 \ub530\ub77c \uc870\uc0ac\ubc29\ud574\uc5d0 \ub530\ub978 \ucc45\uc784\uc774 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.SN,B.GS,null)
B.Ro=s([u.sv,"\ucc98\ubd84\uc2dc\ud6a8\ub294 \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784\uc744 \uc644\uc804\ud788 \uba74\uc81c\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc5c5\ubb34 \ud3b8\uc758\ub9cc\uc744 \uc704\ud55c \uac83\uc774\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \ud589\uc815\ucc98\ubd84\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \ud53c\ud574\uc790\uc758 \uad8c\ub9ac\ub97c \ubc15\ud0c8\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4"],t.s)
