B.ah9=new A.c("gen_iv_time_1","economic_law","\uc870\uc0ac\uc808\ucc28","\ucc98\ubd84\uc2dc\ud6a8\xb7\uc2ec\uc758\uc808\ucc28","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc5d0 \uc77c\uc815\ud55c \uae30\uac04 \uc81c\ud55c(\ucc98\ubd84\uc2dc\ud6a8)\uc774 \uc788\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ro,0,"\ucc98\ubd84\uc2dc\ud6a8 \uc81c\ub3c4\ub294 \uc704\ubc18\ud589\uc704\uac00 \uc788\uc5c8\ub2e4 \ud558\ub354\ub77c\ub3c4 \uc9c0\ub098\uce58\uac8c \uc624\ub79c \uc2dc\uac04\uc774 \uc9c0\ub09c \ud6c4\uc5d0\uae4c\uc9c0 \ubb34\uae30\ud55c \uc81c\uc7ac \uac00\ub2a5\uc131\uc744 \uc5f4\uc5b4\ub450\uba74 \ubc95\ub960\uad00\uacc4\uc758 \uc548\uc815\uc131\uc774 \ud06c\uac8c \uc800\ud574\ub420 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \uace0\ub824\ud558\uc5ec, \uc77c\uc815\ud55c \uae30\uac04\uc774 \uc9c0\ub098\uba74 \uc6d0\uce59\uc801\uc73c\ub85c \ucc98\ubd84\uc744 \ud560 \uc218 \uc5c6\ub3c4\ub85d \uc81c\ud55c\ud558\ub294 \ucde8\uc9c0\ub85c \uc774\ud574\ub41c\ub2e4.",B.a9B,B.X_,null)
B.a77=s(["\uc0ac\uac74\uc758 \uacbd\uc911\uc5d0 \ub530\ub77c \uc804\uc6d0\ud68c\uc758 \ub610\ub294 \uc18c\ud68c\uc758\uc5d0\uc11c \uc2ec\uc758\ud558\uc5ec \uc758\uacb0\ud55c\ub2e4","\uc2ec\uc758\ub294 \ud56d\uc0c1 \ubc95\uc6d0\uc5d0\uc11c\ub9cc \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc2ec\uc758 \uc808\ucc28\ub294 \ud53c\uc2ec\uc778\uc758 \ucc38\uc5ec \uc5c6\uc774 \uc11c\uba74\uc73c\ub85c\ub9cc \uc9c4\ud589\ub41c\ub2e4","\uc2ec\uc758\ub294 \uc624\uc9c1 \uc704\uc6d0\uc7a5 1\uc778\uc758 \ub2e8\ub3c5 \uacb0\uc815\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc2ec\uc758 \uc808\ucc28\ub294 \ubc95\ub960\uc0c1 \uc804\ud600 \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4"],t.s)
