B.ah7=new A.c("gen_iv_time_4","economic_law","\uc870\uc0ac\uc808\ucc28","\ucc98\ubd84\uc2dc\ud6a8\xb7\uc2ec\uc758\uc808\ucc28","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2ec\uc758\xb7\uc758\uacb0 \uc808\ucc28\uc5d0\uc11c \ud53c\uc2ec\uc778\uc5d0\uac8c \ubcf4\uc7a5\ub418\ub294 \uc808\ucc28\uc801 \uad8c\ub9ac\ub85c \uac00\uc7a5 \uc801\uc808\ud558\uc9c0 \uc54a\uc740 \uac83\uc740?",B.W7,0,'\ud53c\uc2ec\uc778\uc5d0\uac8c\ub294 \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc5d0 \ub300\ud55c \uc758\uacac \uc81c\ucd9c, \uc2ec\uc758\uae30\uc77c \ucd9c\uc11d \ubc0f \uc758\uacac\uc9c4\uc220, \uc99d\uac70\uc790\ub8cc \uc81c\ucd9c, \ub300\ub9ac\uc778\uc744 \ud1b5\ud55c \ubc29\uc5b4\uad8c \ud589\uc0ac \ub4f1 \uc801\ubc95\uc808\ucc28\ub97c \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \ub2e4\uc591\ud55c \uc808\ucc28\uc801 \uad8c\ub9ac\uac00 \uc778\uc815\ub41c\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc5b4\ub514\uae4c\uc9c0\ub098 \ubc29\uc5b4\uad8c \ubcf4\uc7a5\uc744 \uc704\ud55c \uc808\ucc28\uc801 \uad8c\ub9ac\uc77c \ubfd0, "\ud56d\uc0c1 \uc2b9\uc18c\uac00 \ubcf4\uc7a5\ub418\ub294 \uad8c\ub9ac"\uc640 \uac19\uc740 \uac83\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Zg,B.no,null)
