B.a4R=s([u.o,"\u2460 \ucc98\ubd84 \u2192 \u2461 \uc2ec\uc758 \u2192 \u2462 \uc870\uc0ac \u2192 \u2463 \uc2e0\uace0 \uc21c\uc73c\ub85c \uc9c4\ud589\ub41c\ub2e4","\uc870\uc0ac\uc808\ucc28\ub294 \uc2ec\uc758 \uc5c6\uc774 \uace7\ubc14\ub85c \ucc98\ubd84\uc73c\ub85c \uc774\uc5b4\uc9c4\ub2e4","\uc870\uc0ac\uc808\ucc28\ub294 \uc21c\uc11c \uc5c6\uc774 \ubb34\uc791\uc704\ub85c \uc9c4\ud589\ub41c\ub2e4","\uc2ec\uc0ac\ubcf4\uace0\uc11c \uc791\uc131\uc740 \uc870\uc0ac\uc808\ucc28\uc640 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uc0ac\uac74\uc774\ub2e4"],t.s)
