B.apM=new A.c("gen_clause_review_order_5","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uad8c\uace0\xb7\uc2dc\uc815\uba85\ub839","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc2dc\uc815\uba85\ub839\uacfc \ud568\uaed8 \uadf8 \uc0ac\uc2e4\uc758 \uacf5\ud45c\ub97c \uba85\ud560 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.J1,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \uc0ac\uc6a9 \uc0ac\uc2e4\uc744 \uc2dc\uc815\ud558\ub3c4\ub85d \uba85\ud558\uba74\uc11c, \uc720\uc0ac\ud55c \uc57d\uad00\uc73c\ub85c \uc778\ud55c \ud53c\ud574\uac00 \ub2e4\ub978 \uace0\uac1d\uc5d0\uac8c \ud655\uc0b0\ub418\ub294 \uac83\uc744 \ubc29\uc9c0\ud560 \ud544\uc694\uac00 \uc788\ub294 \uacbd\uc6b0 \uadf8 \uc704\ubc18 \uc0ac\uc2e4 \ub4f1\uc744 \uacf5\ud45c\ud558\ub3c4\ub85d \uba85\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc81c\ub3c4\uc758 \ucde8\uc9c0\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.V3,B.GO,null)
B.a0C=s(["\ubc18\ubcf5 \uc704\ubc18\uc73c\ub85c\uc11c \uac00\uc911\ub41c \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \uc5b4\ub5a0\ud55c \ubb38\uc81c\ub3c4 \ub418\uc9c0 \uc54a\ub294\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \uc624\ud788\ub824 \uac10\uacbd\uc0ac\uc720\ub85c \uc791\uc6a9\ud55c\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9 \uc5ec\ubd80\ub294 \uc81c\uc7ac \uc218\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \ucd5c\ucd08 \uc704\ubc18\ubcf4\ub2e4 \ud56d\uc0c1 \uac00\ubccd\uac8c \ucde8\uae09\ub41c\ub2e4"],t.s)
B.TD=s(["\ubc18\ubcf5 \uc704\ubc18\uc73c\ub85c\uc11c \uac00\uc911\ub41c \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4"],t.s)
B.a9z=s(["\ubc18\ubcf5 \uc704\ubc18\uc758 \uac00\uc911\uc81c\uc7ac"],t.s)
B.arG=new A.c("gen_clause_review_order_6","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uad8c\uace0\xb7\uc2dc\uc815\uba85\ub839","\uc2dc\uc815\uba85\ub839\uc774 \ud655\uc815\ub41c \uc774\ud6c4 \uc0ac\uc5c5\uc790\uac00 \ub3d9\uc77c\ud55c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc744 \ub2e4\uc2dc \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0\uc758 \ucde8\uae09\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a0C,0,"\uc2dc\uc815\uba85\ub839\uc774 \ud655\uc815\ub418\uc5b4 \uc704\ubc18 \uc870\ud56d\uc744 \uc0ad\uc81c\xb7\uc218\uc815\ud574\uc57c \ud568\uc5d0\ub3c4 \uc0ac\uc5c5\uc790\uac00 \ub3d9\uc77c\ud558\uac70\ub098 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc720\uc0ac\ud55c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc744 \ub2e4\uc2dc \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0\uc5d0\ub294, \uc774\ub294 \ubc18\ubcf5 \uc704\ubc18\uc73c\ub85c\uc11c \ud1b5\uc0c1\uc758 \uc704\ubc18\ubcf4\ub2e4 \ub354 \ubb34\uac70\uc6b4 \uac00\uc911\ub41c \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.TD,B.a9z,null)
B.a4E=s([u.bv,"\uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c0\uba74 \uad00\ub828\ub41c \ubaa8\ub4e0 \uacc4\uc57d\uc774 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uac1c\ubcc4 \uacc4\uc57d\uc758 \ud6a8\ub825\uacfc \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac83\uc774\ub2e4","\uc2dc\uc815\uc870\uce58\uac00 \uc788\uc73c\uba74 \ubbfc\uc0ac\uc18c\uc1a1\uc740 \uc804\ud600 \ud544\uc694\ud558\uc9c0 \uc54a\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uc0ac\ubc95\uc0c1 \ud6a8\ub825\uc5d0 \uc5b4\ub5a0\ud55c \uc601\ud5a5\ub3c4 \ubbf8\uce60 \uc218 \uc5c6\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4"],t.s)
