B.anl=new A.c("gen_clause_review_effect_1","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc57d\uad00 \uc2dc\uc815\uc870\uce58\uac00 \uac1c\ubcc4 \uacc4\uc57d\uc758 \uc0ac\ubc95\uc0c1 \ud6a8\ub825\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a4E,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\ub294 \ud589\uc815\uc801 \uc81c\uc7ac\uc758 \uc131\uaca9\uc744 \uac00\uc9c0\uba70, \uadf8 \uc790\uccb4\ub85c \uac1c\ubcc4 \uacc4\uc57d\uc758 \uc0ac\ubc95\uc0c1 \ud6a8\ub825(\ud574\ub2f9 \uc870\ud56d\uc758 \ubb34\ud6a8 \uc5ec\ubd80 \ub4f1)\uc744 \uc9c1\uc811 \ud655\uc815\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uc5b4\uc11c, \uad6c\uccb4\uc801\uc778 \uacc4\uc57d\uc758 \ud6a8\ub825\uc740 \ubcc4\ub3c4\ub85c \ubbfc\uc0ac\uc18c\uc1a1\uc744 \ud1b5\ud574 \ub2e4\ud22c\uc5b4\uc9c8 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc778 \ubc95\ub9ac\ub85c \uc774\ud574\ub41c\ub2e4.",B.a8U,B.a3G,null)
B.a32=s(["\uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1 \uc77c\ubc18\uc801\uc778 \ubd88\ubcf5\uc808\ucc28\ub97c \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4","\uc2dc\uc815\uba85\ub839\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubd88\ubcf5\uc740 \uc624\uc9c1 \ud615\uc0ac\ubc95\uc6d0\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\ubd88\ubcf5\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \uc2dc\uc815\uba85\ub839\uc774 \ucde8\uc18c\ub41c\ub2e4","\uc2dc\uc815\uba85\ub839\uc740 \ubd88\ubcf5 \uc808\ucc28 \uc790\uccb4\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \ud2b9\uc218\ud55c \ucc98\ubd84\uc774\ub2e4"],t.s)
B.a89=s(["\uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1 \uc77c\ubc18\uc801\uc778 \ubd88\ubcf5\uc808\ucc28\ub97c \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4"],t.s)
B.a7q=s(["\uc2dc\uc815\uba85\ub839\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc808\ucc28"],t.s)
B.amn=new A.c("gen_clause_review_effect_2","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc57d\uad00 \uc2dc\uc815\uba85\ub839\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc808\ucc28\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a32,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc57d\uad00 \uc2dc\uc815\uba85\ub839\ub3c4 \ud558\ub098\uc758 \ud589\uc815\ucc98\ubd84\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uc774\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \uc77c\ubc18\uc801\uc778 \ubd88\ubcf5\uc808\ucc28\uc778 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ud589\uc815\ucc98\ubd84\uc5d0 \ub300\ud55c \uc77c\ubc18 \ubc95\ub9ac\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.a89,B.a7q,null)
B.VB=s([u.fE,"\uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c0\uba74 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uad8c\uc774 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud55c\ub2e4","\uc2dc\uc815\uc870\uce58\uc640 \uc190\ud574\ubc30\uc0c1\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc808\ucc28\uc774\ub2e4","\uc2dc\uc815\uc870\uce58\uac00 \uc788\uc73c\uba74 \uace0\uac1d\uc740 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc5c6\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4","\uc190\ud574\ubc30\uc0c1 \uccad\uad6c\ub294 \uc2dc\uc815\uc870\uce58\uac00 \ud655\uc815\ub41c \uc774\ud6c4\uc5d0\ub9cc \uac00\ub2a5\ud558\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4"],t.s)
