B.a_D=s(["\uc2dc\uc815\uc808\ucc28\uc640 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc758 \uad00\uacc4"],t.s)
B.ahP=new A.c("gen_clause_review_effect_3","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uc57d\uad00 \uc2dc\uc815\uc808\ucc28\uc640 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.VB,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\ub294 \ud589\uc815\uc801 \uc81c\uc7ac\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \uac83\uc73c\ub85c, \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc84c\ub294\uc9c0 \uc5ec\ubd80\uc640\ub294 \ubcc4\uac1c\ub85c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc73c\ub85c \uc778\ud574 \uc2e4\uc81c \ud53c\ud574\ub97c \uc785\uc740 \uace0\uac1d\uc740 \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\uc73c\uba70, \ub450 \uc808\ucc28\ub294 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4.",B.abI,B.a_D,null)
B.a6B=s([u.BU,"\uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc544\ub3c4 \uc5b4\ub5a0\ud55c \ud6c4\uc18d \ubb38\uc81c\ub3c4 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uac00\ub9f9\uacc4\uc57d\uc11c\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc73c\uba74 \uac00\ub9f9\uacc4\uc57d\uc774 \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \ubb34\ud6a8\uac00 \ub41c\ub2e4\uace0\ub9cc \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58 \uad00\ub828 \ub9ac\uc2a4\ud06c\ub294 \uc790\ubb38\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
B.Wr=s([u.BU],t.s)
B.jt=s(["\uac00\ub9f9\ubcf8\ubd80 \uc790\ubb38 \uc2dc \uc720\uc758\uc0ac\ud56d"],t.s)
B.apD=new A.c("gen_clause_review_effect_4","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc57d\uad00(\uac00\ub9f9\uacc4\uc57d\uc11c) \uc2dc\uc815 \uad00\ub828 \ub9ac\uc2a4\ud06c\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a6B,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc790\ubb38\ud560 \ub54c, \uac00\ub9f9\uacc4\uc57d\uc11c(\uc57d\uad00) \uc870\ud56d\uc774 \uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\uc801 \uc81c\uc7ac\uc5d0 \uadf8\uce58\uc9c0 \uc54a\uace0 \uac1c\ubcc4 \uac00\ub9f9\uc810\uacfc\uc758 \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1 \ubd84\uc7c1 \ub4f1 \ucd94\uac00\uc801\uc778 \ub9ac\uc2a4\ud06c\ub85c \uc774\uc5b4\uc9c8 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \ud568\uaed8 \uc548\ub0b4\ud558\uc5ec \uc885\ud569\uc801\uc778 \ub9ac\uc2a4\ud06c \uad00\ub9ac\ub97c \ub3d5\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4.",B.Wr,B.jt,null)
B.Zk=s([u.zE,"\uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc758 \uac1c\uc778 \uc2e0\uc0c1 \uc815\ubcf4\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\uc640 \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uc704\uce58\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
B.ZN=s([u.zE],t.s)
B.al_=new A.c("gen_clause_review_exam_1","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zk,0,"\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\ub294 \uc2ec\uc0ac\uccad\uad6c\uad8c\uc790\uc640 \uc9c1\uad8c\uc2ec\uc0ac\uc758 \uc778\uc815, \uc2dc\uc815\uad8c\uace0\uc640 \uc2dc\uc815\uba85\ub839\uc758 \uad6c\ubcc4, \uadf8\ub9ac\uace0 \uc2dc\uc815\uc870\uce58\uac00 \uac1c\ubcc4 \uacc4\uc57d\uc758 \uc0ac\ubc95\uc0c1 \ud6a8\ub825\uc774\ub098 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uacfc \uc5b4\ub5a4 \uad00\uacc4\ub97c \uac16\ub294\uc9c0\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.ZN,B.ba,null)
B.IH=s([u.jT,"\ub450 \ud30c\ud2b8\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \ub2e4\ub8e8\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \ud30c\ud2b8\ub294 \ubb34\ud6a8\uc0ac\uc720\uc640 \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uadfc\uac70\ud55c\ub2e4","\ubb34\ud6a8\uc0ac\uc720 \ud30c\ud2b8\ub9cc \uc2dc\ud5d8\uc5d0 \ucd9c\uc81c\ub418\uace0 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\ub294 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\ub294 \ud615\uc0ac\uc808\ucc28\ub9cc\uc744 \ub2e4\ub8e8\ub294 \ud30c\ud2b8\uc774\ub2e4"],t.s)
