B.ai6=new A.c("gen_clause_review_exam_4","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uc9c0\uc2dd\uc744 \uc2e4\ubb34\uc5d0 \uc801\uc6a9\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc7a5\uba74\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.aaT,0,"\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc9c0\uc2dd\uc744 \uc2e4\ubb34\uc5d0 \uc801\uc6a9\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc7a5\uba74\uc740, \uac00\ub9f9\ubcf8\ubd80\uc758 \uac00\ub9f9\uacc4\uc57d\uc11c(\uc57d\uad00)\ub97c \uc0ac\uc804\uc5d0 \uac80\ud1a0\ud558\uc5ec \ud5a5\ud6c4 \uc2ec\uc0ac\uccad\uad6c\ub098 \uc9c1\uad8c\uc2ec\uc0ac\uc758 \ub300\uc0c1\uc774 \ub420 \ub9cc\ud55c \ubd88\uacf5\uc815 \uc18c\uc9c0\uac00 \uc788\ub294 \uc870\ud56d\uc744 \ubbf8\ub9ac \ubc1c\uacac\ud558\uace0 \uc218\uc815\ud558\ub3c4\ub85d \uc790\ubb38\ud568\uc73c\ub85c\uc368 \ub9ac\uc2a4\ud06c\ub97c \uc608\ubc29\ud558\ub294 \uac83\uc774\ub2e4.",B.SO,B.acd,null)
