B.am1=new A.c("gen_clause_review_exam_5","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2ec\uc0ac\uccad\uad6c\uac00 \uae30\uac01\ub418\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a0m,0,"\uc57d\uad00 \uc2ec\uc0ac\uccad\uad6c\ub294 \uc2ec\uc0ac \uacb0\uacfc \ud574\ub2f9 \uc57d\uad00 \uc870\ud56d\uc774 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \ud310\ub2e8\ub418\ub294 \uacbd\uc6b0 \uae30\uac01\ub418\uac70\ub098 \ubb34\ud610\uc758\ub85c \ucc98\ub9ac\ub420 \uc218 \uc788\ub2e4. \uc2e0\uccad\uc11c\uc758 \ud615\uc2dd\uc801 \uc0ac\ud56d(\uc0c9\uae54, \uc81c\ucd9c \uc694\uc77c)\uc774\ub098 \uc2e0\uccad\uc778\uc758 \uc720\ud615(\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc5ec\ubd80) \uc790\uccb4\uac00 \uae30\uac01 \uc0ac\uc720\uac00 \ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Tm,B.R1,null)
B.LR=s([u.ud,"\uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758\ub294 \uc57d\uad00 \uc0ac\uac74\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uc808\ucc28\uc774\ub2e4","\uc2ec\uc758\ub294 \ud56d\uc0c1 \uc704\uc6d0\uc7a5 1\uc778\uc758 \ub2e8\ub3c5 \uacb0\uc815\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758\ub294 \uc624\uc9c1 \ud615\uc0ac\uc0ac\uac74\uc5d0\uc11c\ub9cc \uc5f4\ub9b0\ub2e4","\uc2ec\uc758 \uc808\ucc28\ub294 \uc0ac\uc5c5\uc790\uc758 \ucc38\uc5ec\ub97c \uc644\uc804\ud788 \ubc30\uc81c\ud55c \ucc44 \uc9c4\ud589\ub41c\ub2e4"],t.s)
