B.al8=new A.c("gen_clause_review_exam_6","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\uc5d0\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758 \uc2ec\uc758 \uc808\ucc28\uac00 \uac16\ub294 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.LR,0,"\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815 \uc0ac\uac74\ub3c4 \ub2e4\ub978 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc0ac\uac74\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc0ac\uac74\uc758 \uacbd\uc911\uc5d0 \ub530\ub77c \uc804\uc6d0\ud68c\uc758 \ub610\ub294 \uc18c\ud68c\uc758\ub77c\ub294 \ud569\uc758\uccb4 \ubc29\uc2dd\uc73c\ub85c \uc2ec\uc758\xb7\uc758\uacb0\ub418\uba70, \uc774\ub294 \uc704\uc6d0\uc7a5 1\uc778\uc758 \ub2e8\ub3c5 \uacb0\uc815\uc774 \uc544\ub2cc \ud569\uc758\uccb4 \uc2ec\uc758\ub97c \ud1b5\ud574 \uc808\ucc28\uc758 \uacf5\uc815\uc131\uacfc \uc2e0\uc911\ud568\uc744 \ud655\ubcf4\ud558\ub294 \uae30\ub2a5\uc744 \ud55c\ub2e4.",B.Hz,B.Pe,null)
B.a1t=s([u.M,"\ud53c\uc2ec\uc778\uc740 \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc758 \ub0b4\uc6a9\uc744 \uc804\ud600 \uc5f4\ub78c\ud560 \uc218 \uc5c6\ub2e4","\ud53c\uc2ec\uc778\uc740 \uc2ec\uc758 \uc808\ucc28\uc5d0 \uc5b4\ub5a0\ud55c \ud615\ud0dc\ub85c\ub3c4 \ucc38\uc5ec\ud560 \uc218 \uc5c6\ub2e4","\uc2ec\uc0ac\ubcf4\uace0\uc11c\uac00 \uc791\uc131\ub418\uba74 \uadf8 \uc989\uc2dc \uc2dc\uc815\uba85\ub839\uc774 \uc790\ub3d9\uc73c\ub85c \ud655\uc815\ub41c\ub2e4","\ud53c\uc2ec\uc778\uc758 \uc758\uacac \uc81c\ucd9c\uc740 \ubc95\ub960\uc0c1 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.aiz=new A.c("gen_clause_review_exam_7","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2dc\uc815 \uc0ac\uac74\uc5d0\uc11c \ud53c\uc2ec\uc778(\uc0ac\uc5c5\uc790)\uc774 \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc5d0 \ub300\ud574 \uac16\ub294 \uc808\ucc28\uc801 \uad8c\ub9ac\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1t,0,"\uc57d\uad00 \uc2dc\uc815 \uc0ac\uac74\uc5d0\uc11c\ub3c4 \uc2ec\uc0ac\uad00\uc774 \uc791\uc131\ud55c \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc5d0 \ub300\ud574 \ud53c\uc2ec\uc778\uc740 \uc758\uacac\uc744 \uc81c\ucd9c\ud558\uace0, \uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758 \uc2ec\uc758 \uacfc\uc815\uc5d0\uc11c \uc758\uacac\uc744 \uc9c4\uc220\ud560 \uae30\ud68c\ub97c \uac00\uc9c8 \uc218 \uc788\ub2e4. \uc774\ub294 \ucc98\ubd84\uc5d0 \uc55e\uc11c \ud53c\uc2ec\uc778\uc758 \ubc29\uc5b4\uad8c\uc744 \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \ud575\uc2ec\uc801\uc778 \uc808\ucc28\uc774\ub2e4.",B.nS,B.no,null)
B.Se=s([u.if,"\uc57d\uad00 \uc2dc\uc815\uc808\ucc28\uc5d0\ub294 \ucc98\ubd84\uc2dc\ud6a8 \uac1c\ub150\uc774 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc57d\uad00 \uc2dc\uc815\uba85\ub839\uc740 \uc2dc\ud6a8\uc640 \ubb34\uad00\ud558\uac8c \uc5b8\uc81c\ub4e0\uc9c0 \ubb34\uc81c\ud55c\uc73c\ub85c \ub0b4\ub9b4 \uc218 \uc788\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \uc624\uc9c1 \ud615\uc0ac\uc0ac\uac74\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub418\uace0 \uc57d\uad00 \uc0ac\uac74\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\uc57d\uad00 \uc2dc\uc815\uc808\ucc28\uc758 \ucc98\ubd84\uc2dc\ud6a8\ub294 \ud56d\uc0c1 \uc989\uc2dc \uc644\uc131\ub41c\ub2e4"],t.s)
