B.aku=new A.c("gen_pc_nature_5","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8","\uacfc\uc9d5\uae08 \uc81c\ub3c4\uac00 \uc190\ud574\ubc30\uc0c1 \uc81c\ub3c4\uc640 \uad6c\ubcc4\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a59,0,"\uacfc\uc9d5\uae08\uc740 \uad6d\uac00(\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c)\uac00 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ubd80\uacfc\ud558\ub294 \ud589\uc815\uc81c\uc7ac\uc778 \ubc18\uba74, \uc190\ud574\ubc30\uc0c1\uc740 \uc2e4\uc81c \ud53c\ud574\ub97c \uc785\uc740 \uc790\uac00 \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc81c\uae30\ud558\ub294 \ubbfc\uc0ac\uc801 \uad6c\uc81c\uc218\ub2e8\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \uadfc\ubcf8\uc801\uc73c\ub85c \uad6c\ubcc4\ub41c\ub2e4. \uacfc\uc9d5\uae08 \ubd80\uacfc \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ud53c\ud574\uc790\ub294 \ubcc4\ub3c4\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\uc73c\uba70, \ub450 \uc81c\ub3c4\ub294 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4.",B.a2r,B.a9U,null)
B.acT=s([u.wF,"\uacfc\uc9d5\uae08\uc740 \uc608\ubc29\uc801 \uae30\ub2a5\uacfc\ub294 \ubb34\uad00\ud558\uace0 \uc624\uc9c1 \uc0ac\ud6c4\uc801 \ucc98\ubc8c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\uc5b5\uc9c0\ub825\uc740 \ud615\uc0ac\ucc98\ubc8c\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub418\uace0 \uacfc\uc9d5\uae08\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\uacfc\uc9d5\uae08 \uc561\uc218\uac00 \ub0ae\uc744\uc218\ub85d \uc5b5\uc9c0\ub825\uc774 \ucee4\uc9c4\ub2e4","\uc5b5\uc9c0\ub825\uc740 \uc0ac\uc5c5\uc790\uc758 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uc791\ub3d9\ud55c\ub2e4"],t.s)
