B.UY=s(["\uc704\ubc18\uc0ac\uc5c5\uc790\uac00 \uc870\uc0ac\uc5d0 \uc801\uadf9 \ud611\uc870\ud558\uace0 \uc790\uc9c4\ud558\uc5ec \uc2dc\uc815\ud55c \uacbd\uc6b0"],t.s)
