B.alU=new A.c("gen_pc_calc_5","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08 \uc0b0\uc815\uae30\uc900",'\uacfc\uc9d5\uae08 \uc0b0\uc815 \uacfc\uc815\uc5d0\uc11c "\uae30\ubcf8 \uc0b0\uc815\uae30\uc900"\uc5d0 \uc704\ubc18\ud589\uc704\uc758 \uc911\ub300\uc131 \ub4f1\uc5d0 \ub530\ub978 \uc870\uc815\uc744 \uac70\uce58\ub294 \uc77c\ubc18\uc801 \uc0b0\uc815 \uc808\ucc28\uc758 \uc21c\uc11c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Xf,0,"\uacfc\uc9d5\uae08\uc740 \uc77c\ubc18\uc801\uc73c\ub85c \uad00\ub828\ub9e4\ucd9c\uc561 \ub4f1\uc744 \uae30\ucd08\ub85c \ud55c \uae30\ubcf8 \uc0b0\uc815\uae30\uc900\uc744 \uc815\ud558\uace0, \uc704\ubc18\ud589\uc704\uc758 \uc720\ud615\xb7\uc815\ub3c4\uc5d0 \ub530\ub978 \uc870\uc815\uacfc \uc704\ubc18\uc0ac\uc5c5\uc790\ubcc4 \uac00\uc911\xb7\uac10\uacbd \uc0ac\uc720(\uc870\uc0ac\ud611\uc870, \uc7ac\ubc94 \ub4f1)\ub97c \ubc18\uc601\ud558\ub294 \ub2e8\uacc4\ub97c \uac70\uccd0 \ucd5c\uc885 \ubd80\uacfc \uacfc\uc9d5\uae08\uc744 \uc0b0\uc815\ud558\ub294 \uc808\ucc28\ub97c \ub530\ub978\ub2e4.",B.a4H,B.O1,null)
B.a7j=s(["\uc704\ubc18\ud589\uc704 \uc720\ud615\ubcc4\ub85c \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\ub098 \uc0ac\ud68c\uc801 \ud3d0\ud574\uc758 \uc815\ub3c4\uac00 \ub2e4\ub974\uae30 \ub54c\ubb38\uc774\ub2e4","\uacfc\uc9d5\uae08 \uc0c1\ud55c\uc740 \uc704\ubc18\ud589\uc704 \uc720\ud615\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ub3d9\uc77c\ud558\ub2e4","\uc0c1\ud55c \ube44\uc728\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc790\uc0b0 \uaddc\ubaa8\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4","\uc0c1\ud55c \ube44\uc728\uc740 \ub9e4\ub144 \ubb34\uc791\uc704\ub85c \ubcc0\uacbd\ub41c\ub2e4","\uc0c1\ud55c \ube44\uc728\uc740 \uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uad6d\uc801\uc5d0 \ub530\ub77c\uc11c\ub9cc \ub2ec\ub77c\uc9c4\ub2e4"],t.s)
B.a42=s(["\uc704\ubc18\ud589\uc704 \uc720\ud615\ubcc4\ub85c \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\ub098 \uc0ac\ud68c\uc801 \ud3d0\ud574\uc758 \uc815\ub3c4\uac00 \ub2e4\ub974\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
