B.aov=new A.c("gen_pc_calc_6","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08 \uc0b0\uc815\uae30\uc900","\uc704\ubc18\ud589\uc704 \uc720\ud615\uc5d0 \ub530\ub77c \uacfc\uc9d5\uae08 \uc0c1\ud55c \ube44\uc728\uc774 \ub2e4\ub974\uac8c \uc815\ud574\uc9c8 \uc218 \uc788\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a7j,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub098 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ucc98\ub7fc \uacbd\uc7c1\uc9c8\uc11c\uc5d0 \ubbf8\uce58\ub294 \ud3d0\ud574\uac00 \ud070 \uac83\uc73c\ub85c \ud3c9\uac00\ub418\ub294 \uc704\ubc18\ud589\uc704 \uc720\ud615\uc740 \uc0c1\ub300\uc801\uc73c\ub85c \ub192\uc740 \uacfc\uc9d5\uae08 \uc0c1\ud55c \ube44\uc728\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub294 \ubc18\uba74, \uc0c1\ub300\uc801\uc73c\ub85c \ud3d0\ud574\uac00 \uc791\ub2e4\uace0 \ud3c9\uac00\ub418\ub294 \uc720\ud615\uc740 \ub0ae\uc740 \uc0c1\ud55c\uc774 \uc801\uc6a9\ub418\ub294 \ub4f1 \uc704\ubc18\ud589\uc704 \uc720\ud615\ubcc4\ub85c \uc0c1\ud55c \ube44\uc728\uc774 \ucc28\ub4f1\ud654\ub420 \uc218 \uc788\ub2e4.",B.a42,B.Q5,null)
B.Yn=s([u.i5,"\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc0ac\uc5c5\uc790\uc758 \uc804\uccb4 \uc0ac\uc5c5\ubd84\uc57c \ub9e4\ucd9c\uc561\uc744 \uc758\ubbf8\ud558\uba70 \uc704\ubc18\ud589\uc704\uc640 \ubb34\uad00\ud55c \ubd80\ubd84\ub3c4 \ud3ec\ud568\ud55c\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc804\uc138\uacc4 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc704\ubc18\ud589\uc704 \ubc1c\uc0dd \uc774\uc804 10\ub144\uac04\uc758 \ub204\uc801 \ub9e4\ucd9c\uc561\uc744 \uc758\ubbf8\ud55c\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc704\ubc18\uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uc2e0\uace0\ud558\ub294 \uae08\uc561\uc73c\ub85c\ub9cc \uc815\ud574\uc9c4\ub2e4"],t.s)
