B.akk=new A.c("gen_pc_sales_2","economic_law","\uacfc\uc9d5\uae08","\uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815","\uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.K1,0,"\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\ub97c \ub300\ube44\ud558\uc5ec, \uacf5\uc815\uac70\ub798\ubc95\ub839\uc740 \uc77c\uc815\ud55c \uc815\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud55c \ubcc4\ub3c4\uc758 \uacfc\uc9d5\uae08 \uc0c1\ud55c\uc744 \ub9c8\ub828\ud574 \ub450\uace0 \uc788\ub2e4. \uc774\ub97c \ud1b5\ud574 \ub9e4\ucd9c\uc561 \uc790\ub8cc\uac00 \ubd80\uc871\ud55c \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud574\uc11c\ub3c4 \uacfc\uc9d5\uae08 \ubd80\uacfc\uc758 \uacf5\ubc31\uc774 \uc0dd\uae30\uc9c0 \uc54a\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4.",B.KE,B.Y8,null)
