B.aq8=new A.c("gen_pc_sales_3","economic_law","\uacfc\uc9d5\uae08","\uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815","\uc704\ubc18\ud589\uc704 \uae30\uac04 \uc0b0\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Rp,0,"\uc704\ubc18\ud589\uc704 \uae30\uac04\uc740 \uc2e4\uc81c\ub85c \ubb38\uc81c\ub41c \uc704\ubc18\ud589\uc704\uac00 \uac1c\uc2dc\ub418\uc5b4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc885\ub8cc\ub41c \uc2dc\uc810\uae4c\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \uc774\ub294 \uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815 \uae30\uac04\uacfc\ub3c4 \ubc00\uc811\ud558\uac8c \uc5f0\uacb0\ub41c\ub2e4. \uc870\uc0ac \uac1c\uc2dc\uc77c\uc774\ub098 \ucc98\ubd84\uc77c \uc790\uccb4\uac00 \uc704\ubc18\ud589\uc704 \uae30\uac04\uc744 \uacb0\uc815\ud558\ub294 \uae30\uc900\uc740 \uc544\ub2c8\ub2e4.",B.aaq,B.a8K,null)
B.Mh=s([u.i,"\uc5ec\ub7ec \uc2dc\uc7a5\uc5d0 \uac78\uce5c \uc704\ubc18\ud589\uc704\ub294 \ud56d\uc0c1 \ud558\ub098\uc758 \uc2dc\uc7a5 \ub9e4\ucd9c\uc561\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4","\uc5ec\ub7ec \uc2dc\uc7a5\uc5d0 \uac78\uce5c \uc704\ubc18\ud589\uc704\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \ub9e4\ucd9c\uc561\uc740 \uace0\ub824\ud558\uc9c0 \uc54a\uace0 \uc815\uc561\uacfc\uc9d5\uae08\ub9cc \ubd80\uacfc\ub41c\ub2e4","\uc5ec\ub7ec \uc2dc\uc7a5\uc5d0 \uac78\uce5c \uc704\ubc18\uc740 \ubc18\ub4dc\uc2dc \uac1c\ubcc4 \uc0ac\uac74\uc73c\ub85c \ubd84\ub9ac\ud574\uc11c\ub9cc \ucc98\ub9ac\ud574\uc57c \ud55c\ub2e4"],t.s)
