B.ar9=new A.c("gen_pc_sales_4","economic_law","\uacfc\uc9d5\uae08","\uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815","\uc5ec\ub7ec \uac1c\uc758 \uad00\ub828\uc2dc\uc7a5\uc5d0 \uac78\uccd0 \uc704\ubc18\ud589\uc704\uac00 \uc774\ub8e8\uc5b4\uc9c4 \uacbd\uc6b0 \uad00\ub828\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Mh,0,"\uc704\ubc18\ud589\uc704\uac00 \uc5ec\ub7ec \uad00\ub828\uc2dc\uc7a5\uc5d0 \uac78\uccd0 \uc774\ub8e8\uc5b4\uc9c4 \uacbd\uc6b0\uc5d0\ub294, \uc6d0\uce59\uc801\uc73c\ub85c \uac01 \uad00\ub828\uc2dc\uc7a5\ubcc4\ub85c \uc704\ubc18\ud589\uc704\uc640 \uad00\ub828\ub41c \ub9e4\ucd9c\uc561\uc744 \uac1c\ubcc4\uc801\uc73c\ub85c \uc0b0\uc815\ud558\uc5ec \uc774\ub97c \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\ub294 \ubc29\uc2dd\uc774 \ud569\ub9ac\uc801\uc778 \uc811\uadfc\uc73c\ub85c \uc774\ud574\ub41c\ub2e4. \uc774\ub294 \uc704\ubc18\ud589\uc704\uc758 \uc2e4\uc9c8\uc801 \uaddc\ubaa8\uc640 \uc601\ud5a5\uc744 \uc815\ud655\ud788 \ubc18\uc601\ud558\uae30 \uc704\ud568\uc774\ub2e4.",B.Y_,B.ZY,null)
