B.H1=s([u.Et,"\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \ud615\uc0ac\ucc98\ubc8c\uc758 \ud615\ub7c9 \uc0b0\uc815\uc5d0\ub9cc \uc0ac\uc6a9\ub418\uace0 \uacfc\uc9d5\uae08\uacfc\ub294 \ubb34\uad00\ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc624\uc9c1 \uc138\ubb34\ub2f9\uad6d\uc758 \uc138\uae08 \ubd80\uacfc\ub97c \uc704\ud55c \uc790\ub8cc\uc77c \ubfd0\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\uae30 \ub54c\ubb38\uc774\ub2e4","\uad00\ub828\ub9e4\ucd9c\uc561\uc740 \uc18c\ube44\uc790 \ud53c\ud574\uad6c\uc81c \uc808\ucc28\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
