B.aoc=new A.c("gen_pc_proc_5","economic_law","\uacfc\uc9d5\uae08","\ubd80\uacfc\uc808\ucc28\xb7\uac10\uba74","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\uc758 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08 \uac10\uba74\uc81c\ub3c4\uc758 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.KA,0,'\ub2f4\ud569\uc740 \uc740\ubc00\ud558\uac8c \uc774\ub8e8\uc5b4\uc838 \uc678\ubd80\uc5d0\uc11c \uc801\ubc1c\ud558\uae30 \uc5b4\ub824\uc6b4 \uacbd\uc6b0\uac00 \ub9ce\uc73c\ubbc0\ub85c, \ucc38\uc5ec \uc0ac\uc5c5\uc790\uac00 \uc790\ubc1c\uc801\uc73c\ub85c \uc2e0\uace0\ud558\uace0 \uc870\uc0ac\uc5d0 \ud611\uc870\ud558\uba74 \uacfc\uc9d5\uae08 \ub4f1\uc744 \uac10\uba74\ud574\uc8fc\ub294 \uc81c\ub3c4\ub97c \ud1b5\ud574 \ub2f4\ud569 \ub0b4\ubd80\uc790\uc758 \uc2e0\uace0\ub97c \uc720\uc778\ud568\uc73c\ub85c\uc368 \uc801\ubc1c\ub960\uc744 \ub192\uc774\uace0 \ub2f4\ud569\uc758 \uc548\uc815\uc131\uc744 \uc800\ud574\ud558\ub824\ub294 \uc815\ucc45\uc801 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4. (\uc138\ubd80 \uc694\uac74\uacfc \uac10\uba74 \uc21c\uc704 \ub4f1\uc740 "\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74" \ucc55\ud130\uc5d0\uc11c \ubcc4\ub3c4\ub85c \uc790\uc138\ud788 \ub2e4\ub8ec\ub2e4.)',B.P8,B.Ql,null)
B.a1D=s([u.eG,"\uc704\ubc18\uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud558\uba74 \uacfc\uc9d5\uae08 \ucc45\uc784\ub3c4 \uc644\uc804\ud788 \uc18c\uba78\ud55c\ub2e4","\ud569\ubcd1 \ud6c4 \ud68c\uc0ac\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacfc\uc9d5\uae08 \ucc45\uc784\uc744 \uc9c0\uc9c0 \uc54a\ub294\ub2e4","\ud569\ubcd1 \uc2dc \uacfc\uc9d5\uae08\uc740 \uc790\ub3d9\uc73c\ub85c \uad6d\uac00\uc5d0 \uadc0\uc18d\ub418\uc5b4 \uc18c\uba78\ub41c\ub2e4","\ud569\ubcd1 \ud6c4 \ud68c\uc0ac\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \ubc95\ub960\uc0c1 \uae08\uc9c0\ub41c\ub2e4"],t.s)
