B.a4F=s([u.B2,"\uc624\uc9c1 \ucc98\ubd84\uccad \ub2f4\ub2f9\uc790\uc758 \uac1c\uc778 \uc2e0\uc0c1\ub9cc\uc744 \uc2ec\ub9ac\ud55c\ub2e4","\uc624\uc9c1 \uc2e0\uccad\uc778\uc758 \uc7ac\uc0b0 \uaddc\ubaa8\ub9cc\uc744 \uc2ec\ub9ac\ud55c\ub2e4","\ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c\ub294 \uc5b4\ub5a0\ud55c \uc2ec\ub9ac\ub3c4 \uc774\ub8e8\uc5b4\uc9c0\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ucc98\ubd84\uc11c\uc758 \uc885\uc774 \uc7ac\uc9c8\ub9cc\uc744 \uc2ec\ub9ac\ud55c\ub2e4"],t.s)
