B.akc=new A.c("gen_appeal_lawsuit_3","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\ud589\uc815\uc18c\uc1a1 \ub4f1 \uc0ac\ubc95\uc801 \ubd88\ubcf5\uc808\ucc28","\ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c \ubc95\uc6d0\uc774 \uc2ec\ub9ac\ud558\ub294 \ub0b4\uc6a9\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a4F,0,"\ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c \ubc95\uc6d0\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \ucc98\ubd84\uc758 \uc808\ucc28\uc801 \uc801\ubc95\uc131(\uc801\ubc95\uc808\ucc28 \uc900\uc218 \uc5ec\ubd80)\uacfc \uc2e4\uccb4\uc801 \uc704\ubc95\uc131(\uc0ac\uc2e4\uc778\uc815\uc758 \uc624\ub958, \ubc95\ub839 \uc801\uc6a9\xb7\ud574\uc11d\uc758 \uc624\ub958, \uc7ac\ub7c9\uad8c \uc77c\ud0c8\xb7\ub0a8\uc6a9 \uc5ec\ubd80 \ub4f1)\uc744 \uc885\ud569\uc801\uc73c\ub85c \uc2ec\ub9ac\ud558\uc5ec \ucc98\ubd84\uc758 \uc704\ubc95 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud55c\ub2e4.",B.L2,B.a_b,null)
B.a2m=s(["\ud574\ub2f9 \ucc98\ubd84\uc774 \ucde8\uc18c\ub418\uc5b4 \ucc98\ubd84\uc774 \uc5c6\uc5c8\ub358 \uc0c1\ud0dc\ub85c \ub418\ub3cc\uc544\uac00\ub294 \ud6a8\uacfc\uac00 \ubc1c\uc0dd\ud55c\ub2e4","\uc2b9\uc18c\ud574\ub3c4 \ucc98\ubd84\uc758 \ud6a8\ub825\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubcc0\ud654\ub3c4 \uc5c6\ub2e4","\uc2b9\uc18c\ud558\uba74 \uc624\ud788\ub824 \uc0c8\ub85c\uc6b4 \ucc98\ubd84\uc774 \uc790\ub3d9\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4","\uc2b9\uc18c \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ucc98\ubd84\uc740 \ud56d\uc0c1 \uadf8\ub300\ub85c \uc720\uc9c0\ub41c\ub2e4","\uc2b9\uc18c\ud558\uba74 \ucc98\ubd84\uccad\uc774 \ud615\uc0ac\ucc98\ubc8c\uc744 \ubc1b\ub294\ub2e4"],t.s)
