B.aoR=new A.c("gen_appeal_lawsuit_4","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\ud589\uc815\uc18c\uc1a1 \ub4f1 \uc0ac\ubc95\uc801 \ubd88\ubcf5\uc808\ucc28","\ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c \ucc98\ubd84\uc774 \uc704\ubc95\ud558\ub2e4\uace0 \uc778\uc815\ub418\uc5b4 \uc2b9\uc18c\ud55c \uacbd\uc6b0\uc758 \ud6a8\uacfc\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a2m,0,"\ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c \uc6d0\uace0(\ucc98\ubd84\uc758 \uc0c1\ub300\ubc29)\uac00 \uc2b9\uc18c\ud558\uba74, \ud574\ub2f9 \ucc98\ubd84\uc774 \ucde8\uc18c\ub418\uc5b4 \uadf8 \ucc98\ubd84\uc774 \uc560\ucd08\uc5d0 \uc5c6\uc5c8\ub358 \uc0c1\ud0dc\ub85c \ub418\ub3cc\uc544\uac00\ub294 \ud6a8\uacfc(\uc18c\uae09\uc801 \ud6a8\ub825 \uc0c1\uc2e4)\uac00 \ubc1c\uc0dd\ud558\uba70, \uc774\ub294 \ucc98\ubd84 \uc0c1\ub300\ubc29\uc758 \uad8c\ub9ac \uad6c\uc81c\ub97c \uc2e4\uc9c8\uc801\uc73c\ub85c \uc2e4\ud604\ud558\ub294 \ud575\uc2ec\uc801\uc778 \ud6a8\uacfc\uc774\ub2e4.",B.a0a,B.TO,null)
B.OK=s(["\uc9d1\ud589\uc815\uc9c0\ub97c \uc2e0\uccad\ud558\uc5ec \ubc95\uc6d0\uc758 \uacb0\uc815\uc744 \ubc1b\ub294 \ubc29\ubc95\uc774 \uc788\ub2e4","\ucde8\uc18c\uc18c\uc1a1\uc774 \uc81c\uae30\ub418\uba74 \ucc98\ubd84\uc758 \uc9d1\ud589\uc774 \uc5b8\uc81c\ub098 \uc790\ub3d9\uc73c\ub85c \uc815\uc9c0\ub41c\ub2e4","\uc9d1\ud589\uc815\uc9c0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc778\uc815\ub418\uc9c0 \uc54a\ub294 \uc81c\ub3c4\uc774\ub2e4","\uc9d1\ud589\uc815\uc9c0\ub294 \uc624\uc9c1 \ucc98\ubd84\uccad\uc758 \ub3d9\uc758\uac00 \uc788\uc5b4\uc57c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc9d1\ud589\uc815\uc9c0\ub294 \ucde8\uc18c\uc18c\uc1a1\uacfc \uc644\uc804\ud788 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uc808\ucc28\uc774\ub2e4"],t.s)
