B.Uq=s(["\ub300\ubc95\uc6d0\uc5d0 \uc0c1\uace0\ub97c \uc81c\uae30\ud558\ub294 \uc808\ucc28\ub97c \uc774\uc6a9\ud560 \uc218 \uc788\ub2e4","\uace0\ub4f1\ubc95\uc6d0 \ud310\uacb0\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0c1\uace0\ub294 \uc624\uc9c1 \uac80\ucc30\ub9cc \uc81c\uae30\ud560 \uc218 \uc788\ub2e4","\uace0\ub4f1\ubc95\uc6d0 \ud310\uacb0\uc740 \ud56d\uc0c1 \ucd5c\uc885\uc801\uc774\uba70 \ub2e4\ud234 \ubc29\ubc95\uc774 \uc5c6\ub2e4","\uc0c1\uace0\ub294 \ud5cc\ubc95\uc7ac\ud310\uc18c\uc5d0 \uc81c\uae30\ud558\ub294 \uc808\ucc28\uc774\ub2e4"],t.s)
