B.al7=new A.c("gen_appeal_lawsuit_6","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\ud589\uc815\uc18c\uc1a1 \ub4f1 \uc0ac\ubc95\uc801 \ubd88\ubcf5\uc808\ucc28","\uace0\ub4f1\ubc95\uc6d0\uc758 \ud310\uacb0\uc5d0 \ub300\ud574 \ub2e4\uc2dc \ubd88\ubcf5\ud558\uace0\uc790 \ud558\ub294 \uacbd\uc6b0 \ucde8\ud560 \uc218 \uc788\ub294 \uc808\ucc28\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Uq,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \ucc98\ubd84\uc5d0 \ub300\ud55c \ucde8\uc18c\uc18c\uc1a1\uc744 \uc2ec\ub9ac\ud55c \uace0\ub4f1\ubc95\uc6d0\uc758 \ud310\uacb0\uc5d0 \ubd88\ubcf5\ud558\ub294 \ub2f9\uc0ac\uc790\ub294, \ud1b5\uc0c1\uc801\uc778 \uc2ec\uae09 \uad6c\uc870\uc5d0 \ub530\ub77c \ub300\ubc95\uc6d0\uc5d0 \uc0c1\uace0\ub97c \uc81c\uae30\ud558\uc5ec \ubc95\ub960\uc2ec \ucc28\uc6d0\uc758 \uc7ac\uc2ec\uc0ac\ub97c \ubc1b\uc744 \uc218 \uc788\ub2e4.",B.abv,B.NJ,null)
B.SD=s([u.wq,"\uc624\uc9c1 \ud310\uc0ac \uac1c\uc778\uc758 \uc2e0\uc0c1 \uc815\ubcf4\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\uc640 \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc774 \ud30c\ud2b8 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ubc95\uc6d0 \uccad\uc0ac\uc758 \uce35\uc218\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
