B.alu=new A.c("gen_appeal_exam_1","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.SD,0,"\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\ub294 \uc774\uc758\uc2e0\uccad\uc774 \ud589\uc815\uc18c\uc1a1\uc758 \ud544\uc218\uc801 \uc804\uce58\uc808\ucc28\uac00 \uc544\ub2c8\ub77c\ub294 \uc810, \ucde8\uc18c\uc18c\uc1a1\uc758 \uc804\uc18d\uad00\ud560\uc774 \uc11c\uc6b8\uace0\ub4f1\ubc95\uc6d0\uc774\ub77c\ub294 \uc810\uacfc \uc81c\uc18c\uae30\uac04\uc774\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.Sr,B.ba,null)
B.a8i=s(["\uc774\uc758\uc2e0\uccad\uc744 \ubc18\ub4dc\uc2dc \uac70\uccd0\uc57c\ub9cc \ud589\uc815\uc18c\uc1a1\uc744 \uc81c\uae30\ud560 \uc218 \uc788\ub2e4\uace0 \uc11c\uc220\ud558\ub294 \uc120\ud0dd\uc9c0","\uac00\ub9f9\uacc4\uc57d\uc11c\uc758 \ud3f0\ud2b8 \ud06c\uae30\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uce35\uc218\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc704\uc6d0\uc7a5\uc758 \uac1c\uc778 \ucde8\ubbf8\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc2ec\uc0ac\uccad\uad6c \uc811\uc218 \ucc3d\uad6c\uc758 \uc8fc\uc18c\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0"],t.s)
B.RT=s(["\uc774\uc758\uc2e0\uccad\uc744 \ubc18\ub4dc\uc2dc \uac70\uccd0\uc57c\ub9cc \ud589\uc815\uc18c\uc1a1\uc744 \uc81c\uae30\ud560 \uc218 \uc788\ub2e4\uace0 \uc11c\uc220\ud558\ub294 \uc120\ud0dd\uc9c0"],t.s)
B.an7=new A.c("gen_appeal_exam_2","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\uc5d0\uc11c \uc790\uc8fc \ucd9c\uc81c\ub418\ub294 \ud568\uc815 \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a8i,0,"\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28 \ubb38\uc81c\uc5d0\uc11c\ub294 \uc774\uc758\uc2e0\uccad\uc744 \ud544\uc218\uc801 \uc804\uce58\uc808\ucc28\ub85c \uc11c\uc220\ud558\uc5ec \uc774\ub97c \uac70\uce58\uc9c0 \uc54a\uc73c\uba74 \ud589\uc815\uc18c\uc1a1\uc744 \uc81c\uae30\ud560 \uc218 \uc5c6\ub2e4\uace0 \uc624\ub3c4\ud558\ub294 \uc120\ud0dd\uc9c0\uac00 \ud568\uc815\uc73c\ub85c \uc790\uc8fc \ucd9c\uc81c\ub418\ubbc0\ub85c, \uc774\uc758\uc2e0\uccad\uc774 \uc784\uc758\uc801 \uc808\ucc28\ub77c\ub294 \uc810\uc744 \uc815\ud655\ud788 \uad6c\ubcc4\ud574 \ub450\uc5b4\uc57c \ud55c\ub2e4.",B.RT,B.ct,null)
B.Kt=s([u.jK,"\ubd88\ubcf5\uc808\ucc28\ub294 \uc544\ubb34 \ub54c\ub098 \uc81c\uae30\ud574\ub3c4 \ubb34\ubc29\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc774\uc758\uc2e0\uccad\uacfc \ud589\uc815\uc18c\uc1a1\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc808\ucc28\ub77c\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\ubd88\ubcf5\uc808\ucc28\ub294 \uc790\ubb38\ud560 \ud544\uc694\uac00 \uc5c6\ub294 \uc0ac\ud56d\uc774\ub77c\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\ucc98\ubd84\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\uc808\ucc28\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
B.a12=s([u.jK],t.s)
B.Wf=s(["\ubd88\ubcf5\uc808\ucc28 \uc790\ubb38 \uc2dc \uc720\uc758\uc0ac\ud56d"],t.s)
B.aqv=new A.c("gen_appeal_exam_3","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uc2dc\uc815\uba85\ub839\xb7\uacfc\uc9d5\uae08 \ucc98\ubd84\uc744 \ubc1b\uc740 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \ubd88\ubcf5\uc808\ucc28\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Kt,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \ucc98\ubd84\uc744 \ubc1b\uc740 \uac00\ub9f9\ubcf8\ubd80\uc5d0\uac8c \uc774\uc758\uc2e0\uccad\uacfc \ud589\uc815\uc18c\uc1a1(\ucde8\uc18c\uc18c\uc1a1) \uac01\uac01\uc758 \uc808\ucc28\uc801 \ud2b9\uc131(\uc81c\uae30 \uae30\uac04, \uad00\ud560, \uc804\uce58 \uc5ec\ubd80)\uc744 \uc815\ud655\ud788 \uc548\ub0b4\ud558\uc5ec, \uc815\ud574\uc9c4 \uae30\uac04 \ub0b4\uc5d0 \uc801\uc808\ud55c \ubd88\ubcf5 \uc218\ub2e8\uc744 \ub193\uce58\uc9c0 \uc54a\uace0 \ud65c\uc6a9\ud560 \uc218 \uc788\ub3c4\ub85d \ub3d5\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4.",B.a12,B.Wf,null)
B.a1l=s([u.u2,"\ubd88\ubcf5\uc808\ucc28\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd88\uc774\uc775\ub9cc \uc8fc\uae30 \uc704\ud55c \uac83\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ubd88\ubcf5\uc808\ucc28 \uc815\ube44\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc5c5\ubb34\ub97c \uc904\uc774\uae30 \uc704\ud55c \uac83\uc77c \ubfd0\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ubd88\ubcf5\uc808\ucc28\ub294 \uc2e4\uc9c8\uc801\uc778 \uc815\ucc45\uc801 \ud6a8\uc6a9\uc774 \uc804\ud600 \uc5c6\uae30 \ub54c\ubb38\uc774\ub2e4","\ubd88\ubcf5\uc808\ucc28\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \ud655\uc815\uc744 \uc704\ud55c \uac83\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.SL=s([u.u2],t.s)
B.a3Q=s(["\ubd88\ubcf5\uc808\ucc28 \uc815\ube44\uc758 \uc815\ucc45\uc801 \uc774\uc720"],t.s)
B.alv=new A.c("gen_appeal_exam_4","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc808\ucc28\uac00 \uc2e0\uc18d\ud558\uac8c \uc815\ube44\ub418\uc5b4\uc57c \ud558\ub294 \uc815\ucc45\uc801 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1l,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc740 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ud65c\ub3d9\uacfc \uc2dc\uc7a5\uc5d0\uc11c\uc758 \uc9c0\uc704\uc5d0 \uc0c1\ub2f9\ud55c \uc601\ud5a5\uc744 \ubbf8\uce60 \uc218 \uc788\uc73c\ubbc0\ub85c, \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2e0\uc18d\ud558\uace0 \uc2e4\ud6a8\uc801\uc73c\ub85c \uad8c\ub9ac\ub97c \uad6c\uc81c\ubc1b\uc744 \uc218 \uc788\ub3c4\ub85d \uc774\uc758\uc2e0\uccad\xb7\ud589\uc815\uc18c\uc1a1 \ub4f1\uc758 \ubd88\ubcf5\uc808\ucc28\ub97c \uccb4\uacc4\uc801\uc73c\ub85c \uc815\ube44\ud560 \ud544\uc694\uac00 \uc788\ub2e4\ub294 \uac83\uc774 \uc815\ucc45\uc801 \uc774\uc720\uc774\ub2e4.",B.SL,B.a3Q,null)
B.a1e=s([u.u4,"\ub450 \ud30c\ud2b8\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \ub2e4\ub8e8\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\ub294 \uc870\uc0ac\uc808\ucc28\uc640 \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uadfc\uac70\ud55c\ub2e4","\uc870\uc0ac\uc808\ucc28\ub9cc \uc2dc\ud5d8\uc5d0 \ucd9c\uc81c\ub418\uace0 \uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\ub294 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\ub294 \ud615\uc0ac\uc808\ucc28\ub9cc\uc744 \ub2e4\ub8e8\ub294 \ud30c\ud2b8\uc774\ub2e4"],t.s)
B.XP=s([u.u4],t.s)
B.ab2=s(["\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\uc640 \uc870\uc0ac\uc808\ucc28\uc758 \uad00\uacc4"],t.s)
B.aoO=new A.c("gen_appeal_exam_5","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\uc640 \uc870\uc0ac\uc808\ucc28\xb7\ucc98\ubd84\uc2dc\ud6a8 \ud30c\ud2b8\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1e,0,"\uc870\uc0ac\uc808\ucc28 \ud30c\ud2b8\uac00 \uc2e0\uace0\xb7\uc778\uc9c0\ubd80\ud130 \uc2ec\uc758\xb7\ucc98\ubd84\uc5d0 \uc774\ub974\uae30\uae4c\uc9c0\uc758 \uacfc\uc815\uc744 \ub2e4\ub8ec\ub2e4\uba74, \uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28 \ud30c\ud2b8\ub294 \uadf8 \ucc98\ubd84\uc774 \ub0b4\ub824\uc9c4 \uc774\ud6c4 \ucc98\ubd84\uc758 \uc0c1\ub300\ubc29\uc774 \uc774\ub97c \ub2e4\ud22c\ub294 \uad8c\ub9ac\uad6c\uc81c \uc808\ucc28\ub97c \ub2e4\ub8ec\ub2e4\ub294 \uc810\uc5d0\uc11c, \ub450 \ud30c\ud2b8\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc0ac\uac74 \ucc98\ub9ac\uc758 \uc804\uccb4 \ud750\ub984\uc5d0\uc11c \uc55e\ub4a4\ub97c \uc774\ub8e8\ub294 \ubcf4\uc644\uc801 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.XP,B.ab2,null)
B.a_U=s([u.B0,"\uc99d\uba85\ucc45\uc784\uc740 \ud56d\uc0c1 \ucc98\ubd84\uc744 \ub2e4\ud22c\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc788\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \uc18c\ube44\uc790\ub2e8\uccb4\uc5d0\uac8c \uc788\ub2e4","\ucde8\uc18c\uc18c\uc1a1\uc5d0\ub294 \uc99d\uba85\ucc45\uc784\uc774\ub77c\ub294 \uac1c\ub150 \uc790\uccb4\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \uc624\uc9c1 \ubc95\uc6d0\uc758 \uc7ac\ub7c9\uc73c\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4"],t.s)
B.PK=s([u.B0],t.s)
B.HS=s(["\ucde8\uc18c\uc18c\uc1a1\uc758 \uc99d\uba85\ucc45\uc784"],t.s)
B.akT=new A.c("gen_appeal_exam_6","economic_law","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uc774\uc758\uc2e0\uccad\xb7\ubd88\ubcf5\uc808\ucc28\uc5d0\uc11c \uc99d\uba85\ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_U,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \ucc98\ubd84\uc5d0 \ub300\ud55c \ucde8\uc18c\uc18c\uc1a1\uc5d0\uc11c, \ucc98\ubd84\uc758 \uc801\ubc95\uc131(\uc704\ubc18\uc0ac\uc2e4\uc758 \uc874\uc7ac, \ucc98\ubd84\uc758 \uc815\ub2f9\uc131 \ub4f1)\uc5d0 \ub300\ud55c \uc99d\uba85\ucc45\uc784\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ucc98\ubd84\uc744 \ub0b4\ub9b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ubd80\ub2f4\ud558\ub294 \uac83\uc774 \ud589\uc815\uc18c\uc1a1\uc758 \uc77c\ubc18\uc801\uc778 \uc99d\uba85\ucc45\uc784 \ubd84\ubc30 \uc6d0\uce59\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.PK,B.HS,null)
