B.Vx=s(["\uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\xb7\ubd88\uc774\uc775\uc81c\uacf5\xb7\uacbd\uc601\uac04\uc12d 5\uac00\uc9c0\ub85c \uc2dc\ud589\ub839\uc5d0 \uc5f4\uac70"],t.s)
