B.ahi=new A.c("gen_ub_2","economic_law","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uc9c0\uc6d0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Q9,4,'\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ub300\ud574 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc778\ub825\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\uac70\ub098, \ud544\uc694 \uc774\uc0c1\uc758 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud574 \uc774\uc775\uc744 \ubab0\uc544\uc8fc\ub294 \ubc29\uc2dd\uc73c\ub85c \ubd80\ub2f9\ud558\uac8c \uc9c0\uc6d0\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \ubc18\uba74 \ub9c8\uc9c0\ub9c9 \uc120\ud0dd\uc9c0\ucc98\ub7fc \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc5d0 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \ud589\uc704\ub294 "\ubd80\ub2f9\uc5fc\ub9e4"\ub85c\uc11c, \uc774\ub294 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubaa9\uc801\uc758 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ub450 \uc720\ud615 \ubaa8\ub450 "\ubd80\ub2f9\ud558\uac8c \ub0ae\uc740/\uc720\ub9ac\ud55c \uc870\uac74"\uc774\ub77c\ub294 \uacf5\ud1b5\uc810 \ub54c\ubb38\uc5d0 \ud5f7\uac08\ub9ac\uae30 \uc27d\uc9c0\ub9cc, \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778\xb7\uacc4\uc5f4\uc0ac\uc5d0 \ub300\ud55c \uc774\uc775 \ubab0\uc544\uc8fc\uae30\uac00 \ud575\uc2ec\uc774\uace0 \ubd80\ub2f9\uc5fc\ub9e4\ub294 \uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ucd95\ucd9c\ud558\ub824\ub294 \uac00\uaca9\uc815\ucc45\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \uaddc\uc81c \ubaa9\uc801\uc774 \ub2e4\ub974\ub2e4.',B.aaj,B.UI,null)
B.a1A=s(["\ubd80\ub2f9\ud558\uac8c \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \uc54a\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\uc9c0\uc5ed\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \ud589\uc704\ub294 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc744 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc640\ub9cc \uac70\ub798\ud558\ub3c4\ub85d \uad6c\uc18d\ud558\ub294 \uac83\uc740 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a49=s(["\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1"],t.s)
B.abk=s(["\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798"],t.s)
B.ao0=new A.c("gen_ub_3","economic_law","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.a1A,0,'\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\ucc98 \uc120\ud0dd\uc774\ub098 \ud310\ub9e4 \uc9c0\uc5ed\xb7\ub300\uc0c1\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud558\uba70, \uadf8 \ub300\ud45c\uc801 \ud558\uc704 \uc720\ud615\uc774 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798(\uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uad6c\uc18d)\uc640 \uac70\ub798\uc9c0\uc5ed\xb7\uac70\ub798\uc0c1\ub300\ubc29 \uc81c\ud55c\uc774\ub2e4. \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1\ud560 \uc218 \uc788\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\uba70, "\ud56d\uc0c1 \uc801\ubc95"\ud558\ub2e4\ub294 \uc124\uba85(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub610\ud55c \uac70\ub798\uc9c0\uc5ed \uc81c\ud55c\uc740 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc774 \uc544\ub2c8\ub77c \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \uc790\uccb4\uc758 \ud558\uc704\uc720\ud615\uc774\uace0(\uc120\ud0dd\uc9c0 \u2461\ub294 \uc624\ub2f5), \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640\ub294 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615\uc774\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2463\ub3c4 \uc624\ub2f5)\uc744 \ud568\uaed8 \uc815\ub9ac\ud574\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.a49,B.abk,null)
B.a3T=s([u.D0,"\uc0ac\uc5c5\uc790\uac00 \ud1b5\uc0c1\uc801\uc778 \uc2dc\uc98c \ud560\uc778 \ud589\uc0ac\ub97c \uc9c4\ud589\ud558\ub294 \ud589\uc704","\uc7ac\uace0 \uc18c\uc9c4\uc744 \uc704\ud574 \uc77c\uc2dc\uc801\uc73c\ub85c \uac00\uaca9\uc744 \ub0ae\ucd94\ub294 \ud589\uc704","\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubcf4\ub2e4 \uc800\ub834\ud558\uac8c \ud310\ub9e4\ud558\uae30\ub9cc \ud558\uba74 \ud56d\uc0c1 \uc131\ub9bd\ud558\ub294 \ud589\uc704","\uc18c\ube44\uc790\uc5d0\uac8c \uc0ac\uc740\ud488\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704"],t.s)
