B.a6S=s(["\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc758\ubbf8"],t.s)
B.akn=new A.c("gen_predatory_def_1","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc758\ubbf8\xb7\ud310\ub2e8\uae30\uc900",'\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 "\ubd80\ub2f9\uc5fc\ub9e4"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a3T,0,'"\ubd80\ub2f9\uc5fc\ub9e4"\ub294 \uc790\uae30\uc758 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \ub370 \uc18c\uc694\ub418\ub294 \ube44\uc6a9\ubcf4\ub2e4 \ud604\uc800\ud788 \ub0ae\uc740 \ub300\uac00\ub85c \uacc4\uc18d\ud574\uc11c \uacf5\uae09\ud568\uc73c\ub85c\uc368 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\ub97c \uc758\ubbf8\ud55c\ub2e4. \ub2e8\uc21c\ud788 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ubcf4\ub2e4 \uc800\ub834\ud558\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \uc131\ub9bd\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \ube44\uc6a9\uc744 \ubc11\ub3c4\ub294 \uac00\uaca9\uc758 "\uacc4\uc18d\uc131"\uacfc \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\uc758 "\uc6b0\ub824"\uac00 \ud568\uaed8 \uc694\uad6c\ub41c\ub2e4.',B.VT,B.a6S,null)
B.JA=s([u.n,"\uac00\uaca9\uc744 \uc5bc\ub9c8\ub098 \ub0ae\ucdc4\ub294\uc9c0 \uadf8 \uc808\ub300\uc801\uc778 \uae08\uc561 \ud06c\uae30","\ud560\uc778 \ud589\uc0ac\uc758 \uba85\uce6d\uc774 \ubb34\uc5c7\uc778\uc9c0 \uc5ec\ubd80","\uac00\uaca9 \uc778\ud558\uac00 \uc774\ub8e8\uc5b4\uc9c4 \uc694\uc77c","\uc0c1\ud488\uc758 \uc0c9\uae54"],t.s)
