B.as2=new A.c("gen_predatory_def_2","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc758\ubbf8\xb7\ud310\ub2e8\uae30\uc900","\ubd80\ub2f9\uc5fc\ub9e4\uc640 \ud1b5\uc0c1\uc801\uc778 \uac00\uaca9 \ud560\uc778\xb7\uc7ac\uace0 \ucc98\ubd84 \ud310\ub9e4\ub97c \uad6c\ubcc4\ud558\ub294 \ud575\uc2ec \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.JA,0,"\ubd80\ub2f9\uc5fc\ub9e4\uc640 \ud1b5\uc0c1\uc801\uc778 \uac00\uaca9 \ud560\uc778\uc774\ub098 \uc77c\uc2dc\uc801 \uc7ac\uace0 \ucc98\ubd84 \ud310\ub9e4\ub97c \uad6c\ubcc4\ud558\ub294 \ud575\uc2ec \uae30\uc900\uc740, \uac00\uaca9 \uc778\ud558\uac00 \uc77c\ud68c\uc801\xb7\uc77c\uc2dc\uc801\uc778 \uac83\uc744 \ub118\uc5b4 \ube44\uc6a9 \uc774\ud558\uc758 \uc218\uc900\uc73c\ub85c \uacc4\uc18d\ub418\uc5b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubd80\ub2f9\ud55c \ubaa9\uc801\uc774\ub098 \ud6a8\uacfc\ub97c \uac16\ub294\uc9c0 \uc5ec\ubd80\uc774\ub2e4.",B.Nn,B.a0N,null)
B.Wm=s([u.zS,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c \uaddc\ubaa8\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \uac1c\uc778\uc801 \uc758\uacac\ub9cc \uace0\ub824\ud55c\ub2e4","\ubd80\ub2f9\uc131 \ud310\ub2e8\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \uc0c1\ud488\uc758 \uc0c9\uae54\ub9cc \uace0\ub824\ud55c\ub2e4"],t.s)
