B.are=new A.c("gen_predatory_def_3","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc758\ubbf8\xb7\ud310\ub2e8\uae30\uc900","\ubd80\ub2f9\uc5fc\ub9e4\uc758 \ubd80\ub2f9\uc131\uc744 \ud310\ub2e8\ud560 \ub54c \uace0\ub824\ud558\ub294 \uc694\uc18c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Wm,0,"\ubd80\ub2f9\uc5fc\ub9e4\uc758 \ubd80\ub2f9\uc131\uc744 \ud310\ub2e8\ud560 \ub54c\ub294 \ud310\ub9e4\uac00\uaca9\uacfc \uacf5\uae09\ube44\uc6a9\uc758 \ucc28\uc774 \uc815\ub3c4, \uc5fc\ub9e4\uac00 \uc5bc\ub9c8\ub098 \uc9c0\uc18d\uc801\uc73c\ub85c \uc774\ub8e8\uc5b4\uc84c\ub294\uc9c0, \uadf8\ub85c \uc778\ud574 \uad00\ub828\uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\uac00 \ubc1c\uc0dd\ud560 \uc6b0\ub824\uac00 \uc788\ub294\uc9c0 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4.",B.Mt,B.TE,null)
B.a5c=s([u.Bq,"\ubd80\ub2f9\uc5fc\ub9e4 \uaddc\uc81c\ub294 \uc18c\ube44\uc790\uc5d0\uac8c \ud56d\uc0c1 \ubd88\ub9ac\ud55c \uacb0\uacfc\ub9cc \uac00\uc838\uc624\uae30 \ub54c\ubb38\uc774\ub2e4","\ubd80\ub2f9\uc5fc\ub9e4 \uaddc\uc81c\ub294 \uc0ac\uc5c5\uc790\uc758 \uac00\uaca9\uacb0\uc815\uad8c \uc790\uccb4\ub97c \uc804\uba74 \ubd80\uc815\ud558\uae30 \uc704\ud568\uc774\ub2e4","\ubd80\ub2f9\uc5fc\ub9e4 \uaddc\uc81c\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5 \ubcf4\ud638\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\ubd80\ub2f9\uc5fc\ub9e4\ub294 \uacbd\uc7c1\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
