B.akM=new A.c("gen_predatory_def_5","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc758\ubbf8\xb7\ud310\ub2e8\uae30\uc900",'\ubd80\ub2f9\uc5fc\ub9e4\uc758 \uc720\ud615 \uc911 "\uacc4\uc18d\uac70\ub798\uc0c1\uc758 \ubd80\ub2f9\uc5fc\ub9e4"\uc640 "\uadf8 \ubc16\uc758 \uac70\ub798\uc0c1\uc758 \ubd80\ub2f9\uc5fc\ub9e4"\ub97c \uad6c\ubcc4\ud558\ub294 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.My,0,'\ubd80\ub2f9\uc5fc\ub9e4\ub294 \uadf8 \ud589\uc704 \ud0dc\uc591\uc5d0 \ub530\ub77c, \uc0c1\ub2f9\ud55c \uae30\uac04\uc5d0 \uac78\uccd0 \uacc4\uc18d\uc801\uc73c\ub85c \ube44\uc6a9 \uc774\ud558 \uac00\uaca9\uc744 \uc720\uc9c0\ud558\ub294 "\uacc4\uc18d\uac70\ub798\uc0c1\uc758 \ubd80\ub2f9\uc5fc\ub9e4"\uc640 \uc77c\ud68c\uc801\xb7\ub2e8\ubc1c\uc801\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c0\ub294 "\uadf8 \ubc16\uc758 \uac70\ub798\uc0c1\uc758 \ubd80\ub2f9\uc5fc\ub9e4"\ub85c \uad6c\ubd84\ub418\uba70, \uc774\ub294 \uaddc\uc81c\uc0c1 \ucde8\uae09(\ubd80\ub2f9\uc131 \ucd94\uc815 \uc5ec\ubd80 \ub4f1)\uc5d0 \ucc28\uc774\ub97c \uac00\uc838\uc62c \uc218 \uc788\ub2e4.',B.a4C,B.a3d,null)
B.XQ=s([u.r,"\uc628\ub77c\uc778 \ud50c\ub7ab\ud3fc\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubd80\ub2f9\uc5fc\ub9e4 \uaddc\uc81c\uc758 \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4","\ucd08\uae30 \uc810\uc720\uc728 \ud655\ubcf4 \ubaa9\uc801\uc774\uba74 \ud56d\uc0c1 \uc815\ub2f9\ud654\ub418\uc5b4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc6d0\uac00 \uc774\ud558 \uc11c\ube44\uc2a4 \uc81c\uacf5\uc740 \uc628\ub77c\uc778 \ud50c\ub7ab\ud3fc\uc5d0\uc11c\ub294 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub77c\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4","\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc624\uc9c1 \uc18c\ube44\uc790 \ubcf4\ud638 \ucc28\uc6d0\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub41c\ub2e4"],t.s)
