B.TH=s([u.gI,"\uc2dc\uc7a5\uac00\uaca9\uc5d0 \ub9de\ucd94\uc5b4 \uc815\uc0c1\uc801\uc73c\ub85c \uc0c1\ud488\uc744 \ub9e4\uc785\ud558\ub294 \ud589\uc704","\uacbd\uc7c1\uc785\ucc30\uc744 \ud1b5\ud574 \ucd5c\uc800\uac00\ub85c \uc0c1\ud488\uc744 \ub9e4\uc785\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ub0ae\uc740 \uac00\uaca9\uc744 \uc694\uad6c\ud558\ub294 \ud589\uc704","\uc18c\ube44\uc790\ub85c\ubd80\ud130 \uc911\uace0\ud488\uc744 \ub9e4\uc785\ud558\ub294 \ud589\uc704"],t.s)
