B.aj1=new A.c("gen_predatory_type_1","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615(\ubd80\ub2f9\uace0\uac00\ub9e4\uc785 \ub4f1)",'\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 "\ubd80\ub2f9\uace0\uac00\ub9e4\uc785"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.TH,0,'"\ubd80\ub2f9\uace0\uac00\ub9e4\uc785"\uc740 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \ubaa9\uc801\uc73c\ub85c, \ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uac00\uaca9\uc5d0 \ube44\ud574 \ubd80\ub2f9\ud558\uac8c \ub192\uc740 \ub300\uac00\ub85c \uc6d0\uc7ac\ub8cc \ub4f1\uc744 \ub9e4\uc785\ud568\uc73c\ub85c\uc368 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \ud544\uc694\ud55c \uc6d0\uc7ac\ub8cc\ub97c \ud655\ubcf4\ud558\uc9c0 \ubabb\ud558\uac8c \ud558\ub294 \ud589\uc704\ub97c \uc758\ubbf8\ud558\uba70, \ubd80\ub2f9\uc5fc\ub9e4\uc640 \ud568\uaed8 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\uc758 \ub300\ud45c\uc801\uc778 \ud558\uc704 \uc720\ud615\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4.',B.a4j,B.Ka,null)
B.Nz=s([u.a8,"\ub450 \uc720\ud615 \ubaa8\ub450 \uc624\uc9c1 \uc18c\ube44\uc790\ub9cc\uc744 \ub300\uc0c1\uc73c\ub85c \ud558\ub294 \ud589\uc704\uc774\ub2e4","\ub450 \uc720\ud615 \ubaa8\ub450 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\ub450 \uc720\ud615 \ubaa8\ub450 \ub2f4\ud569\uc744 \uc804\uc81c\ub85c \ud574\uc57c\ub9cc \uc131\ub9bd\ud55c\ub2e4","\ub450 \uc720\ud615\uc740 \uc11c\ub85c \uc815\ubc18\ub300\uc758 \uac1c\ub150\uc73c\ub85c \uc804\ud600 \uad00\ub828\uc774 \uc5c6\ub2e4"],t.s)
