B.amR=new A.c("gen_predatory_type_2","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615(\ubd80\ub2f9\uace0\uac00\ub9e4\uc785 \ub4f1)","\ubd80\ub2f9\uc5fc\ub9e4\uc640 \ubd80\ub2f9\uace0\uac00\ub9e4\uc785\uc758 \uacf5\ud1b5\uc810\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Nz,0,'\ubd80\ub2f9\uc5fc\ub9e4(\ube44\uc815\uc0c1\uc801\uc73c\ub85c \ub0ae\uc740 \uac00\uaca9\uc73c\ub85c \ud310\ub9e4)\uc640 \ubd80\ub2f9\uace0\uac00\ub9e4\uc785(\ube44\uc815\uc0c1\uc801\uc73c\ub85c \ub192\uc740 \uac00\uaca9\uc73c\ub85c \ub9e4\uc785)\uc740 \ubc29\ud5a5\uc740 \ubc18\ub300\uc774\uc9c0\ub9cc, \ubaa8\ub450 "\uac00\uaca9"\uc774\ub77c\ub294 \uc218\ub2e8\uc744 \ubd80\ub2f9\ud558\uac8c \uc774\uc6a9\ud558\uc5ec \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc5b4\ub835\uac8c \ub9cc\ub4e4\uace0 \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824 \ud55c\ub2e4\ub294 \uc810\uc5d0\uc11c \uacf5\ud1b5\ub41c \uc815\ucc45\uc801 \uc6b0\ub824\ub97c \ubc18\uc601\ud55c \uaddc\uc81c \uc720\ud615\uc774\ub2e4.',B.LZ,B.Tr,null)
B.Ul=s([u.cM,"\ub450 \uc720\ud615\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc694\uac74\uc744 \uc694\uad6c\ud55c\ub2e4","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615\uc740 \uc624\uc9c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\ub450 \uc720\ud615\uc740 \uc11c\ub85c \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615\uc740 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4"],t.s)
