B.aoS=new A.c("gen_predatory_type_3","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615(\ubd80\ub2f9\uace0\uac00\ub9e4\uc785 \ub4f1)",'\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615\uc758 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc758 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uacfc \uad6c\ubcc4\ub418\ub294 \uc810\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Ul,0,'\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub85c\uc11c\uc758 \ubd80\ub2f9\uc5fc\ub9e4\xb7\ubd80\ub2f9\uace0\uac00\ub9e4\uc785\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uac00 \uc544\ub2cc \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \uc131\ub9bd\ud560 \uc218 \uc788\ub294 \ubc18\uba74, \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc758 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704\ub97c \uc804\uc81c\ub85c \ud55c\ub2e4\ub294 \uc810\uc5d0\uc11c \ub450 \uaddc\uc81c\ub294 \uc801\uc6a9 \ub300\uc0c1\uacfc \uc694\uac74 \uce21\uba74\uc5d0\uc11c \uad6c\ubcc4\ub41c\ub2e4.',B.MU,B.a6D,null)
B.ea=s(["\uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \ud589\uc815\uc801 \uc81c\uc7ac\ub97c \ud560 \uc218 \uc788\ub2e4","\uc5b4\ub5a0\ud55c \uc81c\uc7ac\ub3c4 \ud560 \uc218 \uc5c6\uace0 \uad8c\uace0\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \ud615\uc0ac\uace0\ubc1c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \uc190\ud574\ubc30\uc0c1 \uc18c\uc1a1\uc744 \ub300\uc2e0 \uc81c\uae30\ud574\uc904 \uc218 \uc788\ub2e4","\uc704\ubc18 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\uc744 \uc989\uc2dc \ud3d0\uc1c4\ud574\uc57c \ud55c\ub2e4"],t.s)
