B.apw=new A.c("gen_predatory_type_6","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615(\ubd80\ub2f9\uace0\uac00\ub9e4\uc785 \ub4f1)","\uac00\ub9f9\ubcf8\ubd80\uac00 \uc2e0\uaddc \uacbd\uc7c1 \ube0c\ub79c\ub4dc\uc758 \uc2dc\uc7a5 \uc9c4\uc785\uc744 \ub9c9\uae30 \uc704\ud574 \uc77c\ubd80 \uc9c0\uc5ed\uc5d0\uc11c \uc6d0\uac00 \uc774\ud558\ub85c \uc0c1\ud488\uc744 \uacf5\uae09\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Yh,0,"\uac00\ub9f9\ubcf8\ubd80\uac00 \uc2e0\uaddc \uacbd\uc7c1 \ube0c\ub79c\ub4dc\uc758 \uc2dc\uc7a5 \uc9c4\uc785\uc744 \uc800\uc9c0\ud560 \ubaa9\uc801\uc73c\ub85c \ud2b9\uc815 \uc9c0\uc5ed\uc5d0\uc11c \uc6d0\uac00 \uc774\ud558\ub85c \uc0c1\ud488\uc744 \uacf5\uae09\ud558\ub294 \ud589\uc704\ub294, \uadf8 \uc9c0\uc18d\uc131\uacfc \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\uc758 \uc6b0\ub824\uac00 \uc778\uc815\ub418\ub294 \uacbd\uc6b0 \ubd80\ub2f9\uc5fc\ub9e4\uc5d0 \ud574\ub2f9\ud560 \uc18c\uc9c0\uac00 \uc788\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.ab6,B.a8I,null)
B.Oh=s([u.lS,"\uc99d\uba85\ucc45\uc784\uc740 \ud56d\uc0c1 \ud53c\ud574 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc788\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \uc18c\ube44\uc790\ub2e8\uccb4\uc5d0\uac8c \uc788\ub2e4","\uc99d\uba85\ucc45\uc784\uc740 \ubc95\uc6d0\uc774 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ud558\uc5ec \ubd80\ub2f4\ud55c\ub2e4","\uc99d\uba85\ucc45\uc784 \uac1c\ub150\uc740 \ubd80\ub2f9\uc5fc\ub9e4 \uc0ac\uac74\uc5d0 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
