B.anQ=new A.c("gen_predatory_exam_3","economic_law","\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a_P,0,"\ubd80\ub2f9\uc5fc\ub9e4\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c \uad00\ub828 \ubb38\uc81c\ub294 \ubd80\ub2f9\uc5fc\ub9e4\uc758 \uac1c\ub150\uacfc \ud310\ub2e8\uae30\uc900, \ubd80\ub2f9\uace0\uac00\ub9e4\uc785\uacfc\uc758 \uacf5\ud1b5\uc810(\uac00\uaca9\uc744 \uc774\uc6a9\ud55c \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c), \uadf8\ub9ac\uace0 \ud1b5\uc0c1\uc801\uc778 \uac00\uaca9 \ud560\uc778\xb7\uc7ac\uace0 \ucc98\ubd84 \ud310\ub9e4\uc640\uc758 \uad6c\ubcc4\uc774\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.a0f,B.ba,null)
B.KT=s(["\ub2e8\uc21c\ud55c \uac00\uaca9 \ud560\uc778\uc774\ub098 \uc7ac\uace0 \ucc98\ubd84 \ud310\ub9e4\ub97c \ubd80\ub2f9\uc5fc\ub9e4\uc640 \ub3d9\uc77c\uc2dc\ud558\ub294 \uc120\ud0dd\uc9c0","\uac00\ub9f9\uacc4\uc57d\uc11c\uc758 \ud3f0\ud2b8 \ud06c\uae30\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uce35\uc218\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc704\uc6d0\uc7a5\uc758 \uac1c\uc778 \ucde8\ubbf8\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc2ec\uc0ac\uccad\uad6c \uc811\uc218 \ucc3d\uad6c\uc758 \uc8fc\uc18c\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0"],t.s)
