B.VK=s([u.Er,"\uac00\uaca9\uc744 \ub0ae\ucd94\ub294 \uc804\ub7b5\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\ubd80\ub2f9\uc5fc\ub9e4 \uaddc\uc81c\ub294 \uac00\ub9f9\ubcf8\ubd80\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uac00\uaca9 \uc804\ub7b5\uc740 \uc790\ubb38\ud560 \ud544\uc694\uac00 \uc5c6\ub294 \uc0ac\ud56d\uc774\ub77c\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc6d0\uac00 \uc774\ud558 \uac00\uaca9\uc740 \ud56d\uc0c1 \uc18c\ube44\uc790 \uc774\uc775\uc744 \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ubb38\uc81c\uc5c6\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
