B.ajR=new A.c("gen_refuse_def_4","economic_law","\uac70\ub798\uac70\uc808","\uac70\ub798\uac70\uc808\uc758 \uc758\ubbf8\xb7\uc720\ud615","\uac70\ub798\uac70\uc808\uc774 \uc6d0\uce59\uc801\uc73c\ub85c \uc0ac\uc5c5\uc790\uc758 \uc790\uc720\uc5d0 \uc18d\ud558\uba74\uc11c\ub3c4 \uc608\uc678\uc801\uc73c\ub85c \uaddc\uc81c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Mp,0,"\uacc4\uc57d\uc790\uc720\uc758 \uc6d0\uce59\uc0c1 \uc0ac\uc5c5\uc790\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uac70\ub798\uc0c1\ub300\ubc29\uc744 \uc790\uc720\ub86d\uac8c \uc120\ud0dd\ud560 \uc218 \uc788\uc9c0\ub9cc, \uadf8 \uac70\ub798\uac70\uc808\uc774 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uac70\ub098 \ud2b9\uc815 \uc0ac\uc5c5\uc790(\uc8fc\ub85c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub098 \uadf8 \uac70\ub798\ucc98)\ub97c \ubd80\ub2f9\ud558\uac8c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub294 \uc218\ub2e8\uc73c\ub85c \uc545\uc6a9\ub418\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uaddc\uc81c\ud560 \ud544\uc694\uac00 \uc788\ub2e4\ub294 \uac83\uc774 \uac70\ub798\uac70\uc808 \uaddc\uc81c\uc758 \ucde8\uc9c0\uc774\ub2e4.",B.OE,B.a9Y,null)
B.Ir=s([u.Ae,"\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc740 \ud56d\uc0c1 \ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\ubcf4\ub2e4 \ucc38\uc5ec \uc0ac\uc5c5\uc790 \uc218\uac00 \uc801\uae30 \ub54c\ubb38\uc774\ub2e4","\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc740 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4","\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc740 \uc18c\ube44\uc790\uc5d0\uac8c \ud56d\uc0c1 \uc720\ub9ac\ud55c \uacb0\uacfc\ub97c \uac00\uc838\uc624\uae30 \ub54c\ubb38\uc774\ub2e4","\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc740 \ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\uacfc \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uac8c \ucde8\uae09\ub418\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.XC=s([u.Ae],t.s)
B.P1=s(["\uacf5\ub3d9 \uac70\ub798\uac70\uc808\uc774 \ub354 \uc5c4\uaca9\ud788 \ucde8\uae09\ub418\ub294 \uc774\uc720"],t.s)
B.amG=new A.c("gen_refuse_def_5","economic_law","\uac70\ub798\uac70\uc808","\uac70\ub798\uac70\uc808\uc758 \uc758\ubbf8\xb7\uc720\ud615","\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc774 \ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\ubcf4\ub2e4 \ub354 \uc5c4\uaca9\ud558\uac8c \ucde8\uae09\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ir,0,"\ubcf5\uc218\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc73c\ub85c \ud2b9\uc815 \uc0ac\uc5c5\uc790\uc640\uc758 \uac70\ub798\ub97c \uac70\uc808\ud558\uba74, \uadf8 \ub300\uc0c1 \uc0ac\uc5c5\uc790\uac00 \ub300\uccb4 \uac70\ub798\ucc98\ub97c \ucc3e\uae30\uac00 \ub2e8\ub3c5 \uac70\uc808\uc758 \uacbd\uc6b0\ubcf4\ub2e4 \ud6e8\uc52c \uc5b4\ub824\uc6cc\uc838 \uc0ac\uc5c5\ud65c\ub3d9 \uc790\uccb4\uac00 \ubd09\uc1c4\ub420 \uc704\ud5d8\uc774 \ud06c\uace0 \uc2dc\uc7a5 \uc804\uccb4\uc758 \uacbd\uc7c1\uad6c\uc870\uc5d0 \ubbf8\uce58\ub294 \ud3d0\ud574\ub3c4 \ud06c\uae30 \ub54c\ubb38\uc5d0, \uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808\uc740 \ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\ubcf4\ub2e4 \ub354 \uc5c4\uaca9\ud558\uac8c \ucde8\uae09\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.XC,B.P1,null)
B.a5C=s([u.zW,"\ub450 \uac1c\ub150\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc804\ud600 \uc5c6\ub2e4","\uac70\ub798\uac70\uc808\uc740 \uc5b8\uc81c\ub098 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub85c\ub9cc \uaddc\uc728\ub41c\ub2e4","\ub2f4\ud569\uc73c\ub85c\uc11c\uc758 \uacf5\ub3d9\ud589\uc704\ub294 \uac70\ub798\uac70\uc808\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\ub2e4","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc81c\ub294 \ub2f4\ud569 \uaddc\uc81c\ubcf4\ub2e4 \ud56d\uc0c1 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4"],t.s)
