B.arh=new A.c("gen_refuse_def_6","economic_law","\uac70\ub798\uac70\uc808","\uac70\ub798\uac70\uc808\uc758 \uc758\ubbf8\xb7\uc720\ud615",'\uac70\ub798\uac70\uc808 \uaddc\uc81c\uac00 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\uc758 \uc77c\uc885\uc778 "\uac70\ub798\uac70\uc808 \ub2f4\ud569"\uacfc \uad6c\ubcc4\ub418\ub294 \uc9c0\uc810\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a5C,0,"\ubcf5\uc218\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc73c\ub85c \uac70\ub798\ub97c \uac70\uc808\ud558\ub294 \ud589\uc704\ub294 \uc0ac\uc548\uc5d0 \ub530\ub77c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704(\uacf5\ub3d9\uc758 \uac70\ub798\uac70\uc808)\ub85c \uaddc\uc728\ub420 \uc218\ub3c4 \uc788\uace0, \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\ub85c \uaddc\uc728\ub420 \uc218\ub3c4 \uc788\ub294\ub370, \uc804\uc790\ub294 \ud2b9\uc815 \uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubaa9\uc801\xb7\ud6a8\uacfc\uc5d0, \ud6c4\uc790\ub294 \uad00\ub828\uc2dc\uc7a5 \uc804\uccb4\uc758 \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\uc5d0 \ucd08\uc810\uc744 \ub454\ub2e4\ub294 \uc810\uc5d0\uc11c \uaddc\uc728\uc758 \uad00\uc810\uc774 \ub2e4\ub97c \uc218 \uc788\ub2e4.",B.T1,B.a5o,null)
B.Rj=s([u.kV,"\uac70\ub798\ub97c \uac70\uc808\ud588\ub2e4\ub294 \uc0ac\uc2e4 \uc790\uccb4\ub9cc\uc73c\ub85c \ud56d\uc0c1 \ubd80\ub2f9\uc131\uc774 \uc778\uc815\ub41c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc774 \uac1c\uc778\uc801\uc73c\ub85c \uc11c\uc6b4\ud568\uc744 \ub290\ub07c\uba74 \ud56d\uc0c1 \ubd80\ub2f9\uc131\uc774 \uc778\uc815\ub41c\ub2e4","\uac70\ub798\uac70\uc808\uc758 \ubd80\ub2f9\uc131\uc740 \ud310\ub2e8\ud560 \ud544\uc694\uac00 \uc804\ud600 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uac70\ub798\uac70\uc808\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\ub9cc\uc744 \uacb0\uc815\ud558\ub294 \uac1c\ub150\uc774\ub2e4"],t.s)
