B.a5U=s(["\ub2e8\ub3c5 \uac70\ub798\uac70\uc808\uc758 \ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900"],t.s)
B.apZ=new A.c("gen_refuse_judge_1","economic_law","\uac70\ub798\uac70\uc808","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc815\ub2f9\ud654 \uc0ac\uc720","\ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\uc774 \ubd80\ub2f9\ud558\ub2e4\uace0 \uc778\uc815\ub418\uae30 \uc704\ud55c \ud310\ub2e8\uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Rj,0,"\ub2e8\ub3c5\uc758 \uac70\ub798\uac70\uc808\uc774 \ubd80\ub2f9\ud558\ub2e4\uace0 \uc778\uc815\ub418\ub824\uba74, \ub2e8\uc21c\ud788 \uac70\ub798\ub97c \uac70\uc808\ud588\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c\ub294 \ubd80\uc871\ud558\uace0, \uadf8 \uac70\uc808\uc774 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubaa9\uc801\uc774\ub098 \ud6a8\uacfc\ub97c \uac00\uc9c0\ub294\uc9c0, \uac70\ub798\uac70\uc808\ub85c \uc778\ud574 \uc0c1\ub300\ubc29\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc774 \uc2ec\ud788 \uace4\ub780\ud574\uc9c0\ub294\uc9c0 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uc5ec \ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4.",B.a2O,B.a5U,null)
B.LL=s([u.oh,"\uc774\uc720\ub97c \ubd88\ubb38\ud558\uace0 \ud56d\uc0c1 \ubd80\ub2f9\ud55c \uac70\ub798\uac70\uc808\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uc2e0\uc6a9\ubd88\ub7c9\uc774\ub098 \uacc4\uc57d \uc704\ubc18\uc740 \uac70\ub798\uac70\uc808\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uc0ac\uc720\uc774\ub2e4","\uc774\ub7ec\ud55c \uac70\ub798\uac70\uc808\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \ub41c\ub2e4","\uc774\ub7ec\ud55c \uac70\ub798\uac70\uc808\uc740 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub97c \ud1b5\ud574\uc11c\ub9cc \uc774\ub8e8\uc5b4\uc838\uc57c \ud55c\ub2e4"],t.s)
B.WO=s([u.oh],t.s)
B.IK=s(["\uc815\ub2f9\ud55c \uc0ac\uc720\uc5d0 \uc758\ud55c \uac70\ub798\uac70\uc808"],t.s)
B.arq=new A.c("gen_refuse_judge_2","economic_law","\uac70\ub798\uac70\uc808","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc815\ub2f9\ud654 \uc0ac\uc720","\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uc2e0\uc6a9\ubd88\ub7c9\uc774\ub098 \uacc4\uc57d \uc704\ubc18\uc744 \uc774\uc720\ub85c \ud55c \uac70\ub798\uac70\uc808\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.LL,0,"\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uc2e0\uc6a9\ubd88\ub7c9, \ub300\uae08 \ubbf8\uc9c0\uae09, \uacc4\uc57d \uc704\ubc18 \ub4f1 \ud569\ub9ac\uc801\uc774\uace0 \uc815\ub2f9\ud55c \uc0ac\uc720\uc5d0 \uae30\ucd08\ud55c \uac70\ub798\uac70\uc808\uc740, \uc0ac\uc5c5\uc790\uac00 \uc790\uc2e0\uc758 \uc815\ub2f9\ud55c \uc774\uc775\uc744 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \ud589\uc704\ub85c\uc11c \uc6d0\uce59\uc801\uc73c\ub85c \ubd80\ub2f9\ud55c \uac70\ub798\uac70\uc808\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.WO,B.IK,null)
B.Lk=s(["\uac70\ub798\uac70\uc808\uc758 \uc81c\uc7ac"],t.s)
B.aqi=new A.c("gen_refuse_judge_3","economic_law","\uac70\ub798\uac70\uc808","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc815\ub2f9\ud654 \uc0ac\uc720","\uac70\ub798\uac70\uc808\uc5d0 \ub300\ud574 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.ea,0,"\uac70\ub798\uac70\uc808 \uc704\ubc18\uc774 \uc778\uc815\ub418\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub2e4\ub978 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc2dc\uc815\uc870\uce58(\uac70\ub798\uac1c\uc2dc\xb7\uc7ac\uac1c \uba85\ub839 \ub4f1) \ubc0f \uc704\ubc18 \uc815\ub3c4\uc5d0 \ub530\ub978 \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \ud589\uc815\uc801 \uc870\uce58\ub97c \ucde8\ud560 \uc218 \uc788\ub2e4.",B.ec,B.Lk,null)
B.ah2=new A.c("gen_refuse_judge_4","economic_law","\uac70\ub798\uac70\uc808","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc815\ub2f9\ud654 \uc0ac\uc720","\uac70\ub798\uac70\uc808\ub85c \ud53c\ud574\ub97c \uc785\uc740 \uc0ac\uc5c5\uc790\uc758 \uad6c\uc81c\uc218\ub2e8\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.ed,0,"\ubd80\ub2f9\ud55c \uac70\ub798\uac70\uc808\ub85c \uc778\ud574 \ud53c\ud574\ub97c \uc785\uc740 \uc0ac\uc5c5\uc790\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\uc640\ub294 \ubcc4\ub3c4\ub85c \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud558\ub294 \ub4f1 \uc790\uc2e0\uc758 \uad8c\ub9ac\ub97c \uad6c\uc81c\ubc1b\uae30 \uc704\ud55c \uc218\ub2e8\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\ub2e4.",B.e9,B.eb,null)
B.MK=s([u.ls,"\ud544\uc218\uc124\ube44\ub294 \uac70\ub798\uac70\uc808 \uaddc\uc81c\uc640 \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud544\uc218\uc124\ube44\uc5d0 \ub300\ud55c \uc811\uadfc \uac70\uc808\uc740 \ud56d\uc0c1 \ud569\ubc95\uc73c\ub85c \ucde8\uae09\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ud544\uc218\uc124\ube44\ub294 \uc624\uc9c1 \uad6d\uac00\ub9cc \uc18c\uc720\ud560 \uc218 \uc788\ub294 \uc2dc\uc124\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud544\uc218\uc124\ube44 \uc811\uadfc \uac70\uc808\uc740 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \uc601\ud5a5\uc744 \ubbf8\uce58\uace0 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \ubb34\uad00\ud558\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.N3=s([u.ls],t.s)
B.LX=s(["\ud544\uc218\uc124\ube44 \uc811\uadfc \uac70\uc808\uc758 \ubb38\uc81c"],t.s)
B.ail=new A.c("gen_refuse_judge_5","economic_law","\uac70\ub798\uac70\uc808","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc815\ub2f9\ud654 \uc0ac\uc720","\ud544\uc218\uc124\ube44(\uc5d0\uc13c\uc15c \ud37c\uc2e4\ub9ac\ud2f0)\uc5d0 \ub300\ud55c \uc811\uadfc\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\uac00 \uac70\ub798\uac70\uc808 \uaddc\uc81c\uc5d0\uc11c \ud2b9\ud788 \ubb38\uc81c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.MK,0,"\uc804\ub825\ub9dd, \ud1b5\uc2e0\ub9dd \ub4f1 \ub300\uccb4 \uc218\ub2e8\uc744 \ucc3e\uae30 \uc5b4\ub824\uc6b4 \ud544\uc218\uc124\ube44(\uc5d0\uc13c\uc15c \ud37c\uc2e4\ub9ac\ud2f0)\uc5d0 \ub300\ud55c \uc811\uadfc\uc744 \ubd80\ub2f9\ud558\uac8c \uac70\uc808\ud558\ub294 \uacbd\uc6b0, \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc0ac\uc2e4\uc0c1 \ud574\ub2f9 \uc2dc\uc7a5\uc5d0 \ucc38\uc5ec\ud560 \uc218 \uc5c6\uac8c \ub418\uc5b4 \uacbd\uc7c1 \uc790\uccb4\uac00 \uc6d0\ucc9c\uc801\uc73c\ub85c \ubd09\uc1c4\ub420 \uc218 \uc788\uc73c\ubbc0\ub85c \uac70\ub798\uac70\uc808 \uaddc\uc81c\uc5d0\uc11c \ud2b9\ud788 \uc5c4\uaca9\ud558\uac8c \ub2e4\ub8e8\uc5b4\uc9c0\ub294 \uc9c0\uc810\uc774\ub2e4.",B.N3,B.LX,null)
B.X6=s([u.Cb,"\uac00\ub9f9\ubcf8\ubd80\ub294 \uc5b4\ub5a0\ud55c \uc774\uc720\ub85c\ub4e0 \uc790\uc720\ub86d\uac8c \uacf5\uae09\uc744 \uc911\ub2e8\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4","\ubb3c\ud488 \uacf5\uae09 \uc911\ub2e8\uc740 \uac70\ub798\uac70\uc808 \uaddc\uc81c\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uac00\ub9f9\uacc4\uc57d \uad00\uacc4\uc5d0\uc11c\ub294 \uac70\ub798\uac70\uc808 \uaddc\uc81c\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb3c\ud488 \uacf5\uae09 \uc911\ub2e8\uc740 \uc624\uc9c1 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c\ub9cc \ud3c9\uac00\ub41c\ub2e4"],t.s)
