B.am3=new A.c("gen_ca_1","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc5d0 \ub300\ud55c \uac10\uba74\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a8j,2,'\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4(\ub9ac\ub2c8\uc5b8\uc2dc)\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \uadf8 \uc0ac\uc2e4\uc744 \uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud558\uba74 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08\uc744 \uac10\uacbd \ub610\ub294 \uba74\uc81c\ud574\uc8fc\ub294 \uc81c\ub3c4\ub85c, \ub2f4\ud569\uc758 \uc740\ubc00\uc131\uc744 \uae68\ub728\ub824 \uc801\ubc1c\ub960\uc744 \ub192\uc774\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub2e4. \uadf8\ub7f0\ub370 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \uc5ec\ub7ec \ucc28\ub840 \ubc18\ubcf5\uc801\uc73c\ub85c \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \ud6c4 \ub9e4\ubc88 \uc790\uc9c4\uc2e0\uace0\ub85c \uac10\uba74\ubc1b\ub294 \uacbd\uc6b0\uae4c\uc9c0 \ubb34\uc870\uac74 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud55c\ub2e4\uba74 \uc624\ud788\ub824 \ub2f4\ud569\uc744 \uc870\uc7a5\ud558\ub294 \uc5ed\ud6a8\uacfc\uac00 \uc0dd\uae38 \uc218 \uc788\uc73c\ubbc0\ub85c, \uc2dc\ud589\ub839\uc740 \uc77c\uc815 \uc694\uac74 \ud558\uc5d0 \ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc744 \ubc30\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \uaddc\uc815\ud558\uace0 \uc788\ub2e4. \ub530\ub77c\uc11c "\ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.a7f,B.NR,null)
B.a6G=s([u.aG,"\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0\uac8c \uc624\ud788\ub824 \ub354 \ubb34\uac70\uc6b4 \ucc98\ubc8c\uc744 \uac00\ud558\uae30 \uc704\ud568\uc774\ub2e4","\ub2f4\ud569\uc744 \uc870\uc7a5\ud558\uace0 \uc0ac\uc5c5\uc790 \uac04 \ud611\uc870\ub97c \uac15\ud654\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ubaa8\ub4e0 \uc0ac\uc5c5\uc790\ub97c \ub3d9\uc77c\ud558\uac8c \ucc98\ubc8c\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4\ub294 \uc2e4\uc81c\ub85c \uc544\ubb34\ub7f0 \uc815\ucc45\uc801 \ud6a8\uacfc\uac00 \uc5c6\ub2e4"],t.s)
