B.ajx=new A.c("gen_leniency_intro_1","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4(\ub9ac\ub2c8\uc5b8\uc2dc)\uc758 \ub3c4\uc785 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a6G,0,"\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uac00 \uc790\uc9c4\uc2e0\uace0\ub97c \ud1b5\ud574 \uac10\uba74 \ud61c\ud0dd\uc744 \ubc1b\uc744 \uc218 \uc788\ub3c4\ub85d \ud568\uc73c\ub85c\uc368, \ub2f4\ud569 \ucc38\uc5ec \uc0ac\uc5c5\uc790\ub4e4 \uc0ac\uc774\uc5d0 \ubc30\uc2e0\uc5d0 \ub300\ud55c \ubd88\uc548\uc744 \uc870\uc131\ud558\uc5ec \ub2f4\ud569\uc758 \uc740\ubc00\uc131\uc744 \uae68\ub728\ub9ac\uace0 \uc801\ubc1c\ub960\uc744 \ub192\uc5ec \ub2f4\ud569\uc744 \uc0ac\uc804\uc5d0 \uc5b5\uc9c0\ud558\ub824\ub294 \uc815\ucc45\uc801 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4.",B.M5,B.OT,null)
B.a04=s([u.k8,"\ub2e8\uc21c\ud788 \ub2f4\ud569\uc5d0 \ucc38\uc5ec\ud588\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \uba74\uc81c\ub41c\ub2e4","\uac00\uc7a5 \ub9c8\uc9c0\ub9c9\uc73c\ub85c \uc2e0\uace0\ud55c \uc0ac\uc5c5\uc790\uac00 \ud56d\uc0c1 \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\ub294 \uc5b4\ub5a0\ud55c \uc694\uac74\ub3c4 \uc5c6\uc774 \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","\uc804\ubd80 \uba74\uc81c\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc778\uc815\ub41c\ub2e4"],t.s)
B.XY=s([u.k8],t.s)
