B.ajt=new A.c("gen_leniency_intro_4","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74",'\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74 \uc694\uac74 \uc911 "\uc870\uc0ac \uc885\ub8cc \uc2dc\uae4c\uc9c0 \uc131\uc2e4\ud558\uac8c \ud611\uc870"\ud55c\ub2e4\ub294 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a7J,0,'"\uc870\uc0ac\uac00 \ub05d\ub0a0 \ub54c\uae4c\uc9c0 \uc131\uc2e4\ud558\uac8c \ud611\uc870"\ud55c\ub2e4\ub294 \uc694\uac74\uc740, \uc790\uc9c4\uc2e0\uace0\uc790\uac00 \uc790\uc2e0\uc774 \uc54c\uace0 \uc788\ub294 \uacf5\ub3d9\ud589\uc704 \uad00\ub828 \uc0ac\uc2e4\uc744 \uc9c0\uccb4 \uc5c6\uc774 \uc9c4\uc220\ud558\uace0 \ud544\uc694\ud55c \uc790\ub8cc\ub97c \uc81c\ucd9c\ud558\ub294 \ub4f1 \uc870\uc0ac\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \ub3c4\uc6c0\uc774 \ub418\ub294 \ubc29\uc2dd\uc73c\ub85c \uc9c0\uc18d\uc801\uc73c\ub85c \ud611\ub825\ud558\ub294 \uac83\uc744 \uc758\ubbf8\ud558\uba70, \uc870\uc0ac \ucd08\ubc18\uc5d0\ub9cc \ud611\uc870\ud558\uace0 \uc774\ud6c4 \ud611\uc870\ub97c \uc911\ub2e8\ud558\uba74 \uc774 \uc694\uac74\uc744 \ucda9\uc871\ud558\uc9c0 \ubabb\ud560 \uc218 \uc788\ub2e4.',B.VM,B.Ko,null)
B.Va=s([u.uK,"\uc8fc\ub3c4\uc801 \uc0ac\uc5c5\uc790\uc77c\uc218\ub85d \uc624\ud788\ub824 \ub354 \ud070 \uac10\uba74 \ud61c\ud0dd\uc744 \ubc1b\ub294\ub2e4","\uc8fc\ub3c4 \uc5ec\ubd80\ub294 \uac10\uba74 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc8fc\ub3c4\uc801 \uc0ac\uc5c5\uc790\ub3c4 \uc790\uc9c4\uc2e0\uace0\ub9cc \ud558\uba74 \ud56d\uc0c1 \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","\uc8fc\ub3c4\uc801 \uc0ac\uc5c5\uc790\ub294 \uac10\uba74\uc81c\ub3c4\uc758 \uc720\uc77c\ud55c \uc801\uc6a9 \ub300\uc0c1\uc774\ub2e4"],t.s)
