B.ajl=new A.c("gen_leniency_intro_5","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74","\uc790\uc9c4\uc2e0\uace0\uc790\uac00 \ub2e4\ub978 \uc0ac\uc5c5\uc790\ub97c \uac15\uc694\ud558\uc5ec \uacf5\ub3d9\ud589\uc704\uc5d0 \ucc38\uc5ec\ud558\uac8c \ud55c \uc8fc\ub3c4\uc801 \uc0ac\uc5c5\uc790\uc778 \uacbd\uc6b0 \uac10\uba74 \uc5ec\ubd80\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Va,0,"\ub2e4\ub978 \uc0ac\uc5c5\uc790\ub97c \uac15\uc694\ud558\uc5ec \uacf5\ub3d9\ud589\uc704\uc5d0 \ucc38\uc5ec\ud558\ub3c4\ub85d \ud558\ub294 \ub4f1 \ub2f4\ud569\uc744 \uc8fc\ub3c4\ud55c \uc0ac\uc5c5\uc790\ub294, \uc790\uc9c4\uc2e0\uace0\ub97c \ud558\ub354\ub77c\ub3c4 \uac10\uba74 \ub300\uc0c1\uc5d0\uc11c \ubc30\uc81c\ub418\uac70\ub098 \uac10\uba74 \ud61c\ud0dd\uc774 \uc81c\ud55c\ub420 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc81c\ub3c4\uc758 \ucde8\uc9c0(\ub2f4\ud569 \uc8fc\ub3c4\uc790\uc5d0 \ub300\ud55c \ud2b9\ud61c \ubc29\uc9c0)\uc5d0 \ubd80\ud569\ud558\ub294 \ubc95\ub9ac\ub85c \uc774\ud574\ub41c\ub2e4.",B.abG,B.V6,null)
B.RD=s([u.p9,"\ubaa8\ub4e0 \uc2e0\uace0\uc790\uc5d0\uac8c \uc21c\uc11c\uc640 \ubb34\uad00\ud558\uac8c \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\ub294 \uad6c\uc870","\uc2e0\uace0 \uc21c\uc11c\uc640 \uad00\uacc4\uc5c6\uc774 \ubb34\uc791\uc704\ub85c \ud61c\ud0dd\uc744 \ubc30\ubd84\ud558\ub294 \uad6c\uc870","\uc2e0\uace0\ub97c \uac00\uc7a5 \ub2a6\uac8c \ud55c \uc0ac\uc5c5\uc790\uc5d0\uac8c \uac00\uc7a5 \ud070 \ud61c\ud0dd\uc744 \uc8fc\ub294 \uad6c\uc870","\uc2e0\uace0 \uc790\uccb4\ub97c \uc6d0\ucc9c\uc801\uc73c\ub85c \ucc28\ub2e8\ud558\ub294 \uad6c\uc870"],t.s)
