B.amB=new A.c("gen_leniency_process_4","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uac10\uba74 \uc808\ucc28\xb7\ud615\uc0ac\uace0\ubc1c\uacfc\uc758 \uad00\uacc4","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a3p,0,"\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4 \uad00\ub828 \ubb38\uc81c\ub294 \uc81c\ub3c4\uc758 \ub3c4\uc785 \ucde8\uc9c0, \uc21c\uc704(1\uc21c\uc704\xb72\uc21c\uc704)\ubcc4 \uac10\uba74 \uc218\uc900\uc758 \ucc28\uc774, \uadf8\ub9ac\uace0 \ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\ub098 \ube44\ubc00\uc720\uc9c0 \uc704\ubc18 \ub4f1 \uac10\uba74\uc774 \ubc30\uc81c\ub418\ub294 \uacbd\uc6b0\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \uac1c\ub150 \uc774\ud574\ub97c \ud655\uc778\ud558\ub294 \ubc29\uc2dd\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.Vd,B.ba,null)
B.Y6=s([u.EO,"\ub2f4\ud569 \uc0ac\uc2e4\uc744 \uc808\ub300 \uc2e0\uace0\ud558\uc9c0 \ub9d0\ub77c\uace0\ub9cc \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0\ub294 \ud56d\uc0c1 \ubd88\ub9ac\ud558\ubbc0\ub85c \uace0\ub824\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\ub2f4\ud569 \uc0ac\uc2e4\uc774 \uc788\uc5b4\ub3c4 \uc544\ubb34\ub7f0 \uc870\uce58\ub97c \ucde8\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc5ec\ubd80\ub294 \uac00\ub9f9\uac70\ub798\uc0ac\uc758 \uc790\ubb38 \ubc94\uc704\uc640 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
