B.art=new A.c("gen_leniency_process_5","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uac10\uba74 \uc808\ucc28\xb7\ud615\uc0ac\uace0\ubc1c\uacfc\uc758 \uad00\uacc4","\uac00\ub9f9\ubcf8\ubd80\uac00 \ub2e4\ub978 \uac00\ub9f9\ubcf8\ubd80\ub4e4\uacfc \uacf5\uae09\uac00\uaca9 \ub2f4\ud569\uc744 \ud55c \uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uc790\ubb38 \uc2dc \uc548\ub0b4\ud560 \uc218 \uc788\ub294 \ub0b4\uc6a9\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Y6,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uc758\ub8b0\uc778\uc5d0\uac8c \uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4\uc758 \uc694\uac74\uacfc \uc21c\uc704\ubcc4 \ud61c\ud0dd\uc758 \ucc28\uc774(1\uc21c\uc704 \uc804\ubd80 \uba74\uc81c, 2\uc21c\uc704 \uc774\ud558 \uac10\uacbd \ub4f1)\ub97c \uc124\uba85\ud558\uace0, \uba3c\uc800 \uc2e0\uace0\ud560\uc218\ub85d \uc720\ub9ac\ud55c \ud61c\ud0dd\uc744 \ubc1b\uc744 \uc218 \uc788\uc73c\ubbc0\ub85c \uc870\uc18d\ud55c \ud310\ub2e8\uc774 \ud544\uc694\ud560 \uc218 \uc788\uc74c\uc744 \uc548\ub0b4\ud558\ub294 \uac83\uc774 \uc801\uc808\ud55c \uc790\ubb38 \ubc29\ud5a5\uc774\ub2e4.",B.Mq,B.Qb,null)
B.a10=s([u.k2,"\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc808\ub300 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4\ub294 \uac83\uc774 \ud655\ub9bd\ub41c \ubc95\ub9ac\uc774\ub2e4","\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0\ub97c \ud558\uba74 \ucc38\uc5ec\uc790 \uc804\uc6d0\uc774 \uc790\ub3d9\uc73c\ub85c \ud615\uc0ac\ucc98\ubc8c\uc744 \uba74\uc81c\ubc1b\ub294\ub2e4","\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0\ub294 \uac1c\ubcc4 \uc790\uc9c4\uc2e0\uace0\ubcf4\ub2e4 \ud56d\uc0c1 \ubd88\ub9ac\ud558\uac8c\ub9cc \ucde8\uae09\ub41c\ub2e4","\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0\ub294 \uac10\uba74 \uc21c\uc704 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\ub2e4"],t.s)
B.a2F=s([u.k2],t.s)
B.K3=s(["\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0\uc758 \uc778\uc815 \uc5ec\ubd80"],t.s)
B.ao1=new A.c("gen_leniency_process_6","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uac10\uba74 \uc808\ucc28\xb7\ud615\uc0ac\uace0\ubc1c\uacfc\uc758 \uad00\uacc4","\ubcf5\uc218\uc758 \uc0ac\uc5c5\uc790\uac00 \ub3d9\uc2dc\uc5d0 \uacf5\ub3d9\uc73c\ub85c \uc790\uc9c4\uc2e0\uace0\ub97c \ud558\ub294 \uacbd\uc6b0(\uacf5\ub3d9 \uc790\uc9c4\uc2e0\uace0)\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a10,0,"\ubaa8\ud68c\uc0ac\uc640 \uc790\ud68c\uc0ac \uad00\uacc4\uc5d0 \uc788\ub294 \uc0ac\uc5c5\uc790 \ub4f1 \ud2b9\uc218\ud55c \uacbd\uc6b0, \ubcf5\uc218\uc758 \uc0ac\uc5c5\uc790\uac00 \ub3d9\uc2dc\uc5d0 \uacf5\ub3d9\uc73c\ub85c \uc790\uc9c4\uc2e0\uace0\ub97c \ud558\ub294 \uac83\uc774 \uc778\uc815\ub420 \uc218 \uc788\ub294\uc9c0, \uc778\uc815\ub41c\ub2e4\uba74 \uc5b4\ub5a4 \uc694\uac74 \ud558\uc5d0\uc11c\uc778\uc9c0\uac00 \uc2e4\ubb34\uc0c1 \ub17c\uc758\ub418\ub294 \uc7c1\uc810 \uc911 \ud558\ub098\uc774\ub2e4.",B.a2F,B.K3,null)
B.abm=s([u.r4,"\uac10\uba74 \uacb0\uc815\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uac10\uba74 \uacb0\uc815 \ubd88\ubcf5\uc740 \ud615\uc0ac\ubc95\uc6d0\uc5d0\uc11c\ub9cc \ub2e4\ub8f0 \uc218 \uc788\ub2e4","\uac10\uba74 \uacb0\uc815\uc5d0 \ubd88\ubcf5\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \uac10\uba74 \ud61c\ud0dd\uc774 \ucde8\uc18c\ub41c\ub2e4","\uac10\uba74 \uacb0\uc815\uc740 \ubd88\ubcf5 \uc808\ucc28 \uc790\uccb4\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \ud2b9\uc218\ud55c \ucc98\ubd84\uc774\ub2e4"],t.s)
