B.ard=new A.c("gen_leniency_process_7","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uac10\uba74 \uc808\ucc28\xb7\ud615\uc0ac\uace0\ubc1c\uacfc\uc758 \uad00\uacc4","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74 \uacb0\uc815\uc5d0 \ubd88\ubcf5\ud558\ub294 \uacbd\uc6b0 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.abm,0,"\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74 \uc5ec\ubd80\ub098 \uc21c\uc704\uc5d0 \uad00\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uacb0\uc815\ub3c4 \ud558\ub098\uc758 \ud589\uc815\ucc98\ubd84\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uc774\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \uc77c\ubc18\uc801\uc778 \ubd88\ubcf5\uc808\ucc28\uc778 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ud589\uc815\ucc98\ubd84\uc5d0 \ub300\ud55c \uc77c\ubc18 \ubc95\ub9ac\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.a5X,B.Jf,null)
B.a2v=s(["\ubd88\ud669\uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815","\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c","\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654","\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1","\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"],t.s)
B.aao=s(['"\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"\ucc98\ub7fc \ud2b9\uc815 \uae30\uc5c5\uc758 \uc0ac\uc801 \uc774\uc775\uc744 \uc704\ud55c \ubaa9\uc801\uc740 \uc778\uac00\uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4'],t.s)
