B.ahj=new A.c("gen_ca_2","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uac00 \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ub420 \uc218 \uc788\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00 \ubaa9\uc801\uc73c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a2v,4,'\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub418\uc9c0\ub9cc, \uacf5\uc815\uac70\ub798\ubc95 \uc81c40\uc870 \uc81c2\ud56d\uc740 \uc608\uc678\uc801\uc73c\ub85c \u2460 \ubd88\ud669 \uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815, \u2461 \uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c, \u2462 \uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654, \u2463 \uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\uace0 \ub300\ud1b5\ub839\ub839\uc774 \uc815\ud558\ub294 \uc694\uac74\uc744 \uac16\ucd98 \uacbd\uc6b0\uc5d0 \ud55c\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00\ub97c \ubc1b\uc544 \uacf5\ub3d9\ud589\uc704\ub97c \ud560 \uc218 \uc788\ub3c4\ub85d \ud5c8\uc6a9\ud558\uace0 \uc788\ub2e4. \uc774 \uc778\uac00\uc81c\ub3c4\ub294 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc0b0\uc5c5 \uc804\uccb4\uc758 \ud6a8\uc728\uc131\uc774\ub098 \uc911\uc18c\uae30\uc5c5 \ubcf4\ud638\ucc98\ub7fc \uacf5\uc775\uc801 \ubaa9\uc801\uc774 \uc788\ub294 \uc608\uc678\uc801\uc778 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uac83\uc774\uc9c0, "\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"\ucc98\ub7fc \ud2b9\uc815 \uae30\uc5c5\uc758 \uc0ac\uc801 \uc774\uc775\uc744 \uc704\ud55c \ubaa9\uc801\uc740 \uc778\uac00\uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.aao,B.Vy,null)
B.YQ=s([u.ci,"\uc0ac\uc5c5\uc790 \uac04 \ub2f4\ud569\uc744 \uc804\uba74\uc801\uc73c\ub85c \uc7a5\ub824\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc5c5\ubb34\ub7c9\uc744 \ub298\ub9ac\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc778\uac00\uc81c\ub3c4\ub294 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc544\ubb34\ub7f0 \uc815\ucc45\uc801 \ud6a8\uc6a9\uc774 \uc5c6\ub2e4","\uc778\uac00\uc81c\ub3c4\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\uc758 \uc774\uc775\ub9cc\uc744 \uc704\ud55c \uac83\uc774\ub2e4"],t.s)
