B.akv=new A.c("gen_ca_permit_intro_1","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4\uac00 \ub9c8\ub828\ub41c \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.YQ,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub418\uc9c0\ub9cc, \uc0b0\uc5c5\uad6c\uc870\uc870\uc815\uc774\ub098 \uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c \ub4f1 \uacf5\uc775\uc801 \ubaa9\uc801 \ub2ec\uc131\uc744 \uc704\ud574 \uc608\uc678\uc801\uc73c\ub85c \uacf5\ub3d9\ud589\uc704\uac00 \ud544\uc694\ud55c \uacbd\uc6b0\uac00 \uc788\uc744 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \uace0\ub824\ud558\uc5ec, \uc77c\uc815\ud55c \uc694\uac74 \ud558\uc5d0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00\ub97c \ubc1b\uc544 \uc774\ub97c \ud5c8\uc6a9\ud558\ub294 \uc778\uac00\uc81c\ub3c4\uac00 \ub9c8\ub828\ub418\uc5c8\ub2e4.",B.Me,B.a6M,null)
B.a7m=s([u.hv,"\ud2b9\uc815 \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \uadf9\ub300\ud654\ud558\uae30 \uc704\ud55c \uacbd\uc6b0","\uc0ac\uc5c5\uc790 \uac04 \ub2f4\ud569\uc744 \ud1b5\ud574 \uac00\uaca9\uc744 \uc778\uc0c1\ud558\uae30 \uc704\ud55c \uacbd\uc6b0","\uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\uae30 \uc704\ud55c \uacbd\uc6b0","\uc18c\ube44\uc790\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc870\uac74\uc744 \uac15\uc694\ud558\uae30 \uc704\ud55c \uacbd\uc6b0"],t.s)
