B.al4=new A.c("gen_ca_permit_intro_2","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801",'\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720 \uc911 "\uc0b0\uc5c5\uad6c\uc870\uc870\uc815"\uc774 \uc778\uc815\ub418\ub294 \ubc30\uacbd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a7m,0,"\uc0b0\uc5c5\uad6c\uc870\uc870\uc815\uc744 \uc704\ud55c \uacf5\ub3d9\ud589\uc704 \uc778\uac00\ub294, \ubd88\ud669 \ub4f1\uc73c\ub85c \uc778\ud574 \uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ud63c\uc790\uc758 \ub178\ub825\ub9cc\uc73c\ub85c\ub294 \uadf9\ubcf5\ud558\uae30 \uc5b4\ub824\uc6b4 \uc0b0\uc5c5 \uc804\uccb4\uc758 \uad6c\uc870\uc801 \ubb38\uc81c(\uacfc\uc789\uc124\ube44 \ud574\uc18c \ub4f1)\uc5d0 \ub300\ud574 \uc0ac\uc5c5\uc790\ub4e4\uc774 \uacf5\ub3d9\uc73c\ub85c \ub300\uc751\ud560 \ud544\uc694\uac00 \uc788\ub294 \uacbd\uc6b0\ub97c \uc804\uc81c\ub85c \ud55c\ub2e4.",B.a96,B.L7,null)
B.a8Y=s([u.x,"\uc5f0\uad6c\uac1c\ubc1c \uacf5\ub3d9\ud589\uc704\ub294 \ud56d\uc0c1 \uc18c\ube44\uc790\uc5d0\uac8c \ubd88\ub9ac\ud55c \uacb0\uacfc\ub9cc \uac00\uc838\uc624\uae30 \ub54c\ubb38\uc774\ub2e4","\uc5f0\uad6c\uac1c\ubc1c\uc740 \uacbd\uc7c1\uc81c\ud55c\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uc5f0\uad6c\uac1c\ubc1c \uacf5\ub3d9\ud589\uc704\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\ub9cc \ud560 \uc218 \uc788\ub294 \ud589\uc704\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uc5f0\uad6c\uac1c\ubc1c \uacf5\ub3d9\ud589\uc704\ub294 \ud615\uc0ac\ucc98\ubc8c\uc744 \ud53c\ud558\uae30 \uc704\ud55c \uba85\ubaa9\uc0c1 \uc0ac\uc720\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
