B.amo=new A.c("gen_ca_permit_intro_3","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801",'\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720 \uc911 "\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c"\uc774 \uc778\uc815\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a8Y,0,"\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c\uc744 \uc704\ud55c \uacf5\ub3d9\ud589\uc704\ub294, \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \ub2e8\ub3c5\uc73c\ub85c \uc218\ud589\ud558\uae30\uc5d0\ub294 \ube44\uc6a9\xb7\uc704\ud5d8 \ubd80\ub2f4\uc774 \ud070 \ub300\uaddc\ubaa8 \uc5f0\uad6c\uac1c\ubc1c\uc744 \uc5ec\ub7ec \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc73c\ub85c \ucd94\uc9c4\ud568\uc73c\ub85c\uc368 \uae30\uc220\ud601\uc2e0\uacfc \uc0b0\uc5c5 \uacbd\uc7c1\ub825 \ud5a5\uc0c1\uc744 \ucd09\uc9c4\ud560 \uc218 \uc788\ub2e4\ub294 \uc810\uc5d0\uc11c \uc608\uc678\uc801\uc73c\ub85c \uc778\uac00 \ub300\uc0c1\uc774 \ub41c\ub2e4.",B.Qv,B.a50,null)
B.a6N=s([u.Bv,"\uc0ac\uc5c5\uc790\ub4e4\uc774 \ub2f4\ud569\ud558\uc5ec \uac00\uaca9\uc744 \uc784\uc758\ub85c \ud1b5\uc77c\ud558\ub294 \uac83","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc870\uac74\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uac15\uc694\ud558\ub294 \uac83","\uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub294 \uac83","\uc18c\ube44\uc790\uc758 \uc120\ud0dd\uad8c\uc744 \uc644\uc804\ud788 \uc81c\uac70\ud558\ub294 \uac83"],t.s)
