B.aqF=new A.c("gen_ca_permit_intro_4","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801",'\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720 \uc911 "\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a6N,0,'"\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654"\ub97c \uc704\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc0c1\ud488\uc758 \uaddc\uaca9\uc774\ub098 \ud488\uc9c8\uc744 \ud1b5\uc77c\ud558\ub294 \ub4f1\uc758 \ubc29\ubc95\uc73c\ub85c \uac70\ub798\ube44\uc6a9\uc744 \ub0ae\ucd94\uace0 \uac70\ub798\uc758 \uc548\uc804\uc131\xb7\ud6a8\uc728\uc131\uc744 \ub192\uc774\ub824\ub294 \ubaa9\uc801\uc744 \uac00\uc9c4 \uacf5\ub3d9\ud589\uc704\ub97c \uc758\ubbf8\ud558\uba70, \uc774\ub294 \ub2f4\ud569\uc744 \ud1b5\ud55c \uac00\uaca9 \ud1b5\uc77c\uc774\ub098 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0 \ub300\ud55c \ubd88\ub9ac\ud55c \uc870\uac74 \uac15\uc694\uc640\ub294 \uad6c\ubcc4\ub418\ub294 \uac1c\ub150\uc774\ub2e4.',B.acC,B.a1d,null)
B.a6O=s([u.nP,"\uc911\uc18c\uae30\uc5c5\uc744 \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\uc2dc\ud0a4\uae30 \uc704\ud55c \uac83\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uc911\uc18c\uae30\uc5c5 \uac04 \ub2f4\ud569\uc744 \ubb34\uc870\uac74 \ud5c8\uc6a9\ud558\uae30 \uc704\ud55c \uac83\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1\uc740 \uc778\uac00\uc0ac\uc720\uc640 \uc804\ud600 \ubb34\uad00\ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uc911\uc18c\uae30\uc5c5 \uc9c0\uc6d0\uc740 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
