B.alS=new A.c("gen_ca_permit_intro_5","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801",'\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720 \uc911 "\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1"\uc774 \uc778\uc815\ub418\ub294 \ubc30\uacbd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a6O,0,"\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1\uc744 \uc704\ud55c \uacf5\ub3d9\ud589\uc704\ub294, \uac1c\ubcc4 \uc911\uc18c\uae30\uc5c5\uc774 \ub300\uae30\uc5c5\uacfc\uc758 \uacbd\uc7c1\uc5d0\uc11c \uc0c1\ub300\uc801\uc73c\ub85c \ubd88\ub9ac\ud55c \uc9c0\uc704\uc5d0 \uc788\ub294 \ud604\uc2e4\uc744 \uace0\ub824\ud558\uc5ec, \uc911\uc18c\uae30\uc5c5\ub4e4\uc774 \uacf5\ub3d9\uc73c\ub85c \ub300\uc751\ud568\uc73c\ub85c\uc368 \uacbd\uc7c1\ub825\uc744 \ud655\ubcf4\ud560 \ud544\uc694\uac00 \uc788\ub2e4\ub294 \uc815\ucc45\uc801 \ubc30\ub824\uc5d0\uc11c \uc778\uc815\ub418\ub294 \uc778\uac00\uc0ac\uc720\uc774\ub2e4.",B.GE,B.MY,null)
B.K8=s(["\ud2b9\uc815 \ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300","\ubd88\ud669\uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815","\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c","\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654","\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1"],t.s)
