B.arg=new A.c("gen_ca_permit_intro_6","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4","\uc778\uac00\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uc778\uac00 \ubaa9\uc801","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720\ub85c \uba85\uc2dc\uc801\uc73c\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294 \uac83\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.K8,0,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720\ub294 \ubd88\ud669\uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815, \uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c, \uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654, \uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1 \ub4f1 \uacf5\uc775\uc801 \ubaa9\uc801\uc5d0 \ud55c\uc815\ub418\uba70, \ud2b9\uc815 \ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300\uc640 \uac19\uc740 \uc0ac\uc801 \uc774\uc775 \ucd94\uad6c \ubaa9\uc801\uc740 \uc778\uac00\uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.Pz,B.Kz,null)
B.Wy=s(["\uc778\uac00\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\uace0 \ub300\ud1b5\ub839\ub839\uc774 \uc815\ud558\ub294 \uc138\ubd80 \uc694\uac74\uc744 \ucda9\uc871\ud558\uc5ec\uc57c \ud55c\ub2e4","\ub2e8\uc21c\ud788 \uc0ac\uc5c5\uc790\uc758 \uc2e0\uccad \uc758\uc0ac\ub9cc \uc788\uc73c\uba74 \ucda9\ubd84\ud558\ub2e4","\ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c \uc804\ub825\uc774 \uc5c6\uc5b4\uc57c\ub9cc \ud55c\ub2e4","\ubc18\ub4dc\uc2dc \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704\uc5d0 \uc788\ub294 \uc0ac\uc5c5\uc790\uc5ec\uc57c\ub9cc \ud55c\ub2e4","\ubc18\ub4dc\uc2dc 3\uac1c \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uc2e0\uccad\ud574\uc57c\ub9cc \ud55c\ub2e4"],t.s)
B.O0=s(["\uc778\uac00\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\uace0 \ub300\ud1b5\ub839\ub839\uc774 \uc815\ud558\ub294 \uc138\ubd80 \uc694\uac74\uc744 \ucda9\uc871\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
