B.acJ=s(["\uacf5\ub3d9\ud589\uc704\uc758 \ubaa9\uc801, \ub0b4\uc6a9, \ucc38\uc5ec \uc0ac\uc5c5\uc790, \uae30\ub300\ud6a8\uacfc \ub4f1\uc744 \uc18c\uba85\ud558\ub294 \uc790\ub8cc","\uc2e0\uccad\uc778\uc758 \ubcd1\ub825 \uc99d\uba85\uc11c","\uc2e0\uccad\uc778\uc758 \uac00\uc871\uad00\uacc4\uc99d\uba85\uc11c","\uc2e0\uccad\uc778\uc758 \ud559\ub825 \uc99d\uba85\uc11c","\uc2e0\uccad\uc778\uc758 \uac1c\uc778 \ucde8\ubbf8 \uad00\ub828 \uc790\ub8cc"],t.s)
