B.a3l=s([u.DD,"\uc0ac\uc5c5\uc790\uac00 \uc790\uccb4 \ud310\ub2e8\uc5d0 \ub530\ub77c \uc124\ube44 \ud22c\uc790\ub97c \ubcf4\ub958\ud558\ub294 \ud589\uc704","\uc815\ubd80\uac00 \ud658\uacbd \uaddc\uc81c\uc0c1 \uc124\ube44 \uc2e0\uc124\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc790\uae08 \uc0ac\uc815\uc73c\ub85c \uc778\ud574 \uc124\ube44 \ud22c\uc790\ub97c \ubbf8\ub8e8\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc2e0\uae30\uc220 \ub3c4\uc785\uc744 \uc704\ud574 \uc678\ubd80 \ucee8\uc124\ud305\uc744 \ubc1b\ub294 \ud589\uc704"],t.s)
