B.a4i=s([u.cn,"\uc0ac\uc5c5\uc790\uac00 \ud45c\uc900\ud654 \uae30\uad6c\ub97c \ud1b5\ud574 \uc815\ub2f9\ud55c \uc808\ucc28\ub85c \uaddc\uaca9\uc744 \ud1b5\uc77c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \ud310\ub2e8\ud558\uc5ec \ud2b9\uc815 \uaddc\uaca9\uc758 \uc0c1\ud488\ub9cc \uc0dd\uc0b0\ud558\uae30\ub85c \uacb0\uc815\ud558\ub294 \ud589\uc704","\uc815\ubd80\uac00 \uc548\uc804\uae30\uc900\uc5d0 \ub530\ub77c \uaddc\uaca9\uc744 \uc815\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc18c\ube44\uc790 \uc694\uad6c\uc5d0 \ub9de\ucd94\uc5b4 \ub2e4\uc591\ud55c \uaddc\uaca9\uc758 \uc0c1\ud488\uc744 \uac1c\ubc1c\ud558\ub294 \ud589\uc704"],t.s)
