B.ar0=new A.c("gen_collusion_type_info_1","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615",'\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615 \uc911 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ub610\ub294 \uc0ac\uc5c5\ub0b4\uc6a9\uc744 \ubc29\ud574\xb7\uc81c\ud55c\ud558\ub294 \ud589\uc704"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.GW,0,'"\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ub610\ub294 \uc0ac\uc5c5\ub0b4\uc6a9\uc744 \ubc29\ud574\xb7\uc81c\ud55c\ud558\ub294 \ud589\uc704"\ub294 \ub2f4\ud569\uc5d0 \ucc38\uc5ec\ud558\uc9c0 \uc54a\uac70\ub098 \ub2f4\ud569 \ub0b4\uc6a9\uc744 \ub530\ub974\uc9c0 \uc54a\ub294 \uc0ac\uc5c5\uc790(\uc774\ub978\ubc14 \uc544\uc6c3\uc0ac\uc774\ub354)\uc758 \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744, \ub2f4\ud569 \ucc38\uc5ec \uc0ac\uc5c5\uc790\ub4e4\uc774 \uacf5\ub3d9\uc73c\ub85c \ubc29\ud574\ud558\uac70\ub098 \uc81c\ud55c\ud568\uc73c\ub85c\uc368 \ub2f4\ud569\uc758 \uc2e4\ud6a8\uc131\uc744 \ud655\ubcf4\ud558\ub824\ub294 \uc720\ud615\uc744 \uc758\ubbf8\ud55c\ub2e4.',B.OP,B.a72,null)
B.acP=s([u.L,"\uacf5\uac1c\ub41c \ud1b5\uacc4\uc790\ub8cc\ub97c \ub2e8\uc21c\ud788 \uc5f4\ub78c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc870\uc0ac\uae30\uad00\uc758 \uacf5\uac1c \ubcf4\uace0\uc11c\ub97c \ucc38\uace0\ud558\ub294 \ud589\uc704","\uc18c\ube44\uc790\uac00 \uc0c1\ud488 \uc815\ubcf4\ub97c \uc778\ud130\ub137\uc5d0\uc11c \uac80\uc0c9\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc790\uc0ac\uc758 \uc7ac\ubb34\uc81c\ud45c\ub97c \uacf5\uc2dc\ud558\ub294 \ud589\uc704"],t.s)
B.a3a=s([u.L],t.s)
B.JB=s(["\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc758 \uc758\ubbf8"],t.s)
B.aqx=new A.c("gen_collusion_type_info_2","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615",'\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615 \uc911 "\uc815\ubcf4\ub97c \uc8fc\uace0\ubc1b\uc74c\uc73c\ub85c\uc368 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.acP,0,'"\uc815\ubcf4\uad50\ud658\uc744 \ud1b5\ud55c \uacbd\uc7c1\uc81c\ud55c" \uc720\ud615\uc740 \uc0ac\uc5c5\uc790\ub4e4\uc774 \uac00\uaca9, \uc0dd\uc0b0\ub7c9, \uc6d0\uac00 \ub4f1 \uacbd\uc7c1\uc5d0 \ubbfc\uac10\ud55c \uc815\ubcf4\ub97c \uc11c\ub85c \uad50\ud658\ud558\uace0 \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc0ac\uc2e4\uc0c1 \uc870\uc728\ud568\uc73c\ub85c\uc368, \uba85\uc2dc\uc801\uc778 \uac00\uaca9\xb7\ubb3c\ub7c9 \ud569\uc758\uac00 \uc5c6\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud6a8\uacfc\ub97c \uac00\uc838\uc624\ub294 \ub2f4\ud569 \uc720\ud615\uc73c\ub85c, \ucd5c\uadfc \uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc5d0 \ub300\ud55c \uaddc\uc81c\uac00 \uba85\uc2dc\uc801\uc73c\ub85c \uac15\ud654\ub41c \ub300\ud45c\uc801\uc778 \ubd84\uc57c\uc774\ub2e4.',B.a3a,B.JB,null)
B.QK=s([u.G,"\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc740 \uc560\ucd08\uc5d0 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4","\uc815\ubcf4\uad50\ud658\uc740 \ud56d\uc0c1 \uacf5\uac1c\ub41c \ubc29\uc2dd\uc73c\ub85c\ub9cc \uc774\ub8e8\uc5b4\uc9c0\uae30 \ub54c\ubb38\uc774\ub2e4","\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc740 \uc99d\uba85\ucc45\uc784\uc774 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc788\uae30 \ub54c\ubb38\uc774\ub2e4","\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc740 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.a1f=s([u.G],t.s)
B.M9=s(["\uc815\ubcf4\uad50\ud658 \ub2f4\ud569 \uc785\uc99d\uc758 \uc5b4\ub824\uc6c0"],t.s)
B.aqe=new A.c("gen_collusion_type_info_3","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615","\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc774 \uba85\uc2dc\uc801\uc778 \uac00\uaca9 \ud569\uc758\ubcf4\ub2e4 \uc785\uc99d\uc774 \uc5b4\ub824\uc6b4 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.QK,0,"\uc815\ubcf4\uad50\ud658 \ub2f4\ud569\uc740 \uac00\uaca9\uc774\ub098 \ubb3c\ub7c9\uc744 \uc9c1\uc811 \ud569\uc758\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc815\ubcf4\ub97c \uad50\ud658\ud558\ub294 \uac04\uc811\uc801\uc778 \ubc29\uc2dd\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c0\uae30 \ub54c\ubb38\uc5d0, \uadf8\ub7ec\ud55c \uc815\ubcf4\uad50\ud658\uc774 \uc2e4\uc81c\ub85c \uacbd\uc7c1\uc81c\ud55c\uc758 \uc758\ub3c4\ub97c \uac00\uc9c0\uace0 \uc774\ub8e8\uc5b4\uc84c\ub294\uc9c0\uc640 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\ub97c \ub0b3\uc558\ub294\uc9c0\ub97c \ubcc4\ub3c4\ub85c \uc99d\uba85\ud574\uc57c \ud558\ub294 \uc5b4\ub824\uc6c0\uc774 \uc788\ub2e4.",B.a1f,B.M9,null)
B.Qj=s([u.A_,"\ud611\uc758\uccb4 \ud65c\ub3d9\uc774\ubbc0\ub85c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\ubc95\ud558\ub2e4","\uac00\ub9f9\uc810 \ubaa8\uc9d1 \ubc29\ud574\ub294 \ub2f4\ud569 \uaddc\uc81c\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc774\ub7ec\ud55c \ud589\uc704\ub294 \ud56d\uc0c1 \uc18c\ube44\uc790 \ubcf4\ud638\ub97c \uc704\ud55c \uac83\uc73c\ub85c \uc815\ub2f9\ud654\ub41c\ub2e4","\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc624\uc9c1 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\ub85c\ub9cc \ud3c9\uac00\ub418\uace0 \ub2f4\ud569\uacfc\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
B.P3=s([u.A_],t.s)
B.I_=s(["\uac00\ub9f9\ubcf8\ubd80 \ud611\uc758\uccb4\uc758 \uc2e0\uaddc\uc9c4\uc785 \ubc29\ud574"],t.s)
B.apE=new A.c("gen_collusion_type_info_4","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615","\uac00\ub9f9\ubcf8\ubd80 \ud611\uc758\uccb4\uac00 \ube44\ud68c\uc6d0 \uc2e0\uaddc \ube0c\ub79c\ub4dc\uc758 \uac00\ub9f9\uc810 \ubaa8\uc9d1\uc744 \uc870\uc9c1\uc801\uc73c\ub85c \ubc29\ud574\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Qj,0,"\uae30\uc874 \uac00\ub9f9\ubcf8\ubd80\ub4e4\uc758 \ud611\uc758\uccb4\uac00 \uc2e0\uaddc \uc9c4\uc785 \ube0c\ub79c\ub4dc\uc758 \uac00\ub9f9\uc810 \ubaa8\uc9d1 \ud65c\ub3d9\uc744 \uc870\uc9c1\uc801\uc73c\ub85c \ubc29\ud574\ud558\ub294 \ud589\uc704\ub294, \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubc29\ud574\xb7\uc81c\ud55c\ud558\ub294 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \uc18c\uc9c0\uac00 \uc788\uc73c\uba70, \uc774\ub294 \uc2e0\uaddc \uc9c4\uc785\uc744 \ubd09\uc1c4\ud558\uc5ec \uae30\uc874 \uc0ac\uc5c5\uc790\ub4e4\uc758 \uacbd\uc7c1\uc744 \uc778\uc704\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \uacb0\uacfc\ub97c \uac00\uc838\uc62c \uc218 \uc788\ub2e4.",B.P3,B.I_,null)
B.a3N=s([u.eK,"\uc720\ud615\uc744 \ud3ed\ub113\uac8c \uaddc\uc815\ud558\uba74 \uc624\ud788\ub824 \ub2f4\ud569 \uaddc\uc81c\uac00 \uc57d\ud654\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ubc95\uc815 \uc720\ud615\uc740 \uc2e4\ubb34\uc0c1 \uc804\ud600 \ud65c\uc6a9\ub418\uc9c0 \uc54a\uae30 \ub54c\ubb38\uc774\ub2e4","\ubc95\uc815 \uc720\ud615\uc774 \ub9ce\uc744\uc218\ub85d \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\ubc95\uc815 \uc720\ud615\uc740 \ud615\uc2dd\uc801 \ub098\uc5f4\uc5d0 \ubd88\uacfc\ud558\uc5ec \uc2e4\uc9c8\uc801 \uc758\ubbf8\uac00 \uc5c6\ub2e4"],t.s)
B.acv=s([u.eK],t.s)
B.RJ=s(["\ubc95\uc815 \uc720\ud615\uc774 \ud3ed\ub113\uac8c \uaddc\uc815\ub41c \uc774\uc720"],t.s)
B.ao4=new A.c("gen_collusion_type_info_5","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\uc758 \ubc95\uc815 \uc720\ud615\uc774 \uc608\uc2dc\uc801\uc73c\ub85c \ud3ed\ub113\uac8c \uaddc\uc815\ub418\uc5b4 \uc788\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a3N,0,"\uacf5\uc815\uac70\ub798\ubc95\uc774 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc720\ud615\uc744 \uac00\uaca9, \uac70\ub798\uc870\uac74, \uc0dd\uc0b0\xb7\ucd9c\uace0 \uc81c\ud55c, \uc2dc\uc7a5\ubd84\ud560, \uc124\ube44\uc81c\ud55c, \uc0c1\ud488 \uaddc\uaca9 \uc81c\ud55c, \ud68c\uc0ac \uc124\ub9bd, \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \uc815\ubcf4\uad50\ud658 \ub4f1\uc73c\ub85c \ud3ed\ub113\uac8c \uc608\uc2dc\uc801\uc73c\ub85c \uaddc\uc815\ud558\uace0 \uc788\ub294 \uac83\uc740, \uc0ac\uc5c5\uc790\ub4e4\uc774 \ucde8\ud560 \uc218 \uc788\ub294 \ub2f4\ud569\uc758 \ubc29\uc2dd\uc774 \ub9e4\uc6b0 \ub2e4\uc591\ud558\uace0 \uacc4\uc18d \uc9c4\ud654\ud558\ubbc0\ub85c \uc0c8\ub85c\uc6b4 \ud615\ud0dc\uc758 \uacbd\uc7c1\uc81c\ud55c \ud569\uc758\ub3c4 \uaddc\uc728\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uae30 \uc704\ud568\uc774\ub2e4.",B.acv,B.RJ,null)
B.IN=s([u.H,"\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \uac1c\uc778 \uc2e0\uc0c1 \uc815\ubcf4\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615\uacfc \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc774 \ud30c\ud2b8 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ub2f4\ud569 \ud68c\uc758 \uc7a5\uc18c\uc758 \uc8fc\uc18c\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
B.a_4=s([u.H],t.s)
B.arS=new A.c("gen_collusion_type_info_6","economic_law","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574 \uc720\ud615","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.IN,0,"\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uc720\ud615 \uad00\ub828 \ubb38\uc81c\ub294 \uac00\uaca9\xb7\uac70\ub798\uc870\uac74\uc5d0 \uad00\ud55c \uc720\ud615, \uc0dd\uc0b0\xb7\uc2dc\uc7a5\ubd84\ud560\xb7\uc124\ube44\uc81c\ud55c \ub4f1 \uc2dc\uc7a5\uad6c\uc870\uc5d0 \uad00\ud55c \uc720\ud615, \uc815\ubcf4\uad50\ud658\xb7\ub2e4\ub978 \uc0ac\uc5c5\uc790 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574 \uc720\ud615\uc774\ub77c\ub294 \uc138 \uac08\ub798\uc758 \uad6c\ubcc4\uacfc, \uac01 \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\ub294 \uad6c\uccb4\uc801\uc778 \ud589\uc704 \uc608\uc2dc\ub97c \uc815\ud655\ud788 \uad6c\ubd84\ud558\ub294 \uac83\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.a_4,B.ba,null)
B.Xw=s(["\uc2dc\uc7a5\uc810\uc720\uc728 55%\uc778 \ub2e8\uc77c \uc0ac\uc5c5\uc790 A","\uc2dc\uc7a5\uc810\uc720\uc728 40%\uc778 B\uc640 \uc2dc\uc7a5\uc810\uc720\uc728 15%\uc778 C\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 3\uc704 \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\ubcf4\ub2e4 \ud070 \uacbd\uc6b0\uc758 B, C","\uc2dc\uc7a5\uc810\uc720\uc728 12%\uc5d0 \ubd88\uacfc\ud558\uace0 \uc2dc\uc7a5\uc810\uc720\uc728 \uc21c\uc704\uac00 3\uc704 \uc774\ud558\uc778 D","\uc2dc\uc7a5\uc810\uc720\uc728\uc774 \uac01\uac01 35%, 20%\uc778 3 \uc774\ud558\uc758 \uc0ac\uc5c5\uc790 \uc911 \ud558\ub098\uc778 E","\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0 \uc810\uc720\uc728\uc774 40%\uc778 F"],t.s)
B.a2Q=s(["\uc21c\uc704\ub3c4 3\uc704 \ubc16\uc778 \uc0ac\uc5c5\uc790\ub294 \uc704 \ub450 \uc694\uac74 \uc911 \uc5b4\ub290 \uac83\ub3c4 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \ucd94\uc815 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678"],t.s)
B.a2B=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815"],t.s)
B.ajX=new A.c("gen_md_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\ub294? (\uacc4\uc5f4\uad00\uacc4\ub294 \uc5c6\ub2e4\uace0 \uac00\uc815\ud558\uba70, \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc5f0\uac04 \ub9e4\ucd9c\uc561 \uae30\uc900)",B.Xw,2,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c6\uc870\ub294 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \u2460 \uc2dc\uc7a5\uc810\uc720\uc728\uc774 1\uc704\uc778 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 50% \uc774\uc0c1\uc774\uac70\ub098, \u2461 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0c1\uc704 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 75% \uc774\uc0c1\uc778 \uacbd\uc6b0(\ub2e4\ub9cc \uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uc81c\uc678)\uc5d0 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \uc774 \uae30\uc900\uc744 \uc801\uc6a9\ud558\uba74 A(55%)\ub294 \u2460\uc5d0 \ud574\ub2f9\ud558\uace0, B(23%)\xb7C(70%)\xb7D(4%)\xb7E(6%)\xb7F(40%) \uac19\uc740 \uc0ac\ub840\uc5d0\uc11c\ub3c4 \uc0c1\uc704 3\uac1c \ud569\uc0b0 \uc810\uc720\uc728\uacfc 10% \ubbf8\ub9cc \uc81c\uc678 \uaddc\uc815\uc744 \uc801\uc6a9\ud574 \ud310\ub2e8\ud574\uc57c \ud55c\ub2e4. \uc2dc\uc7a5\uc810\uc720\uc728\uc774 \ub0ae\uace0(\uc608: 12%) \uc21c\uc704\ub3c4 3\uc704 \ubc16\uc778 \uc0ac\uc5c5\uc790\ub294 \uc704 \ub450 \uc694\uac74 \uc911 \uc5b4\ub290 \uac83\ub3c4 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \ucd94\uc815 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec\uc774\ub2e4.",B.a2Q,B.a2B,null)
B.a0d=s(["\uac70\ub798\uc758 \uac1d\uccb4\ubcc4\ub85c \uac70\ub798\ub418\ub294 \uc0c1\ud488\uc758 \uc885\ub958 \ubc0f \uc131\uc9c8\uc5d0 \ub530\ub77c \uad6c\ubd84\ub420 \uc218 \uc788\ub294 \uac70\ub798\ubd84\uc57c\ub97c \ub9d0\ud55c\ub2e4","\uc218\uc694\uc790\uac00 \uac00\uaca9 \uc778\uc0c1\uc5d0 \ub300\uc751\ud574 \ub2e4\ub978 \uc0c1\ud488\uc73c\ub85c \ub300\uccb4\ud560 \uc218 \uc788\ub294 \uc815\ub3c4(\uc218\uc694\ub300\uccb4\uc131)\ub97c \uc8fc\uc694 \ud310\ub2e8\uae30\uc900\uc73c\ub85c \uc0bc\ub294\ub2e4","\uacf5\uae09\uc790\uc758 \uc0dd\uc0b0\uc124\ube44 \uc804\ud658 \uac00\ub2a5\uc131 \ub4f1 \uacf5\uae09\ub300\uccb4\uc131\ub3c4 \uc2dc\uc7a5 \ud68d\uc815\uc5d0\uc11c \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uac70\ub798\uc758 \uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \uad00\ub828\uc2dc\uc7a5 \ud68d\uc815\uacfc \ubb34\uad00\ud558\uba70 \uc624\uc9c1 \uc0c1\ud488\uc758 \uc885\ub958\ub9cc\uc73c\ub85c \uc2dc\uc7a5\uc744 \ud68d\uc815\ud55c\ub2e4","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\ub294 \uac70\ub798\uc758 \uac1d\uccb4\xb7\ub2e8\uacc4\xb7\uc9c0\uc5ed\ubcc4\ub85c \ub2e4\ub974\uac8c \ub098\ud0c0\ub0a0 \uc218 \uc788\ub2e4"],t.s)
B.a3j=s(["\uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \uad00\ub828\uc2dc\uc7a5 \ud68d\uc815\uacfc \ubb34\uad00"],t.s)
B.PQ=s(["\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c","\uad00\ub828\uc2dc\uc7a5 \ud68d\uc815"],t.s)
B.apt=new A.c("gen_md_share_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5) \ud68d\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?',B.a0d,3,'\uad00\ub828\uc2dc\uc7a5(\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c) \ud68d\uc815\uc740 \uc0c1\ud488\uc2dc\uc7a5\ubfd0 \uc544\ub2c8\ub77c \uc9c0\ub9ac\uc801 \uc2dc\uc7a5\ub3c4 \ud568\uaed8 \uace0\ub824\ud558\uc5ec \uc774\ub8e8\uc5b4\uc9c4\ub2e4. \uc218\uc694\uc790\uac00 \ub2e4\ub978 \uc9c0\uc5ed\uc758 \uacf5\uae09\uc790\ub85c\ubd80\ud130 \uc0c1\ud488\uc744 \uc870\ub2ec\ud560 \uc218 \uc788\ub294\uc9c0(\uc9c0\ub9ac\uc801 \ub300\uccb4\uac00\ub2a5\uc131) \uc5ed\uc2dc \uc2dc\uc7a5\uc9c0\ubc30\ub825 \ud310\ub2e8\uc5d0 \uc911\uc694\ud55c \uc694\uc18c\uc774\ubbc0\ub85c, "\uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \ubb34\uad00\ud558\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \uc2e4\ubb34\uc0c1 \uad00\ub828\uc2dc\uc7a5\uc740 \uc0c1\ud488\uc2dc\uc7a5\uacfc \uc9c0\uc5ed\uc2dc\uc7a5\uc744 \ud568\uaed8 \ud68d\uc815\ud55c \ub4a4 \uadf8 \uad50\uc9d1\ud569\uc744 \uae30\uc900\uc73c\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud55c\ub2e4.',B.a3j,B.PQ,null)
B.a7E=s(["\uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uc0c1\uc704 3\uac1c \uc0ac\uc5c5\uc790 \ud569\uc0b0 \uc810\uc720\uc728 \uacc4\uc0b0\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 1\uc704 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 40%\uc774\uba74 \uadf8 \uc790\uccb4\ub9cc\uc73c\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub41c\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc740 \ud55c\ubc88 \uc131\ub9bd\ud558\uba74 \ubc18\uc99d\uc744 \ud1b5\ud574\uc11c\ub3c4 \ubc88\ubcf5\ud560 \uc218 \uc5c6\ub2e4","\uc5f0\uac04 \ub9e4\ucd9c\uc561 \ub610\ub294 \uacf5\uae09\ub7c9 \uae30\uc900 \uc911 \uc5b4\ub290 \ud558\ub098\ub9cc \uc0ac\uc6a9\ud560 \uc218 \uc788\uace0 \ubcd1\ud589 \uc0ac\uc6a9\uc740 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ucd94\uc815 \uc694\uac74\uc744 \ucda9\uc871\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \ub2e4\uc218\uc778 \uacbd\uc6b0 \uadf8\uc911 1\uac1c \uc0ac\uc5c5\uc790\ub9cc \uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc9c0\uc815\ub41c\ub2e4"],t.s)
B.Z1=s(["\uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uadf8 \uc0b0\uc815\uc5d0\uc11c \uc81c\uc678"],t.s)
B.a9i=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815","10% \ubbf8\ub9cc \uc81c\uc678"],t.s)
B.aqX=new A.c("gen_md_share_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740? (\uacc4\uc5f4\uad00\uacc4 \uc5c6\uc74c\uc744 \uc804\uc81c)",B.a7E,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc2dc\ud589\ub839\uc740 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0c1\uc704 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 75% \uc774\uc0c1\uc778 \uacbd\uc6b0\ub97c \ucd94\uc815 \uc694\uac74\uc73c\ub85c \uc0bc\ub418, \uc774\ub54c \uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uadf8 \uc0b0\uc815\uc5d0\uc11c \uc81c\uc678\ud558\ub3c4\ub85d \uc815\ud558\uace0 \uc788\ub2e4. 1\uc704 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 50% \ubbf8\ub9cc(\uc608: 40%)\uc774\uba74 \ub2e8\ub3c5 \ucd94\uc815 \uc694\uac74(50% \uc774\uc0c1)\uc744 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \uadf8 \uc790\uccb4\ub9cc\uc73c\ub85c \ucd94\uc815\ub418\uc9c0 \uc54a\uc73c\uba70, \ucd94\uc815\uc740 \ubc95\ub960\uc0c1 \ucd94\uc815\uc73c\ub85c\uc11c \ubc18\uc99d\uc744 \ud1b5\ud574 \ubc88\ubcf5\ub420 \uc218 \uc788\ub2e4. \ub9e4\ucd9c\uc561\xb7\uacf5\uae09\ub7c9 \uae30\uc900\uc740 \uc0ac\uc5c5\uc758 \ud2b9\uc131\uc5d0 \ub530\ub77c \uc801\uc808\ud788 \uc120\ud0dd\ub418\ub294 \uac83\uc774\uc9c0 \ubcd1\ud589 \uc0ac\uc6a9\uc774 \uae08\uc9c0\ub418\ub294 \uac83\ub3c4 \uc544\ub2c8\ub2e4.",B.Z1,B.a9i,null)
B.a_C=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c \uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uad00\uacc4\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ud310\ub2e8\uacfc \uc804\ud600 \uad00\ub828\uc774 \uc5c6\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\uac00 \uba87 \uac1c\uc774\ub4e0 \ud569\uc0b0 \uc810\uc720\uc728\uc740 \ud56d\uc0c1 \ub2e8\ub3c5 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\ubcf4\ub2e4 \ub0ae\uac8c \uacc4\uc0b0\ub41c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0\uc740 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \ud310\ub2e8\uc5d0\uc11c\ub9cc \uc801\uc6a9\ub418\uace0 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ud310\ub2e8\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \uac1c\ubcc4 \ubc95\uc778\uc758 \uc810\uc720\uc728\ub9cc \ub3c5\ub9bd\uc801\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4"],t.s)
B.a4h=s(["\uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud55c\ub2e4"],t.s)
B.a7O=s(["\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8"],t.s)
B.aiY=new A.c("gen_md_share_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud569\uc0b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.a_C,0,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c\ub294 \uc0ac\uc5c5\uc790\uac00 \uc18d\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc758 \uacc4\uc5f4\ud68c\uc0ac \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \ud615\uc2dd\uc801\uc73c\ub85c\ub294 \ubcc4\uac1c \ubc95\uc778\uc774\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \ub3d9\uc77c\ud55c \uc9c0\ubc30\ub825 \uc544\ub798 \uc788\ub294 \uacc4\uc5f4\ud68c\uc0ac\ub4e4\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \uac1c\ubcc4\uc801\uc73c\ub85c\ub9cc \ubcf4\uba74 \uc2e4\uc81c \uc2dc\uc7a5\uc9c0\ubc30\ub825\uc744 \uacfc\uc18c\ud3c9\uac00\ud560 \uc704\ud5d8\uc774 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4. \ub530\ub77c\uc11c \uacc4\uc5f4\uad00\uacc4\uac00 \uc788\ub294 \uacbd\uc6b0 \ud569\uc0b0 \uc810\uc720\uc728\uc744 \uae30\uc900\uc73c\ub85c \ucd94\uc815 \uc694\uac74 \ucda9\uc871 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud574\uc57c \ud55c\ub2e4.",B.a4h,B.a7O,null)
B.Hl=s(["\ucd94\uc815 \uaddc\uc815\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc785\uc99d \ubd80\ub2f4\uc744 \uc644\ud654\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ucd94\uc815\uc744 \ubc1b\uc740 \uc0ac\uc5c5\uc790\ub294 \uc2e4\uc81c\ub85c\ub294 \uc2dc\uc7a5\uc9c0\ubc30\ub825\uc774 \uc5c6\ub2e4\ub294 \uc810\uc744 \ubc18\uc99d\ud558\uc5ec \ucd94\uc815\uc744 \ubc88\ubcf5\ud560 \uc218 \uc788\ub2e4","\ucd94\uc815 \uc694\uac74\uc740 \uc2dc\uc7a5\uc810\uc720\uc728\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \uc9c4\uc785\uc7a5\ubcbd\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790 \uc218 \ub4f1 \ub2e4\ub978 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\ub294 \uc0c1\ud488\uc774\ub098 \uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \uc0ac\uc5c5\uc790\ubfd0 \uc544\ub2c8\ub77c \uc218\uc694\uc790\uc758 \uc9c0\uc704\uc5d0 \uc788\ub294 \uc0ac\uc5c5\uc790\ub3c4 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4","\ucd94\uc815\uc744 \ubc1b\uc9c0 \uc54a\uc740 \uc0ac\uc5c5\uc790\ub3c4 \ub2e4\ub978 \uc0ac\uc815\uc744 \uadfc\uac70\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4"],t.s)
B.abF=s(["\uc9c4\uc785\uc7a5\ubcbd\uc758 \uc874\uc7ac, \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc218\uc640 \uaddc\ubaa8, \uc720\uc0ac\ud488\xb7\uc778\uc811\uc2dc\uc7a5\uc758 \uc874\uc7ac \uc5ec\ubd80 \ub4f1 \ub2e4\uc591\ud55c \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824"],t.s)
B.Hj=s(["\uc2dc\uc7a5\uc9c0\ubc30\ub825 \uc2e4\uc9c8\ud310\ub2e8","\ucd94\uc815\uc758 \uc131\uaca9"],t.s)
B.akJ=new A.c("gen_md_share_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uacfc \uad00\ub828\ud558\uc5ec \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Hl,2,'\uc2dc\uc7a5\uc810\uc720\uc728\uc5d0 \uc758\ud55c \ucd94\uc815\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8\uc744 \uc6a9\uc774\ud558\uac8c \ud558\uae30 \uc704\ud55c \ubc95\ub960\uc0c1 \ucd94\uc815\uc5d0 \ubd88\uacfc\ud558\uba70, \uc2e4\uc81c \uc2dc\uc7a5\uc9c0\ubc30\ub825 \uc720\ubb34\ub97c \ucd5c\uc885\uc801\uc73c\ub85c \ud310\ub2e8\ud560 \ub54c\ub294 \uc9c4\uc785\uc7a5\ubcbd\uc758 \uc874\uc7ac, \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc218\uc640 \uaddc\ubaa8, \uc720\uc0ac\ud488\xb7\uc778\uc811\uc2dc\uc7a5\uc758 \uc874\uc7ac \uc5ec\ubd80 \ub4f1 \ub2e4\uc591\ud55c \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4. \ub530\ub77c\uc11c "\uc2dc\uc7a5\uc810\uc720\uc728\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \ub2e4\ub978 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ucd94\uc815\uc744 \ubc1b\uc9c0 \ubabb\ud55c \uc0ac\uc5c5\uc790\ub77c\ub3c4 \uc774\ub7ec\ud55c \uc2e4\uc9c8\uc801 \uc0ac\uc815\uc5d0 \ub530\ub77c \uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc778\uc815\ub420 \uc218 \uc788\uace0, \ubc18\ub300\ub85c \ucd94\uc815\ub41c \uc0ac\uc5c5\uc790\ub3c4 \ubc18\uc99d\uc73c\ub85c \uc774\ub97c \ubc88\ubcf5\ud560 \uc218 \uc788\ub2e4.',B.abF,B.Hj,null)
B.a2L=s(["\uc6d0\uce59\uc801\uc73c\ub85c \ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc758 \uad6d\ub0b4 \uacf5\uae09\ub41c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561 \ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728\ub85c \uc0b0\uc815\ud55c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc624\uc9c1 \uc218\ucd9c\uc561\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4","\uc6a9\uc5ed\uc5c5\uc758 \uacbd\uc6b0 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815 \uc790\uccb4\uac00 \ubd88\uac00\ub2a5\ud558\ub2e4","\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacf5\uae09\ub7c9 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc5c6\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \ud56d\uc0c1 \uc804\uc138\uacc4 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4"],t.s)
B.WC=s(["\ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc758 \uad6d\ub0b4 \uacf5\uae09\ub41c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561 \ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728\ub85c \uc0b0\uc815"],t.s)
B.QM=s(["\uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815\uae30\uc900"],t.s)
B.aj9=new A.c("gen_md_share_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815 \uae30\uc900\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a2L,0,"\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud574\ub2f9 \uc0ac\uc5c5\uc790\uac00 \ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc5d0 \uad6d\ub0b4\uc5d0\uc11c \uacf5\uae09\ud55c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561(\ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728)\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4. \ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub294 \uacf5\uae09\ub7c9, \uc0dd\uc0b0\ub2a5\ub825, \uc790\uc0b0\ucd1d\uc561 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \ud65c\uc6a9\ud574 \uc0b0\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\uc73c\uba70, \uc774\ub294 \uc0c1\ud488\uc5c5\ubfd0 \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc5c5\uc5d0\ub3c4 \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4. \uad6d\ub0b4\uc2dc\uc7a5\uc744 \ub300\uc0c1\uc73c\ub85c \ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ubbc0\ub85c \uc218\ucd9c\uc561\uc774\ub098 \uc804\uc138\uacc4 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud558\uc9c0 \uc54a\ub294\ub2e4.",B.WC,B.QM,null)
B.VP=s(["\u3131, \u3134","\u3131, \u3137","\u3134, \u3137","\u3134, \u3139","\u3137, \u3139"],t.s)
B.Xl=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc694\uc18c(\uc124\ube44\xb7\uae30\uc220 \ub4f1)\uc758 \uc0ac\uc6a9\xb7\uc811\uadfc\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704(\u3137)\uac00 \ub300\ud45c\uc801"],t.s)
B.L_=s(["\uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704"],t.s)
B.ak1=new A.c("gen_md_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704 \uc720\ud615 \uc911 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\ub798\ud558\ub294 \uc720\ud1b5\uc0ac\uc5c5\uc790\uc640 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \ud589\uc704\n\u3134. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubc29\ud574\ud558\uae30 \uc704\ud574 \uc800\uac00\ub85c \uc0c1\ud488\uc744 \ud310\ub9e4\ud558\ub294 \ud589\uc704\n\u3137. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488 \uc0dd\uc0b0\uc5d0 \ud544\uc218\uc801\uc778 \uc694\uc18c\uc758 \uc0ac\uc6a9\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\n\u3139. \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uac00\uaca9\uc744 \uacb0\uc815\ud558\ub294 \ud589\uc704",B.VP,1,'\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc911 "\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704"\ub294 \uc0c8\ub85c\uc6b4 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0 \uc9c4\uc785\ud558\ub294 \uac83 \uc790\uccb4\ub97c \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d \uccb4\uacb0(\u3131)\uacfc \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc694\uc18c(\uc124\ube44\xb7\uae30\uc220 \ub4f1)\uc758 \uc0ac\uc6a9\xb7\uc811\uadfc\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704(\u3137)\uac00 \ub300\ud45c\uc801\uc774\ub2e4. \ubc18\uba74 \u3134(\uc800\uac00 \ud310\ub9e4\ub85c \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574)\uc740 \uc774\ubbf8 \uc2dc\uc7a5\uc5d0 \uc874\uc7ac\ud558\ub294 \uc0ac\uc5c5\uc790\ub97c \uaca8\ub0e5\ud55c "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574" \uc720\ud615\uc774\uace0, \u3139(\uc18c\ube44\uc790\uc774\uc775\uc744 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uac00\uaca9 \uacb0\uc815)\uc740 \ubcc4\ub3c4\uc758 \ub3c5\uc790\uc801\uc778 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615(\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704)\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4. \ub2e4\uc12f \uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc744 \uc11c\ub85c \uad6c\ubd84\ud574\uc11c \uc554\uae30\ud558\ub294 \uac83\uc774 \uc774 \ucc55\ud130\uc758 \ud575\uc2ec\uc774\ub2e4.',B.Xl,B.L_,null)
B.O7=s(["\uc0c1\ud488\uc758 \uac00\uaca9\uc744 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ubd80\ub2f9\ud558\uac8c \uacb0\uc815\xb7\uc720\uc9c0 \ub610\ub294 \ubcc0\uacbd\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4","\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uc815\ub2f9\ud55c \uc0ac\uc720\uac00 \uc788\ub294 \uac00\uaca9 \uc778\uc0c1\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \uac00\uaca9\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4","\uac00\uaca9\ubfd0\ub9cc \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc758 \ub300\uac00\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc5d0 \ud3ec\ud568\ub41c\ub2e4","\uac00\uaca9\uc758 \uc778\uc0c1\ubfd0\ub9cc \uc544\ub2c8\ub77c \ubd80\ub2f9\ud55c \uc778\ud558\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\uac00\uaca9\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\ub824\uba74 \ubc18\ub4dc\uc2dc \uc2e4\uc81c\ub85c \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.S5=s(["\uadf8\ub85c \uc778\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2e4\uc81c\ub85c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uacb0\uacfc\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.a4N=s(["\uac00\uaca9\ub0a8\uc6a9"],t.s)
B.aiL=new A.c("gen_md_type_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\uac00\uaca9\ub0a8\uc6a9" \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?',B.O7,4,"\uac00\uaca9\ub0a8\uc6a9\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac00\uaca9(\ub610\ub294 \uc6a9\uc5ed\uc758 \ub300\uac00)\uc744 \ubd80\ub2f9\ud558\uac8c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd\ud558\ub294 \ud589\uc704 \uc790\uccb4\ub97c \uaddc\uc81c\ud558\ub294 \uac83\uc73c\ub85c, \uadf8\ub85c \uc778\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2e4\uc81c\ub85c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uacb0\uacfc\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\ub294\ub2e4. \ubd80\ub2f9\uc131 \ud310\ub2e8\uc740 \uc6d0\uac00 \ubcc0\ub3d9 \uc694\uc778, \uc720\uc0ac \uc2dc\uc7a5\uc758 \uac00\uaca9 \uc218\uc900, \uc774\uc724 \ud3ed\uc758 \ubcc0\ud654 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uba70, \uc778\uc0c1\ubfd0 \uc544\ub2c8\ub77c \ubd80\ub2f9\ud55c \uc778\ud558(\uc6d0\uac00 \uc774\ud558 \ud310\ub9e4\ub97c \ud1b5\ud55c \uacbd\uc7c1\uc81c\ud55c \ub4f1)\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.S5,B.a4N,null)
B.Ux=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c1\ud488\uc758 \uacf5\uae09\ub7c9\uc744 \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\ub294 \ud589\uc704","\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uc774\uc775\uc744 \uc81c\uacf5\ud558\ub3c4\ub85d \uac15\uc694\ud558\ub294 \ud589\uc704","\uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uae30 \uc704\ud558\uc5ec \uc815\uc0c1\uac70\ub798\uad00\ud589\uc5d0 \ube44\ucd94\uc5b4 \uc774\ub840\uc801\uc778 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \ubc29\ud574\ud558\ub294 \ud589\uc704"],t.s)
B.abd=s(["\uc0c1\ud488\uc758 \uc0dd\uc0b0\xb7\ucd9c\uace0\xb7\ud310\ub9e4\ub97c \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\uac70\ub098 \uc99d\uac00\uc2dc\ucf1c"],t.s)
B.a8Z=s(["\ucd9c\uace0\uc870\uc808"],t.s)
B.ao9=new A.c("gen_md_type_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\ucd9c\uace0\uc870\uc808" \ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740?',B.Ux,0,"\ucd9c\uace0\uc870\uc808\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c1\ud488\uc758 \uc0dd\uc0b0\xb7\ucd9c\uace0\xb7\ud310\ub9e4\ub97c \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\uac70\ub098 \uc99d\uac00\uc2dc\ucf1c \uc0c1\ud488 \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \uc774\ub294 \uc2dc\uc7a5\uc758 \uc218\uae09\uc744 \uc778\uc704\uc801\uc73c\ub85c \uc870\uc791\ud558\uc5ec \uac00\uaca9\uc774\ub098 \uac70\ub798\uc870\uac74\uc5d0 \ubd80\ub2f9\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub824\ub294 \ud589\uc704\ub85c\uc11c, \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\xb7\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\uc640\ub294 \uad6c\ubcc4\ub418\ub294 \ub3c5\uc790\uc801\uc778 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc774\ub2e4.",B.abd,B.a8Z,null)
B.aal=s(["\u3131, \u3134","\u3131, \u3137","\u3134, \u3137","\u3131, \u3134, \u3137","\u3134\ub9cc"],t.s)
B.aad=s(["\ud544\uc218\uc694\uc18c \uc0ac\uc6a9 \uac70\uc808(\u3131), \uc6d0\uc7ac\ub8cc \uad6c\ub9e4 \ubc29\ud574(\u3134), \uc778\ub825 \ucc44\uc6a9 \ubc29\ud574 \ub4f1\uc774 \ub300\ud45c\uc801 \uc720\ud615"],t.s)
B.a3k=s(["\uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
B.aj0=new A.c("gen_md_type_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488 \uc0dd\uc0b0\xb7\ud310\ub9e4\uc5d0 \ud544\uc218\uc801\uc778 \uc694\uc18c\uc758 \uc0ac\uc6a9\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\n\u3134. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc6d0\uc7ac\ub8cc \uad6c\ub9e4\ub97c \ubc29\ud574\ud558\ub294 \ud589\uc704\n\u3137. \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uc0c1\ud488 \ud310\ub9e4\ub97c \ud558\ub294 \ud589\uc704',B.aal,0,'"\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\ub294 \uc774\ubbf8 \uc2dc\uc7a5\uc5d0 \uc874\uc7ac\ud558\ub294 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub85c, \ud544\uc218\uc694\uc18c \uc0ac\uc6a9 \uac70\uc808(\u3131), \uc6d0\uc7ac\ub8cc \uad6c\ub9e4 \ubc29\ud574(\u3134), \uc778\ub825 \ucc44\uc6a9 \ubc29\ud574 \ub4f1\uc774 \ub300\ud45c\uc801 \uc720\ud615\uc774\ub2e4. \ubc18\uba74 \u3137(\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc6b0\ub824\uac00 \uc788\ub294 \uc0c1\ud488 \ud310\ub9e4)\uc740 \ubcc4\ub3c4\ub85c \ubd84\ub958\ub418\ub294 "\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704" \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704\uc640 \uad6c\ubd84\ud574\uc57c \ud55c\ub2e4.',B.aad,B.a3k,null)
B.a6_=s(["\ubd80\ub2f9\ud558\uac8c \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\ub85c\uc11c \ub2e4\ub978 4\uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc\ub294 \ubcc4\ub3c4\ub85c \uaddc\uc815\ub41c \ubcf4\ucda9\uc801 \uc720\ud615\uc774\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \ubc18\ub4dc\uc2dc \uac00\uaca9 \uc778\uc0c1\uc744 \uc218\ubc18\ud558\uc5ec\uc57c \uc131\ub9bd\ud55c\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\uac00 \uc131\ub9bd\ud558\ub824\uba74 \uc2e4\uc81c \uc18c\ube44\uc790 \ud53c\ud574\uac00 \ud655\uc815\uc801\uc73c\ub85c \ubc1c\uc0dd\ud574\uc57c \ud55c\ub2e4"],t.s)
B.Rs=s(["\ub2e4\ub978 4\uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc\ub294 \ubcc4\ub3c4\ub85c \uaddc\uc815\ub41c \ubcf4\ucda9\uc801 \uc720\ud615"],t.s)
B.Yp=s(["\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704"],t.s)
B.ajT=new A.c("gen_md_type_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?',B.a6_,0,'\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \ubd80\ub2f9\ud558\uac8c \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uac00\uaca9\ub0a8\uc6a9\xb7\ucd9c\uace0\uc870\uc808\xb7\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uc2dc\uc7a5\ucc38\uac00\ubc29\ud574\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c\ub77c\ub294 \ub2e4\ub978 \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub354\ub77c\ub3c4 \uc18c\ube44\uc790 \uc774\uc775\uc744 \ud604\uc800\ud788 \uce68\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub2e4\uba74 \uaddc\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \ub9c8\ub828\ub41c \ubcf4\ucda9\uc801\xb7\ud3ec\uad04\uc801 \uc131\uaca9\uc758 \uc720\ud615\uc774\ub2e4. "\uc6b0\ub824\uac00 \uc788\ub294" \ud589\uc704\ub97c \uaddc\uc81c \ub300\uc0c1\uc73c\ub85c \ud558\ubbc0\ub85c \uc2e4\uc81c \ud53c\ud574\uac00 \ud655\uc815\uc801\uc73c\ub85c \ubc1c\uc0dd\ud560 \uac83\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\uc73c\uba70, \uac00\uaca9 \uc778\uc0c1\uc744 \ubc18\ub4dc\uc2dc \uc218\ubc18\ud574\uc57c \ud558\ub294 \uac83\ub3c4 \uc544\ub2c8\ub2e4.',B.Rs,B.Yp,null)
B.a3O=s(["\uac00\uaca9\ub0a8\uc6a9 \u2013 \ucd9c\uace0\uc870\uc808 \u2013 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \u2013 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c\xb7\uc18c\ube44\uc790\uc774\uc775\uc800\ud574","\uac00\uaca9\ub0a8\uc6a9 \u2013 \ubd80\ub2f9\uc5fc\ub9e4 \u2013 \uac70\ub798\uac70\uc808 \u2013 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \u2013 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uac00\uaca9\ub0a8\uc6a9 \u2013 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \u2013 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \u2013 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574","\ucd9c\uace0\uc870\uc808 \u2013 \ub2f4\ud569 \u2013 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \u2013 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uac00\uaca9\ub0a8\uc6a9 \u2013 \ucd9c\uace0\uc870\uc808 \u2013 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \u2013 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \u2013 \uc18c\ube44\uc790\uc774\uc775\uc800\ud574"],t.s)
B.a7s=s(["\uac00\uaca9\ub0a8\uc6a9, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c"],t.s)
B.MZ=s(["\ub0a8\uc6a9\ud589\uc704 5\uc720\ud615 \ucd1d\uc815\ub9ac"],t.s)
B.anu=new A.c("gen_md_type_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 5\uac00\uc9c0 \uc720\ud615\uc744 \uc62c\ubc14\ub974\uac8c \uc5f0\uacb0\ud55c \uac83\uc740?",B.a3O,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c5\uc870\uac00 \uc815\ud558\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 5\uac00\uc9c0 \uc720\ud615\uc740 \u2460 \uac00\uaca9\ub0a8\uc6a9, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uae30 \uc704\ud55c \uac70\ub798 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\uc774\ub2e4. \ubd80\ub2f9\uc5fc\ub9e4\xb7\uac70\ub798\uac70\uc808\xb7\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\xb7\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ub2f4\ud569\xb7\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \ub4f1\uc740 \ubaa8\ub450 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub098 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \ub4f1 \ub2e4\ub978 \ub300\ubd84\ub958\uc5d0 \uc18d\ud558\ub294 \uac1c\ub150\uc774\ubbc0\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4.",B.a7s,B.MZ,null)
B.acQ=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c\uc11c\uc758 \uc9c0\uc704\ub97c \ubcf4\uc720\ud558\ub294 \uac83 \uc790\uccb4\ub294 \uc704\ubc95\ud558\uc9c0 \uc54a\uace0, \uadf8 \uc9c0\uc704\ub97c \ub0a8\uc6a9\ud558\ub294 \ud589\uc704\ub9cc \uaddc\uc81c \ub300\uc0c1\uc774\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub418\uba74 \uadf8 \uc0ac\uc5c5\uc790\uc758 \ubaa8\ub4e0 \uac00\uaca9 \uacb0\uc815 \ud589\uc704\ub294 \uc608\uc678 \uc5c6\uc774 \uc704\ubc95\ud558\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uaddc\uc81c\ub294 \uc911\uc18c\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc544\ub2cc \uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub294 \uc5b4\ub5a4 \uacbd\uc6b0\uc5d0\ub3c4 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc81c\ub97c \ubc1b\uc9c0 \uc54a\ub294\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc81c\uc774\ub2e4"],t.s)
B.Om=s(["\uc9c0\uc704\ub97c \ubcf4\uc720\ud558\ub294 \uac83 \uc790\uccb4\ub294 \uc704\ubc95\ud558\uc9c0 \uc54a\uace0, \uadf8 \uc9c0\uc704\ub97c \ub0a8\uc6a9\ud558\ub294 \ud589\uc704\ub9cc \uaddc\uc81c \ub300\uc0c1"],t.s)
B.Zc=s(["\ub0a8\uc6a9\ud589\uc704 \uaddc\uc81c\uc758 \uc131\uaca9"],t.s)
B.ahb=new A.c("gen_md_criteria_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uaddc\uc81c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.acQ,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc2dc\uc7a5\uc5d0\uc11c \uc9c0\ubc30\uc801 \uc9c0\uc704\ub97c \uac16\ub294 \uac83 \uc790\uccb4\ub97c \uae08\uc9c0\ud558\uc9c0 \uc54a\ub294\ub2e4. \uaddc\uc81c \ub300\uc0c1\uc740 \uadf8\ub7ec\ud55c \uc9c0\uc704\ub97c "\ub0a8\uc6a9"\ud558\uc5ec \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uac70\ub098 \uc18c\ube44\uc790 \uc774\uc775\uc744 \uce68\ud574\ud558\ub294 \ud589\uc704\uc774\ub2e4. \ub530\ub77c\uc11c \uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \uac00\uaca9 \uacb0\uc815\uc774\ub77c\ub3c4 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uc73c\uba74 \uc704\ubc95\ud558\uc9c0 \uc54a\uc744 \uc218 \uc788\uace0, \uc774 \uaddc\uc81c\ub294 \uc911\uc18c\uae30\uc5c5\uc774\ub098 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ud55c\uc815\ub418\uc9c0 \uc54a\uc73c\uba70, \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc544\ub2cc \uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub3c4 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \ub2e4\ub978 \uaddc\uc815\uc73c\ub85c \uaddc\uc81c\ub420 \uc218 \uc788\ub2e4.',B.Om,B.Zc,null)
B.Hw=s(["\ud574\ub2f9 \ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\uc640 \ud6a8\uc728\uc131 \uc99d\ub300\ud6a8\uacfc \ub4f1\uc744 \ube44\uad50\ud615\ub7c9\ud558\uc5ec \uc885\ud569\uc801\uc73c\ub85c \ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4","\ubd80\ub2f9\uc131\uc740 \uc624\uc9c1 \ud589\uc704\uc790\uc758 \uc8fc\uad00\uc801 \uc545\uc758 \uc720\ubb34\ub9cc\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4","\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\uac00 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub77c\uba74 \ud56d\uc0c1 \ubd80\ub2f9\ud558\ub2e4\uace0 \ubcf8\ub2e4","\ud6a8\uc728\uc131 \uc99d\ub300\ud6a8\uacfc\ub294 \ubd80\ub2f9\uc131 \ud310\ub2e8\uc5d0\uc11c \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubd80\ub2f9\uc131 \ud310\ub2e8\uc740 \ud589\uc704\uc758 \ud615\uc2dd\ub9cc \ubcf4\uace0 \uc2e4\uc9c8\uc801 \ud6a8\uacfc\ub294 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.We=s(["\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\uc640 \ud6a8\uc728\uc131 \uc99d\ub300\ud6a8\uacfc \ub4f1\uc744 \ube44\uad50\ud615\ub7c9\ud558\uc5ec \uc885\ud569\uc801\uc73c\ub85c \ud310\ub2e8"],t.s)
B.ac4=s(["\ubd80\ub2f9\uc131 \ud310\ub2e8 \ubc29\ubc95"],t.s)
B.arC=new A.c("gen_md_criteria_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 \ubd80\ub2f9\uc131(\uc704\ubc95\uc131) \ud310\ub2e8\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Hw,0,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 \ubd80\ub2f9\uc131\uc740 \ud574\ub2f9 \ud589\uc704\ub85c \uc778\ud574 \ubc1c\uc0dd\ud558\ub294 \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc(\uc9c4\uc785\uc7a5\ubcbd \uac15\ud654, \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \ub4f1)\uc640 \ud6a8\uc728\uc131 \uc99d\ub300\ud6a8\uacfc(\ube44\uc6a9\uc808\uac10, \ud488\uc9c8\ud5a5\uc0c1 \ub4f1)\ub97c \ube44\uad50\ud615\ub7c9\ud574 \uc885\ud569\uc801\uc73c\ub85c \ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801 \uc811\uadfc\uc774\ub2e4. \ub2e8\uc21c\ud788 \uc8fc\uad00\uc801 \uc545\uc758 \uc720\ubb34\ub098 \ud589\uc704\uc758 \ud615\uc2dd\ub9cc\uc73c\ub85c \ud310\ub2e8\ud558\uc9c0 \uc54a\uc73c\uba70, \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\uac00 \uc5c6\uac70\ub098 \ubbf8\ubbf8\ud55c \uacbd\uc6b0\uc5d0\ub294 \ub0a8\uc6a9\uc73c\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\uc744 \uc218 \uc788\ub2e4.",B.We,B.ac4,null)
B.Sl=s(["\ucc29\ucde8\ub0a8\uc6a9\uc740 \uc8fc\ub85c \uac70\ub798\uc0c1\ub300\ubc29\uc774\ub098 \uc18c\ube44\uc790\ub85c\ubd80\ud130 \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \ucde8\ud558\ub294 \uc720\ud615\uc774\ub2e4","\ubc30\uc81c\ub0a8\uc6a9\uc740 \uc8fc\ub85c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubab0\uc544\ub0b4\uac70\ub098 \uc0c8\ub85c\uc6b4 \uc9c4\uc785\uc744 \ub9c9\ub294 \uc720\ud615\uc774\ub2e4","\uac00\uaca9\ub0a8\uc6a9\uc740 \ub300\ud45c\uc801\uc778 \ucc29\ucde8\ub0a8\uc6a9 \uc720\ud615\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4","\uc774 \uad6c\ubd84\uc740 \ud559\ubb38\uc801\xb7\uc2e4\ubb34\uc801\uc73c\ub85c \ub0a8\uc6a9\ud589\uc704\uc758 \uc131\uaca9\uc744 \uc774\ud574\ud558\ub294 \ub370 \ud65c\uc6a9\ub418\uc9c0\ub9cc, \ubc95 \uc870\ubb38\uc774 \uc774 \uba85\uce6d\uc744 \uc9c1\uc811 \uc0ac\uc6a9\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4",u.aN],t.s)
