B.anM=new A.c("gen_md_criteria_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc911 \ucc29\ucde8\ub0a8\uc6a9(\uac00\uaca9\ub0a8\uc6a9\xb7\uc18c\ube44\uc790\uc774\uc775\uc800\ud574\ud589\uc704 \ub4f1)\uacfc \ubc30\uc81c\ub0a8\uc6a9(\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \ub4f1)\uc758 \uad6c\ubd84\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Sl,4,"\ucc29\ucde8\ub0a8\uc6a9\uacfc \ubc30\uc81c\ub0a8\uc6a9\uc740 \ub0a8\uc6a9\ud589\uc704\uc758 \uc131\uaca9\uc744 \uc124\uba85\ud558\uae30 \uc704\ud574 \uac15\ud559\uc0c1 \uc0ac\uc6a9\ub418\ub294 \ubd84\ub958\ub85c, \uacf5\uc815\uac70\ub798\ubc95 \uc870\ubb38\uc774 \uc9c1\uc811 \uadf8 \uba85\uce6d\uc744 \uaddc\uc815\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub2e4. \ucc29\ucde8\ub0a8\uc6a9\uc740 \uac70\ub798\uc0c1\ub300\ubc29\xb7\uc18c\ube44\uc790\ub85c\ubd80\ud130 \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \ucde8\ud558\ub294 \uc720\ud615(\uac00\uaca9\ub0a8\uc6a9 \ub4f1), \ubc30\uc81c\ub0a8\uc6a9\uc740 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uac70\ub098 \uc2e0\uaddc\uc9c4\uc785\uc744 \ub9c9\ub294 \uc720\ud615\uc744 \uac00\ub9ac\ud0a4\uc9c0\ub9cc, \uc2e4\uc81c \uc0ac\uc548\uc5d0\uc11c\ub294 \ud558\ub098\uc758 \ud589\uc704\uac00 \ub450 \uc131\uaca9\uc744 \ud568\uaed8 \uac00\uc9c8 \uc218\ub3c4 \uc788\uc5b4 \uc644\uc804\ud788 \ubc30\ud0c0\uc801\uc774\ub77c\uace0 \ub2e8\uc815\ud560 \uc218 \uc5c6\ub2e4.",B.VN,B.TT,null)
B.SG=s(["\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uac1d\uad00\uc801 \uc694\uc778\uc5d0 \ub530\ub978 \ud569\ub9ac\uc801\uc778 \uac00\uaca9 \uc870\uc815","\uae30\uc220\ud601\uc2e0\uc774\ub098 \ud6a8\uc728\uc131 \uc99d\ub300\ub97c \uc704\ud55c \ubd88\uac00\ud53c\ud55c \uc870\uce58","\uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\ub300\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \uae30\uc5ec\ud558\ub294 \uac70\ub798\uc870\uac74 \ubcc0\uacbd","\uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58","\uc548\uc804\uc774\ub098 \ud488\uc9c8\uad00\ub9ac\ub97c \uc704\ud574 \ud569\ub9ac\uc801\uc73c\ub85c \ud544\uc694\ud55c \ubc94\uc704\uc758 \uac70\ub798\uc870\uac74 \uc124\uc815"],t.s)
B.Ta=s(["\uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58"],t.s)
B.OF=s(["\uc815\ub2f9\ud55c \uc774\uc720","\uc704\ubc95\uc131 \uc870\uac01"],t.s)
B.alO=new A.c("gen_md_criteria_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900",'\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc788\uc5b4 \uc704\ubc95\uc131\uc774 \uc870\uac01\ub420 \uc218 \uc788\ub294 \uc0ac\uc815\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?',B.SG,3,"\uc815\ub2f9\ud55c \uc774\uc720\ub294 \uc6d0\uac00 \uc694\uc778, \ud6a8\uc728\uc131\xb7\uae30\uc220\ud601\uc2e0, \uc18c\ube44\uc790 \ud6c4\uc0dd, \ud569\ub9ac\uc801\uc778 \ud488\uc9c8\xb7\uc548\uc804\uad00\ub9ac \ud544\uc694\uc131 \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uc0ac\uc720\ub97c \uac00\ub9ac\ud0a8\ub2e4. \ubc18\uba74 \uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58\ub294 \uc815\ub2f9\ud55c \uc774\uc720\ub85c \uc778\uc815\ub418\uae30 \uc5b4\ub835\uace0 \uc624\ud788\ub824 \ubc30\uc81c\ub0a8\uc6a9\uc758 \uc804\ud615\uc801\uc778 \uc9d5\ud45c\ub85c \ud3c9\uac00\ub41c\ub2e4.",B.Ta,B.OF,null)
B.Hd=s(["\ud589\uc704 \uc8fc\uccb4\uac00 \ud574\ub2f9 \uac70\ub798\ubd84\uc57c\uc758 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5ec\uc57c \ud55c\ub2e4","\ubb38\uc81c\ub41c \ud589\uc704\uac00 \ubc95\uc774 \uc815\ud55c \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \uc911 \ud558\ub098\uc5d0 \ud574\ub2f9\ud574\uc57c \ud55c\ub2e4","\uadf8 \ud589\uc704\uc5d0 \ubd80\ub2f9\uc131(\uc704\ubc95\uc131)\uc774 \uc778\uc815\ub418\uc5b4\uc57c \ud55c\ub2e4","\ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud55c\ub2e4","\uac1c\ubcc4 \uc0ac\uc548\uc758 \uc2dc\uc7a5\uad6c\uc870, \uac70\ub798\uad00\ud589 \ub4f1 \uad6c\uccb4\uc801 \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4"],t.s)
B.O8=s(["\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud55c\ub2e4"],t.s)
B.a_u=s(["\ub0a8\uc6a9\ud589\uc704 \uc131\ub9bd\uc694\uac74"],t.s)
B.amY=new A.c("gen_md_criteria_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 \uc131\ub9bd\uc694\uac74\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Hd,3,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\ub824\uba74 \u2460 \ud589\uc704\uc790\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc77c \uac83, \u2461 \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \uac83, \u2462 \ubd80\ub2f9\uc131(\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824 \ub4f1)\uc774 \uc778\uc815\ub420 \uac83\uc774\ub77c\ub294 \uc694\uac74\uc774 \ubaa8\ub450 \ucda9\uc871\ub418\uc5b4\uc57c \ud55c\ub2e4. \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\ub2e4\uba74 \ubd80\ub2f9\uc131 \uc694\uac74\uc774 \ud760\uacb0\ub418\uc5b4 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.O8,B.a_u,null)
B.Y1=s(["\ub3d9\uc77c\ud558\uac70\ub098 \uc720\uc0ac\ud55c \uc678\ud615\uc758 \ud589\uc704\ub77c\ub3c4 \ud589\uc704 \uc8fc\uccb4\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778\uc9c0\uc5d0 \ub530\ub77c \ub0a8\uc6a9\ud589\uc704 \ub610\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub85c \uac01\uac01 \uaddc\uc728\ub420 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac1c\ub150\uc774\ub77c \uc911\ubcf5 \uaddc\uc815\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc815\uc73c\ub85c\ub294 \uc804\ud600 \uaddc\uc728\ub420 \uc218 \uc5c6\ub2e4","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc815\uc774\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uc0ac\uc5c5\uc790 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \ubaa8\ub4e0 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a2z=s(["\ud589\uc704 \uc8fc\uccb4\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778\uc9c0\uc5d0 \ub530\ub77c \ub0a8\uc6a9\ud589\uc704 \ub610\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub85c \uac01\uac01 \uaddc\uc728\ub420 \uc218 \uc788\ub2e4"],t.s)
B.MM=s(["\ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \uad00\uacc4"],t.s)
B.akB=new A.c("gen_md_criteria_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704(\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \ubcc4\ub3c4\uc758 \ub300\ubd84\ub958)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Y1,0,"\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uac70\ub798\uac70\uc808\ucc98\ub7fc \uc678\ud615\uc774 \ube44\uc2b7\ud55c \ud589\uc704\ub77c\ub3c4, \ud589\uc704\uc790\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\uba74 \ub0a8\uc6a9\ud589\uc704\ub85c, \uadf8\ub807\uc9c0 \uc54a\uc73c\uba74 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \ub2e4\ub978 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. \ub450 \uc81c\ub3c4\ub294 \uaddc\uc81c \ucde8\uc9c0\uc640 \uc694\uac74\uc774 \ub2e4\ub974\uba70 \uc0c1\ud638 \ubc30\ud0c0\uc801\uc73c\ub85c \ub300\uccb4\ub418\ub294 \uad00\uacc4\uac00 \uc544\ub2c8\ub77c, \uc0ac\uc548\uc5d0 \ub530\ub77c \ud568\uaed8 \uac80\ud1a0\ub420 \uc218\ub3c4 \uc788\ub2e4. \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uadf8 \uc815\uc758\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc81c\ub77c\ub294 \uc810\uc774 \ud575\uc2ec\uc774\ub2e4.",B.a2z,B.MM,null)
B.TQ=s(["\ud574\ub2f9 \ud589\uc704\uc758 \uc911\uc9c0\ub97c \uba85\ud558\ub294 \uc2dc\uc815\uc870\uce58","\uc704\ubc18\ud589\uc704 \uc0ac\uc2e4\uc758 \uacf5\ud45c \ub4f1 \ud544\uc694\ud55c \uc2dc\uc815\uc870\uce58","\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud55c \uacfc\uc9d5\uae08 \ubd80\uacfc","\ud53c\ud574\ub97c \uc785\uc740 \uc18c\ube44\uc790\uc5d0 \ub300\ud55c \ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c","\uac00\uaca9 \uc778\ud558 \ub4f1 \uc704\ubc18\uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\uae30 \uc704\ud55c \uc870\uce58"],t.s)
B.RX=s(["\ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c"],t.s)
B.a1Z=s(["\uc2dc\uc815\uc870\uce58 \uc885\ub958"],t.s)
B.ap4=new A.c("gen_md_sanction_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud574 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?",B.TQ,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud574 \ud589\uc704 \uc911\uc9c0\uba85\ub839, \uc2dc\uc815\uc870\uce58, \uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c, \uad00\ub828\ub9e4\ucd9c\uc561 \uae30\uc900 \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1 \ud589\uc815\uc801 \uc81c\uc7ac\ub97c \ud560 \uc218 \uc788\ub2e4. \ub2e4\ub9cc "\ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c"\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815 \uc81c\uc7ac \uc218\ub2e8\uc774 \uc544\ub2c8\ub77c \ud615\uc0ac\uc18c\uc1a1\uc808\ucc28\uc5d0\uc11c \uac80\uc0ac\xb7\ubc95\uc6d0\uc774 \uad00\uc5ec\ud558\ub294 \uc601\uc5ed\uc73c\ub85c, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc9c1\uc811 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud589\ud558\ub294 \uc870\uce58\uac00 \uc544\ub2c8\ub2e4.',B.RX,B.a1Z,null)
B.PU=s(["\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc77c\uc815 \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc704\ubc18\ud589\uc704\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ub3d9\uc77c\ud55c \uc815\uc561\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4","\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacfc\uc9d5\uae08 \uc0c1\ud55c\uc740 \uc815\uc561\uc73c\ub85c \uace0\uc815\ub418\uc9c0 \uc54a\uace0 \ubcc4\ub3c4 \uae30\uc900\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \ubc18\ub4dc\uc2dc \ubc95\uc6d0\uc758 \uc7ac\ud310\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0\ub294 \uacfc\uc9d5\uae08 \uc81c\ub3c4\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Nr=s(["\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc77c\uc815 \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc"],t.s)
B.nh=s(["\uacfc\uc9d5\uae08 \uc0b0\uc815\uae30\uc900"],t.s)
B.anC=new A.c("gen_md_sanction_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.PU,0,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08\uc740 \uc704\ubc18\ud589\uc704 \uad00\ub828 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ubc95\ub839\uc774 \uc815\ud55c \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \ubd80\uacfc\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\ub97c \ub300\ube44\ud55c \ubcc4\ub3c4\uc758 \uc815\uc561 \uae30\uc900(\uacfc\uc9d5\uae08 \uc0c1\ud55c\uc561)\ub3c4 \ud568\uaed8 \ub9c8\ub828\ub418\uc5b4 \uc788\ub2e4. \uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\ucc98\ubd84\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c0\uba70 \ubc95\uc6d0\uc758 \uc7ac\ud310\uc744 \uac70\uccd0\uc57c\ub9cc \uac00\ub2a5\ud55c \uac83\uc740 \uc544\ub2c8\uace0(\ubd88\ubcf5 \uc2dc \uc0ac\ud6c4\uc801\uc73c\ub85c \ud589\uc815\uc18c\uc1a1\uc774 \uac00\ub2a5\ud560 \ubfd0), \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4\uc5d0 \ub530\ub77c \uae08\uc561\uc774 \ub2ec\ub77c\uc9c4\ub2e4.",B.Nr,B.nh,null)
B.aa2=s(["\ucc98\ubd84\uc5d0 \uc774\uc758\uac00 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubd88\ubcf5\uc774 \ubd88\uac00\ub2a5\ud558\ub2e4","\ubd88\ubcf5\uc740 \uc624\uc9c1 \ud5cc\ubc95\uc18c\uc6d0\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc774\uc758\uc2e0\uccad \uc808\ucc28 \uc5c6\uc774 \ud615\uc0ac\uc7ac\ud310\uc73c\ub85c\ub9cc \ub2e4\ud234 \uc218 \uc788\ub2e4","\ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc740 \uc18c\ube44\uc790\ub9cc \uc81c\uae30\ud560 \uc218 \uc788\ub2e4"],t.s)
B.X9=s(["\uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4"],t.s)
B.nY=s(["\ubd88\ubcf5\uc808\ucc28"],t.s)
B.arL=new A.c("gen_md_sanction_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.aa2,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc5d0 \uc774\uc758\uac00 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ub300\ud55c \uc774\uc758\uc2e0\uccad\uc774\ub098 \ubc95\uc6d0\uc5d0 \ub300\ud55c \ud589\uc815\uc18c\uc1a1\uc744 \ud1b5\ud574 \ucc98\ubd84\uc758 \ucde8\uc18c\xb7\ubcc0\uacbd\uc744 \uad6c\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \ub2e4\ub978 \ud589\uc815\ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5 \uad6c\uc870\uc640 \uc720\uc0ac\ud558\uba70, \ud615\uc0ac\uc7ac\ud310\uc774\ub098 \ud5cc\ubc95\uc18c\uc6d0\ub9cc\uc774 \uc720\uc77c\ud55c \ubd88\ubcf5 \uc218\ub2e8\uc740 \uc544\ub2c8\ub2e4.",B.X9,B.nY,null)
B.Wz=s(["\uc704\ubc18\ud589\uc704\ub97c \uc911\uc9c0\uc2dc\ucf1c \uacbd\uc7c1\uc9c8\uc11c\ub97c \ud68c\ubcf5\ud558\ub294 \uac83","\uc704\ubc18\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc7a5\ub798\uc758 \uc720\uc0ac\ud589\uc704 \uc7ac\ubc1c\uc744 \ubc29\uc9c0\ud558\ub3c4\ub85d \ud558\ub294 \uac83","\ud53c\ud574\ub97c \uc785\uc740 \uacbd\uc7c1\uc0ac\uc5c5\uc790\xb7\uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ubcf4\ud638\ud558\ub294 \ub370 \uae30\uc5ec\ud558\ub294 \uac83","\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c \uc790\uccb4\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uac83","\uacbd\uc7c1\uc9c8\uc11c\ub97c \uc800\ud574\ud55c \uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\uc5ec \uc815\uc0c1\uc801\uc778 \uc2dc\uc7a5\uae30\ub2a5\uc744 \ud68c\ubcf5\ud558\ub294 \uac83"],t.s)
B.HH=s(["\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c \uc790\uccb4\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uac83"],t.s)
B.Yf=s(["\uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801"],t.s)
B.aiE=new A.c("gen_md_sanction_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801\uc73c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.Wz,3,"\uc2dc\uc815\uc870\uce58\ub294 \uc704\ubc18\ud589\uc704\ub97c \uc911\uc9c0\uc2dc\ud0a4\uace0 \uacbd\uc7c1\uc9c8\uc11c\uc640 \uc2dc\uc7a5\uae30\ub2a5\uc744 \uc815\uc0c1\uc801\uc73c\ub85c \ud68c\ubcf5\uc2dc\ud0a4\uba70, \uc7ac\ubc1c\uc744 \ubc29\uc9c0\ud558\uace0 \uad00\ub828 \uc0ac\uc5c5\uc790\xb7\uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ubcf4\ud638\ud558\ub294 \ub370 \ubaa9\uc801\uc774 \uc788\ub2e4. \uc704\ubc18\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\uc2dc\ud0a4\ub294 \uac83 \uc790\uccb4\uac00 \uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801\uc740 \uc544\ub2c8\uba70, \uc5b4\ub514\uae4c\uc9c0\ub098 \uc704\ubc18\uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\ub294 \ub370 \ucd08\uc810\uc774 \uc788\ub2e4.",B.HH,B.Yf,null)
B.acE=s(["\uc77c\uc815\ud55c \uacbd\uc6b0 \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc774 \ud568\uaed8 \uc801\uc6a9\ub420 \uc218 \uc788\uc5b4 \ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4","\ud615\uc0ac\ucc98\ubc8c\uc774 \ud655\uc815\ub418\uba74 \uacfc\uc9d5\uae08 \ub4f1 \ud589\uc815\uc81c\uc7ac\ub294 \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \ucde8\uc18c\ub41c\ub2e4","\ud615\uc0ac\ucc98\ubc8c\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\ub294 \uc18c\ube44\uc790\uc758 \uac1c\ubcc4 \ub3d9\uc758\uc5d0 \ub530\ub77c \uacb0\uc815\ub41c\ub2e4"],t.s)
B.a_s=s(["\ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Sn=s(["\ud615\uc0ac\ucc98\ubc8c \ubcd1\uacfc \uac00\ub2a5\uc131"],t.s)
B.anD=new A.c("gen_md_sanction_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uac00 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.acE,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \ub4f1 \uc8fc\uc694 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ud589\uc815\uc81c\uc7ac(\uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08)\uc640 \ubcc4\ub3c4\ub85c \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc744 \ub450\uace0 \uc788\uc5b4, \uc0ac\uc548\uc5d0 \ub530\ub77c \ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ud568\uaed8 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4. \ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\uc640 \uacfc\uc9d5\uae08 \ub4f1 \ud589\uc815\uc81c\uc7ac\ub294 \ubcc4\uac1c\uc758 \uc808\ucc28\uc640 \uc694\uac74\uc5d0 \ub530\ub77c \ud310\ub2e8\ub418\ubbc0\ub85c, \ud558\ub098\uac00 \ud655\uc815\ub418\uc5c8\ub2e4\uace0 \ub2e4\ub978 \ud558\ub098\uac00 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.a_s,B.Sn,null)
B.abE=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\ub2e4","\uc774\ud574\uad00\uacc4\uc778\uc758 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c \uc870\uc0ac\uac00 \uc2dc\uc791\ub420 \uc218\ub3c4 \uc788\ub2e4","\uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc774 \ub0b4\ub824\uc9c8 \uc218 \uc788\ub2e4","\uc870\uc0ac\uc640 \ucc98\ubd84 \uacfc\uc815\uc5d0\uc11c \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc758\uacac\uc9c4\uc220 \uae30\ud68c\uac00 \uc804\ud600 \ubd80\uc5ec\ub418\uc9c0 \uc54a\ub294\ub2e4","\ucc98\ubd84 \uc804 \uc2ec\uc758 \ub4f1 \uc808\ucc28\uc801 \ub2e8\uacc4\ub97c \uac70\uce58\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4"],t.s)
B.Wh=s(["\uc758\uacac\uc9c4\uc220 \uae30\ud68c\uac00 \uc804\ud600 \ubd80\uc5ec\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Pm=s(["\uc870\uc0ac\xb7\ucc98\ubd84 \uc808\ucc28"],t.s)
B.aiB=new A.c("gen_md_sanction_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc870\uc0ac \ubc0f \ucc98\ubd84 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.abE,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c1\uad8c \ub610\ub294 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\uace0, \uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \uc2ec\uc758 \ub4f1 \uc808\ucc28\ub97c \uac70\uccd0 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc744 \ub0b4\ub9b0\ub2e4. \uc774 \uacfc\uc815\uc5d0\uc11c \ud53c\uc2ec\uc778(\uc0ac\uc5c5\uc790)\uc5d0\uac8c\ub294 \uc758\uacac\uc9c4\uc220 \uae30\ud68c \ub4f1 \ubc29\uc5b4\uad8c\uc774 \ubcf4\uc7a5\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ubbc0\ub85c, "\uc758\uacac\uc9c4\uc220 \uae30\ud68c\uac00 \uc804\ud600 \ubd80\uc5ec\ub418\uc9c0 \uc54a\ub294\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.Wh,B.Pm,null)
B.a_q=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704 \ub610\ub294 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\ud589\uc704"],t.s)
B.acb=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704 \ub610\ub294 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
B.Lx=s(["\ud544\uc218\uc694\uc18c \uac70\uc808 \uc0ac\ub840"],t.s)
B.an3=new A.c("gen_md_case_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778 A\uc0ac\uac00 \uacbd\uc7c1\uc0ac\uc5c5\uc790 B\uc0ac\uc758 \uc2e0\uc81c\ud488 \ucd9c\uc2dc\ub97c \ubc29\ud574\ud560 \ubaa9\uc801\uc73c\ub85c, \uc790\uc0ac \uc720\ud1b5\ub9dd\uc5d0\ub9cc \uacf5\uae09\ud558\ub294 \ud544\uc218\ubd80\ud488\uc758 \ud310\ub9e4\ub97c B\uc0ac\uc5d0\uac8c \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\uc808\ud55c \uacbd\uc6b0 \ud574\ub2f9\ud558\ub294 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a_q,0,'\ud544\uc218\uc801\uc778 \uc694\uc18c(\ubd80\ud488\xb7\uc124\ube44 \ub4f1)\uc758 \uc0ac\uc6a9\uc744 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\uc808\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \uc9c4\uc785\uc774\ub098 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub294 \uc0ac\uc548\uc5d0 \ub530\ub77c "\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704" \ub610\ub294 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\ub85c \ud3ec\uc12d\ub420 \uc218 \uc788\ub294 \ub300\ud45c\uc801\uc778 \ubc30\uc81c\ub0a8\uc6a9 \uc0ac\ub840\uc774\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \ubaa8\ub450 \uc774 \uc0ac\ub840\uc758 \uc0ac\uc2e4\uad00\uacc4\uc640 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uaddc\uc81c \uc720\ud615\uc774\ub2e4.',B.acb,B.Lx,null)
B.Xa=s([u.pv,"\uc2dc\uc7a5\uc810\uc720\uc728\uc774 \uc5bc\ub9c8\uc774\ub4e0 \uac00\uaca9\uc744 \uc62c\ub9ac\ub294 \ud589\uc704\ub294 \ud56d\uc0c1 \ud569\ubc95\uc774\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac00\uaca9 \uc778\uc0c1\uc740 \ud56d\uc0c1 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\uc640 \ubb34\uad00\ud558\uac8c \ud310\ub2e8\ub41c\ub2e4"],t.s)
B.Op=s([u.pv],t.s)
B.Ny=s(["\uac00\uaca9\ub0a8\uc6a9 \uc0ac\ub840"],t.s)
B.ajW=new A.c("gen_md_case_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc810\uc720\uc728 70%\uc778 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc6d0\uac00 \uc0c1\uc2b9 \uc694\uc778\uc774 \uc804\ud600 \uc5c6\uc74c\uc5d0\ub3c4 \ud2b9\ubcc4\ud55c \uc774\uc720 \uc5c6\uc774 \uc790\uc0ac \uc81c\ud488 \uac00\uaca9\uc744 \ud070 \ud3ed\uc73c\ub85c \uc778\uc0c1\ud55c \uacbd\uc6b0, \uc774\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Xa,0,"\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uadfc\uac70 \uc5c6\uc774 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uac00\uaca9\uc744 \ubd80\ub2f9\ud558\uac8c \uc778\uc0c1\ud558\ub294 \uac83\uc740 \uac00\uaca9\ub0a8\uc6a9\uc758 \uc804\ud615\uc801\uc778 \uc0ac\ub840\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc790\uc0ac \uc0c1\ud488\uc744 \uac70\ub798\ud558\ub294 \uc720\ud1b5\uc5c5\uc790\uc5d0\uac8c \ud310\ub9e4\uac00\uaca9\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704\ub85c \uc774 \uc0ac\ub840\uc640 \ub2e4\ub974\uace0, \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc8fc\uccb4\uac00 \ub418\uc5b4\uc57c \ud558\ubbc0\ub85c \uc5ed\uc2dc \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.Op,B.Ny,null)
B.Hs=s(["\ucd9c\uace0\uc870\uc808","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5"],t.s)
B.a74=s(["\uc0dd\uc0b0\xb7\ucd9c\uace0\ub7c9\uc744 \ucd5c\uadfc \ucd94\uc138\ubcf4\ub2e4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ucf1c \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub294 \ucd9c\uace0\uc870\uc808"],t.s)
B.a3Y=s(["\ucd9c\uace0\uc870\uc808 \uc0ac\ub840"],t.s)
B.ah6=new A.c("gen_md_case_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \ubc18\ub3c4\uccb4 \uc218\uc694 \uae09\uc99d \uc0c1\ud669\uc5d0\uc11c \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0dd\uc0b0\ub7c9\uc744 \uc885\uc804 \ub300\ube44 \ud604\uc800\ud788 \uc904\uc5ec \uc2dc\uc7a5\uc5d0 \uc778\uc704\uc801\uc778 \ud488\uadc0 \ud604\uc0c1\uc744 \uc77c\uc73c\ud0a8 \uacbd\uc6b0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc740?",B.Hs,0,"\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0dd\uc0b0\xb7\ucd9c\uace0\ub7c9\uc744 \ucd5c\uadfc \ucd94\uc138\ubcf4\ub2e4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ucf1c \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub294 \ucd9c\uace0\uc870\uc808\uc758 \uc804\ud615\uc801 \uc0ac\ub840\uc774\ub2e4. \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \uac01\uac01 \ub2e4\ub978 \uc694\uac74\uacfc \uc8fc\uccb4\ub97c \uc804\uc81c\ub85c \ud558\ub294 \ubcc4\uac1c\uc758 \uaddc\uc81c \uc720\ud615\uc73c\ub85c, \uc774 \uc0ac\ub840\uc640\ub294 \uc131\uaca9\uc774 \ub2e4\ub974\ub2e4.",B.a74,B.a3Y,null)
B.a0x=s([u.cL,"\uc2e0\uaddc \uc9c4\uc785\uc744 \ub9c9\ub294 \ud589\uc704\ub294 \uc774\uc720\ub97c \ubd88\ubb38\ud558\uace0 \ud56d\uc0c1 \uc704\ubc95\ud558\ub2e4","\uc548\uc804\uae30\uc900\uc744 \uc774\uc720\ub85c \ub4e0 \uacbd\uc6b0\ub294 \ud56d\uc0c1 \ud615\uc2dd\uc801 \ud56d\ubcc0\uc73c\ub85c \ucde8\uae09\ub418\uc5b4 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0 \ubc18\ub4dc\uc2dc \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub85c \uc758\uc728\ud574\uc57c \ud55c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c\ub9cc \uaddc\uc728\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a4S=s([u.cL],t.s)
B.a4e=s(["\uc815\ub2f9\ud55c \uc774\uc720 \ud56d\ubcc0 \uc0ac\ub840"],t.s)
B.akp=new A.c("gen_md_case_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc2e0\uaddc \uc9c4\uc785\uc744 \uc2dc\ub3c4\ud558\ub294 B\uc0ac\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \uac70\uc808\ud558\uba74\uc11c, \ub3d9\uc2dc\uc5d0 \uadf8 \uac70\uc808\uc774 \uc548\uc804\uae30\uc900 \ubbf8\ub2ec\uc744 \uc774\uc720\ub85c \ud55c \ud569\ub9ac\uc801 \uc870\uce58\uc600\uc74c\uc774 \uac1d\uad00\uc801\uc73c\ub85c \uc785\uc99d\ub41c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a0x,0,'\ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\ucc98\ub7fc \ubcf4\uc774\ub294 \ud589\uc704\ub77c\ub3c4, \uc548\uc804\xb7\ud488\uc9c8\uad00\ub9ac \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc2e4\uc81c\ub85c \uc785\uc99d\ub41c\ub2e4\uba74 \uc704\ubc95\uc131\uc774 \uc870\uac01\ub418\uc5b4 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\uc744 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uc774\ub7ec\ud55c \ud56d\ubcc0\uc740 \ud615\uc2dd\uc801 \uc8fc\uc7a5\ub9cc\uc73c\ub85c\ub294 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uac1d\uad00\uc801 \uadfc\uac70\uac00 \ub4b7\ubc1b\uce68\ub418\uc5b4\uc57c \ud558\uba70, \uc774 \uc0ac\ub840\ub294 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\ub098 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc640\ub294 \ubb34\uad00\ud55c \ub2e8\ub3c5\ud589\uc704 \uc0ac\uc548\uc774\ub2e4.',B.a4S,B.a4e,null)
B.Re=s(["\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \uc704\ubc18","\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\ud589\uc704"],t.s)
B.a_M=s(["\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
B.act=s(["\uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704 \uc0ac\ub840"],t.s)
B.aix=new A.c("gen_md_case_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc790\uc0ac\uc640 \uacbd\uc7c1 \uad00\uacc4\uc5d0 \uc788\ub294 B\uc0ac\uc5d0 \ub300\ud574\uc11c\ub9cc \ub9e4\uc6b0 \ubd88\ub9ac\ud55c \uac70\ub798\uc870\uac74\uc744 \uc81c\uc2dc\ud558\uc5ec B\uc0ac\uc758 \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud604\uc800\ud788 \uc5b4\ub835\uac8c \ub9cc\ub4e4\uc5c8\ub2e4\uba74, \uc774\ub294 \ub2e4\uc74c \uc911 \uc5b4\ub290 \uc720\ud615\uc73c\ub85c \ud3ec\uc12d\ub420 \uac00\ub2a5\uc131\uc774 \uac00\uc7a5 \ud070\uac00?",B.Re,0,'\uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud55c \uac70\ub798\uc870\uac74\uc744 \uc81c\uc2dc\ud558\uc5ec \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud604\uc800\ud788 \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub294 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \uc804\ud615\uc801 \uc0ac\ub840\uc774\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \uac01\uac01 \ubcc4\ub3c4\uc758 \uc694\uac74(\uc720\ud1b5\uc5c5\uc790\uc5d0 \ub300\ud55c \uac00\uaca9 \uac15\uc81c, \uc0ac\uc5c5\uc790 \uac04 \ud569\uc758, \uae30\uc5c5\uc9d1\ub2e8 \uaddc\uc81c, \ud2b9\uc218\uad00\uacc4\uc778 \uac70\ub798 \ub4f1)\uc744 \uc804\uc81c\ub85c \ud558\ubbc0\ub85c \uc774 \uc0ac\ub840\uc640\ub294 \ubd80\ud569\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.a_M,B.act,null)
B.aat=s(["\ud589\uc704\uc790\uac00 \ud574\ub2f9 \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0","\ubb38\uc81c\ub41c \ud589\uc704\uac00 \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \uc911 \uc5b4\ub514\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0","\ud589\uc704\uc758 \ubd80\ub2f9\uc131(\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\xb7\uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824 \ub4f1)\uc774 \uc778\uc815\ub418\ub294\uc9c0","\ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801\uc778 \ud3c9\ud310\uc774 \uc5b4\ub5a0\ud55c\uc9c0","\uc815\ub2f9\ud55c \uc774\uc720 \ub4f1 \uc704\ubc95\uc131 \uc870\uac01\uc0ac\uc720\uac00 \uc874\uc7ac\ud558\ub294\uc9c0"],t.s)
B.Y3=s(["\ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801\uc778 \ud3c9\ud310\uc774 \uc5b4\ub5a0\ud55c\uc9c0"],t.s)
B.aaE=s(["\uc0ac\ub840\ubd84\uc11d \uccb4\ud06c\ub9ac\uc2a4\ud2b8"],t.s)
B.amO=new A.c("gen_md_case_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc0ac\ub840\ub97c \ubd84\uc11d\ud560 \ub54c \uac80\ud1a0\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.aat,3,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc0ac\ub840 \ubd84\uc11d\uc740 \ud589\uc704\uc790\uc758 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud574\ub2f9 \uc5ec\ubd80, \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \ud574\ub2f9\uc131, \ubd80\ub2f9\uc131 \uc778\uc815 \uc5ec\ubd80, \uc815\ub2f9\ud55c \uc774\uc720 \ub4f1 \uc704\ubc95\uc131 \uc870\uac01\uc0ac\uc720 \uc874\ubd80\ub97c \uc911\uc2ec\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4. \ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801 \ud3c9\ud310\uc740 \ubc95\uc801 \ud310\ub2e8 \uc694\uc18c\uac00 \uc544\ub2c8\ubbc0\ub85c \uac80\ud1a0 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4.",B.Y3,B.aaE,null)
B.a1s=s(["\uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud589\uc704\ub85c \uc778\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0 \uc774 \ubc95\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc744 \uae30\uc900\uc73c\ub85c \uc81c\ud55c \ud574\uc11d\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uc678\uad6d \ubc95\ub960\uc0c1 \uc801\ubc95\ud558\ub2e4\uba74 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc774 \ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub41c\ub2e4","\uc815\ubd80\ub294 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uadfc\uac70 \uc870\ubb38\uc740 \uc774 \ubc95 \uc81c\uc815 \ub2f9\uc2dc\ubd80\ud130 \uc874\uc7ac\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4"],t.s)
B.Xy=s(["\uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc"],t.s)
B.a_A=s(["\uc5ed\uc678\uc801\uc6a9"],t.s)
B.aiO=new A.c("gen_gn_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc758 \uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.a1s,2,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c3\uc870\ub294 \uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud6a8\uacfc\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud55c\ub2e4\ub294 \uc5ed\uc678\uc801\uc6a9 \uc6d0\uce59\uc744 \uba85\uc2dc\ud558\uace0 \uc788\ub2e4. \ub300\ubc95\uc6d0 \ud310\ub840(\ud751\uc5f0\uc804\uadf9\ubd09 \uc0ac\uac74 \ub4f1)\ub294 \uc774\ub54c "\uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0"\ub97c \ubb38\uc81c\ub41c \uad6d\uc678\ud589\uc704\ub85c \uc778\ud574 \uc9c1\uc811\uc801\xb7\uc0c1\ub2f9\ud558\uace0 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0\ub85c \uc81c\ud55c \ud574\uc11d\ud558\ub418, \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uadf8 \uc678\uad6d \ubc95\ub960\uc0c1\uc73c\ub85c\ub294 \uc801\ubc95\ud55c \ud589\uc704\uc600\ub2e4 \ud558\ub354\ub77c\ub3c4 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc\ud558\uc600\ub2e4. \uc989 "\uc678\uad6d\uc5d0\uc11c \uc801\ubc95 = \uad6d\ub0b4\ubc95 \uc801\uc6a9 \ubc30\uc81c"\ub77c\ub294 \ub4f1\uc2dd\uc740 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec\uc774\uba70, \uad6d\uac00 \uac04 \ud611\uc815 \uccb4\uacb0 \uadfc\uac70(\uc81c56\uc870)\ub098 \uc5ed\uc678\uc801\uc6a9 \uc870\ubb38\uc758 \uc2e0\uc124 \uc5f0\ud601\ub3c4 \ud568\uaed8 \uc54c\uc544\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.Xy,B.a_A,null)
B.a5T=s(["\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud558\ub294 \uac83","\ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5\ud558\ub294 \uac83","\uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud558\ub294 \uac83","\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc744 \ub3c4\ubaa8\ud558\ub294 \uac83","\ud2b9\uc815 \uc0b0\uc5c5 \ubd84\uc57c\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uae30\uc5c5\uacfc\uc758 \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83"],t.s)
B.Zi=s(["\ud2b9\uc815 \uc0b0\uc5c5 \ubd84\uc57c\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uae30\uc5c5\uacfc\uc758 \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83"],t.s)
B.VY=s(["\ubc95\uc758 \ubaa9\uc801"],t.s)
B.an2=new A.c("gen_gn_purpose_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c1\uc870\uac00 \uba85\uc2dc\ud558\ub294 \ubaa9\uc801\uc73c\ub85c \ubcfc \uc218 \uc5c6\ub294 \uac83\uc740?",B.a5T,4,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c1\uc870\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704\uc758 \ub0a8\uc6a9\uacfc \uacfc\ub3c4\ud55c \uacbd\uc81c\ub825 \uc9d1\uc911\uc744 \ubc29\uc9c0\ud558\uace0 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \ubc0f \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub97c \uaddc\uc81c\ud558\uc5ec \uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud568\uc73c\ub85c\uc368 \ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5\ud558\uace0 \uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud568\uacfc \uc544\uc6b8\ub7ec \uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc744 \ub3c4\ubaa8\ud568\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ud2b9\uc815 \uc0b0\uc5c5\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83\uc740 \uc774 \ubc95\uc758 \ubaa9\uc801\uc774 \uc544\ub2c8\uba70, \uc624\ud788\ub824 \uacbd\uc7c1 \ucd09\uc9c4\uc774 \ud575\uc2ec \ubaa9\uc801\uc774\ub2e4.",B.Zi,B.VY,null)
B.aab=s(["\uc790\uc720\ub85c\uc6b4 \uc2dc\uc7a5 \uc9c4\uc785\xb7\uacbd\uc7c1\uc758 \ubcf4\uc7a5(\uc790\uc720\uacbd\uc7c1)\uacfc \ubd80\ub2f9\ud55c \ubc29\ubc95\uc5d0 \uc758\ud55c \uacbd\uc7c1 \ubc30\uc81c \uae08\uc9c0(\uacf5\uc815\uacbd\uc7c1)\ub97c \ud568\uaed8 \ucd94\uad6c\ud558\ub294 \uac1c\ub150\uc774\ub2e4","\uc790\uc720\uacbd\uc7c1\ub9cc\uc744 \ucd94\uad6c\ud560 \ubfd0 \uacf5\uc815\uc131\uc740 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacf5\uc815\uacbd\uc7c1\ub9cc\uc744 \ucd94\uad6c\ud560 \ubfd0 \uc9c4\uc785\uc758 \uc790\uc720\ub294 \ubcf4\uc7a5\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacbd\uc7c1\uc758 \uc790\uc720\uc640 \uacf5\uc815\uc131\uc740 \uc11c\ub85c \uc591\ub9bd\ud560 \uc218 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uc774 \uac1c\ub150\uc740 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.UL=s(["\uc790\uc720\ub85c\uc6b4 \uc2dc\uc7a5 \uc9c4\uc785\xb7\uacbd\uc7c1\uc758 \ubcf4\uc7a5(\uc790\uc720\uacbd\uc7c1)\uacfc \ubd80\ub2f9\ud55c \ubc29\ubc95\uc5d0 \uc758\ud55c \uacbd\uc7c1 \ubc30\uc81c \uae08\uc9c0(\uacf5\uc815\uacbd\uc7c1)\ub97c \ud568\uaed8 \ucd94\uad6c"],t.s)
B.Jn=s(["\uc790\uc720\uacbd\uc7c1\uacfc \uacf5\uc815\uacbd\uc7c1"],t.s)
B.apj=new A.c("gen_gn_purpose_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 \ucd94\uad6c\ud558\ub294 "\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.aab,0,'"\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1"\uc740 \ub204\uad6c\ub098 \uc2dc\uc7a5\uc5d0 \uc790\uc720\ub86d\uac8c \uc9c4\uc785\ud558\uc5ec \uacbd\uc7c1\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc790\uc720\uacbd\uc7c1\uc758 \uce21\uba74\uacfc, \ubd80\ub2f9\ud55c \ubc29\ubc95\uc73c\ub85c \uacbd\uc7c1\uc790\ub97c \ubc30\uc81c\ud558\uac70\ub098 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \ud589\uc704\ub294 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4\ub294 \uacf5\uc815\uacbd\uc7c1\uc758 \uce21\uba74\uc744 \ud568\uaed8 \ud3ec\ud568\ud558\ub294 \uac1c\ub150\uc774\ub2e4. \ub450 \uce21\uba74\uc740 \ub300\ub9bd\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uc791\ub3d9\ud558\uba70, \uc0ac\uc5c5\uc790 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4.',B.UL,B.Jn,null)
B.a01=s(["\uacf5\uc815\ud55c \uacbd\uc7c1\ud658\uacbd\uc744 \uc870\uc131\ud568\uc73c\ub85c\uc368 \uc0ac\uc5c5\uc790\ub4e4\uc774 \ud601\uc2e0\uacfc \ud6a8\uc728\uc131 \ud5a5\uc0c1\uc744 \ud1b5\ud574 \uacbd\uc7c1\ud558\ub3c4\ub85d \uc720\uc778\ud558\ub824\ub294 \uac83\uc774\ub2e4","\ud2b9\uc815 \uae30\uc5c5\uc5d0\uac8c \ub3c5\uc810\uc801 \uc9c0\uc704\ub97c \ubcf4\uc7a5\ud574 \uc548\uc815\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ub3d5\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ubaa8\ub4e0 \uae30\uc5c5\uc758 \uc2e0\uc81c\ud488 \uac1c\ubc1c\uc744 \uc815\ubd80\uac00 \uc9c1\uc811 \uc9c0\uc6d0\ud558\uaca0\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4","\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9\uc740 \ubc95\uc758 \ubaa9\uc801\uacfc \ubb34\uad00\ud55c \ubd80\uc218\uc801 \ubb38\uad6c\uc5d0 \ubd88\uacfc\ud558\ub2e4","\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9 \uc870\uc7a5\uc740 \ub300\uae30\uc5c5\uc5d0\ub9cc \ud574\ub2f9\ub418\ub294 \ubaa9\uc801\uc774\ub2e4"],t.s)
B.Kw=s(["\uacf5\uc815\ud55c \uacbd\uc7c1\ud658\uacbd\uc744 \uc870\uc131\ud568\uc73c\ub85c\uc368 \uc0ac\uc5c5\uc790\ub4e4\uc774 \ud601\uc2e0\uacfc \ud6a8\uc728\uc131 \ud5a5\uc0c1\uc744 \ud1b5\ud574 \uacbd\uc7c1\ud558\ub3c4\ub85d \uc720\uc778"],t.s)
B.a0y=s(["\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9 \uc870\uc7a5"],t.s)
B.ajD=new A.c("gen_gn_purpose_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 "\ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5"\ud55c\ub2e4\uace0 \uaddc\uc815\ud55c \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a01,0,"\uacbd\uc7c1\uc774 \ud65c\ubc1c\ud55c \uc2dc\uc7a5\uc5d0\uc11c\ub294 \uc0ac\uc5c5\uc790\ub4e4\uc774 \uc0b4\uc544\ub0a8\uae30 \uc704\ud574 \ube44\uc6a9\uc808\uac10\xb7\ud488\uc9c8\uac1c\uc120\xb7\uae30\uc220\ud601\uc2e0 \ub4f1 \ucc3d\uc758\uc801\uc778 \ub178\ub825\uc744 \uae30\uc6b8\uc774\uac8c \ub41c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uc740 \uc2dc\uc7a5\uc9c0\ubc30\ub825 \ub0a8\uc6a9\uc774\ub098 \ubd80\ub2f9\ud55c \ub2f4\ud569\xb7\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \uacbd\uc7c1\uc744 \uc65c\uace1\ud558\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud568\uc73c\ub85c\uc368 \uc774\ub7ec\ud55c \ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9\uc774 \uc774\ub8e8\uc5b4\uc9c8 \uc218 \uc788\ub294 \ud658\uacbd\uc744 \uc870\uc131\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4.",B.Kw,B.a0y,null)
B.a7I=s(["\uac1c\ubcc4 \uc18c\ube44\uc790\ud53c\ud574\uc758 \uc0ac\ud6c4\uc801 \uad6c\uc81c\ubcf4\ub2e4\ub294 \uacbd\uc7c1 \ucd09\uc9c4\uc744 \ud1b5\ud574 \uc18c\ube44\uc790\ud6c4\uc0dd\uc744 \uc99d\uc9c4\ud558\ub294 \uac04\uc811\uc801\xb7\uad6c\uc870\uc801 \ubcf4\ud638\uc5d0 \uac00\uae5d\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc744 \uc644\uc804\ud788 \ub300\uccb4\ud558\ub294 \uc18c\ube44\uc790\ud53c\ud574 \uad6c\uc81c \uc804\ub2f4 \ubc95\ub960\uc774\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc774 \ubc95\uc758 \ubaa9\uc801\uc5d0 \uc804\ud600 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \ubaa9\uc801\uc774\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\uc744 \ud1b5\ud574\uc11c\ub9cc \ub2ec\uc131\ub41c\ub2e4"],t.s)
B.a2I=s(["\uacbd\uc7c1 \ucd09\uc9c4\uc744 \ud1b5\ud574 \uc18c\ube44\uc790\ud6c4\uc0dd\uc744 \uc99d\uc9c4\ud558\ub294 \uac04\uc811\uc801\xb7\uad6c\uc870\uc801 \ubcf4\ud638\uc5d0 \uac00\uae5d\ub2e4"],t.s)
B.Sw=s(["\uc18c\ube44\uc790\ubcf4\ud638\uc758 \uc131\uaca9"],t.s)
B.ar7=new A.c("gen_gn_purpose_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc5d0 \uc758\ud55c "\uc18c\ube44\uc790 \ubcf4\ud638"\uc758 \uc131\uaca9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a7I,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uac1c\ubcc4 \uc18c\ube44\uc790\uc758 \ud53c\ud574\ub97c \uc9c1\uc811 \uad6c\uc81c\ud558\ub294 \uc808\ucc28(\uc608: \uc18c\ube44\uc790\ubd84\uc7c1\uc870\uc815)\ub97c \uc8fc\ub41c \uc218\ub2e8\uc73c\ub85c \ud558\uae30\ubcf4\ub2e4\ub294, \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud558\uc5ec \uac00\uaca9 \uc778\ud558\xb7\ud488\uc9c8 \ud5a5\uc0c1 \ub4f1 \uc18c\ube44\uc790\ud6c4\uc0dd \uc99d\uc9c4 \ud6a8\uacfc\uac00 \uc2dc\uc7a5 \uc804\ubc18\uc5d0 \ubbf8\uce58\ub3c4\ub85d \ud558\ub294 \uad6c\uc870\uc801\xb7\uac04\uc811\uc801 \ubc29\uc2dd\uc73c\ub85c \uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud558\ub294 \uc131\uaca9\uc774 \uac15\ud558\ub2e4. \uac1c\ubcc4 \ud53c\ud574\uad6c\uc81c\ub294 \uc18c\ube44\uc790\uae30\ubcf8\ubc95 \ub4f1 \ub2e4\ub978 \ubc95\ub960\uc758 \uc601\uc5ed\uacfc \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4.",B.a2I,B.Sw,null)
B.SU=s(["\uacfc\ub3c4\ud55c \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub97c \uc704\ud55c \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c","\uac1c\ubcc4 \uc18c\ube44\uc790\uc5d0 \ub300\ud55c \uc190\ud574\ubc30\uc0c1 \uc18c\uc1a1 \uc808\ucc28","\ud615\uc0ac\uc18c\uc1a1\ubc95\uc0c1 \uc99d\uac70\uc7ac\ud310\uc8fc\uc758","\ubbfc\ubc95\uc0c1 \uacc4\uc57d\uc790\uc720\uc758 \uc6d0\uce59","\ub178\ub3d9\ubc95\uc0c1 \uadfc\ub85c\uc2dc\uac04 \uaddc\uc81c"],t.s)
B.a62=s(["\uacfc\ub3c4\ud55c \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub97c \uc704\ud55c \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c"],t.s)
B.a3K=s(["\uad6d\ubbfc\uacbd\uc81c \uade0\ud615\ubc1c\uc804","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c"],t.s)
B.amz=new A.c("gen_gn_purpose_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 "\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804"\uc744 \ubaa9\uc801\uc73c\ub85c \uaddc\uc815\ud55c \uac83\uacfc \uac00\uc7a5 \ubc00\uc811\ud558\uac8c \uad00\ub828\ub41c \uc81c\ub3c4\ub294?',B.SU,0,"\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc774\ub77c\ub294 \ubaa9\uc801\uc740 \ud2b9\uc815 \uae30\uc5c5\uc9d1\ub2e8\uc73c\ub85c \uacbd\uc81c\ub825\uc774 \uacfc\ub3c4\ud558\uac8c \uc9d1\uc911\ub418\ub294 \uac83\uc744 \uc5b5\uc81c\ud558\uae30 \uc704\ud55c \uc9c0\uc8fc\ud68c\uc0ac \uaddc\uc81c, \uc0c1\ud638\ucd9c\uc790\xb7\uc21c\ud658\ucd9c\uc790 \uc81c\ud55c, \ucc44\ubb34\ubcf4\uc99d \uc81c\ud55c \ub4f1 \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c\uc640 \uac00\uc7a5 \ubc00\uc811\ud558\uac8c \uad00\ub828\ub41c\ub2e4. \uc774\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc774\ub098 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc81c\uc640\ub294 \ubcc4\ub3c4\ub85c \uad6d\ubbfc\uacbd\uc81c \uc804\uccb4\uc758 \uade0\ud615\uc744 \uace0\ub824\ud558\ub294 \ucde8\uc9c0\uc758 \uaddc\uc815\uc774\ub2e4.",B.a62,B.a3K,null)
B.a_Z=s([u.zL,"\uacbd\uc7c1\ubc95\uc758 \uc720\uc77c\ud55c \ubaa9\uc801\uc740 \ud2b9\uc815 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \uac1c\uc778\uc758 \ub9e4\ucd9c\uc744 \ubcf4\uc7a5\ud558\ub294 \uac83\uc774\ub2e4","\uacbd\uc7c1\ubc95\uc740 \uacbd\uc7c1\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c\uc744 \ubc29\uc9c0\ud558\ub294 \uac83\uc744 \ucd5c\uc6b0\uc120 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\uacbd\uc7c1\ubc95\uc740 \uc18c\ube44\uc790\ubcf4\ub2e4 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\uc744 \uc6b0\uc120\ud55c\ub2e4","\uacbd\uc7c1\ubc95\uc758 \ubcf4\ud638\ubc95\uc775\uc740 \uc2dc\ub300\uc640 \ubb34\uad00\ud558\uac8c \uace0\uc815\ub418\uc5b4 \uc788\uc73c\uba70 \ud559\uc124\uc0c1 \ub2e4\ud23c\uc774 \uc5c6\ub2e4"],t.s)
B.aaz=s([u.zL],t.s)
B.a_Q=s(["\uacbd\uc7c1\uc758 \ubcf4\ud638 vs \uacbd\uc7c1\uc790\uc758 \ubcf4\ud638"],t.s)
B.aqJ=new A.c("gen_gn_purpose_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150","\uacbd\uc7c1\ubc95\uc758 \ubcf4\ud638\ubc95\uc775\uc5d0 \uad00\ud55c \uc77c\ubc18\uc801 \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_Z,0,'\uacbd\uc7c1\ubc95 \uc774\ub860\uc0c1 \ub110\ub9ac \ubc1b\uc544\ub4e4\uc5ec\uc9c0\ub294 \uad00\uc810\uc740 "\uacbd\uc7c1\uc758 \ubcf4\ud638\uc774\uc9c0 \uacbd\uc7c1\uc790\uc758 \ubcf4\ud638\uac00 \uc544\ub2c8\ub2e4"\ub77c\ub294 \uba85\uc81c\ub85c \uc694\uc57d\ub41c\ub2e4. \uc989 \ud2b9\uc815 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \uac1c\uc778\uc758 \uc874\uc18d\uc774\ub098 \uc774\uc775 \uc790\uccb4\ub97c \ubcf4\uc7a5\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uc5ec\ub7ec \uc0ac\uc5c5\uc790\uac00 \uc790\uc720\ub86d\uace0 \uacf5\uc815\ud558\uac8c \uacbd\uc7c1\ud560 \uc218 \uc788\ub294 \uc2dc\uc7a5\uc758 \uad6c\uc870\uc640 \uacfc\uc815\uc744 \ubcf4\ud638\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ubcf4\ud638\ubc95\uc775\uc774\ub77c\ub294 \uac83\uc774\ub2e4. \uc774 \uad00\uc810\uc5d0\uc11c\ub294 \uacbd\uc7c1\uc758 \uacb0\uacfc\ub85c \ube44\ud6a8\uc728\uc801\uc778 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uac83 \uc790\uccb4\ub294 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.aaz,B.a_Q,null)
B.a_N=s(["\uc81c\uc870\uc5c5\xb7\uc11c\ube44\uc2a4\uc5c5 \ub610\ub294 \uadf8 \ubc16\uc758 \uc0ac\uc5c5\uc744 \ud558\ub294 \uc790\ub85c\uc11c, \ubc95\uc778\xb7\uac1c\uc778\uc744 \ubd88\ubb38\ud55c\ub2e4","\uc790\ubcf8\uae08 \uc77c\uc815 \uaddc\ubaa8 \uc774\uc0c1\uc778 \ubc95\uc778\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc0c1\uc7a5\uae30\uc5c5\ub9cc\uc744 \uc0ac\uc5c5\uc790\ub85c \ubcf8\ub2e4","\uc624\uc9c1 \uc601\ub9ac\ub97c \ubaa9\uc801\uc73c\ub85c \uc124\ub9bd\ub41c \ubc95\uc778\ub9cc \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uacf5\uacf5\uae30\uad00\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.XS=s(["\ubc95\uc778\xb7\uac1c\uc778\uc744 \ubd88\ubb38\ud55c\ub2e4"],t.s)
B.Xu=s(["\uc0ac\uc5c5\uc790\uc758 \uc815\uc758"],t.s)
B.aiZ=new A.c("gen_gn_def_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc0ac\uc5c5\uc790"\uc758 \uc815\uc758\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a_N,0,'\uacf5\uc815\uac70\ub798\ubc95\uc0c1 "\uc0ac\uc5c5\uc790"\ub294 \uc81c\uc870\uc5c5\xb7\uc11c\ube44\uc2a4\uc5c5 \ub610\ub294 \uadf8 \ubc16\uc758 \uc0ac\uc5c5\uc744 \ud558\ub294 \uc790\ub97c \ub9d0\ud558\uba70, \ubc95\uc778\uc778\uc9c0 \uac1c\uc778\uc778\uc9c0, \uc601\ub9ac\xb7\ube44\uc601\ub9ac\ub97c \ubd88\ubb38\ud558\uace0 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uc774\uc0c1 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc790\ubcf8\uae08 \uaddc\ubaa8\ub098 \uc0c1\uc7a5 \uc5ec\ubd80\ub294 \uc0ac\uc5c5\uc790\uc131 \ud310\ub2e8\uc758 \uae30\uc900\uc774 \uc544\ub2c8\uba70, \uacf5\uacf5\uae30\uad00\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\ub85c \ucde8\uae09\ub420 \uc218 \uc788\ub2e4.',B.XS,B.Xu,null)
B.a5Z=s(["\uadf8 \ud615\ud0dc\ub97c \ubd88\ubb38\ud558\uace0 2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4","\ub3d9\uc77c\ud55c \uc9c0\uc5ed\uc5d0 \uc18c\uc7ac\ud55c \uc0ac\uc5c5\uc790\ub4e4\uc758 \uce5c\ubaa9 \ubaa8\uc784","\ub2e8 1\uac1c\uc758 \uc0ac\uc5c5\uc790\ub85c \uad6c\uc131\ub41c \ub2e8\uccb4","\uc815\ubd80\uac00 \uc124\ub9bd\uc744 \uac15\uc81c\ud55c \ubc95\uc815\ub2e8\uccb4\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\ub85c\ub9cc \uad6c\uc131\ub41c \ub2e8\uccb4\ub97c \uc758\ubbf8\ud55c\ub2e4"],t.s)
B.XR=s(["2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4"],t.s)
B.a88=s(["\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\uc758"],t.s)
B.ahn=new A.c("gen_gn_def_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc0ac\uc5c5\uc790\ub2e8\uccb4"\uc758 \uc815\uc758\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a5Z,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc870\ud569\xb7\ud611\ud68c \ub4f1 \uba85\uce6d\uc774\ub098 \ubc95\uc801 \ud615\ud0dc\uc640 \uad00\uacc4\uc5c6\uc774, 2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4\ub97c \uc758\ubbf8\ud55c\ub2e4. \ub2e8\uc21c \uce5c\ubaa9 \ubaa8\uc784\uc774\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc0ac\uc5c5\uc790 \uacf5\ub3d9\uc758 \uc774\uc775 \uc99d\uc9c4\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub85c \uc778\uc815\ub420 \uc218 \uc788\uc73c\uba70, \ubc18\ub4dc\uc2dc \ubc95\uc815\ub2e8\uccb4\uc774\uac70\ub098 \uc815\ubd80\uac00 \uc124\ub9bd\uc744 \uac15\uc81c\ud55c \ub2e8\uccb4\uc77c \ud544\uc694\ub294 \uc5c6\ub2e4.",B.XR,B.a88,null)
B.Ri=s(["2 \uc774\uc0c1\uc758 \ud68c\uc0ac\uac00 \ub3d9\uc77c\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc5d0 \uc18d\ud558\ub294 \uacbd\uc6b0 \uc11c\ub85c\ub97c \uacc4\uc5f4\ud68c\uc0ac\ub77c \ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \ubc18\ub4dc\uc2dc \ub3d9\uc77c \uc5c5\uc885\uc744 \uc601\uc704\ud558\ub294 \ud68c\uc0ac\ub9cc\uc744 \uac00\ub9ac\ud0a8\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \uc678\uad6d\uc5d0 \ubcf8\uc0ac\ub97c \ub454 \ud68c\uc0ac\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uac1c\ub150\uc774\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uc5ec\ubd80\ub294 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub85c\ub9cc \ud310\ub2e8\ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \uc0c1\uc7a5 \uc5ec\ubd80\uc5d0 \ub530\ub77c \uacb0\uc815\ub41c\ub2e4"],t.s)
B.Zq=s(["2 \uc774\uc0c1\uc758 \ud68c\uc0ac\uac00 \ub3d9\uc77c\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc5d0 \uc18d\ud558\ub294 \uacbd\uc6b0 \uc11c\ub85c\ub97c \uacc4\uc5f4\ud68c\uc0ac\ub77c \ud55c\ub2e4"],t.s)
B.a8R=s(["\uacc4\uc5f4\ud68c\uc0ac\uc758 \uc815\uc758"],t.s)
B.ai2=new A.c("gen_gn_def_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uacc4\uc5f4\ud68c\uc0ac"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Ri,0,"\uacc4\uc5f4\ud68c\uc0ac\ub294 2 \uc774\uc0c1\uc758 \ud68c\uc0ac\uac00 \ub3d9\uc77c\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc5d0 \uc18d\ud558\ub294 \uacbd\uc6b0 \uadf8 \uc0c1\ud638\uac04\uc758 \uad00\uacc4\ub97c \uac00\ub9ac\ud0a4\ub294 \uac1c\ub150\uc774\ub2e4. \ub3d9\uc77c \uc5c5\uc885 \uc5ec\ubd80, \uc0c1\uc7a5 \uc5ec\ubd80, \ub9e4\ucd9c\uc561 \uaddc\ubaa8\uc640\ub294 \ubb34\uad00\ud558\uba70, \ub3d9\uc77c\ud55c \uc9c0\ubc30\ub825 \uc544\ub798 \uc788\ub294 \uae30\uc5c5\uc9d1\ub2e8 \uc18c\uc18d \uc5ec\ubd80\uac00 \ud575\uc2ec \ud310\ub2e8\uae30\uc900\uc774\ub2e4. \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8\uc774\ub098 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \ub4f1 \uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacc4\uc5f4\ud68c\uc0ac \uad00\uacc4\uac00 \uc911\uc694\ud55c \uace0\ub824\uc694\uc18c\ub85c \uc791\uc6a9\ud55c\ub2e4.",B.Zq,B.a8R,null)
B.SE=s(["\uc8fc\uc2dd(\uc9c0\ubd84)\uc758 \uc18c\uc720\ub97c \ud1b5\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac\ub97c \ub9d0\ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uc81c\uc870\uc5c5\uc744 \uc9c1\uc811 \uc601\uc704\ud574\uc57c \ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc8fc\uc2dd\uc744 \uc804\ud600 \ubcf4\uc720\ud558\uc9c0 \uc54a\ub294 \ud68c\uc0ac\ub97c \uc758\ubbf8\ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac \uc81c\ub3c4\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc804\uba74\uc801\uc73c\ub85c \uae08\uc9c0\ub41c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ud55c \uc720\ud615\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4"],t.s)
B.a2p=s(["\uc8fc\uc2dd(\uc9c0\ubd84)\uc758 \uc18c\uc720\ub97c \ud1b5\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac"],t.s)
B.H2=s(["\uc9c0\uc8fc\ud68c\uc0ac\uc758 \uc815\uc758"],t.s)
B.aiU=new A.c("gen_gn_def_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc9c0\uc8fc\ud68c\uc0ac"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.SE,0,"\uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc8fc\uc2dd(\uc9c0\ubd84) \uc18c\uc720\ub97c \ud1b5\ud574 \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac\ub97c \ub9d0\ud55c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uc740 \uc9c0\uc8fc\ud68c\uc0ac \uc790\uccb4\ub97c \uc804\uba74 \uae08\uc9c0\ud558\uc9c0 \uc54a\uace0, \ubd80\ucc44\ube44\uc728 \uc81c\ud55c\uc774\ub098 \uc790\ud68c\uc0ac \uc9c0\ubd84\uc728 \uc694\uac74 \ub4f1 \uc77c\uc815\ud55c \ud589\uc704\uaddc\uc81c\ub97c \ud1b5\ud574 \uad00\ub9ac\ud558\ub294 \ubc29\uc2dd\uc744 \ucde8\ud55c\ub2e4. \uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \ud68c\uc0ac(\uc0ac\uc5c5\uc790)\uc758 \ud55c \ud615\ud0dc\uc774\ub2e4.",B.a2p,B.H2,null)
B.a8N=s(['\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacbd\uc7c1\uc81c\ud55c\uc801 \ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uc640 \ubcc4\ub3c4\ub85c "\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub41c\ub2e4',"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub294 \ubc95\ub960\uc0c1 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uac8c \ucde8\uae09\ub418\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub294 \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc774 \ubd80\uacfc\ub420 \uc218 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc \ubc1b\uc744 \uc218 \uc788\ub2e4"],t.s)
B.a6A=s(['\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub41c\ub2e4'],t.s)
B.aa4=s(["\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uaddc\uc728\uc758 \ub3c5\uc790\uc131"],t.s)
B.aiW=new A.c("gen_gn_def_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub97c \uad6c\ubcc4\ud558\ub294 \uc2e4\uc775\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a8N,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc81c\ud55c\ud558\uac70\ub098 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704 \ub4f1\uc744 "\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ubcc4\ub3c4\uc758 \uc7a5(\u7ae0)\uc5d0\uc11c \uaddc\uc728\ud558\uace0 \uc788\uc5b4, \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1\uacfc\ub294 \uad6c\ubd84\ub418\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc81c \uccb4\uacc4\ub97c \uac16\ub294\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub3c4 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \uc81c\uc7ac\uac00 \ubd80\uacfc\ub420 \uc218 \uc788\ub2e4.',B.a6A,B.aa4,null)
B.Ov=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9, \uae30\uc5c5\uacb0\ud569, \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \ub4f1 \uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc0ac\uc6a9\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \ubc95 \uc2dc\ud589 \uc774\ud6c4 \uc0ad\uc81c\ub420 \uc608\uc815\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \uc678\uad6d\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.a2V=s(["\uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc0ac\uc6a9\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.N1=s(["\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c \uc815\uc758\uc758 \uc704\uce58"],t.s)
B.apW=new A.c("gen_gn_def_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'"\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5) \uc815\uc758\uaddc\uc815\uc774 \ubc95\ub960 \ucd1d\uce59\uc5d0 \uc704\uce58\ud558\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Ov,0,'"\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5)\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9 \uc5ec\ubd80, \uae30\uc5c5\uacb0\ud569\uc758 \uacbd\uc7c1\uc81c\ud55c\uc131, \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc131\ub9bd \ub4f1 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc5ec\ub7ec \ud575\uc2ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc804\uc81c\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\ub2e4. \uc774 \ub54c\ubb38\uc5d0 \uac1c\ubcc4 \uc7a5(\u7ae0)\uc774 \uc544\ub2c8\ub77c \ubc95\ub960 \ucd1d\uce59(\uc815\uc758\uaddc\uc815)\uc5d0\uc11c \ud1b5\uc77c\uc801\uc73c\ub85c \uaddc\uc815\ud558\uc5ec \uc5ec\ub7ec \uaddc\uc815\uc5d0 \uc77c\uad00\ub418\uac8c \uc801\uc6a9\ub420 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4.',B.a2V,B.N1,null)
B.S0=s(["\ud2b9\ud5c8\uad8c\xb7\uc2e4\uc6a9\uc2e0\uc548\uad8c\xb7\ub514\uc790\uc778\uad8c\xb7\uc0c1\ud45c\uad8c\xb7\uc800\uc791\uad8c\uc758 \uc815\ub2f9\ud55c \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc544\ub2c8\ud55c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c\uc740 \uc774 \ubc95\uc758 \uc801\uc6a9\ub300\uc0c1\uc5d0\uc11c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc644\uc804\ud788 \ubc30\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \ud589\uc0ac\ub294 \uadf8 \ubaa9\uc801\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\ub41c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 \uc0c1\ud45c\uad8c\uc5d0\ub9cc \ud55c\uc815\ub41c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 \uc678\uad6d\uc5d0 \ub4f1\ub85d\ub41c \uad8c\ub9ac\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.Vu=s(["\uc815\ub2f9\ud55c \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc544\ub2c8\ud55c\ub2e4"],t.s)
B.a5r=s(["\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678"],t.s)
B.akq=new A.c("gen_gn_scope_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubb34\uccb4\uc7ac\uc0b0\uad8c\uc758 \ud589\uc0ac\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.S0,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \ud2b9\ud5c8\uad8c\xb7\uc2e4\uc6a9\uc2e0\uc548\uad8c\xb7\ub514\uc790\uc778\uad8c\xb7\uc0c1\ud45c\uad8c\xb7\uc800\uc791\uad8c \ub4f1 \ubb34\uccb4\uc7ac\uc0b0\uad8c\uc758 "\uc815\ub2f9\ud55c" \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc815\ub2f9\ud55c \uad8c\ub9ac\ud589\uc0ac\uc758 \ubc94\uc704 \ub0b4\uc5d0\uc11c\ub9cc \uc778\uc815\ub418\ub294 \uc81c\ud55c\uc801 \uc801\uc6a9\uc81c\uc678\uc774\uba70, \uad8c\ub9ac\ub97c \ube59\uc790\ud558\uc5ec \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704\uae4c\uc9c0 \ubcf4\ud638\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.',B.Vu,B.a5r,null)
B.VZ=s([u.E7,"\ud2b9\ud5c8\uad8c \ud589\uc0ac\ub77c\ub294 \uc774\uc720\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub41c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\uc81c\uc7ac\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\ud2b9\ud5c8\uad8c\uc744 \uc774\uc720\ub85c \ud55c \ud589\uc704\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2ec\uc0ac \ub300\uc0c1 \uc790\uccb4\uac00 \ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4"],t.s)
