B.aqC=new A.c("gen_gn_scope_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ud2b9\ud5c8\uad8c\uc790\uc778 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \ud2b9\ud5c8\uad8c\uc744 \ube59\uc790\ud558\uc5ec \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640\uc758 \uac70\ub798\ub97c \uac70\uc808\ud558\uace0 \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824 \ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.VZ,0,'\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 "\uc815\ub2f9\ud55c" \uad8c\ub9ac\ud589\uc0ac\uc5d0 \ud55c\uc815\ub41c\ub2e4. \ud2b9\ud5c8\uad8c\uc744 \uba85\ubaa9\uc73c\ub85c \ub0b4\uc138\uc6b0\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub824\ub294 \ubaa9\uc801\uc758 \ud589\uc704(\uc608: \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uac70\ub798\uac70\uc808\uc744 \ud1b5\ud55c \ubc30\uc81c)\ub294 \uc815\ub2f9\ud55c \uad8c\ub9ac\ud589\uc0ac\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6cc \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\uace0, \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9 \ub4f1 \ud1b5\uc0c1\uc801\uc778 \uc2ec\uc0ac \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.',B.Wt,B.Nl,null)
B.a7W=s(["\uc18c\uaddc\ubaa8 \uc0ac\uc5c5\uc790 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc0c1\ud638\ubd80\uc870\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\uace0 \uc784\uc758\uc124\ub9bd\xb7\ud0c8\ud1f4\uc758 \uc790\uc720\xb7\uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\ub294 \uc801\uc6a9\uc774 \uc81c\uc678\ub420 \uc218 \uc788\ub2e4","\uc870\ud569\uc774\ub77c\ub294 \uba85\uce6d\uc744 \uc0ac\uc6a9\ud558\uae30\ub9cc \ud558\uba74 \uc694\uac74\uacfc \uad00\uacc4\uc5c6\uc774 \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\ub41c\ub2e4","\uc870\ud569\uc758 \ud589\uc704\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\uc81c\uc678 \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub2e4","\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678\ub294 \ub300\uae30\uc5c5\uc73c\ub85c \uad6c\uc131\ub41c \uc870\ud569\uc5d0\ub3c4 \ub3d9\uc77c\ud558\uac8c \uc778\uc815\ub41c\ub2e4","\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678 \uc5ec\ubd80\ub294 \uc870\ud569\uc758 \uc124\ub9bd\uc5f0\ub3c4\ub9cc\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4"],t.s)
B.Wc=s(["\uc784\uc758\uc124\ub9bd\xb7\ud0c8\ud1f4\uc758 \uc790\uc720\xb7\uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\ub294 \uc801\uc6a9\uc774 \uc81c\uc678\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a5O=s(["\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678 \uc694\uac74"],t.s)
B.ark=new A.c("gen_gn_scope_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc77c\uc815\ud55c \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\uc5d0 \ub300\ud55c \uc801\uc6a9\uc81c\uc678\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a7W,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\uaddc\ubaa8 \uc0ac\uc5c5\uc790 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc0c1\ud638\ubd80\uc870\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\uba70 \uc784\uc758\ub85c \uc124\ub9bd\ub418\uace0 \uc870\ud569\uc6d0\uc758 \uac00\uc785\xb7\ud0c8\ud1f4\uac00 \uc790\uc720\ub86d\uace0 \uc758\uacb0\uad8c\uc774 \ud3c9\ub4f1\ud55c \ub4f1 \uc77c\uc815\ud55c \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\uc5d0 \ub300\ud574 \uc801\uc6a9\uc744 \uc81c\uc678\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc694\uac74 \ucda9\uc871 \uc5ec\ubd80\uc5d0 \ub530\ub77c \ud310\ub2e8\ub418\ub294 \uac83\uc774\uc9c0, \ub2e8\uc21c\ud788 "\uc870\ud569"\uc774\ub77c\ub294 \uba85\uce6d \uc0ac\uc6a9\ub9cc\uc73c\ub85c \uc778\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.',B.Wc,B.a5O,null)
B.IM=s(["\uc870\ud569\uc774 \ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \uacbd\uc6b0","\uc870\ud569\uc6d0\uc758 \uc218\uac00 5\uc778\uc744 \ucd08\uacfc\ud558\ub294 \uacbd\uc6b0","\uc870\ud569\uc758 \uc124\ub9bd \ubaa9\uc801\uc774 \uc0c1\ud638\ubd80\uc870\uc778 \uacbd\uc6b0","\uc870\ud569\uc6d0\uc758 \uac00\uc785\uacfc \ud0c8\ud1f4\uac00 \uc790\uc720\ub85c\uc6b4 \uacbd\uc6b0","\uc870\ud569\uc758 \uc758\uacb0\uad8c\uc774 \ud3c9\ub4f1\ud558\uac8c \ubcf4\uc7a5\ub418\ub294 \uacbd\uc6b0"],t.s)
B.JL=s(["\ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \uacbd\uc6b0"],t.s)
B.a6L=s(["\uc870\ud569 \uc801\uc6a9\uc81c\uc678\uc758 \ud55c\uacc4"],t.s)
B.an4=new A.c("gen_gn_scope_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\uc801\uc6a9\uc81c\uc678 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc774\ub77c \ud558\ub354\ub77c\ub3c4 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc728\uc744 \ubc1b\uc744 \uc218 \uc788\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.IM,0,"\uc801\uc6a9\uc81c\uc678 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc774\ub77c\ub3c4 \uadf8 \uc870\ud569\uc774 \ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \ub4f1\uc758 \ud589\uc704\ub97c \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uaddc\uc728\uc744 \ubc1b\uc744 \uc218 \uc788\ub2e4. \uc870\ud569\uc6d0 \uc218, \uc124\ub9bd\ubaa9\uc801, \uac00\uc785\xb7\ud0c8\ud1f4\uc758 \uc790\uc720, \uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1\uc740 \uc624\ud788\ub824 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uae30 \uc704\ud55c \uc694\uac74\uc5d0 \ud574\ub2f9\ud558\ub294 \uc0ac\ud56d\ub4e4\uc774\ub2e4.",B.JL,B.a6L,null)
B.acS=s(["\uad6d\ub0b4\uc5d0\uc11c \uc0ac\uc5c5\uc744 \uc601\uc704\ud558\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc6d0\uce59\uc801\uc73c\ub85c \uc801\uc6a9\ub418\uba70, \uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uc5d0 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4","\uc774 \ubc95\uc740 \ubbfc\uac04 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \ubc95\uc740 \uc678\uad6d\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \ubc95\uc740 \uac1c\uc778\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\uace0 \ubc95\uc778\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc774 \ubc95\uc758 \uc778\uc801 \uc801\uc6a9\ubc94\uc704\ub294 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4"],t.s)
B.abq=s(["\uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uc5d0 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4"],t.s)
B.Wv=s(["\uc778\uc801 \uc801\uc6a9\ubc94\uc704"],t.s)
B.aqG=new A.c("gen_gn_scope_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\uacf5\uc815\uac70\ub798\ubc95\uc758 \uc778\uc801 \uc801\uc6a9\ubc94\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.acS,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uad6d\ub0b4\uc5d0\uc11c \uc0ac\uc5c5\uc744 \uc601\uc704\ud558\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc6d0\uce59\uc801\uc73c\ub85c \uc801\uc6a9\ub418\uba70, \ubc95\uc778\xb7\uac1c\uc778\uc744 \ubd88\ubb38\ud55c\ub2e4. \uad6d\uac00\ub098 \uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uacf5\uad8c\ub825 \ud589\uc0ac \uc8fc\uccb4\uac00 \uc544\ub2c8\ub77c \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\uace0, \uc5ed\uc678\uc801\uc6a9 \ubc95\ub9ac\uc5d0 \ub530\ub77c \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uc5d0\ub3c4 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.abq,B.Wv,null)
B.I4=s([u._,"\ub2e4\ub978 \ubc95\ub839\uc758 \uc874\uc7ac\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc790\ub3d9\uc73c\ub85c \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc774 \uc804\uba74 \ubc30\uc81c\ub41c\ub2e4","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \ud589\uc704\ub294 \uadf8 \ub0b4\uc6a9\uc744 \ubd88\ubb38\ud558\uace0 \ubaa8\ub450 \uc801\uc6a9\uc81c\uc678 \ub300\uc0c1\uc774\ub2e4","\ub2e4\ub978 \ubc95\ub839\uacfc\uc758 \uad00\uacc4\ub294 \uc774 \ubc95\uc5d0\uc11c \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \ud589\uc704\ub294 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4"],t.s)
B.T9=s([u._],t.s)
B.YX=s(["\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \uc815\ub2f9\ud589\uc704"],t.s)
B.aof=new A.c("gen_gn_scope_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \uc815\ub2f9\ud55c \ud589\uc704\uc640 \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc81c\uc678\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.I4,0,"\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub77c \ud589\ud558\ub294 \uc815\ub2f9\ud55c \ud589\uc704\uc5d0 \ub300\ud55c \uc801\uc6a9\uc81c\uc678\ub294 \uadf8 \ubc95\ub839\uc5d0 \uba85\uc2dc\uc801\uc774\uace0 \uad6c\uccb4\uc801\uc778 \uadfc\uac70\uac00 \uc788\ub294 \uacbd\uc6b0\uc5d0 \ud55c\ud574 \uc81c\ud55c\uc801\uc73c\ub85c \uc778\uc815\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \ub2e8\uc21c\ud788 \ub2e4\ub978 \ubc95\ub839\uc774 \uc874\uc7ac\ud55c\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc774 \uc790\ub3d9\uc73c\ub85c \uc804\uba74 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uadf8 \ud589\uc704\uac00 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294\uc9c0 \uc5ec\ubd80\uac00 \ud568\uaed8 \uac80\ud1a0\ub41c\ub2e4.",B.T9,B.YX,null)
B.Rb=s(["\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc77c\ubc18\ubc95\uc801 \uc9c0\uc704\ub97c \uac00\uc9c0\uba70, \uac1c\ubcc4 \ubc95\ub960\uc740 \ud2b9\uc815 \uac70\ub798\ubd84\uc57c\uc5d0 \ud2b9\ud654\ub41c \ud2b9\ubcc4\ubc95\uc73c\ub85c\uc11c \uc6b0\uc120 \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc740 \uacf5\uc815\uac70\ub798\ubc95\uacfc \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ubc95\uccb4\uacc4\uc774\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc774 \uc788\uc73c\uba74 \uacf5\uc815\uac70\ub798\ubc95\uc740 \ud574\ub2f9 \ubd84\uc57c\uc5d0\uc11c \uc644\uc804\ud788 \ud6a8\ub825\uc744 \uc0c1\uc2e4\ud55c\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc774 \ud56d\uc0c1 \uac1c\ubcc4 \ubc95\ub960\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc740 \ub3d9\uc2dc\uc5d0 \uc801\uc6a9\ub420 \uc218 \uc5c6\ub2e4"],t.s)
B.Mc=s(["\uac1c\ubcc4 \ubc95\ub960\uc740 \ud2b9\uc815 \uac70\ub798\ubd84\uc57c\uc5d0 \ud2b9\ud654\ub41c \ud2b9\ubcc4\ubc95\uc73c\ub85c\uc11c \uc6b0\uc120 \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4"],t.s)
B.a6i=s(["\uc77c\ubc18\ubc95\xb7\ud2b9\ubcc4\ubc95 \uad00\uacc4"],t.s)
B.aq4=new A.c("gen_gn_system_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uac00\ub9f9\uc0ac\uc5c5\uac70\ub798\uc758 \uacf5\uc815\ud654\uc5d0 \uad00\ud55c \ubc95\ub960, \ud558\ub3c4\uae09\uac70\ub798 \uacf5\uc815\ud654\uc5d0 \uad00\ud55c \ubc95\ub960 \ub4f1 \uac1c\ubcc4 \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Rb,0,"\uac00\ub9f9\uc0ac\uc5c5\ubc95\xb7\ud558\ub3c4\uae09\ubc95 \ub4f1\uc740 \ud2b9\uc815 \uac70\ub798\ubd84\uc57c(\uac00\ub9f9, \ud558\ub3c4\uae09 \ub4f1)\uc758 \ud2b9\uc131\uc744 \ubc18\uc601\ud574 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uae30\ubcf8 \uc774\ub150 \uc544\ub798 \ub9c8\ub828\ub41c \ud2b9\ubcc4\ubc95\uc73c\ub85c, \ud574\ub2f9 \ubd84\uc57c\uc5d0\uc11c\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \ud2b9\ubcc4\ubc95\uc774 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4. \ub2e4\ub9cc \uc774\ub4e4 \ubc95\ub960\ub3c4 \uad81\uadf9\uc801\uc73c\ub85c\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc774 \ucd94\uad6c\ud558\ub294 \uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1 \ucd09\uc9c4\uc774\ub77c\ub294 \uc774\ub150\uc744 \uacf5\uc720\ud558\uba70, \ub450 \ubc95\ub960\uc774 \uc0c1\ud638 \ubc30\ud0c0\uc801\uc73c\ub85c \ub2e8\uc808\ub41c \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Mc,B.a6i,null)
B.a40=s(["\uc57d\uad00\ubc95\uc740 \ubd88\uacf5\uc815\uc57d\uad00 \uc2ec\uc0ac\ub97c \ubcc4\ub3c4\ub85c \uaddc\uc728\ud558\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uad00\uc758 \uac1c\ubcc4 \ubc95\ub960\ub85c\uc11c \uacf5\uc815\uac70\ub798\ubc95\uacfc \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4","\uc57d\uad00\ubc95\uc740 \uacf5\uc815\uac70\ub798\ubc95\uacfc \uc804\ud600 \uad00\ub828 \uc5c6\ub294 \ub2e4\ub978 \uc815\ubd80\ubd80\ucc98 \uc18c\uad00 \ubc95\ub960\uc774\ub2e4","\uc57d\uad00\ubc95\uc774 \uc2dc\ud589\ub418\uba74 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc815\uc740 \uc804\ubd80 \ud3d0\uc9c0\ub41c\ub2e4","\uc57d\uad00\ubc95\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc57d\uad00\uc5d0 \uad00\ud55c \uc0ac\ud56d\uc740 \uc624\uc9c1 \ubbfc\ubc95\uc73c\ub85c\ub9cc \uaddc\uc728\ub418\uace0 \uc57d\uad00\ubc95\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.TP=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uad00\uc758 \uac1c\ubcc4 \ubc95\ub960\ub85c\uc11c \uacf5\uc815\uac70\ub798\ubc95\uacfc \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4"],t.s)
B.MO=s(["\uc57d\uad00\ubc95\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4"],t.s)
B.aja=new A.c("gen_gn_system_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a40,0,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc18c\uad00\ud558\ub294 \uac1c\ubcc4 \ubc95\ub960\ub85c\uc11c, \uc0ac\uc5c5\uc790\uac00 \ubbf8\ub9ac \ub9c8\ub828\ud55c \uc57d\uad00 \uc870\ud56d\uc758 \ubd88\uacf5\uc815\uc131\uc744 \uc2ec\uc0ac\xb7\uaddc\uc81c\ud558\ub294 \uac83\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uacfc\ub294 \uaddc\uc728 \ub300\uc0c1\uacfc \uc694\uac74\uc774 \ub2e4\ub974\uc9c0\ub9cc, \uac19\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccb4\uacc4 \uc548\uc5d0\uc11c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uc791\ub3d9\ud558\ub294 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.TP,B.MO,null)
B.a4s=s(["\ub450 \ubc95\ub960\uc740 \ubaa9\uc801\uacfc \ubcf4\ud638\ubc95\uc775\uc758 \uac15\uc870\uc810\uc774 \ub2e4\ub974\uc9c0\ub9cc \uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\uc9c4\uc774\ub77c\ub294 \uce21\uba74\uc5d0\uc11c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uae30\ub2a5\ud55c\ub2e4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc774 \uc2dc\ud589\ub41c \uc774\ud6c4 \uacf5\uc815\uac70\ub798\ubc95\uc740 \ud3d0\uc9c0\ub418\uc5c8\ub2e4","\ub450 \ubc95\ub960\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uaddc\uc815\ud558\uace0 \uc788\uc5b4 \ud558\ub098\ub9cc \uc874\uc7ac\ud574\ub3c4 \ubb34\ubc29\ud558\ub2e4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc740 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc18c\ube44\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\ube44\uc790 \uad00\ub828 \uc0ac\ud56d\uc744 \uc804\ud600 \ub2e4\ub8e8\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Zx=s(["\uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\uc9c4\uc774\ub77c\ub294 \uce21\uba74\uc5d0\uc11c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uae30\ub2a5\ud55c\ub2e4"],t.s)
B.Wi=s(["\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uacfc\uc758 \uad00\uacc4"],t.s)
B.apv=new A.c("gen_gn_system_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a4s,0,"\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc740 \uc18c\ube44\uc790\uc758 \uad8c\uc775 \uc99d\uc9c4\uacfc \ud53c\ud574\uad6c\uc81c\ub97c \uc9c1\uc811\uc801 \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \ubc18\uba74, \uacf5\uc815\uac70\ub798\ubc95\uc740 \uacbd\uc7c1 \ucd09\uc9c4\uc744 \ud1b5\ud55c \uad6c\uc870\uc801\xb7\uac04\uc811\uc801 \uc18c\ube44\uc790\ud6c4\uc0dd \uc99d\uc9c4\uc5d0 \ubc29\uc810\uc774 \uc788\ub2e4. \ub450 \ubc95\ub960\uc740 \uac15\uc870\uc810\uc774 \ub2e4\ub974\uc9c0\ub9cc \uad81\uadf9\uc801\uc73c\ub85c \uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\uc9c4\uc774\ub77c\ub294 \uacf5\ud1b5\uc758 \uc9c0\ud5a5\uc810\uc744 \uac00\uc9c0\uace0 \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uae30\ub2a5\ud55c\ub2e4.",B.Zx,B.Wi,null)
B.abB=s(["\ub3d9\uc77c\ud55c \uc0ac\uc548\uc5d0 \ub300\ud574 \ud2b9\ubcc4\ubc95\uc5d0 \ubcc4\ub3c4\uc758 \uaddc\uc815\uc774 \uc788\uc73c\uba74 \uadf8 \ud2b9\ubcc4\ubc95 \uaddc\uc815\uc774 \uc77c\ubc18\ubc95\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\ud2b9\ubcc4\ubc95\uacfc \uc77c\ubc18\ubc95\uc774 \ucda9\ub3cc\ud558\uba74 \ud56d\uc0c1 \uc77c\ubc18\ubc95\uc774 \uc6b0\uc120\ud55c\ub2e4","\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \uacf5\uc815\uac70\ub798\ubc95 \uccb4\uacc4\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ud2b9\ubcc4\ubc95\uc774 \uc788\uc73c\uba74 \uc77c\ubc18\ubc95\uc740 \uadf8 \uc989\uc2dc \uc804\uccb4\uac00 \ud3d0\uc9c0\ub41c \uac83\uc73c\ub85c \ubcf8\ub2e4","\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \ud615\ubc95\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \ud589\uc815\ubc95 \ubd84\uc57c\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.a8E=s(["\ud2b9\ubcc4\ubc95\uc5d0 \ubcc4\ub3c4\uc758 \uaddc\uc815\uc774 \uc788\uc73c\uba74 \uadf8 \ud2b9\ubcc4\ubc95 \uaddc\uc815\uc774 \uc77c\ubc18\ubc95\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.YJ=s(["\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59"],t.s)
B.ajP=new A.c("gen_gn_system_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4",'"\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.abB,0,'"\ud2b9\ubcc4\ubc95\uc740 \uc77c\ubc18\ubc95\uc5d0 \uc6b0\uc120\ud55c\ub2e4"\ub294 \ubc95 \uc801\uc6a9\uc758 \uc77c\ubc18\uc6d0\uce59\uc73c\ub85c, \ub3d9\uc77c\ud55c \uc0ac\ud56d\uc5d0 \ub300\ud574 \ud2b9\ubcc4\ubc95\uc5d0 \ubcc4\ub3c4\uc758 \uaddc\uc815\uc774 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub294 \uadf8 \ud2b9\ubcc4\ubc95\uc774 \uc77c\ubc18\ubc95\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uacfc \uac00\ub9f9\uc0ac\uc5c5\ubc95\xb7\ud558\ub3c4\uae09\ubc95 \ub4f1\uc758 \uad00\uacc4\uc5d0\uc11c\ub3c4 \uc774 \uc6d0\ufffd\ub9ac\uc774 \uc801\uc6a9\ub418\uc5b4, \ud574\ub2f9 \ud2b9\ubcc4\ubc95\uc774 \uaddc\uc728\ud558\ub294 \uc0ac\ud56d\uc5d0\ub294 \ud2b9\ubcc4\ubc95\uc774 \uba3c\uc800 \uc801\uc6a9\ub41c\ub2e4.',B.a8E,B.YJ,null)
B.a86=s(["\ud53c\ud574\uc790\ub294 \uacf5\uc815\uac70\ub798\ubc95 \ubc0f \ubbfc\ubc95\uc0c1 \uc190\ud574\ubc30\uc0c1 \uad00\ub828 \uaddc\uc815 \ub4f1\uc744 \ud1b5\ud574 \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc5d0 \ub300\ud574\uc11c\ub294 \uc5b4\ub5a0\ud55c \ubbfc\uc0ac\uc801 \uad6c\uc81c\uc218\ub2e8\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\ubbfc\uc0ac\uc801 \uad6c\uc81c\ub294 \ubc18\ub4dc\uc2dc \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \ucc98\ubd84\uc774 \uc788\uc5b4\uc57c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc190\ud574\ubc30\uc0c1\uccad\uad6c\uad8c\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc778\uc815\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18 \ud53c\ud574\uc790\ub294 \ud615\uc0ac\uace0\uc18c\ub9cc \uac00\ub2a5\ud558\uace0 \ubbfc\uc0ac\uc18c\uc1a1\uc740 \uc81c\uae30\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.SR=s(["\uacf5\uc815\uac70\ub798\ubc95 \ubc0f \ubbfc\ubc95\uc0c1 \uc190\ud574\ubc30\uc0c1 \uad00\ub828 \uaddc\uc815 \ub4f1\uc744 \ud1b5\ud574 \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4"],t.s)
