B.and=new A.c("gen_gn_extra_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc5ed\uc678\uc801\uc6a9\xb7\uad6d\uc81c\ud611\ub825","\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc758 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Oz,0,"\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8\ub85c \uc778\ud55c \ud6a8\uacfc\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0\uc5d0\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc744 \uc801\uc6a9\ud560 \uc218 \uc788\ub3c4\ub85d \ud568\uc73c\ub85c\uc368, \uad6d\uacbd\uc744 \ub118\uc5b4 \uc774\ub8e8\uc5b4\uc9c0\ub294 \uad6d\uc81c\uce74\ub974\ud154 \ub4f1\uc73c\ub85c\ubd80\ud130 \uad6d\ub0b4\uc2dc\uc7a5\uc758 \uacbd\uc7c1\uc9c8\uc11c\ub97c \ubcf4\ud638\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4. \ub2e4\ub9cc \ubaa8\ub4e0 \uad6d\uc678\ud589\uc704\uc5d0 \ubb34\uc81c\ud55c \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5\uc744 \uc694\uac74\uc73c\ub85c \ud55c\ub2e4.",B.Vb,B.VC,null)
B.ace=s(["\ubb38\uc81c\ub41c \uad6d\uc678\ud589\uc704\ub85c \uc778\ud574 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc801\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uc5ec\ubd80\ub294 \uc804\uc801\uc73c\ub85c \uc678\uad6d \uc815\ubd80\uc758 \ub3d9\uc758 \uc5ec\ubd80\uc5d0 \ub2ec\ub824 \uc788\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uc5ec\ubd80\ub294 \ud589\uc704\uac00 \uc774\ub8e8\uc5b4\uc9c4 \uc2dc\uac01(\ub0ae/\ubc24)\uc5d0 \ub530\ub77c \ub2ec\ub77c\uc9c4\ub2e4"],t.s)
