B.arY=new A.c("gen_gn_extra_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc5ed\uc678\uc801\uc6a9\xb7\uad6d\uc81c\ud611\ub825","\uc5ed\uc678\uc801\uc6a9 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \uae30\uc900\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.ace,0,'\ud310\ub840\ub294 \uc5ed\uc678\uc801\uc6a9\uc758 \uc694\uac74\uc774 \ub418\ub294 "\uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ub300\ud55c \uc601\ud5a5"\uc744 \ubb38\uc81c\ub41c \uad6d\uc678\ud589\uc704\ub85c \uc778\ud574 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0\ub85c \uc81c\ud55c \ud574\uc11d\ud55c\ub2e4. \uc774\ub294 \ubb34\ubd84\ubcc4\ud55c \uc5ed\uc678\uc801\uc6a9\uc744 \ubc29\uc9c0\ud558\uba74\uc11c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uad6d\ub0b4 \uacbd\uc7c1\uc9c8\uc11c\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub294 \uaddc\uc728\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uade0\ud615\uc810 \uc5ed\ud560\uc744 \ud55c\ub2e4.',B.Id,B.a3I,null)
B.Ly=s(["\uc815\ubd80\ub294 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc54a\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95\uc758 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uad6d\uc81c\ud611\ub825 \uaddc\uc815\uc740 \uc774 \ubc95\uc5d0 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc678\uad6d\uc815\ubd80\uc640\uc758 \ud611\uc815\uc740 \ubc18\ub4dc\uc2dc \uad6d\ud68c\uc758 \uac1c\ubcc4 \uc0ac\uac74\ubcc4 \ub3d9\uc758\ub97c \uac70\uccd0\uc57c\ub9cc \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uad6d\uc81c\ud611\ub825\uc740 \uc624\uc9c1 \ubbfc\uac04\uae30\uc5c5 \uac04\uc758 \uacc4\uc57d\uc744 \ud1b5\ud574\uc11c\ub9cc \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc678\uad6d\uc815\ubd80\uc640\uc758 \ud611\uc815 \uccb4\uacb0\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc544\ub2cc \ubc95\uc6d0\uc758 \uad8c\ud55c\uc774\ub2e4"],t.s)
