B.ajg=new A.c("gen_gn_extra_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc5ed\uc678\uc801\uc6a9\xb7\uad6d\uc81c\ud611\ub825","\uc5ed\uc678\uc801\uc6a9\uc744 \uc778\uc815\ud558\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub294 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.abw,0,"\uc5ed\uc678\uc801\uc6a9\uc744 \uc778\uc815\ud558\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \uc678\uad6d\uc758 \uc8fc\uad8c\uc801 \uad00\ud560\uad8c\uacfc \ucda9\ub3cc\ud560 \uac00\ub2a5\uc131\uc774 \uc788\uc73c\ubbc0\ub85c, \uad6d\uac00 \uac04 \uc608\uc591(comity)\uc774\ub098 \uad6d\uc81c\ud611\ub825\uc758 \ud544\uc694\uc131 \ub4f1\uc774 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4. \uc774\ub294 \uc5ed\uc678\uc801\uc6a9\uc774 \ubb34\uc81c\ud55c\uc801\uc73c\ub85c \ud655\uc7a5\ub418\uc9c0 \uc54a\ub3c4\ub85d \ud558\ub294 \uade0\ud615\uc7a5\uce58\uc758 \ud558\ub098\ub85c \uc774\ud574\ub41c\ub2e4.",B.JQ,B.Ts,null)
B.a2w=s([u.iy,"\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4 \uc0ac\uc5c5\uc790\ub97c \ud574\uc678 \uc9c4\ucd9c \uc2dc \uaddc\uc81c\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4\uc2dc\uc7a5\uacfc \ubb34\uad00\ud55c \uc21c\uc218 \uc678\uad6d \ub0b4 \uac70\ub798\uae4c\uc9c0 \uaddc\uc728\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4 \uc18c\ube44\uc790\uc758 \ud574\uc678\uc9c1\uad6c\ub97c \uae08\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uc678\uad6d \uc815\ubd80\uc758 \uc694\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \ubc1c\ub3d9\ub420 \uc218 \uc788\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4"],t.s)
