B.ahU=new A.c("gen_ta_compete_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\ub85c \ud558\uc5ec\uae08 \uc0c1\ud488 \uac00\uaca9\uc744 \uc77c\uc815 \uc218\uc900 \uc774\uc0c1\uc73c\ub85c \uc720\uc9c0\ud558\ub3c4\ub85d \uacb0\uc758\ud558\uace0 \uc774\ub97c \uc2e4\ud589\ud558\uac8c \ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.SP,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uac00\uaca9\uc744 \uc77c\uc815 \uc218\uc900\uc73c\ub85c \uc720\uc9c0\ud558\ub3c4\ub85d \uacb0\uc758\ud558\uace0 \uc2e4\ud589\ud558\uac8c \ud558\ub294 \ud589\uc704\ub294, \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\uaca9\uc5d0 \uad00\ud55c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub97c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc8fc\ub3c4\ud55c \uac83\uc73c\ub85c \ud3c9\uac00\ub418\uc5b4 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704(\uc81c51\uc870 \uc81c1\ud56d \uc81c1\ud638)\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc758\uc0ac\uacb0\uc815\uc774\ub77c\ub294 \ud615\uc2dd\uc744 \ucde8\ud558\ub354\ub77c\ub3c4 \uadf8 \uc2e4\uc9c8\uc774 \uacbd\uc7c1\uc81c\ud55c\uc801 \ud569\uc758\ub77c\uba74 \uaddc\uc81c\ub97c \ud53c\ud560 \uc218 \uc5c6\uc73c\uba70, \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uc774\ub97c \uc2e4\ud589\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790 \ubaa8\ub450\uc5d0\uac8c \ucc45\uc784\uc774 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.a3X,B.Qm,null)
B.ack=s([u.eJ,"\ud310\ub2e8\uae30\uc900\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\uad00\uc5d0 \uba85\uc2dc\ub41c \ubaa9\uc801\ub9cc\uc744 \ubcf8\ub2e4","\uacbd\uc7c1\uc81c\ud55c \uc5ec\ubd80\ub294 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\uace0 \uacb0\uc758\uac00 \uc788\uc5c8\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \uc704\ubc95\ud558\ub2e4","\uc774 \uc720\ud615\uc740 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\uc81c\uc7ac\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\ud310\ub2e8\uae30\uc900\uc740 \uad6c\uc131\uc0ac\uc5c5\uc790 \uc218\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ub3d9\uc77c\ud55c \uacb0\ub860\uc5d0 \uc774\ub978\ub2e4"],t.s)
