B.aiV=new A.c("gen_ta_compete_5","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\ubcf4\uad50\ud658 \ud589\uc704\uac00 \uacbd\uc7c1\uc81c\ud55c\uc801 \uacf5\ub3d9\ud589\uc704\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ks,0,"\uac00\uaca9, \uc0dd\uc0b0\ub7c9, \ud310\ub9e4\uc870\uac74 \ub4f1 \uacbd\uc7c1\uc5d0 \ubbfc\uac10\ud55c \uc815\ubcf4\ub97c \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub97c \ub9e4\uac1c\ub85c \uad6c\uc131\uc0ac\uc5c5\uc790 \uac04\uc5d0 \uad50\ud658\ud558\ub3c4\ub85d \ud558\uc5ec \uc0ac\uc2e4\uc0c1 \ub2f4\ud569\uacfc \uc720\uc0ac\ud55c \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\ub97c \ub0b3\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4. \ubc18\uba74 \uacf5\uac1c\ub41c \ud1b5\uacc4\uc790\ub8cc\uc758 \ub2e8\uc21c \uc885\ud569\xb7\ubc30\ud3ec, \uc77c\ubc18\uc801 \uc0b0\uc5c5\ub3d9\ud5a5 \uacf5\uc720, \uc548\uc804 \uad00\ub828 \uc815\ubcf4 \uacf5\uc720 \ub4f1\uc740 \ud1b5\uc0c1\uc801\uc73c\ub85c \uacbd\uc7c1\uc81c\ud55c \uc6b0\ub824\uac00 \ud06c\uc9c0 \uc54a\uc740 \uc815\ub2f9\ud55c \ud65c\ub3d9\uc73c\ub85c \ud3c9\uac00\ub41c\ub2e4.",B.YE,B.QP,null)
B.a5h=s([u.D7,"\ub450 \uc81c\ub3c4\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uaddc\uc815\uc740 \ubd88\ud544\uc694\ud55c \uc911\ubcf5\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad00\uc5ec\ud558\uba74 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \uaddc\uc815\uc740 \uc804\ufffd\uba74 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ub2f4\ud569\ubcf4\ub2e4 \ud56d\uc0c1 \uac00\ubccd\uac8c \ucc98\ubc8c\ub41c\ub2e4","\ub450 \uc81c\ub3c4\ub294 \uc804\ud600 \ub2e4\ub978 \ubc95\ub960\uc5d0 \uaddc\uc815\ub418\uc5b4 \uc788\uc5b4 \uc11c\ub85c \ucc38\uc870\ud560 \uc218 \uc5c6\ub2e4"],t.s)
