B.amd=new A.c("gen_ta_compete_6","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacbd\uc7c1\uc81c\ud55c\uc801 \uacf5\ub3d9\ud589\uc704 \uaddc\uc81c\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790 \uac04 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uaddc\uc81c\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a5h,0,"\uacbd\uc7c1\uc81c\ud55c\uc801 \ud589\uc704\uc758 \uc8fc\uccb4\uac00 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc790\uccb4\uc778 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704(\uc81c51\uc870)\ub85c, \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub4e4 \uac04\uc758 \ud569\uc758\uc778 \uacbd\uc6b0\uc5d0\ub294 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\uc81c40\uc870 \ub4f1)\ub85c \uac01\uac01 \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. \ud558\ub098\uc758 \uc0ac\uc548\uc5d0\uc11c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacb0\uc758\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \uc2e4\ud589 \ud569\uc758\uac00 \ud568\uaed8 \uc874\uc7ac\ud558\uba74 \ub450 \uaddc\uc815\uc774 \ud568\uaed8 \ubb38\uc81c\ub420 \uc218\ub3c4 \uc788\uc73c\uba70, \uc5b4\ub290 \ud558\ub098\uac00 \ub2e4\ub978 \ud558\ub098\ub97c \uc644\uc804\ud788 \ub300\uccb4\ud558\uac70\ub098 \ubc30\uc81c\ud558\ub294 \uad00\uacc4\ub294 \uc544\ub2c8\ub2e4.",B.YU,B.a4l,null)
B.Xx=s([u.bY,"\uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c\uc740 \uae30\uc874 \ud68c\uc6d0\uc758 \uc774\uc775 \ubcf4\ud638\ub97c \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ud56d\uc0c1 \uc815\ub2f9\ud558\ub2e4","\uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c\uc740 \uc624\uc9c1 \uc815\ubd80\uc758 \uc778\ud5c8\uac00 \uc81c\ub3c4\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub418\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ud68c\uc6d0 \uc790\uaca9 \uc694\uac74\uc744 \uc804\ud600 \uc815\ud560 \uc218 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c \ud589\uc704\ub294 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \uc601\ud5a5\uc744 \ubbf8\uce58\uace0 \uacbd\uc7c1\uacfc\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
