B.a9X=s(["\ud569\ub9ac\uc801 \uc790\uaca9\uc694\uac74\uc758 \ud5c8\uc6a9"],t.s)
B.aoj=new A.c("gen_ta_restrict_5","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud68c\uc6d0\uc790\uaca9 \uc694\uac74\uc73c\ub85c \ud569\ub9ac\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \ucd5c\uc18c\ud55c\uc758 \uc804\ubb38\uc131 \uae30\uc900(\uc608: \uad00\ub828 \uc790\uaca9\uc99d \ubcf4\uc720)\uc744 \uc694\uad6c\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a4f,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc5c5\ubb34\uc758 \uc804\ubb38\uc131\uc774\ub098 \uc548\uc804 \ud655\ubcf4 \ub4f1\uc744 \uc704\ud574 \ud569\ub9ac\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \ucd5c\uc18c\ud55c\uc758 \uc790\uaca9\uc694\uac74(\uad00\ub828 \uc790\uaca9\uc99d \ubcf4\uc720 \ub4f1)\uc744 \uc815\ud558\ub294 \uac83\uc740, \uadf8 \uc790\uccb4\ub85c \ubd80\ub2f9\ud55c \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c\uc774\ub77c\uace0 \ub2e8\uc815\ud558\uae30 \uc5b4\ub835\ub2e4. \ubb38\uc81c\ub294 \uadf8\ub7ec\ud55c \uae30\uc900\uc774 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc2e0\uaddc \uc9c4\uc785\uc744 \uc790\uc758\uc801\xb7\uacfc\ub3c4\ud558\uac8c \ubd09\uc1c4\ud558\ub294 \uc218\ub2e8\uc73c\ub85c \ub0a8\uc6a9\ub418\ub294\uc9c0 \uc5ec\ubd80\uc774\ub2e4.",B.SS,B.a9X,null)
B.Pf=s([u.Bs,"\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560\uc740 \ud56d\uc0c1 \ud6a8\uc728\uc801\uc778 \uacbd\uc601\uae30\ubc95\uc73c\ub85c\uc11c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560 \uacb0\uc758\ub294 \uc18c\ube44\uc790\uc5d0\uac8c \uc804\ud600 \uc601\ud5a5\uc744 \ubbf8\uce58\uc9c0 \uc54a\ub294\ub2e4","\uc774\ub7ec\ud55c \uacb0\uc758\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uc815\ubd80\ub9cc \ud560 \uc218 \uc788\ub294 \uc870\uce58\uc774\ub2e4","\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560\uc740 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uac1c\ubcc4 \uacc4\uc57d\uc73c\ub85c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c8 \ubfd0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
B.Wd=s([u.Bs],t.s)
B.abc=s(["\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560 \uacb0\uc758"],t.s)
B.akA=new A.c("gen_ta_restrict_6","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\uc9c0\uc5ed\uc744 \uc784\uc758\ub85c \ub098\ub204\uc5b4 \uc11c\ub85c\uc758 \uc9c0\uc5ed\uc744 \uce68\ubc94\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uacb0\uc758\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Pf,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uc601\uc5c5\uc9c0\uc5ed\uc744 \uc784\uc758\ub85c \ubd84\ud560\ud558\uc5ec \uc11c\ub85c \uce68\ubc94\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uacb0\uc758\ud558\ub294 \uac83\uc740, \uc9c0\uc5ed\ubcc4 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\uac70\ud558\ub294 \ud589\uc704\ub85c\uc11c \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\xb7\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uc18c\ube44\uc790\uc758 \uc120\ud0dd\uad8c \ucd95\uc18c\uc640 \uac00\uaca9 \uc0c1\uc2b9\uc73c\ub85c \uc774\uc5b4\uc9c8 \uc218 \uc788\uc5b4 \uacbd\uc7c1\uc81c\ud55c \uc6b0\ub824\uac00 \ud06c\ub2e4.",B.Wd,B.abc,null)
B.OA=s(["\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub41c\ub2e4","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub9cc \ud560 \uc218 \uc788\uc73c\ubbc0\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ubc29\uc870\ud589\uc704\uc5d0 \ub300\ud574 \uc5b4\ub5a0\ud55c \ucc45\uc784\ub3c4 \uc9c0\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uc720\ud615\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\uc81c\uc7ac\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\uc774 \uc720\ud615\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\uad00\uc5d0 \uba85\uc2dc\ub418\uc9c0 \uc54a\uc73c\uba74 \uaddc\uc81c\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.VU=s(["\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub41c\ub2e4"],t.s)
B.Lo=s(["\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ubc29\uc870"],t.s)
B.aij=new A.c("gen_ta_aid_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \ubc29\uc870","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub85c \ud558\uc5ec\uae08 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \uc774\ub97c \ubc29\uc870\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.OA,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c51\uc870 \uc81c1\ud56d \uc81c4\ud638\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub610\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \uc774\ub97c \ubc29\uc870\ud558\ub294 \ud589\uc704\ub97c \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc815\ud55c\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc9c1\uc811 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \uc8fc\uccb4\uac00 \uc544\ub2c8\ub354\ub77c\ub3c4, \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uadf8\ub7ec\ud55c \ud589\uc704\ub97c \uc720\ub3c4\xb7\ubc29\uc870\ud55c\ub2e4\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc790\uccb4\uac00 \ucc45\uc784\uc744 \uc9c8 \uc218 \uc788\ub2e4.",B.VU,B.Lo,null)
B.HL=s([u.s8,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc9c0\uce68\uc740 \uad8c\uace0\uc5d0 \ubd88\uacfc\ud558\ubbc0\ub85c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uac70\ub798\uac70\uc808\uc740 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \uc790\uc720\uc774\ubbc0\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc9c0\uce68\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc774 \uacbd\uc6b0 \ud2b9\uc815 \uc720\ud1b5\uc5c5\uc790\uc5d0\uac8c\ub294 \uc5b4\ub5a0\ud55c \ubc95\uc801 \ubcf4\ud638\ub3c4 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc9c0\uce68\uc740 \uc624\uc9c1 \ub3c4\ub355\uc801 \ubb38\uc81c\uc77c \ubfd0 \ubc95\uc801 \ubb38\uc81c\uac00 \uc544\ub2c8\ub2e4"],t.s)
B.S1=s([u.s8],t.s)
