B.ai8=new A.c("gen_ta_distinct_2","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uae08\uc9c0\ud589\uc704\uc640 \uac1c\ubcc4\uc0ac\uc5c5\uc790 \ud589\uc704\uc758 \uad6c\ubcc4","\uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \uc774\ub97c \ub2ec\uc131\ud558\uc9c0 \ubabb\ud558\uba74 \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\uaca0\ub2e4\uace0 \ud55c \uacbd\uc6b0, \uc774\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.To,0,'\ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0 \ub300\ud574 \ud589\ud558\ub294 \uac83\uc73c\ub85c, \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc758 \ud558\uc704 \uc720\ud615\uc778 "\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c"\ub85c \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc774\ub7ec\ud55c \ud589\uc704\ub97c \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \ud558\ub3c4\ub85d \uc720\ub3c4\xb7\ubc29\uc870\ud588\ub2e4\uba74 \ubcc4\ub3c4\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub3c4 \ud568\uaed8 \ubb38\uc81c\ub420 \uc218 \uc788\uc9c0\ub9cc, \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ub2e8\ub3c5 \ud589\uc704 \uc790\uccb4\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.VI,B.Vq,null)
B.O6=s([u.vE,"\ub450 \uaddc\uc815\uc740 \uc808\ub300 \ub3d9\uc2dc\uc5d0 \uc801\uc6a9\ub420 \uc218 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uac00 \uc131\ub9bd\ud558\uba74 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\ub294 \uc790\ub3d9\uc73c\ub85c \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4","\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub294 \uace0\ub824\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\ub450 \uaddc\uc815\uc740 \uc11c\ub85c \uc644\uc804\ud788 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uc0ac\uc548\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
