B.arM=new A.c("gen_ta_distinct_3","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uae08\uc9c0\ud589\uc704\uc640 \uac1c\ubcc4\uc0ac\uc5c5\uc790 \ud589\uc704\uc758 \uad6c\ubcc4","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc640 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \uac04 \ub2f4\ud569)\uac00 \ud558\ub098\uc758 \uc0ac\uc548\uc5d0\uc11c \ub3d9\uc2dc\uc5d0 \ubb38\uc81c\ub420 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.O6,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uac00\uaca9 \ub2f4\ud569 \ub4f1\uc744 \uacb0\uc758\ud558\uace0 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc774 \uc774\ub97c \uc2e4\uc81c\ub85c \uc2e4\ud589\ud558\ub294 \ud569\uc758\uae4c\uc9c0 \uc774\ub8e8\uc5b4\uc9c4 \uc0ac\uc548\uc5d0\uc11c\ub294, \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uaddc\uc815\uacfc \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uaddc\uc815\uc774 \ud568\uaed8 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4. \ub450 \uaddc\uc815\uc740 \ud589\uc704 \uc8fc\uccb4\ub97c \ub2ec\ub9ac\ud558\uc5ec \ubcd1\ud589 \uc801\uc6a9\ub420 \uc218 \uc788\ub294 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.Qw,B.a_o,null)
B.a6W=s([u.hp,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uac1c\ucd5c\ud558\ub294 \ubaa8\ub4e0 \ud589\uc0ac\ub294 \uc608\uc678 \uc5c6\uc774 \uaddc\uc81c \ub300\uc0c1\uc774 \ub41c\ub2e4","\uce5c\ubaa9\ud589\uc0ac\ub294 \ud56d\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub85c \uac04\uc8fc\ub41c\ub2e4","\uce5c\ubaa9\ud589\uc0ac \uac1c\ucd5c\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc124\ub9bd \uc790\uccb4\ub97c \uc704\ubc95\ud558\uac8c \ub9cc\ub4e0\ub2e4","\uce5c\ubaa9\ud589\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc774 \ud544\uc694\ud558\ub2e4"],t.s)
