B.aiC=new A.c("gen_ta_distinct_4","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uae08\uc9c0\ud589\uc704\uc640 \uac1c\ubcc4\uc0ac\uc5c5\uc790 \ud589\uc704\uc758 \uad6c\ubcc4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ub2e8\uc21c\ud788 \uce5c\ubaa9 \ub3c4\ubaa8\ub97c \uc704\ud55c \ud589\uc0ac\ub97c \uac1c\ucd5c\ud558\ub294 \uac83\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a6W,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub294 \uacbd\uc7c1\uc81c\ud55c, \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c, \uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c, \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ub3c4\xb7\ubc29\uc870 \ub4f1 \ud2b9\uc815\ud55c \uacbd\uc7c1\uc81c\ud55c\uc801 \ud6a8\uacfc\ub97c \ub0b3\ub294 \ud589\uc704\ub97c \uaddc\uc728\ud558\ub294 \uac83\uc774\ubbc0\ub85c, \uadf8\ub7ec\ud55c \uc694\uc18c\uac00 \uc804\ud600 \uc5c6\ub294 \uc21c\uc218\ud55c \uce5c\ubaa9\ud589\uc0ac \uac1c\ucd5c \uc790\uccb4\ub294 \ud1b5\uc0c1 \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4. \ub2e4\ub9cc \uce5c\ubaa9\ud589\uc0ac\ub97c \ube59\uc790\ud558\uc5ec \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\uaca9\xb7\ubb3c\ub7c9 \ub4f1\uc5d0 \uad00\ud55c \uc815\ubcf4\uad50\ud658\uc774\ub098 \ub2f4\ud569\uc774 \uc774\ub8e8\uc5b4\uc9c4\ub2e4\uba74 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.a85,B.a_B,null)
B.Ia=s([u.gl,"\uc5c5\uacc4 \ud45c\uc900 \uc81c\uc815\uc740 \uadf8 \uc790\uccb4\ub85c \ud56d\uc0c1 \uc704\ubc95\ud55c \uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c \ud589\uc704\uc774\ub2e4","\ud45c\uc900 \uc81c\uc815\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uad8c\ud55c \ubc16\uc758 \ud589\uc704\ub85c\uc11c \uc560\ucd08\uc5d0 \ubb34\ud6a8\uc774\ub2e4","\ud45c\uc900 \uc900\uc218 \uad8c\uc7a5\uc740 \uac15\uc81c\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub85c \uac04\uc8fc\ub41c\ub2e4","\uc5c5\uacc4 \ud45c\uc900\uc740 \ubc18\ub4dc\uc2dc \ubc95\ub960\ub85c\ub9cc \uc81c\uc815\ub420 \uc218 \uc788\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uad00\uc5ec\ud560 \uc218 \uc5c6\ub2e4"],t.s)
