B.ap8=new A.c("gen_ta_distinct_5","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uae08\uc9c0\ud589\uc704\uc640 \uac1c\ubcc4\uc0ac\uc5c5\uc790 \ud589\uc704\uc758 \uad6c\ubcc4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc5c5\uacc4 \ud45c\uc900(\uaddc\uaca9)\uc744 \uc81c\uc815\ud558\uc5ec \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \uc900\uc218\ub97c \uad8c\uc7a5\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Ia,0,"\ud488\uc9c8\xb7\uc548\uc804 \ub4f1\uc744 \uc704\ud55c \ud569\ub9ac\uc801 \uc5c5\uacc4\ud45c\uc900 \uc81c\uc815\uacfc \uadf8 \uc900\uc218 \uad8c\uc7a5\uc740 \uadf8 \uc790\uccb4\ub85c \ud1b5\uc0c1 \uacbd\uc7c1\uc81c\ud55c\uc801\uc774\ub77c\uace0 \ubcf4\uae30 \uc5b4\ub835\ub2e4. \ub2e4\ub9cc \ud45c\uc900\uc744 \uba85\ubaa9\uc73c\ub85c \uc2e0\uaddc \uc0ac\uc5c5\uc790\uc758 \uc9c4\uc785\uc744 \ubd80\ub2f9\ud558\uac8c \uc5b4\ub835\uac8c \ub9cc\ub4e4\uac70\ub098 \ud2b9\uc815 \uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\ub294 \uc218\ub2e8\uc73c\ub85c \ub0a8\uc6a9\ub41c\ub2e4\uba74, \uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\uc774\ub098 \uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c \ub4f1 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.UO,B.UJ,null)
B.a60=s(["\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc","\uc704\ubc18\ud589\uc704\uc5d0 \uad00\uc5ec\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ubcc4\ub3c4\uc758 \uc2dc\uc815\uc870\uce58","\uc704\ubc18\uc0ac\uc2e4\uc758 \uacf5\ud45c \uba85\ub839","\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uac15\uc81c \ud574\uc0b0 \uba85\ub839\uc744 \ud56d\uc0c1 \uc6b0\uc120\uc801\uc73c\ub85c \ubc1c\ub3d9","\uc704\ubc18\ud589\uc704\uc758 \uc911\uc9c0 \uba85\ub839"],t.s)
