B.akS=new A.c("gen_ta_sanction_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ub300\ud574 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.a60,3,"\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub294 \uc2dc\uc815\uc870\uce58, \uacfc\uc9d5\uae08 \ubd80\uacfc, \uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c, \uc704\ubc18\ud589\uc704 \uc911\uc9c0\uba85\ub839 \ub4f1\uc774 \ud65c\uc6a9\ub418\uba70, \uc704\ubc18\ud589\uc704\uc5d0 \uad00\uc5ec\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ubcc4\ub3c4\uc758 \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c8 \uc218 \uc788\ub2e4. \ubc18\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uac15\uc81c \ud574\uc0b0\uc740 \ud1b5\uc0c1\uc801\uc778 \uc6b0\uc120\uc801 \uc81c\uc7ac\uc218\ub2e8\uc774 \uc544\ub2c8\uba70, \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ud1b5\uc0c1\uc758 \uc81c\uc7ac\ub85c \ub300\uc751\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4.",B.U1,B.abt,null)
B.Th=s([u.z,"\uacfc\uc9d5\uae08\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \ubd80\uacfc\ub418\uace0 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubd80\uacfc\ub420 \uc218 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ubc95\uc778\uaca9\uc774 \uc5c6\uc73c\ubbc0\ub85c \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc5c6\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc7ac\uc0b0\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc815\uc561\uc73c\ub85c\ub9cc \ubd80\uacfc\ub41c\ub2e4","\uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ud310\uacb0\uc774 \ud655\uc815\ub41c \uc774\ud6c4\uc5d0\ub9cc \uac00\ub2a5\ud558\ub2e4"],t.s)
