B.anp=new A.c("gen_ta_sanction_2","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704 \uc704\ubc18\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08 \ubd80\uacfc\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Th,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704 \uc704\ubc18\uc5d0 \ub300\ud574 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc790\uccb4\uc5d0 \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \ud55c\ud3b8, \uc704\ubc18\ud589\uc704\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\ub2f4\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ubcc4\ub3c4\ub85c \uacfc\uc9d5\uae08 \ub4f1 \uc81c\uc7ac\ub97c \ubd80\uacfc\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ubc95\uc778\uaca9\uc774 \uc5c6\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \uc77c\uc815\ud55c \uc694\uac74 \ud558\uc5d0 \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.a6y,B.SB,null)
B.a5K=s(["\ud574\ub2f9 \uacb0\uc758\ub098 \uc9c0\uce68\uc758 \ucde8\uc18c \uba85\ub839","\uc704\ubc18\ud589\uc704\uc758 \uc911\uc9c0 \uba85\ub839","\uc704\ubc18\uc0ac\uc2e4\uc758 \uacf5\ud45c \uba85\ub839","\uc7ac\ubc1c\ubc29\uc9c0\ub97c \uc704\ud55c \uc870\uce58 \uba85\ub839","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc784\uc9c1\uc6d0 \uac1c\uc778\uc5d0 \ub300\ud55c \uc2e0\uccb4\uc758 \uc790\uc720 \uc81c\ud55c"],t.s)
