B.ahe=new A.c("gen_ta_sanction_3","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\uc758 \ub0b4\uc6a9\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud558\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a5K,4,'\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\uc5d0\ub294 \uc704\ubc95\ud55c \uacb0\uc758\xb7\uc9c0\uce68\uc758 \ucde8\uc18c, \ud589\uc704\uc758 \uc911\uc9c0, \uc704\ubc18\uc0ac\uc2e4\uc758 \uacf5\ud45c, \uc7ac\ubc1c\ubc29\uc9c0\ub97c \uc704\ud55c \uc870\uce58 \ub4f1\uc774 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4. "\uc784\uc9c1\uc6d0 \uac1c\uc778\uc5d0 \ub300\ud55c \uc2e0\uccb4\uc758 \uc790\uc720 \uc81c\ud55c"\uacfc \uac19\uc740 \uc870\uce58\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\uc801 \uc2dc\uc815\uc870\uce58\uc758 \ubc94\uc704\ub97c \ubc97\uc5b4\ub098\ub294 \uac83\uc73c\ub85c, \uc774\ub294 \ud615\uc0ac\uc808\ucc28\uc5d0\uc11c \ubc95\uc6d0\uc774 \uad00\uc5ec\ud560 \ubb38\uc81c\uc774\uc9c0 \uc2dc\uc815\uc870\uce58\uc758 \ub0b4\uc6a9\uc774 \ub420 \uc218 \uc5c6\ub2e4.',B.Ue,B.a9g,null)
B.Qh=s([u.O,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud574\uc11c\ub294 \uc5b4\ub5a0\ud55c \uc870\uc0ac\ub3c4 \uc9c4\ud589\ud560 \uc218 \uc5c6\ub2e4","\uc870\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uad6c\uc131\uc0ac\uc5c5\uc790 \uc804\uc6d0\uc758 \ub3d9\uc758\uac00 \uc788\uc5b4\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc870\uc0ac\uc5d0 \uc804\ud600 \ud611\uc870\ud560 \uc758\ubb34\uac00 \uc5c6\ub2e4","\uc870\uc0ac \uacb0\uacfc\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c4\ub2e4"],t.s)
