B.aiK=new A.c("gen_ta_sanction_4","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc870\uc0ac \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Qh,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub3c4 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud558\uac70\ub098, \uc774\ud574\uad00\uacc4\uc778\uc758 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c \uc870\uc0ac\ub97c \uc9c4\ud589\ud560 \uc218 \uc788\ub2e4. \uc870\uc0ac\uc5d0 \uad6c\uc131\uc0ac\uc5c5\uc790 \uc804\uc6d0\uc758 \ub3d9\uc758\uac00 \ud544\uc694\ud55c \uac83\uc740 \uc544\ub2c8\uba70, \uc870\uc0ac \uacb0\uacfc \uc704\ubc18\uc0ac\uc2e4\uc774 \uc778\uc815\ub418\uc9c0 \uc54a\uc73c\uba74 \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c0\uc9c0 \uc54a\uc744 \uc218\ub3c4 \uc788\ub2e4.",B.abT,B.a_V,null)
B.a4b=s(["\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud560 \uc218 \uc788\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud560 \uc218 \uc5c6\ub2e4","\ubd88\ubcf5\uc740 \uc624\uc9c1 \uad6c\uc131\uc0ac\uc5c5\uc790 \uac1c\uc778\ub9cc \uc81c\uae30\ud560 \uc218 \uc788\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ubd88\ubcf5\ud560 \uc218 \uc5c6\ub2e4","\ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc740 \ud615\uc0ac\uc7ac\ud310\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\ubd88\ubcf5\uc808\ucc28\ub294 \uc815\ubd80\uc758 \uc7ac\ub7c9\uc73c\ub85c \uc644\uc804\ud788 \ubc30\uc81c\ub420 \uc218 \uc788\ub2e4"],t.s)
B.Tb=s(["\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud560 \uc218 \uc788\ub2e4"],t.s)
B.ahW=new A.c("gen_ta_sanction_5","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a4b,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08 \ucc98\ubd84\uc5d0 \uc774\uc758\uac00 \uc788\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294, \ub2e4\ub978 \uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18 \ucc98\ubd84\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1\uc744 \ud1b5\ud574 \uadf8 \ucc98\ubd84\uc758 \ucde8\uc18c\xb7\ubcc0\uacbd\uc744 \uad6c\ud560 \uc218 \uc788\ub2e4.",B.Tb,B.nY,null)
B.a5i=s([u.aj,"\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \ucc45\uc784\uc744 \ubb3b\ub294 \uac83\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ucc45\uc784\uc744 \uc644\uc804\ud788 \ub300\uccb4\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ucc45\uc784 \ucd94\uad81\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc81c\ub3c4\uc758 \uc2e4\ud6a8\uc131\uacfc \ubb34\uad00\ud558\ub2e4","\uc774\ub294 \uc624\ub85c\uc9c0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc7ac\uc815 \ubd80\ub2f4\uc744 \uc904\uc774\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uad6c\uc131\uc0ac\uc5c5\uc790 \ucc45\uc784\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud574\uc0b0\ub41c \uacbd\uc6b0\uc5d0\ub9cc \ubb38\uc81c\ub41c\ub2e4"],t.s)
B.Z7=s([u.aj],t.s)
B.a8_=s(["\uad6c\uc131\uc0ac\uc5c5\uc790 \ucc45\uc784 \ucd94\uad81\uc758 \ucde8\uc9c0"],t.s)
B.aif=new A.c("gen_ta_sanction_6","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uaddc\uc81c\uc758 \uc2e4\ud6a8\uc131\uc744 \ub192\uc774\uae30 \uc704\ud574 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ucc45\uc784\uc744 \ubb3c\uc744 \uc218 \uc788\ub3c4\ub85d \ud55c \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a5i,0,"\uc704\ubc18\ud589\uc704\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \uad00\uc5ec\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ucc45\uc784\uc744 \ubb3c\uc744 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uac83\uc740, \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub77c\ub294 \uc870\uc9c1\uc758 \ud615\uc2dd \ub4a4\uc5d0 \uc228\uc5b4 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uc790\uc2e0\uc758 \ucc45\uc784\uc744 \ud68c\ud53c\ud558\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uace0, \uc2e4\uc9c8\uc801\uc778 \uc704\ubc18\ud589\uc704\uc790\uc5d0\uac8c \uc0c1\uc751\ud558\ub294 \ucc45\uc784\uc744 \ubd80\uacfc\ud568\uc73c\ub85c\uc368 \uaddc\uc81c\uc758 \uc2e4\ud6a8\uc131\uc744 \ub192\uc774\uae30 \uc704\ud55c \ucde8\uc9c0\ub85c \uc774\ud574\ub41c\ub2e4.",B.Z7,B.a8_,null)
B.a_a=s(["\uc0ac\uc5c5\uc790\uac00 \uc0c1\ud488\uc744 \uac70\ub798\ud558\uba70 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud558\uc5ec \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\ub294 \ud589\uc704\ub294 \uad6c\uc18d\ub825 \uc5ec\ubd80\uc640 \uc0c1\uad00\uc5c6\uc774 \ud56d\uc0c1 \uae08\uc9c0\ub41c\ub2e4","\uc800\uc791\uad8c\ubc95\uc0c1 \uc800\uc791\ubb3c\ub85c\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc0c1\ud488\uc758 \uacbd\uc6b0 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub420 \uc218 \uc788\ub2e4","\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uc5b4\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uae08\uc9c0\ub294 \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uac15\uc81c\ub825 \uc5c6\ub294 \ud76c\ub9dd\uac00\uaca9\uc744 \uc81c\uc2dc\ud558\ub294 \ud589\uc704\ub3c4 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \uae08\uc9c0\ub41c\ub2e4"],t.s)
B.a43=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc804\uc790\ucd9c\ud310\ubb3c \ub4f1\uc5d0 \ub300\ud574\uc11c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub41c\ub2e4"],t.s)
