B.arO=new A.c("gen_rp_1","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.a_a,1,'\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud574 \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\uac70\ub098 \uad6c\uc18d\uc870\uac74\uc744 \ubd99\uc774\ub294 \ud589\uc704\ub85c \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub41c\ub2e4(\uacf5\uc815\uac70\ub798\ubc95 \uc81c46\uc870). \ub2e4\ub9cc \uc608\uc678\uc801\uc73c\ub85c \u300c\uc800\uc791\uad8c\ubc95\u300d\uc0c1 \uc800\uc791\ubb3c \uc911 \uad00\uacc4 \uc911\uc559\ud589\uc815\uae30\uad00\uc758 \uc7a5\uacfc \ud611\uc758\ub97c \uac70\uccd0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc804\uc790\ucd9c\ud310\ubb3c \ub4f1\uc5d0 \ub300\ud574\uc11c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub41c\ub2e4. \ubc18\uba74 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub3c4 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc788\uc73c\uba74 \ud5c8\uc6a9\ub420 \uc218 \uc788\uace0(\uc120\ud0dd\uc9c0 \u2462\uc740 \uc624\ub2f5), \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc0c1\ud488\ubfd0 \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub3c4 \uc801\uc6a9\ub418\uba70(\uc120\ud0dd\uc9c0 \u2463\ub294 \uc624\ub2f5), \uac15\uc81c\ub825 \uc5c6\ub294 \ub2e8\uc21c \ud76c\ub9dd\uac00\uaca9 \uc81c\uc2dc\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4(\uc120\ud0dd\uc9c0 \u2464\ub294 \uc624\ub2f5)\ub294 \uc810\ub3c4 \ud568\uaed8 \uc815\ub9ac\ud574\uc57c \ud55c\ub2e4.',B.a43,B.PH,null)
B.Tx=s([u.DM,"\uc0ac\uc5c5\uc790\uac00 \uc18c\ube44\uc790\uc5d0\uac8c \ub2e8\uc21c\ud788 \uad8c\uc7a5\uc18c\ube44\uc790\uac00\uaca9\uc744 \uc54c\ub824\uc8fc\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc790\uc2e0\uc758 \uc0c1\ud488 \uac00\uaca9\uc744 \uc2a4\uc2a4\ub85c \uc778\uc0c1\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac00\uaca9\uc815\ubcf4\ub97c \uad50\ud658\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc815\ubd80\uc5d0 \uac00\uaca9 \uc778\uac00\ub97c \uc2e0\uccad\ud558\ub294 \ud589\uc704"],t.s)
B.Vr=s([u.DM],t.s)
