B.alJ=new A.c("gen_rpm_def_1","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\uc758\xb7\uc131\ub9bd\uc694\uac74","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \uc815\uc758\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Tx,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc778 \uc0ac\uc5c5\uc790 \ub610\ub294 \uadf8 \ub2e4\uc74c \uac70\ub798\ub2e8\uacc4\uc758 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\ud560 \ub54c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud558\uc5ec \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\xb7\uc81c\uacf5\ud558\ub3c4\ub85d \uac15\uc81c\ud558\uac70\ub098 \uad6c\uc18d\uc870\uac74\uc744 \ubd99\uc5ec \uac70\ub798\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \ub2e8\uc21c\ud55c \uad8c\uc7a5\uac00\uaca9 \uc81c\uc2dc\ub098 \uc0ac\uc5c5\uc790 \uc790\uc2e0\uc758 \uac00\uaca9 \uacb0\uc815 \ud589\uc704\ub294 \uc774\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.Vr,B.a3v,null)
