B.a8u=s([u.v2,"\ud56d\uc0c1 \uc18c\ube44\uc790\uac00\uaca9\uc744 \uc778\uc0c1\uc2dc\ud0a4\ub294 \ud6a8\uacfc\ub9cc \uac00\uc838\uc628\ub2e4","\uc720\ud1b5\uc5c5\uc790\uc758 \uc774\uc724\uc744 \ud56d\uc0c1 \uadf9\ub300\ud654\uc2dc\ud0a4\ub294 \ud6a8\uacfc\ub9cc \uac00\uc838\uc628\ub2e4","\uc18c\ube44\uc790 \ud6c4\uc0dd\uacfc\ub294 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc624\uc9c1 \uc81c\uc870\uc5c5\uc790\uc758 \uc774\uc724\ub9cc \uac10\uc18c\uc2dc\ud0a8\ub2e4"],t.s)
