B.amH=new A.c("gen_rpm_type_2","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ucd5c\uace0\xb7\ucd5c\uc800 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\uc758 \uad6c\ubcc4","\ucd5c\uace0\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \uc18c\ube44\uc790\uc5d0\uac8c \ubbf8\uce60 \uc218 \uc788\ub294 \uae0d\uc815\uc801 \ud6a8\uacfc\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a8u,0,"\ucd5c\uace0\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704(\uac00\uaca9\uc744 \uc77c\uc815 \uc218\uc900 \uc774\uc0c1\uc73c\ub85c \uc62c\ub9ac\uc9c0 \ubabb\ud558\uac8c \ud558\ub294 \ud589\uc704)\ub294 \uacbd\uc6b0\uc5d0 \ub530\ub77c \uc720\ud1b5\uc5c5\uc790\uc758 \uc9c0\ub098\uce5c \uac00\uaca9 \uc778\uc0c1\uc744 \uc5b5\uc81c\ud558\uc5ec \uc18c\ube44\uc790\uac00\uaca9\uc744 \ub0ae\ucd94\ub294 \ud6a8\uacfc\ub97c \uac00\uc838\uc62c \uc218 \uc788\ub2e4\ub294 \uc810\uc5d0\uc11c, \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640\ub294 \ub2e4\ub978 \uc815\ucc45\uc801 \ud3c9\uac00\ub97c \ubc1b\ub294\ub2e4.",B.a7X,B.HW,null)
B.a7k=s(["\uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub418\ub294 \uc704\ubc95\ud55c \ud589\uc704\ub85c \ucde8\uae09\ub41c\ub2e4","\uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud569\ubc95\uc801\uc778 \ud589\uc704\ub85c \ucde8\uae09\ub41c\ub2e4","\ud56d\uc0c1 \uc18c\ube44\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\ubbc0\ub85c \uc7a5\ub824\ub41c\ub2e4","\uc624\uc9c1 \uad8c\uace0\uc0ac\ud56d\uc5d0 \ubd88\uacfc\ud558\uc5ec \uc81c\uc7ac \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\ucd5c\uace0\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uac8c \ucde8\uae09\ub418\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4"],t.s)
