B.ajv=new A.c("gen_rpm_type_4","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ucd5c\uace0\xb7\ucd5c\uc800 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\uc758 \uad6c\ubcc4","\uc628\ub77c\uc778 \uc624\ud508\ub9c8\ucf13\uc5d0\uc11c \ucd5c\uc800\ud310\ub9e4\uac00\ub97c \uc9c0\uc815\ud558\uace0 \uc774\ub97c \uc5b4\uae34 \ud310\ub9e4\uc790\uc5d0\uac8c \uc785\uc810 \uc81c\ud55c \ub4f1 \ubd88\uc774\uc775\uc744 \uac00\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1U,0,"\uc628\ub77c\uc778 \uc624\ud508\ub9c8\ucf13\uc5d0\uc11c \ucd5c\uc800\ud310\ub9e4\uac00\ub97c \uc9c0\uc815\ud558\uace0 \uc774\ub97c \uc900\uc218\ud558\uc9c0 \uc54a\ub294 \ud310\ub9e4\uc790\uc5d0\uac8c \uc785\uc810 \uc81c\ud55c \ub4f1 \ubd88\uc774\uc775\uc744 \uac00\ud558\ub294 \ud589\uc704\ub294 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud560 \uac00\ub2a5\uc131\uc774 \uc788\uc73c\uba70, \uc774 \uacbd\uc6b0 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\ub294\uc9c0 \uc5ec\ubd80\uac00 \uc704\ubc95\uc131 \ud310\ub2e8\uc758 \ud575\uc2ec \uc7c1\uc810\uc774 \ub41c\ub2e4.",B.a2M,B.T0,null)
B.HB=s([u.Z,"\uad6c\uc18d\uc870\uac74\uc758 \uc874\uc7ac \uc5ec\ubd80\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uad6c\uc18d\uc870\uac74\uc774 \uc788\uc5b4\ub3c4 \ud56d\uc0c1 \uc801\ubc95\ud55c \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uad6c\uc18d\uc870\uac74\uc774 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \uc704\ubc95\ud55c \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uad6c\uc18d\uc870\uac74\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\ub9cc \uacb0\uc815\ud55c\ub2e4"],t.s)
