B.anj=new A.c("gen_rpm_type_5","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ucd5c\uace0\xb7\ucd5c\uc800 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\uc758 \uad6c\ubcc4",'\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\uc5d0\uc11c "\uad6c\uc18d\uc870\uac74"\uc758 \uc874\uc7ac \uc5ec\ubd80\uac00 \uac16\ub294 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.HB,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\uc5d0\uc11c\ub294 \uc0ac\uc5c5\uc790\uac00 \uc815\ud55c \uac00\uaca9\uc744 \ub530\ub974\uc9c0 \uc54a\uc744 \uacbd\uc6b0 \uac70\ub798 \uc911\ub2e8\uc774\ub098 \uacf5\uae09 \uc81c\ud55c \ub4f1 \ubd88\uc774\uc775\uc774 \uac00\ud574\uc9c0\ub294 \uad6c\uc18d\uc870\uac74\uc774 \uc788\ub294\uc9c0 \uc5ec\ubd80\uac00 \uc704\ubc95\uc131 \ud310\ub2e8\uc758 \ud575\uc2ec \uc694\uc18c\uac00 \ub418\uba70, \uc774\ub7ec\ud55c \uad6c\uc18d\ub825\uc774 \uc5c6\ub2e4\uba74 \ub2e8\uc21c \ud76c\ub9dd\uac00\uaca9 \uc81c\uc2dc\uc5d0 \uadf8\uccd0 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4.",B.Ou,B.T8,null)
B.a3B=s([u.oz,"\uac00\ub9f9 \uad00\uacc4\uc5d0\uc11c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\uac00 \uc804\ud600 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774\ub7ec\ud55c \ud1b5\ubcf4\ub294 \uac00\ub9f9\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc624\uc9c1 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub85c\ub9cc \ud3c9\uac00\ub41c\ub2e4","\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640 \ubb34\uad00\ud55c \ub2e8\uc21c \uacbd\uc601\uc9c0\ub3c4\uc774\ub2e4"],t.s)
