B.Sx=s([u.tu,"\uc800\uc791\ubb3c\uc740 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\uc640 \uc804\ud600 \ubb34\uad00\ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uc800\uc791\ubb3c\uc740 \ud56d\uc0c1 \uac00\uaca9\uc744 \ubb34\ub8cc\ub85c \ud574\uc57c \ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uc800\uc791\uad8c\uc790\ub97c \ucc98\ubc8c\ud558\uae30 \uc704\ud55c \uaddc\uc815\uc774\ub2e4","\uc800\uc791\ubb3c \uc720\ud1b5\uc5c5\uc790\ub97c \ud56d\uc0c1 \ubd88\ub9ac\ud558\uac8c \ud558\uae30 \uc704\ud55c \uaddc\uc815\uc774\ub2e4"],t.s)
