B.Uc=s([u.v5,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c \uaddc\ubaa8\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \uac1c\uc778\uc801 \uc758\uacac\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uad6d\uc801\ub9cc \uace0\ub824\ud55c\ub2e4","\uc815\ub2f9\ud55c \uc774\uc720 \ud310\ub2e8\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
