B.Rz=s([u.mI,"\uc815\ub2f9\ud55c \uc774\uc720\uc758 \uc99d\uba85\ucc45\uc784\uc740 \ud56d\uc0c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ubd80\ub2f4\ud55c\ub2e4","\uc815\ub2f9\ud55c \uc774\uc720\ub294 \uc99d\uba85\ud560 \ud544\uc694\uac00 \uc804\ud600 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uc815\ub2f9\ud55c \uc774\uc720\uc758 \uc99d\uba85\ucc45\uc784\uc740 \uc18c\ube44\uc790\ub2e8\uccb4\uac00 \ubd80\ub2f4\ud55c\ub2e4","\uc815\ub2f9\ud55c \uc774\uc720\ub294 \ubc95\uc6d0\uc774 \uc9c1\uad8c\uc73c\ub85c\ub9cc \ud310\ub2e8\ud55c\ub2e4"],t.s)
