B.Yk=s([u.wP,"\ubb34\uc784\uc2b9\ucc28 \ubb38\uc81c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubb34\uc784\uc2b9\ucc28 \ubc29\uc9c0\ub294 \uc624\uc9c1 \ucd5c\uace0\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0\uc11c\ub9cc \ub17c\uc758\ub41c\ub2e4","\ubb34\uc784\uc2b9\ucc28 \ubc29\uc9c0\ub294 \uc5b8\uc81c\ub098 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \uc815\ub2f9\ud654\ud558\ub294 \uc808\ub300\uc801 \uc0ac\uc720\uc774\ub2e4","\ubb34\uc784\uc2b9\ucc28\ub294 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \ucc45\uc784\uc774 \uc788\ub294 \ubb38\uc81c\uc774\ub2e4"],t.s)
