B.ahN=new A.c("gen_rpm_exception_5","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720\xb7\uc608\uc678","\ube0c\ub79c\ub4dc \ub0b4 \uc11c\ube44\uc2a4 \uacbd\uc7c1(\ubb34\uc784\uc2b9\ucc28 \ubc29\uc9c0)\uc774 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \uc815\ub2f9\ud654 \uc0ac\uc720\ub85c \ub17c\uc758\ub418\ub294 \ub9e5\ub77d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Yk,0,"\uc77c\ubd80 \uc720\ud1b5\uc5c5\uc790\uac00 \ud310\ub9e4 \uc804 \uc0c1\ub2f4\xb7\uc804\uc2dc \ub4f1 \uc11c\ube44\uc2a4\uc5d0 \ud22c\uc790\ud558\uc9c0 \uc54a\uace0 \uac00\uaca9\ub9cc \ub0ae\ucdb0 \ud310\ub9e4\ud568\uc73c\ub85c\uc368, \uc11c\ube44\uc2a4\ub97c \uc81c\uacf5\ud558\ub294 \ub2e4\ub978 \uc720\ud1b5\uc5c5\uc790\uc758 \ub178\ub825\uc5d0 \ubb34\uc784\uc2b9\ucc28\ud558\ub294 \ubb38\uc81c\ub97c \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \ubaa9\uc801\uc774 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \uc815\ub2f9\ud654 \uc0ac\uc720\ub85c \ub17c\uc758\ub418\ub294 \ub300\ud45c\uc801\uc778 \ub9e5\ub77d\uc774\ub2e4. \ub2e4\ub9cc \uc774\uac83\uc774 \ud56d\uc0c1 \uc808\ub300\uc801\uc73c\ub85c \uc815\ub2f9\ud654\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uace0 \uc885\ud569\uc801 \ud615\ub7c9\uc758 \ud55c \uc694\uc18c\ub85c \uace0\ub824\ub41c\ub2e4.",B.SY,B.JS,null)
