B.Z_=s(["\uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \uc870\uce58\ub97c \ucde8\ud560 \uc218 \uc788\ub2e4","\uc5b4\ub5a0\ud55c \uc81c\uc7ac\ub3c4 \ud560 \uc218 \uc5c6\uace0 \uad8c\uace0\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \ud615\uc0ac\uace0\ubc1c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\ucc98\ubd84\uc740 \ubd88\uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \uc190\ud574\ubc30\uc0c1 \uc18c\uc1a1\uc744 \ub300\uc2e0 \uc81c\uae30\ud574\uc904 \uc218 \uc788\ub2e4","\uc704\ubc18 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\uc744 \uc989\uc2dc \ud3d0\uc1c4\ud574\uc57c \ud55c\ub2e4"],t.s)
