B.a9A=s([u.ds,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc124\ub9bd\uc5f0\ub3c4\ub9cc \uace0\ub824\ub41c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \ub098\uc774\ub9cc \uace0\ub824\ub41c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud56d\uc0c1 \uc815\uc561\uc73c\ub85c \uc77c\ub960\uc801\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4","\uacfc\uc9d5\uae08 \uc0b0\uc815\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
