B.aqI=new A.c("gen_sp_type_2","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uaddc\uc81c \ub300\uc0c1\xb7\ud589\uc704 \uc720\ud615",'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc758 \ud558\uc704 \uc720\ud615 \uc911 "\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc758 \uac70\ub798"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a3t,0,'"\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc758 \uac70\ub798"\ub294 \uc815\uc0c1\uc801\uc778 \uac70\ub798 \uad00\ud589\uc5d0\uc11c \uc801\uc6a9\ub418\ub294 \uc870\uac74(\uac00\uaca9, \uc774\uc790\uc728 \ub4f1)\uc5d0 \ube44\ud574 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ud604\uc800\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uae08\xb7\uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\ud568\uc73c\ub85c\uc368 \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \uc758\ubbf8\ud558\ub294 \uc0ac\uc775\ud3b8\ucde8 \uaddc\uc81c\uc758 \ub300\ud45c\uc801\uc778 \ud558\uc704 \uc720\ud615\uc774\ub2e4.',B.V0,B.N6,null)
B.Gy=s([u.d2,"\ud68c\uc0ac\uac00 \uc790\uccb4\uc801\uc73c\ub85c \uc0ac\uc5c5\uae30\ud68c\ub97c \uac1c\ubc1c\ud558\uc5ec \ud65c\uc6a9\ud558\ub294 \ud589\uc704","\uc678\ubd80 \uc0ac\uc5c5\uc790\uc640 \uacf5\uc815\ud55c \uc808\ucc28\ub97c \uac70\uccd0 \uc0ac\uc5c5 \uc81c\ud734\ub97c \ub9fa\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778\uc774 \uc544\ub2cc \uc790\uc5d0\uac8c \uc0ac\uc5c5 \uc815\ubcf4\ub97c \uacf5\uc720\ud558\ub294 \ud589\uc704","\ud68c\uc0ac\uac00 \uc815\ub2f9\ud55c \ub300\uac00\ub97c \ubc1b\uace0 \uc0ac\uc5c5\uad8c\uc744 \uc591\ub3c4\ud558\ub294 \ud589\uc704"],t.s)
B.JX=s([u.d2],t.s)
B.aaH=s(["\uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5\uc758 \uc758\ubbf8"],t.s)
B.ajS=new A.c("gen_sp_type_3","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uaddc\uc81c \ub300\uc0c1\xb7\ud589\uc704 \uc720\ud615",'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc758 \ud558\uc704 \uc720\ud615 \uc911 "\uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5"\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Gy,0,'"\uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5"\uc740 \ud68c\uc0ac\uac00 \uc2a4\uc2a4\ub85c \uc218\ud589\ud558\uc600\uc744 \uacbd\uc6b0 \uc0c1\ub2f9\ud55c \uc774\uc775\uc774 \ub420 \uac83\uc73c\ub85c \uc608\uc0c1\ub418\ub294 \uc0ac\uc5c5\uae30\ud68c\ub97c \uc815\ub2f9\ud55c \ub300\uac00 \uc5c6\uc774 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ub118\uaca8\uc8fc\uc5b4 \uadf8 \uc774\uc775\uc744 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \uc758\ubbf8\ud558\uba70, \ud68c\uc0ac\uc758 \uc774\uc775\uc744 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc720\ucd9c\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc0ac\uc775\ud3b8\ucde8 \uc720\ud615\uc774\ub2e4.',B.JX,B.aaH,null)
B.JG=s([u.g6,"\uc5ec\ub7ec \uc0ac\uc5c5\uc790\uc640 \uacf5\uc815\ud55c \uc785\ucc30\uc744 \uac70\uccd0 \ucd5c\uc801\uc758 \uac70\ub798\ucc98\ub97c \uc120\uc815\ud558\ub294 \ud589\uc704","\uac70\ub798 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ucd5c\uc800\uac00 \uc785\ucc30\uc790\uc640 \uac70\ub798\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778\uc774 \uc544\ub2cc \ud68c\uc0ac\uc640 \ub300\uaddc\ubaa8\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\uac70\ub798 \uaddc\ubaa8\ub97c \uc810\uc9c4\uc801\uc73c\ub85c \ucd95\uc18c\ud558\ub294 \ud589\uc704"],t.s)
B.Lf=s([u.g6],t.s)
B.a6k=s(["\uc77c\uac10\ubab0\uc544\uc8fc\uae30\uc758 \uc758\ubbf8"],t.s)
B.akl=new A.c("gen_sp_type_4","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uaddc\uc81c \ub300\uc0c1\xb7\ud589\uc704 \uc720\ud615",'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc758 \ud558\uc704 \uc720\ud615 \uc911 "\ud569\ub9ac\uc801 \uace0\ub824\ub098 \ube44\uad50 \uc5c6\uc774 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\ub85c \uac70\ub798"\ud558\ub294 \ud589\uc704(\uc77c\uac10\ubab0\uc544\uc8fc\uae30)\uc758 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.JG,0,'\uc774\ub978\ubc14 "\uc77c\uac10\ubab0\uc544\uc8fc\uae30"\ub85c \ubd88\ub9ac\ub294 \uc774 \uc720\ud615\uc740, \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc640\uc758 \uac00\uaca9\xb7\ud488\uc9c8\xb7\uae30\uc220\ub825 \ub4f1\uc5d0 \ub300\ud55c \ud569\ub9ac\uc801\uc778 \ube44\uad50\xb7\uac80\ud1a0 \uc5c6\uc774 \ud2b9\uc218\uad00\uacc4\uc778\uc774 \uc9c0\ubc30\ud558\ub294 \ud68c\uc0ac\uc5d0 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\uc758 \uac70\ub798\ub97c \ubab0\uc544\uc90c\uc73c\ub85c\uc368 \uadf8 \ud68c\uc0ac\uc5d0 \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \uc758\ubbf8\ud55c\ub2e4.',B.Lf,B.a6k,null)
B.LS=s([u.bN,"\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\ub294 \ub300\uae30\uc5c5\uc758 \uc815\uc0c1\uc801\uc778 \uacc4\uc5f4\uc0ac \uac04 \uac70\ub798 \uc790\uccb4\ub97c \uc804\uba74 \uae08\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uaddc\uc81c\ub294 \uc18c\uc561\uc8fc\uc8fc\uc758 \uc774\uc775\uacfc \uc804\ud600 \ubb34\uad00\ud55c \ubb38\uc81c\uc774\ub2e4","\uc774 \uaddc\uc81c\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\uc774 \uaddc\uc81c\ub294 \uc911\uc18c\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc81c\uc774\ub2e4"],t.s)
