B.an8=new A.c("gen_sp_type_5","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uaddc\uc81c \ub300\uc0c1\xb7\ud589\uc704 \uc720\ud615","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\uac00 \ud544\uc694\ud55c \uc815\ucc45\uc801 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.LS,0,'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\ub294, \ub300\uae30\uc5c5\uc9d1\ub2e8\uc758 \ucd1d\uc218 \uc77c\uac00\ub098 \uacc4\uc5f4\ud68c\uc0ac\uc5d0 \ubd80\ub2f9\ud55c \ubc29\ubc95\uc73c\ub85c \ubd80\ub97c \uc774\uc804\uc2dc\ucf1c \uacbd\uc81c\ub825 \uc9d1\uc911\uc744 \uc2ec\ud654\uc2dc\ud0a4\uace0, \uadf8 \uacfc\uc815\uc5d0\uc11c \uc18c\uc561\uc8fc\uc8fc \ub4f1 \ub2e4\ub978 \uc774\ud574\uad00\uacc4\uc790\uc758 \uc774\uc775\uc744 \uce68\ud574\ud558\ub294 \uc774\ub978\ubc14 "\uc0ac\uc775\ud3b8\ucde8" \ubb38\uc81c\ub97c \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uc815\ucc45\uc801 \ubaa9\uc801\uc744 \uac16\ub294\ub2e4.',B.acY,B.VF,null)
