B.Hk=s([u.Ew,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c \uaddc\ubaa8\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \ud2b9\uc218\uad00\uacc4\uc778 \uac1c\uc778\uc758 \ucde8\ubbf8\ub9cc \uace0\ub824\ud55c\ub2e4","\ubd80\ub2f9\uc131 \ud310\ub2e8\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \uac70\ub798\uac00 \uc774\ub8e8\uc5b4\uc9c4 \uc694\uc77c\ub9cc \uace0\ub824\ud55c\ub2e4"],t.s)
