B.apQ=new A.c("gen_sp_sanction_5","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc81c\uc7ac",'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\uc5d0\uc11c "\uc815\uc0c1\uc801\uc778 \uac70\ub798\uc5d0\uc11c \uc801\uc6a9\ub418\uc5c8\uc744 \uc870\uac74"\uc744 \ud310\ub2e8\ud558\ub294 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.VD,0,'"\uc815\uc0c1\uc801\uc778 \uac70\ub798\uc5d0\uc11c \uc801\uc6a9\ub418\uc5c8\uc744 \uc870\uac74"\uc744 \ud310\ub2e8\ud560 \ub54c\ub294, \uc720\uc0ac\ud55c \uc2dc\uae30\xb7\uaddc\ubaa8\xb7\uc870\uac74\uc758 \ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc0ac\ub840\ub098 \uc2dc\uc7a5\uc5d0\uc11c \ud615\uc131\ub41c \uac00\uaca9\xb7\uc774\uc790\uc728 \ub4f1\uc744 \ucc38\uace0\ud558\uc5ec \ubb38\uc81c\ub41c \uac70\ub798\uc870\uac74\uacfc \ube44\uad50\xb7\ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc778 \ubc29\uc2dd\uc774\ub2e4.',B.Te,B.GR,null)
