B.akU=new A.c("gen_sp_sanction_6","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc81c\uc7ac","\uc911\uc18c\uac00\ub9f9\ubcf8\ubd80\uac00 \ucd1d\uc218 \uc77c\uac00\uac00 \uc9c0\ubd84\uc744 \ubcf4\uc720\ud55c \ubb3c\ub958\ud68c\uc0ac\uc640 \ud569\ub9ac\uc801 \ube44\uad50 \uc5c6\uc774 \ub300\uaddc\ubaa8 \ubb3c\ub958\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.GK,0,"\uac00\ub9f9\ubcf8\ubd80\uac00 \ub2e4\ub978 \ubb3c\ub958\uc5c5\uccb4\uc640\uc758 \uac00\uaca9\xb7\uc11c\ube44\uc2a4 \ube44\uad50 \ub4f1 \ud569\ub9ac\uc801\uc778 \uac80\ud1a0 \uc5c6\uc774 \ucd1d\uc218 \uc77c\uac00\uac00 \uc9c0\ubd84\uc744 \ubcf4\uc720\ud55c \ubb3c\ub958\ud68c\uc0ac\uc640 \ub300\uaddc\ubaa8 \ubb3c\ub958\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \uacbd\uc6b0, \uc774\ub294 \uc77c\uac10\ubab0\uc544\uc8fc\uae30 \uc720\ud615\uc758 \ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc5d0 \ud574\ub2f9\ud560 \uc18c\uc9c0\uac00 \uc788\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.a2c,B.Mr,null)
B.Up=s([u.rn,"\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \uac1c\uc778 \uc2e0\uc0c1 \uc815\ubcf4\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uacfc \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc774 \ud30c\ud2b8 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ubb3c\ub958\ucc3d\uace0\uc758 \uc704\uce58\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
