B.ahX=new A.c("gen_sp_exam_1","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Up,0,'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uad00\ub828 \ubb38\uc81c\ub294 \uc720\ub9ac\ud55c \uc870\uac74\uc758 \uac70\ub798, \uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5, \uc77c\uac10\ubab0\uc544\uc8fc\uae30\ub77c\ub294 \ud558\uc704 \uc720\ud615\uc758 \uad6c\ubcc4\uacfc, \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\ub294 "\ud2b9\uc218\uad00\uacc4\uc778"\uc758 \ubc94\uc704(\ub3d9\uc77c\uc778, \uce5c\uc871, \uacc4\uc5f4\ud68c\uc0ac \ub4f1)\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.',B.RK,B.ba,null)
B.acN=s([u.vj,"\uac00\ub9f9\uacc4\uc57d\uc11c\uc758 \ud3f0\ud2b8 \ud06c\uae30\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uce35\uc218\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc704\uc6d0\uc7a5\uc758 \uac1c\uc778 \ucde8\ubbf8\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc2ec\uc0ac\uccad\uad6c \uc811\uc218 \ucc3d\uad6c\uc758 \uc8fc\uc18c\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0"],t.s)
B.a5S=s([u.vj],t.s)
B.akO=new A.c("gen_sp_exam_2","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uad00\ub828 \ubb38\uc81c\uc5d0\uc11c \uc790\uc8fc \ucd9c\uc81c\ub418\ub294 \ud568\uc815 \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.acN,0,'\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \ubb38\uc81c\uc5d0\uc11c\ub294 \ud2b9\uc218\uad00\uacc4\uc778\uacfc \ubb34\uad00\ud55c \uc77c\ubc18 \uc18c\ube44\uc790 \ub300\uc0c1 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\uc774\ub098 \uc81c3\uc790\uc640\uc758 \uc815\uc0c1\uc801\uc778 \uac70\ub798\ub97c \uaddc\uc81c \ub300\uc0c1\uc5d0 \ud3ec\ud568\uc2dc\ud0a4\ub294 \uc120\ud0dd\uc9c0\uac00 \ud568\uc815\uc73c\ub85c \uc790\uc8fc \ucd9c\uc81c\ub418\ubbc0\ub85c, \uaddc\uc81c \ub300\uc0c1\uc774 "\ud2b9\uc218\uad00\uacc4\uc778"\uc5d0\uac8c \uc774\uc775\uc774 \uadc0\uc18d\ub418\ub294 \uac70\ub798\uc5d0 \ud55c\uc815\ub41c\ub2e4\ub294 \uc810\uc744 \uc815\ud655\ud788 \uad6c\ubcc4\ud574 \ub450\uc5b4\uc57c \ud55c\ub2e4.',B.a5S,B.ct,null)
B.Z5=s([u.d9,"\uacc4\uc5f4\uc0ac \uac04 \uac70\ub798\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\ub294 \ud504\ub79c\ucc28\uc774\uc988 \uadf8\ub8f9\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uacc4\uc5f4\uc0ac\uc640\uc758 \uac70\ub798\ub294 \ube44\uad50\xb7\uac80\ud1a0 \uc5c6\uc774 \uc790\uc720\ub86d\uac8c \uc9c4\ud589\ud574\ub3c4 \ub41c\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc774 \uaddc\uc81c \uad00\ub828 \uc790\ubb38\uc740 \ud544\uc694\ud558\uc9c0 \uc54a\uc740 \uc0ac\ud56d\uc774\ub77c\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
B.UH=s([u.d9],t.s)
B.Ws=s(["\uacc4\uc5f4\uc0ac \uac70\ub798 \uc790\ubb38 \uc2dc \uc720\uc758\uc0ac\ud56d"],t.s)
B.aqY=new A.c("gen_sp_exam_3","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \ud504\ub79c\ucc28\uc774\uc988 \uadf8\ub8f9\uc758 \uacc4\uc5f4\uc0ac \uac04 \uac70\ub798\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Z5,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \ud504\ub79c\ucc28\uc774\uc988 \uadf8\ub8f9 \ub0b4 \uacc4\uc5f4\uc0ac \uac04 \uac70\ub798\ub97c \uc790\ubb38\ud560 \ub54c, \ucd1d\uc218 \uc77c\uac00\ub098 \ud2b9\uc218\uad00\uacc4\uc778\uc774 \uad00\ub828\ub41c \uacc4\uc5f4\uc0ac\uc640 \uac70\ub798\ud558\ub294 \uacbd\uc6b0 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc640\uc758 \uac00\uaca9\xb7\ud488\uc9c8 \ube44\uad50 \ub4f1 \ud569\ub9ac\uc801\uc778 \uac80\ud1a0 \uc808\ucc28\ub97c \uac70\uccd0 \uac70\ub798\uc758 \uc815\ub2f9\uc131\uc744 \ud655\ubcf4\ud558\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\ub294 \uc810\uc744 \uba85\ud655\ud788 \uc548\ub0b4\ud574\uc57c \ud55c\ub2e4.",B.UH,B.Ws,null)
B.RV=s([u.sB,"\uc911\uc18c\uae30\uc5c5\uc5d0\ub294 \ud2b9\uc218\uad00\uacc4\uc778\uc774\ub77c\ub294 \uac1c\ub150 \uc790\uccb4\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\uae30 \ub54c\ubb38\uc774\ub2e4","\ub300\uae30\uc5c5\uc9d1\ub2e8\ub9cc \uacc4\uc5f4\ud68c\uc0ac\ub97c \uac00\uc9c8 \uc218 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4","\uc774 \uaddc\uc81c\ub294 \ub300\uae30\uc5c5\uc9d1\ub2e8\uc744 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \uac83\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uc774 \uaddc\uc81c\ub294 \uc624\uc9c1 \uc0c1\uc7a5\ud68c\uc0ac\uc5d0\ub9cc \uc801\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
