B.aoo=new A.c("gen_sp_exam_4","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\uac00 \ub300\uae30\uc5c5\uc9d1\ub2e8(\uacf5\uc2dc\ub300\uc0c1\uae30\uc5c5\uc9d1\ub2e8 \ub4f1)\uc744 \uc8fc\ub41c \ub300\uc0c1\uc73c\ub85c \ud558\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.RV,0,"\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\uac00 \uc8fc\ub85c \ub300\uae30\uc5c5\uc9d1\ub2e8\uc744 \ub300\uc0c1\uc73c\ub85c \ub17c\uc758\ub418\ub294 \uac83\uc740, \ub2e4\uc218\uc758 \uacc4\uc5f4\ud68c\uc0ac\uc640 \ubcf5\uc7a1\ud55c \uc9c0\ubc30\uad6c\uc870\ub97c \uac00\uc9c4 \ub300\uae30\uc5c5\uc9d1\ub2e8\uc5d0\uc11c \ucd1d\uc218 \uc77c\uac00\ub85c\uc758 \ubd80\ub2f9\ud55c \ubd80\uc758 \uc774\uc804\uacfc \uacbd\uc81c\ub825 \uc9d1\uc911 \ubb38\uc81c\uac00 \uad6c\uc870\uc801\uc73c\ub85c \ubc1c\uc0dd\ud558\uae30 \uc27d\uae30 \ub54c\ubb38\uc774\uba70, \uc774\ub294 \uacbd\uc81c\ub825 \uc9d1\uc911 \uc5b5\uc81c\ub77c\ub294 \uc815\ucc45 \ubaa9\ud45c\uc640 \uc5f0\uacb0\ub41c\ub2e4.",B.a2R,B.a48,null)
B.a67=s([u.qW,"\ub450 \ud30c\ud2b8\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \ub2e4\ub8e8\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \ud30c\ud2b8\ub294 \ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uacfc \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uadfc\uac70\ud55c\ub2e4","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\ub9cc \uc2dc\ud5d8\uc5d0 \ucd9c\uc81c\ub418\uace0 \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub294 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub294 \ud615\uc0ac\uc808\ucc28\ub9cc\uc744 \ub2e4\ub8e8\ub294 \ud30c\ud2b8\uc774\ub2e4"],t.s)
B.Qd=s([u.qW],t.s)
B.QB=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uacfc \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\uc758 \uad00\uacc4"],t.s)
B.apx=new A.c("gen_sp_exam_5","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc2dc\ud5d8 \ud3ec\uc778\ud2b8\xb7\uc2e4\ubb34 \uc801\uc6a9","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uacfc \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \ud30c\ud2b8\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a67,0,"\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uacfc \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub294 \ubaa8\ub450 \ub300\uae30\uc5c5\uc9d1\ub2e8\uc758 \uacfc\ub3c4\ud55c \uacbd\uc81c\ub825 \uc9d1\uc911\uc744 \uc5b5\uc81c\ud55c\ub2e4\ub294 \uacf5\ud1b5\ub41c \ubb38\uc81c\uc758\uc2dd\uc744 \uacf5\uc720\ud558\uc9c0\ub9cc, \uc804\uc790\ub294 \ucd1d\uc218 \uc77c\uac00 \ub4f1\uc5d0 \ub300\ud55c \uac1c\ubcc4\uc801\uc778 \uc0ac\uc775\ud3b8\ucde8 \ud589\uc704 \uaddc\uc81c\uc5d0, \ud6c4\uc790\ub294 \uc9c0\uc8fc\ud68c\uc0ac \uaddc\uc81c\xb7\uc21c\ud658\ucd9c\uc790 \uae08\uc9c0 \ub4f1 \ub300\uae30\uc5c5\uc9d1\ub2e8\uc758 \uad6c\uc870\uc801 \uaddc\uc81c\uc5d0 \ucd08\uc810\uc744 \ub454\ub2e4\ub294 \uc810\uc5d0\uc11c \uc11c\ub85c \ubcf4\uc644\uc801\uc778 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.Qd,B.QB,null)
B.a95=s(["\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud574\ub2f9 \uc0ac\uac74\uc5d0 \ub300\ud55c \uc2ec\uc758\uc808\ucc28\ub294 \uc885\ub8cc\ub41c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc774\ud589\uac15\uc81c\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud5a5\ud6c4 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc18c\uc1a1\uc5d0\uc11c \uc2e0\uccad\uc778\uc740 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\ubc31\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc5b4 \uc6d0\uace0\uc758 \uc785\uc99d\ucc45\uc784\uc774 \uba74\uc81c\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc758 \uc774\ud589\uc2e4\ud0dc\ub97c \uc810\uac80\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ucde8\uc18c\ub41c \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc911\ub2e8\ub418\uc5c8\ub358 \uc6d0\ub798\uc758 \uc2ec\uc758\uc808\ucc28\ub97c \uacc4\uc18d\ud560 \uc218 \uc788\ub2e4"],t.s)
