B.aqK=new A.c("gen_super_status_4","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uac70\ub798\uc0c1\uc9c0\uc704 \uc874\ubd80\uc758 \ud310\ub2e8","\ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uc640 \ub0a9\ud488\uc5c5\uccb4 \uc0ac\uc774\uc5d0\uc11c \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \ubb38\uc81c\ub418\ub294 \ub300\ud45c\uc801\uc778 \ubc30\uacbd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.ab7,0,"\ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uc640 \ub0a9\ud488\uc5c5\uccb4 \uc0ac\uc774\uc5d0\uc11c \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \ubb38\uc81c\ub418\ub294 \ubc30\uacbd\uc5d0\ub294, \ub0a9\ud488\uc5c5\uccb4\uac00 \ub9e4\ucd9c\uc758 \uc0c1\ub2f9 \ubd80\ubd84\uc744 \uc18c\uc218\uc758 \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uc5d0 \uc758\uc874\ud558\uc5ec \uac70\ub798\ucc98 \uc804\ud658\uc774 \uc5b4\ub824\uc6b4 \uac70\ub798 \uad6c\uc870\uac00 \uc790\ub9ac\ud558\uace0 \uc788\uc73c\uba70, \uc774\ub85c \uc778\ud574 \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uac00 \uc0c1\ub300\uc801\uc73c\ub85c \uc6b0\uc6d4\ud55c \ud611\uc0c1\ub825\uc744 \uac16\uac8c \ub41c\ub2e4.",B.TN,B.a3e,null)
B.a2n=s(["\uac70\ub798\uc0c1\ub300\ubc29 \ub300\ud45c\uc758 \uac1c\uc778\uc801 \ucde8\ubbf8","\uac70\ub798\uc758\uc874\ub3c4(\ub9e4\ucd9c \ube44\uc911)","\uac70\ub798\ucc98 \uc804\ud658\uc758 \uc6a9\uc774\uc131","\uac70\ub798 \uac1c\uc2dc\xb7\uacc4\uc18d\uc5d0 \uad00\ud55c \ud611\uc0c1\ub825\uc758 \ucc28\uc774","\uac70\ub798\uc758 \uacc4\uc18d\uc131 \ubc0f \ud2b9\uc720\uc790\uc0b0 \ud22c\uc790 \uc815\ub3c4"],t.s)
