B.arc=new A.c("gen_super_status_5","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uac70\ub798\uc0c1\uc9c0\uc704 \uc874\ubd80\uc758 \ud310\ub2e8","\uac70\ub798\uc0c1 \uc9c0\uc704 \uc778\uc815 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c \uace0\ub824\ub418\ub294 \uc694\uc18c\ub85c \uac00\uc7a5 \uc801\uc808\ud558\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a2n,0,"\uac70\ub798\uc0c1 \uc9c0\uc704 \uc778\uc815 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c\ub294 \uac70\ub798\uc758\uc874\ub3c4, \uac70\ub798\ucc98 \uc804\ud658\uc758 \uc6a9\uc774\uc131, \ud611\uc0c1\ub825\uc758 \ucc28\uc774, \uac70\ub798\uc758 \uacc4\uc18d\uc131 \ubc0f \ud2b9\uc720\uc790\uc0b0(\uac00\ub9f9\uc810 \uc778\ud14c\ub9ac\uc5b4 \ub4f1) \ud22c\uc790 \uc815\ub3c4 \ub4f1\uc774 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ub41c\ub2e4. \uac70\ub798\uc0c1\ub300\ubc29 \ub300\ud45c\uc758 \uac1c\uc778\uc801 \ucde8\ubbf8\ub294 \uc774\ub7ec\ud55c \ud310\ub2e8\uacfc \ubb34\uad00\ud55c \uc694\uc18c\uc774\ub2e4.",B.a3L,B.Vo,null)
