B.Il=s([u.h_,"\uac00\ub9f9\ubcf8\ubd80\uac00 \uc784\uc758\ub85c \uac00\uaca9\uc744 \ub300\ud3ed \uc778\uc0c1\ud574\ub3c4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uac00\ub9f9\uc810\uc758 \uc758\uc0ac\uc640 \ubb34\uad00\ud558\uac8c \ubb34\uc870\uac74 \uad6c\uc785\uc744 \uac15\uc694\ud574\ub3c4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uac00\ub9f9\ubcf8\ubd80\uac00 \uc9c0\uc815 \uc5c5\uccb4\ub85c\ubd80\ud130 \ub9ac\ubca0\uc774\ud2b8\ub97c \ubc1b\uc544\ub3c4 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uad6c\uc785\uac15\uc81c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc608\uc678 \uc5c6\uc774 \uc704\ubc95\ud558\ub2e4"],t.s)
