B.aj7=new A.c("gen_super_forcebuy_2","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694","\uac00\ub9f9\ubcf8\ubd80\uac00 \uac00\ub9f9\uc810\uc5d0\uac8c \ubcf8\ubd80\uac00 \uc9c0\uc815\ud55c \uc5c5\uccb4\uc758 \uc790\uc7ac\ub9cc\uc744 \uad6c\uc785\ud558\ub3c4\ub85d \uac15\uc81c\ud558\ub294 \ud589\uc704(\uad6c\uc785\uac15\uc81c)\uac00 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Il,0,"\uac00\ub9f9\uc0ac\uc5c5\uc758 \ud2b9\uc131\uc0c1 \uc0c1\ud488\uc758 \ub3d9\uc77c\uc131 \uc720\uc9c0\ub098 \ud488\uc9c8\uad00\ub9ac\ub97c \uc704\ud574 \ud544\uc694\ud55c \ucd5c\uc18c\ud55c\uc758 \ubc94\uc704 \ub0b4\uc5d0\uc11c \uac00\ub9f9\ubcf8\ubd80\uac00 \uc9c0\uc815\ud558\ub294 \uc790\uc7ac\uc758 \uad6c\uc785\uc744 \uc694\uad6c\ud558\ub294 \uac83\uc740 \ud569\ub9ac\uc801 \uc774\uc720\uac00 \uc778\uc815\ub418\uc5b4 \uad6c\uc785\uac15\uc81c\ub85c\uc11c\uc758 \ubd80\ub2f9\uc131\uc774 \ubd80\uc815\ub420 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uadf8 \ubc94\uc704\ub97c \ub118\uc5b4 \uacfc\ub3c4\ud558\uac8c \uac15\uc694\ud558\uac70\ub098 \ubd80\ub2f9\ud55c \uac00\uaca9\uc744 \ucc45\uc815\ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc704\ubc95\uc131\uc774 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.a_G,B.QF,null)
B.U9=s([u.Db,"\uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ub300\uac00\ub97c \uc9c0\uae09\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc790\ubc1c\uc801\uc73c\ub85c \uc120\ubb3c\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubb34\uc0c1\uc73c\ub85c \uc11c\ube44\uc2a4\ub97c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uacfc \uacf5\ub3d9\uc73c\ub85c \ub9c8\ucf00\ud305 \ube44\uc6a9\uc744 \ubd84\ub2f4\ud558\uae30\ub85c \ud569\uc758\ud558\ub294 \ud589\uc704"],t.s)
