B.Je=s([u.mN,"\ub450 \uc720\ud615\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac1c\ub150\uc73c\ub85c \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uad6c\uc785\uac15\uc81c\ub294 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774\uace0 \uc774\uc775\uc81c\uacf5\uac15\uc694\ub294 \uc544\ub2c8\ub77c\ub294 \ucc28\uc774","\uad6c\uc785\uac15\uc81c\ub294 \uac00\ub9f9\uacc4\uc57d\uc5d0\uc11c\ub9cc, \uc774\uc775\uc81c\uacf5\uac15\uc694\ub294 \uc77c\ubc18 \uac70\ub798\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub41c\ub2e4\ub294 \ucc28\uc774","\uad6c\uc785\uac15\uc81c\ub294 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c, \uc774\uc775\uc81c\uacf5\uac15\uc694\ub294 \uc0ac\uc5c5\uc790\ub97c \ub300\uc0c1\uc73c\ub85c\ub9cc \ubb38\uc81c\ub41c\ub2e4\ub294 \ucc28\uc774"],t.s)
