B.Jd=s(["\uc815\ud669\uc99d\uac70\uc5d0 \uc758\ud55c \ud569\uc758 \uc778\uc815"],t.s)
B.apr=new A.c("gen_collusion_presume_4","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\ud569\uc758 \ucd94\uc815\xb7\uc99d\uba85\ucc45\uc784","\uc815\ud669\uc99d\uac70\ub9cc\uc73c\ub85c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \ud569\uc758\ub97c \uc778\uc815\ud560 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.XT,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc740\ubc00\ud558\uac8c \uc774\ub8e8\uc5b4\uc9c0\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544 \uc9c1\uc811\uc99d\uac70\ub97c \ud655\ubcf4\ud558\uae30 \uc5b4\ub824\uc6b4 \uacbd\uc6b0\uac00 \ub9ce\uc73c\ubbc0\ub85c, \uc9c1\uc811\uc99d\uac70\uac00 \uc5c6\ub354\ub77c\ub3c4 \uac00\uaca9 \uc778\uc0c1\uc758 \uc2dc\uae30\xb7\ud3ed \uc77c\uce58, \ud68c\ud569 \uc815\ud669, \uc815\ubcf4\uad50\ud658 \ub0b4\uc5ed \ub4f1 \uc5ec\ub7ec \uc815\ud669\uc99d\uac70\ub97c \uc885\ud569\ud558\uc5ec \ud569\uc758\uc758 \uc874\uc7ac\ub97c \uc778\uc815\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ud310\ub840\uc758 \ud0dc\ub3c4\uc774\ub2e4.",B.ML,B.Jd,null)
B.VG=s(["\ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \ud569\uc758\ub97c \uc778\uc815\ud558\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc99d\uac70\ub85c \uc0ac\uc6a9\ub420 \uc218 \uc5c6\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\ub9cc \uc788\uc73c\uba74 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \ubc18\ubc15 \uae30\ud68c \uc5c6\uc774 \uace7\ubc14\ub85c \ucc98\ubd84\uc774 \ud655\uc815\ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \uc624\uc9c1 \uc790\uc9c4\uc2e0\uace0\uc790 \ubcf8\uc778\uc758 \uc0ac\uac74\uc5d0\ub9cc \uc0ac\uc6a9\ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \ud56d\uc0c1 \uc2e0\ube59\uc131\uc774 \uc5c6\ub294 \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4"],t.s)
B.Uv=s(["\ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \ud569\uc758\ub97c \uc778\uc815\ud558\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4"],t.s)
B.Xq=s(["\uc790\uc9c4\uc2e0\uace0 \uc9c4\uc220\uc758 \uc99d\uac70\uac00\uce58"],t.s)
B.all=new A.c("gen_collusion_presume_5","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\ud569\uc758 \ucd94\uc815\xb7\uc99d\uba85\ucc45\uc784","\uc790\uc9c4\uc2e0\uace0(\ub9ac\ub2c8\uc5b8\uc2dc)\ub97c \ud1b5\ud574 \ud655\ubcf4\ub41c \uc9c4\uc220\uc774 \ub2e4\ub978 \ucc38\uc5ec \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ud569\uc758 \uc99d\uba85\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.VG,0,"\uc790\uc9c4\uc2e0\uace0(\ub9ac\ub2c8\uc5b8\uc2dc)\ub97c \ud1b5\ud574 \ud655\ubcf4\ub41c \uc0ac\uc5c5\uc790\uc758 \uc9c4\uc220\uc740 \ub2e4\ub978 \ucc38\uc5ec \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ud569\uc758\ub97c \uc99d\uba85\ud558\ub294 \ub370 \uc788\uc5b4 \ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ub418\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uadf8 \uc9c4\uc220\ub9cc\uc73c\ub85c \uace7\ubc14\ub85c \ubc18\ubc15 \uae30\ud68c \uc5c6\uc774 \ucc98\ubd84\uc774 \ud655\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Uv,B.Xq,null)
B.Nf=s(["\ud569\uc758 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ucc38\uace0\ub418\ub294 \uc5ec\ub7ec \uc815\ud669 \uc911 \ud558\ub098\ub85c \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\ub9cc\uc73c\ub85c \ud56d\uc0c1 \ud569\uc758\uac00 \ud655\uc815\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \ud569\uc758 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \uc624\uc9c1 \uae30\uc5c5\uacb0\ud569 \uc2ec\uc0ac\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \ud569\uc758\ub97c \ubd80\uc815\ud558\ub294 \uc808\ub300\uc801 \uc99d\uac70\uc774\ub2e4"],t.s)
B.XW=s(["\ud569\uc758 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ucc38\uace0\ub418\ub294 \uc5ec\ub7ec \uc815\ud669 \uc911 \ud558\ub098\ub85c \uace0\ub824\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a2J=s(["\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uacfc \ud569\uc758 \ud310\ub2e8"],t.s)
B.ars=new A.c("gen_collusion_presume_6","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\ud569\uc758 \ucd94\uc815\xb7\uc99d\uba85\ucc45\uc784","\ud569\uc758\uc758 \uc99d\uba85\uacfc \uad00\ub828\ud558\uc5ec \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc774 \uac16\ub294 \uc758\ubbf8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Nf,0,"\uc0ac\uc5c5\uc790\ub4e4\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9 \uc591\uc0c1\uc740 \uadf8 \uc790\uccb4\ub85c \ud569\uc758\ub97c \ud655\uc815\ud558\ub294 \uc808\ub300\uc801 \uc99d\uac70\ub294 \uc544\ub2c8\uc9c0\ub9cc, \ub2e4\ub978 \uc815\ud669\uc99d\uac70\ub4e4\uacfc \ud568\uaed8 \ud569\uc758 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ucc38\uace0\ud560 \uc218 \uc788\ub294 \uc5ec\ub7ec \uc694\uc18c \uc911 \ud558\ub098\ub85c \uace0\ub824\ub420 \uc218 \uc788\ub2e4.",B.XW,B.a2J,null)
B.GZ=s([u.a7,"\ud569\uc758\uac00 \uc788\uc5c8\ub358 \ucd5c\ucd08 \uc2dc\uc810\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uace0 \uc774\ud6c4 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ud56d\uc0c1 \uc815\ubd80\uc758 \uc870\uc0ac \uac1c\uc2dc\uc77c\ub85c \uace0\uc815\ub41c\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ud310\ub2e8\ud560 \ud544\uc694\uac00 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \uc5b8\ub860\ubcf4\ub3c4\uc77c\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4"],t.s)
B.PJ=s([u.a7],t.s)
B.K6=s(["\uacf5\ub3d9\ud589\uc704 \uc885\uae30\uc758 \ud310\ub2e8\uae30\uc900"],t.s)
B.aki=new A.c("gen_collusion_end_1","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30(\u7d42\u671f)\ub97c \ud310\ub2e8\ud558\ub294 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.GZ,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ub2e8\uc21c\ud788 \ud569\uc758\uac00 \uc131\ub9bd\ud55c \uc2dc\uc810\uc774 \uc544\ub2c8\ub77c, \ud569\uc758\uc5d0 \ub530\ub978 \uc2e4\ud589\ud589\uc704\uac00 \ucd5c\uc885\uc801\uc73c\ub85c \uc885\ub8cc\ub41c \uc2dc\uc810\uc744 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4. \uc774\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815, \ucc98\ubd84\uc2dc\ud6a8 \uae30\uc0b0 \ub4f1\uc5d0 \uc911\uc694\ud55c \uc758\ubbf8\ub97c \uac16\ub294\ub2e4.",B.PJ,B.K6,null)
B.QO=s([u.i_,"\ub0b4\uc2ec\uc73c\ub85c\ub9cc \uc774\ud0c8\uc744 \uacb0\uc2ec\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \uadf8 \uc2dc\uc810\ubd80\ud130 \ucc45\uc784\uc5d0\uc11c \ubc97\uc5b4\ub09c\ub2e4","\uc774\ud0c8 \uc758\uc0ac\ub97c \ud45c\uc2dc\ud558\uba74 \uacfc\uac70\uc758 \ucc45\uc784\uae4c\uc9c0 \ubaa8\ub450 \uc18c\uae09\ud558\uc5ec \uba74\uc81c\ub41c\ub2e4","\uc774\ud0c8 \uc758\uc0ac \ud45c\uc2dc\ub294 \ubc95\uc801\uc73c\ub85c \uc544\ubb34\ub7f0 \uc758\ubbf8\uac00 \uc5c6\ub2e4","\uc774\ud0c8 \uc758\uc0ac\ub97c \ud45c\uc2dc\ud558\uba74 \uc624\ud788\ub824 \uac00\uc911\ucc98\ubc8c\ub41c\ub2e4"],t.s)
