B.Qk=s(["\uacf5\ub3d9\ud589\uc704\ub85c\ubd80\ud130\uc758 \uc774\ud0c8"],t.s)
B.als=new A.c("gen_collusion_end_2","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\uacf5\ub3d9\ud589\uc704\uc5d0 \ucc38\uc5ec\ud588\ub358 \uc0ac\uc5c5\uc790\uac00 \ub2e4\ub978 \ucc38\uc5ec\uc790\uc5d0\uac8c \uc774\ud0c8 \uc758\uc0ac\ub97c \ud45c\uc2dc\ud55c \uacbd\uc6b0\uc758 \ud6a8\uacfc\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.QO,0,"\uacf5\ub3d9\ud589\uc704\uc5d0 \ucc38\uc5ec\ud588\ub358 \uc0ac\uc5c5\uc790\uac00 \uc774\ub97c \uc885\ub8cc\ud558\ub824\uba74 \ub2e8\uc21c\ud55c \ub0b4\uc2ec\uc758 \uc758\uc0ac\ub9cc\uc73c\ub85c\ub294 \ubd80\uc871\ud558\uace0, \uc774\ud0c8\uc758 \uc758\uc0ac\uac00 \ub2e4\ub978 \ucc38\uc5ec\uc790\uc5d0\uac8c \uc2e4\uc9c8\uc801\uc73c\ub85c \uc804\ub2ec\ub418\uace0 \uc2e4\uc81c \uc774\ud0c8\uc5d0 \ubd80\ud569\ud558\ub294 \ud589\uc704(\uac00\uaca9 \uc778\ud558 \ub4f1)\uac00 \uc778\uc815\ub418\uc5b4\uc57c \uadf8 \uc2dc\uc810 \uc774\ud6c4\uc758 \ucc45\uc784\uc5d0\uc11c \ubc97\uc5b4\ub0a0 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ubc95\ub9ac\ub85c \ub17c\uc758\ub41c\ub2e4.",B.QQ,B.Qk,null)
B.Tp=s(["\uc6d0\uce59\uc801\uc73c\ub85c \uc790\uc2e0\uc774 \uc2e4\uc81c\ub85c \uac00\ub2f4\ud55c \uc2dc\uc810 \uc774\ud6c4\uc758 \ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub9cc \ucc45\uc784\uc744 \uc9c4\ub2e4","\ub4a4\ub2a6\uac8c \uac00\ub2f4\ud574\ub3c4 \ucc98\uc74c\ubd80\ud130 \ucc38\uc5ec\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc5b4 \uc774\uc804 \ud589\uc704\uae4c\uc9c0 \ubaa8\ub450 \ucc45\uc784\uc9c4\ub2e4","\ub4a4\ub2a6\uac8c \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\ub294 \uc5b4\ub5a0\ud55c \ucc45\uc784\ub3c4 \uc9c0\uc9c0 \uc54a\ub294\ub2e4","\uac00\ub2f4 \uc2dc\uc810\uc740 \ucc45\uc784 \ubc94\uc704 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ub4a4\ub2a6\uac8c \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\ub294 \ud56d\uc0c1 \uac00\uc7a5 \ubb34\uac70\uc6b4 \ucc45\uc784\uc744 \uc9c4\ub2e4"],t.s)
B.Rl=s(["\uc6d0\uce59\uc801\uc73c\ub85c \uc790\uc2e0\uc774 \uc2e4\uc81c\ub85c \uac00\ub2f4\ud55c \uc2dc\uc810 \uc774\ud6c4\uc758 \ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub9cc \ucc45\uc784\uc744 \uc9c4\ub2e4"],t.s)
B.Rf=s(["\ub4a4\ub2a6\uac8c \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784\ubc94\uc704"],t.s)
B.as_=new A.c("gen_collusion_end_3","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\uacf5\ub3d9\ud589\uc704\uc5d0 \ub4a4\ub2a6\uac8c \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784 \ubc94\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Tp,0,"\uacf5\ub3d9\ud589\uc704\uc5d0 \ub4a4\ub2a6\uac8c \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uc790\uc2e0\uc774 \uc2e4\uc81c\ub85c \uadf8 \uacf5\ub3d9\ud589\uc704\uc5d0 \ucc38\uc5ec\ud558\uac8c \ub41c \uc2dc\uc810 \uc774\ud6c4\uc758 \ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub9cc \ucc45\uc784\uc744 \uc9c0\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \uac00\ub2f4 \uc774\uc804\uc5d0 \ub2e4\ub978 \uc0ac\uc5c5\uc790\ub4e4\uc774 \ud589\ud55c \ubd80\ubd84\uae4c\uc9c0 \ub2f9\uc5f0\ud788 \ucc45\uc784\uc744 \uc9c0\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Rl,B.Rf,null)
B.aas=s([u.d,"\ubaa8\ub4e0 \ucc38\uc5ec \uc0ac\uc5c5\uc790\uc5d0\uac8c \ud56d\uc0c1 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc81c\uc7ac\uac00 \ubd80\uacfc\ub41c\ub2e4","\uac00\uc7a5 \uc801\uac8c \uad00\uc5ec\ud55c \uc0ac\uc5c5\uc790\uac00 \uac00\uc7a5 \ubb34\uac70\uc6b4 \uc81c\uc7ac\ub97c \ubc1b\ub294\ub2e4","\uc81c\uc7ac\ub294 \ucc38\uc5ec \uc0ac\uc5c5\uc790 \uc218\uc640 \ubb34\uad00\ud558\uac8c 1\uac1c \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc9d1\uc911\ub41c\ub2e4","\uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \uad00\uc5ec \uc815\ub3c4\ub294 \uc81c\uc7ac \uc218\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4"],t.s)
