B.ait=new A.c("gen_collusion_end_4","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\uc5ec\ub7ec \uc0ac\uc5c5\uc790\uac00 \ucc38\uc5ec\ud55c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc5d0\uc11c \uac01 \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ucc45\uc784 \ubd80\uacfc \ubc29\uc2dd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.aas,0,"\uc5ec\ub7ec \uc0ac\uc5c5\uc790\uac00 \ucc38\uc5ec\ud55c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc0ac\uac74\uc5d0\uc11c\ub294 \uac01 \uc0ac\uc5c5\uc790\ubcc4\ub85c \uacf5\ub3d9\ud589\uc704\uc5d0\uc758 \uad00\uc5ec \uc815\ub3c4, \uac00\ub2f4 \uae30\uac04, \uc8fc\ub3c4\uc801 \uc5ed\ud560 \uc5ec\ubd80 \ub4f1\uc744 \uace0\ub824\ud558\uc5ec \uac1c\ubcc4\uc801\uc73c\ub85c \ucc45\uc784\uacfc \uc81c\uc7ac(\uacfc\uc9d5\uae08 \ub4f1) \uc218\uc704\uac00 \ucc28\ub4f1\uc801\uc73c\ub85c \uc815\ud574\uc9c8 \uc218 \uc788\ub2e4.",B.a7w,B.M3,null)
B.a2D=s([u.y8,"\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\uc640 \ucc98\ubd84\uc2dc\ud6a8\ub294 \uc11c\ub85c \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \uacf5\ub3d9\ud589\uc704\uac00 \uc2dc\uc791\ub41c \uc2dc\uc810\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uace0 \uc885\uae30\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uacf5\ub3d9\ud589\uc704 \uc0ac\uac74\uc5d0\ub294 \ucc98\ubd84\uc2dc\ud6a8 \uac1c\ub150\uc774 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ucc98\ubd84\uc2dc\ud6a8\ub294 \uacf5\ub3d9\ud589\uc704 \uc0ac\uac74\uc5d0\uc11c \uc5b8\uc81c\ub098 \ubb34\uc81c\ud55c\uc774\ub2e4"],t.s)
