B.ahg=new A.c("gen_collusion_end_5","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\uacf5\ub3d9\ud589\uc704 \uc885\ub8cc \uc2dc\uc810 \ud310\ub2e8\uc774 \ucc98\ubd84\uc2dc\ud6a8\uc640 \uac16\ub294 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a2D,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc0ac\uac74\uc5d0\uc11c \uc885\uae30(\uc2e4\ud589\ud589\uc704\uac00 \ucd5c\uc885\uc801\uc73c\ub85c \uc885\ub8cc\ub41c \uc2dc\uc810)\ub97c \uc5b8\uc81c\ub85c \ubcfc \uac83\uc778\uc9c0\uc5d0 \ub530\ub77c \ucc98\ubd84\uc2dc\ud6a8\uc758 \uae30\uc0b0\uc810\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\uc5b4, \uc774\ub294 \uc2e4\ubb34\uc0c1 \ub2e4\ud22c\uc5b4\uc9c0\ub294 \uc911\uc694\ud55c \uc7c1\uc810 \uc911 \ud558\ub098\uc774\ub2e4.",B.abh,B.Su,null)
B.a2t=s(["\uc704\uc6d0\ud68c\ub294 \uc704\uc6d0\uc7a5 1\uba85, \ubd80\uc704\uc6d0\uc7a5 1\uba85\uc744 \ud3ec\ud568\ud55c 9\uba85\uc758 \uc704\uc6d0\uc73c\ub85c \uad6c\uc131\ud55c\ub2e4","\uc704\uc6d0\uc7a5\uacfc \ubd80\uc704\uc6d0\uc7a5\uc740 \uc815\ubb34\uc9c1 \uacf5\ubb34\uc6d0\uc73c\ub85c \uc784\uba85\ud55c\ub2e4","\uc704\uc6d0 \uc911 4\uba85\uc740 \uc0c1\uc784\uc704\uc6d0, 4\uba85\uc740 \ube44\uc0c1\uc784\uc704\uc6d0\uc73c\ub85c \ud55c\ub2e4","\uc704\uc6d0\uc740 \ubaa8\ub450 \ubc18\ub4dc\uc2dc \uad6d\ud68c\uc758\uc6d0 \uc2e0\ubd84\uc744 \uacb8\uc9c1\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc704\uc6d0\uc7a5\xb7\ubd80\uc704\uc6d0\uc7a5\xb7\ub2e4\ub978 \uc704\uc6d0\uc740 \uad6d\ubb34\ucd1d\ub9ac\uc758 \uc81c\uccad\uc73c\ub85c \ub300\ud1b5\ub839\uc774 \uc784\uba85 \ub610\ub294 \uc704\ucd09\ud55c\ub2e4"],t.s)
B.a8h=s(["\uc704\uc6d0\uc740 \ubaa8\ub450 \ubc18\ub4dc\uc2dc \uad6d\ud68c\uc758\uc6d0 \uc2e0\ubd84\uc744 \uacb8\uc9c1\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
B.Pn=s(["\uc704\uc6d0\ud68c \uad6c\uc131 \uc778\uc6d0"],t.s)
B.aoG=new A.c("gen_ftc_org_comp_1","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\ud68c\uc758 \uad6c\uc131","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uad6c\uc131\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a2t,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc704\uc6d0\uc7a5 1\uba85\uacfc \ubd80\uc704\uc6d0\uc7a5 1\uba85\uc744 \ud3ec\ud568\ud55c 9\uba85\uc758 \uc704\uc6d0(\uc0c1\uc784\uc704\uc6d0 4\uba85, \ube44\uc0c1\uc784\uc704\uc6d0 4\uba85)\uc73c\ub85c \uad6c\uc131\ub418\uba70, \uc704\uc6d0\uc7a5\xb7\ubd80\uc704\uc6d0\uc7a5\uc740 \uc815\ubb34\uc9c1 \uacf5\ubb34\uc6d0\uc73c\ub85c \uad6d\ubb34\ucd1d\ub9ac\uc758 \uc81c\uccad\uc744 \uac70\uccd0 \ub300\ud1b5\ub839\uc774 \uc784\uba85\ud55c\ub2e4. \uc704\uc6d0\uc740 \uad6d\ud68c\uc758\uc6d0\uc744 \uacb8\uc9c1\ud560 \uc218 \uc5c6\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, "\ubc18\ub4dc\uc2dc \uad6d\ud68c\uc758\uc6d0 \uc2e0\ubd84\uc744 \uacb8\uc9c1\ud558\uc5ec\uc57c \ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.a8h,B.Pn,null)
B.N5=s(["\uc704\uc6d0\uc758 \uc784\uae30\ub294 3\ub144\uc73c\ub85c \ud558\uba70, 1\ucc28\uc5d0 \ud55c\ud558\uc5ec \uc5f0\uc784\ud560 \uc218 \uc788\ub2e4","\uc704\uc6d0\uc758 \uc784\uae30\ub294 \uc885\uc2e0\uc73c\ub85c \ud55c\ub2e4","\uc704\uc6d0\uc758 \uc784\uae30\ub294 1\ub144\uc774\uba70 \uc5f0\uc784\ud560 \uc218 \uc5c6\ub2e4","\uc704\uc6d0\uc758 \uc784\uae30\ub294 \ub300\ud1b5\ub839\uc758 \uc784\uae30\uc640 \uc5f0\ub3d9\ub418\uc5b4 \uc790\ub3d9\uc73c\ub85c \ubcc0\uacbd\ub41c\ub2e4","\uc704\uc6d0\uc758 \uc784\uae30\uc5d0 \uad00\ud55c \uaddc\uc815\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.a9y=s(["\uc704\uc6d0\uc758 \uc784\uae30\ub294 3\ub144\uc73c\ub85c \ud558\uba70, 1\ucc28\uc5d0 \ud55c\ud558\uc5ec \uc5f0\uc784\ud560 \uc218 \uc788\ub2e4"],t.s)
B.W_=s(["\uc704\uc6d0\uc758 \uc784\uae30"],t.s)
