B.a_F=s(["\uc704\uc6d0\uc740 \uae08\uace0 \uc774\uc0c1\uc758 \ud615\uc744 \uc120\uace0\ubc1b\uc740 \uacbd\uc6b0\uac00 \uc544\ub2c8\uba74 \ubcf8\uc778\uc758 \uc758\uc0ac\uc5d0 \ubc18\ud558\uc5ec \uba74\uc9c1\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc704\uc6d0\uc740 \ud0c4\ud575\uacb0\uc815\uc73c\ub85c \ud30c\uba74\ub420 \uc218 \uc788\ub2e4","\uc7a5\uae30\uac04 \uc2ec\uc2e0\uc1e0\uc57d\uc73c\ub85c \uc9c1\ubb34\ub97c \uc218\ud589\ud560 \uc218 \uc5c6\uac8c \ub41c \uacbd\uc6b0 \ub4f1 \ubc95\uc5d0\uc11c \uc815\ud55c \uc0ac\uc720\uac00 \uc788\uc73c\uba74 \uba74\uc9c1\ub420 \uc218 \uc788\ub2e4","\uc704\uc6d0\uc740 \uc815\uce58\uc801 \uc0ac\uc815\uc5d0 \ub530\ub77c \uc544\ubb34 \ub54c\ub098 \uc784\uc758\ub85c \ud574\uc784\ub420 \uc218 \uc788\ub2e4","\uc704\uc6d0\uc758 \uc2e0\ubd84\ubcf4\uc7a5\uc740 \uc704\uc6d0\ud68c\uc758 \ub3c5\ub9bd\uc801\xb7\uc911\ub9bd\uc801 \uc9c1\ubb34\uc218\ud589\uc744 \ub4b7\ubc1b\uce68\ud558\uae30 \uc704\ud55c \uc7a5\uce58\uc774\ub2e4"],t.s)
B.GV=s(["\uc704\uc6d0\uc740 \uc815\uce58\uc801 \uc0ac\uc815\uc5d0 \ub530\ub77c \uc544\ubb34 \ub54c\ub098 \uc784\uc758\ub85c \ud574\uc784\ub420 \uc218 \uc788\ub2e4"],t.s)
B.a7A=s(["\uc704\uc6d0\uc758 \uc2e0\ubd84\ubcf4\uc7a5"],t.s)
B.aqb=new A.c("gen_ftc_org_comp_3","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\ud68c\uc758 \uad6c\uc131","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc758 \uc2e0\ubd84\ubcf4\uc7a5\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a_F,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc740 \ud0c4\ud575\uacb0\uc815\uc73c\ub85c \ud30c\uba74\ub418\uac70\ub098 \uae08\uace0 \uc774\uc0c1\uc758 \ud615\uc744 \uc120\uace0\ubc1b\uac70\ub098 \uc7a5\uae30\uac04 \uc2ec\uc2e0\uc1e0\uc57d\uc73c\ub85c \uc9c1\ubb34\ub97c \uc218\ud589\ud560 \uc218 \uc5c6\uac8c \ub418\ub294 \ub4f1 \ubc95\uc5d0\uc11c \uc815\ud55c \uc0ac\uc720\uac00 \uc788\ub294 \uacbd\uc6b0\uac00 \uc544\ub2c8\uba74 \ubcf8\uc778\uc758 \uc758\uc0ac\uc5d0 \ubc18\ud558\uc5ec \uba74\uc9c1\ub418\uc9c0 \uc54a\ub294\ub2e4. \uc774\ub7ec\ud55c \uc2e0\ubd84\ubcf4\uc7a5\uc740 \uc704\uc6d0\ud68c\uac00 \uc815\uce58\uc801 \uc555\ub825\uc5d0\uc11c \ubc97\uc5b4\ub098 \ub3c5\ub9bd\uc801\xb7\uc911\ub9bd\uc801\uc73c\ub85c \uc9c1\ubb34\ub97c \uc218\ud589\ud558\ub3c4\ub85d \ud558\uae30 \uc704\ud55c \uac83\uc73c\ub85c, "\uc544\ubb34 \ub54c\ub098 \uc784\uc758\ub85c \ud574\uc784\ub420 \uc218 \uc788\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.GV,B.a7A,null)
B.ac7=s(["\ubc95\ub960\xb7\uacbd\uc81c\xb7\uacbd\uc601 \ub4f1\uc758 \ubd84\uc57c\uc5d0\uc11c \ud559\uc2dd\uacfc \uacbd\ud5d8\uc774 \ud48d\ubd80\ud55c \uc0ac\ub78c","\uacf5\uc815\uac70\ub798 \uad00\ub828 \uc0ac\uac74\uc744 \ub2e4\ub8e8\uc5b4 \ubcf8 \ud310\uc0ac\xb7\uac80\uc0ac \ub610\ub294 \ubcc0\ud638\uc0ac \uacbd\ub825\uc774 \uc788\ub294 \uc0ac\ub78c","\uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \uc0ac\ubb34\uc5d0 \uc885\uc0ac\ud55c 3\uae09 \uc774\uc0c1 \uacf5\ubb34\uc6d0 \uacbd\ub825\uc774 \uc788\ub294 \uc0ac\ub78c","\ubc18\ub4dc\uc2dc \ud2b9\uc815 \uc815\ub2f9\uc758 \ub2f9\uc6d0\uc774\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc790\uaca9","\uacbd\uc81c \uad00\ub828 \uc5f0\uad6c\uae30\uad00\uc5d0\uc11c \ubd80\uad50\uc218\uae09 \uc774\uc0c1\uc758 \uc9c1\uc5d0 \uc788\uc5c8\ub358 \uc0ac\ub78c"],t.s)
B.a6s=s(["\ubc18\ub4dc\uc2dc \ud2b9\uc815 \uc815\ub2f9\uc758 \ub2f9\uc6d0\uc774\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc790\uaca9"],t.s)
