B.aoX=new A.c("gen_ftc_org_comp_4","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\ud68c\uc758 \uad6c\uc131","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc758 \uc790\uaca9\uc694\uac74\uc73c\ub85c \ubc95\uc5d0\uc11c \uc694\uad6c\ud558\ub294 \uac83\uacfc \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.ac7,3,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc740 \ubc95\ub960\xb7\uacbd\uc81c\xb7\uacbd\uc601 \ub4f1\uc758 \ubd84\uc57c\uc758 \ud559\uc2dd\uacfc \uacbd\ud5d8, \ud310\uc0ac\xb7\uac80\uc0ac\xb7\ubcc0\ud638\uc0ac \uacbd\ub825, \uace0\uc704 \uacf5\ubb34\uc6d0 \uacbd\ub825, \uc5f0\uad6c\uae30\uad00 \uacbd\ub825 \ub4f1 \uc804\ubb38\uc131\uc744 \uae30\uc900\uc73c\ub85c \uc784\uba85\xb7\uc704\ucd09\ub41c\ub2e4. \ud2b9\uc815 \uc815\ub2f9\uc758 \ub2f9\uc6d0 \uc5ec\ubd80\ub294 \uc704\uc6d0 \uc790\uaca9\uc694\uac74\uc73c\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc73c\uba70, \uc624\ud788\ub824 \uc704\uc6d0\ud68c\uc758 \uc815\uce58\uc801 \uc911\ub9bd\uc131\uc774 \uac15\uc870\ub41c\ub2e4.",B.a6s,B.RZ,null)
B.Nj=s([u.yp,"\uc0c1\uc784\uc704\uc6d0\uacfc \ube44\uc0c1\uc784\uc704\uc6d0\uc740 \uad8c\ud55c\uacfc \uc758\uacb0\uad8c\uc5d0 \uc788\uc5b4 \uc804\ud600 \ucc28\uc774\uac00 \uc5c6\uc5b4 \uad6c\ubcc4\uc758 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\ube44\uc0c1\uc784\uc704\uc6d0\ub9cc \uc758\uacb0\uad8c\uc744 \uac00\uc9c0\uace0 \uc0c1\uc784\uc704\uc6d0\uc740 \uc758\uacb0\uad8c\uc774 \uc5c6\ub2e4","\uc0c1\uc784\uc704\uc6d0\uc740 \ubbfc\uac04\uc778\ub9cc, \ube44\uc0c1\uc784\uc704\uc6d0\uc740 \uacf5\ubb34\uc6d0\ub9cc \uc784\uba85\ub420 \uc218 \uc788\ub2e4","\uc0c1\uc784\uc704\uc6d0\uacfc \ube44\uc0c1\uc784\uc704\uc6d0\uc758 \uad6c\ubd84\uc740 \ubc95\ub960\uc0c1 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
