B.apI=new A.c("gen_ftc_org_comp_5","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\ud68c\uc758 \uad6c\uc131","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc0c1\uc784\uc704\uc6d0\uacfc \ube44\uc0c1\uc784\uc704\uc6d0\uc758 \ucc28\uc774\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Nj,0,"\uc0c1\uc784\uc704\uc6d0\uc740 \uc704\uc6d0\ud68c\uc5d0 \uc0c1\uc2dc \uadfc\ubb34\ud558\uba70 \uc5c5\ubb34\uc5d0 \uc804\ub150\ud558\ub294 \ubc18\uba74, \ube44\uc0c1\uc784\uc704\uc6d0\uc740 \uc0c1\uc2dc \uadfc\ubb34 \uc758\ubb34 \uc5c6\uc774 \ud68c\uc758 \ub4f1 \ud544\uc694\ud55c \uacbd\uc6b0\uc5d0 \uc9c1\ubb34\ub97c \uc218\ud589\ud55c\ub2e4. \ub2e4\ub9cc \uc758\uacb0\uc5d0 \ucc38\uc5ec\ud560 \ub54c\ub294 \uc0c1\uc784\uc704\uc6d0\xb7\ube44\uc0c1\uc784\uc704\uc6d0 \ubaa8\ub450 \ub3d9\ub4f1\ud55c \uc758\uacb0\uad8c\uc744 \uac00\uc9c4\ub2e4.",B.WZ,B.a2k,null)
B.a1j=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uad6d\ubb34\ucd1d\ub9ac \uc18c\uc18d\uc758 \uc911\uc559\ud589\uc815\uae30\uad00\uc73c\ub85c\uc11c \ud569\uc758\uc81c \ud589\uc815\uae30\uad00\uc758 \uc131\uaca9\uc744 \uac00\uc9c4\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc0ac\ubc95\ubd80\uc5d0 \uc18c\uc18d\ub41c \ubc95\uc6d0\uc758 \uc77c\uc885\uc774\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc21c\uc218 \ubbfc\uac04\ub2e8\uccb4\ub85c\uc11c \uc544\ubb34\ub7f0 \ud589\uc815\uad8c\ud55c\uc774 \uc5c6\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c0\ubc29\uc790\uce58\ub2e8\uccb4 \uc0b0\ud558 \uae30\uad00\uc774\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uad6d\ud68c\uc5d0 \uc18c\uc18d\ub41c \ubcf4\uc870\uae30\uad00\uc774\ub2e4"],t.s)
