B.a4O=s(["\uc7ac\uc801\uc704\uc6d0 \uacfc\ubc18\uc218\uc758 \ucd9c\uc11d\uacfc \ucd9c\uc11d\uc704\uc6d0 \uacfc\ubc18\uc218\uc758 \ucc2c\uc131\uc73c\ub85c \uc758\uacb0\ud55c\ub2e4","\uc7ac\uc801\uc704\uc6d0 \uc804\uc6d0\uc758 \ucc2c\uc131\uc774 \uc788\uc5b4\uc57c\ub9cc \uc758\uacb0\ud560 \uc218 \uc788\ub2e4","\ucd9c\uc11d\uc704\uc6d0 1\uc778\uc758 \ucc2c\uc131\ub9cc\uc73c\ub85c \uc758\uacb0\ud560 \uc218 \uc788\ub2e4","\uc758\uacb0\uc815\uc871\uc218\uc5d0 \uad00\ud55c \uaddc\uc815\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc7ac\uc801\uc704\uc6d0\uc758 3\ubd84\uc758 2 \uc774\uc0c1\uc774 \ud56d\uc0c1 \ucd9c\uc11d\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
