B.a6e=s(["\uc0c1\uc784\uc704\uc6d0 1\uba85\uc744 \ud3ec\ud568\ud55c 3\uba85\uc758 \uc704\uc6d0\uc73c\ub85c \uad6c\uc131\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4","\uc18c\ud68c\uc758\ub294 \ube44\uc0c1\uc784\uc704\uc6d0 9\uba85 \uc804\uc6d0\uc73c\ub85c \uad6c\uc131\ub41c\ub2e4","\uc18c\ud68c\uc758\ub294 \uc704\uc6d0\uc7a5 1\uc778\ub9cc\uc73c\ub85c \uad6c\uc131\ub41c\ub2e4","\uc18c\ud68c\uc758\ub294 \uc0ac\ubb34\ucc98 \uc9c1\uc6d0\ub9cc\uc73c\ub85c \uad6c\uc131\ub41c\ub2e4","\uc18c\ud68c\uc758\uc758 \uad6c\uc131\uc6d0 \uc218\ub294 \ubc95\ub960\uc0c1 \uc815\ud574\uc838 \uc788\uc9c0 \uc54a\ub2e4"],t.s)
