B.ani=new A.c("gen_ftc_org_meet_6","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\ud68c\uc758\uc758 \uc885\ub958\xb7\uc758\uacb0\uc815\uc871\uc218","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc7a5\uc758 \uad8c\ud55c\uc73c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.HM,3,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc7a5\uc740 \uc704\uc6d0\ud68c\ub97c \ub300\ud45c\ud558\uace0 \ud68c\uc758\ub97c \uc18c\uc9d1\ud558\uc5ec \uadf8 \uc758\uc7a5\uc774 \ub418\uba70, \uc0ac\ubb34\ucc98\ub97c \uc9c0\ud718\xb7\uac10\ub3c5\ud558\ub294 \ub4f1 \uc704\uc6d0\ud68c \uc6b4\uc601\uc744 \ucd1d\uad04\ud55c\ub2e4. \ub2e4\ub9cc \uc704\uc6d0\ud68c\ub294 \ud589\uc815\uae30\uad00\uc774\ubbc0\ub85c \ubc95\uc6d0\uc758 \uc7ac\ud310\uc5d0 \uad00\uc5ec\ud558\uc5ec \uc9c1\uc811 \ud310\uacb0\uc744 \uc120\uace0\ud558\ub294 \uac83\uacfc \uac19\uc740 \uc0ac\ubc95\uad8c\ud55c\uc740 \uc704\uc6d0\uc7a5\uc758 \uad8c\ud55c\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.KR,B.abg,null)
B.a75=s(["\uc704\uc6d0 \ubcf8\uc778\uc774 \ud574\ub2f9 \uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uc774\uac70\ub098 \ub2f9\uc0ac\uc790\uc640 \uce5c\uc871\uad00\uacc4\uc5d0 \uc788\ub294 \uacbd\uc6b0","\uc704\uc6d0\uc774 \uc0ac\uac74\uacfc \ubb34\uad00\ud55c \ub2e4\ub978 \uc9c0\uc5ed\uc5d0 \uac70\uc8fc\ud558\ub294 \uacbd\uc6b0","\uc704\uc6d0\uc774 \ud574\ub2f9 \uc0ac\uac74\uc5d0 \ub300\ud574 \uc5b8\ub860 \uae30\uc0ac\ub97c \uc77d\uc740 \uc801\uc774 \uc788\ub294 \uacbd\uc6b0","\uc704\uc6d0\uc758 \uc784\uae30\uac00 \uace7 \ub9cc\ub8cc\ub420 \uc608\uc815\uc778 \uacbd\uc6b0","\uc704\uc6d0\uc774 \ud574\ub2f9 \uc0ac\uac74\uacfc \uad00\ub828\ub41c \uc5c5\uc885\uc5d0 \ub300\ud574 \uc77c\ubc18\uc801\uc778 \uc9c0\uc2dd\uc744 \uac00\uc9c4 \uacbd\uc6b0"],t.s)
B.a9m=s(["\uc704\uc6d0 \ubcf8\uc778\uc774 \ud574\ub2f9 \uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uc774\uac70\ub098 \ub2f9\uc0ac\uc790\uc640 \uce5c\uc871\uad00\uacc4\uc5d0 \uc788\ub294 \uacbd\uc6b0"],t.s)
B.a4x=s(["\uc704\uc6d0\uc758 \uc81c\ucc99 \uc0ac\uc720"],t.s)
B.arT=new A.c("gen_ftc_org_recusal_1","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\uc758 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc758 \uc81c\ucc99 \uc0ac\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a75,0,"\uc704\uc6d0 \ubcf8\uc778\uc774 \ud574\ub2f9 \uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uc774\uac70\ub098 \ub2f9\uc0ac\uc790\uc640 \uce5c\uc871\uad00\uacc4 \ub4f1 \ud2b9\ubcc4\ud55c \uc774\ud574\uad00\uacc4\uac00 \uc788\ub294 \uacbd\uc6b0, \uadf8 \uc704\uc6d0\uc740 \ud574\ub2f9 \uc0ac\uac74\uc758 \uc2ec\uc758\xb7\uc758\uacb0\uc5d0\uc11c \uc81c\ucc99\ub418\uc5b4 \uad00\uc5ec\ud560 \uc218 \uc5c6\ub2e4. \uc774\ub294 \uc2ec\uc758\uc758 \uacf5\uc815\uc131\uc744 \ub2f4\ubcf4\ud558\uae30 \uc704\ud55c \uc81c\ub3c4\uc774\ub2e4.",B.a9m,B.a4x,null)
B.Kd=s(["\uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uac00 \uc704\uc6d0\uc5d0\uac8c \uc2ec\uc758\xb7\uc758\uacb0\uc758 \uacf5\uc815\uc131\uc744 \uae30\ub300\ud558\uae30 \uc5b4\ub824\uc6b4 \uc0ac\uc815\uc774 \uc788\ub2e4\uace0 \uc8fc\uc7a5\ud558\uba70 \uadf8 \uc704\uc6d0\uc758 \ubc30\uc81c\ub97c \uc2e0\uccad\ud558\ub294 \uc81c\ub3c4\uc774\ub2e4","\uae30\ud53c\ub294 \uc704\uc6d0 \uc2a4\uc2a4\ub85c \uc0ac\uac74\uc5d0\uc11c \ubb3c\ub7ec\ub098\uaca0\ub2e4\uace0 \uacb0\uc815\ud558\ub294 \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4","\uae30\ud53c \uc2e0\uccad\uc740 \uc5b4\ub5a0\ud55c \uc0ac\uc720\uac00 \uc5c6\uc5b4\ub3c4 \ubb34\uc870\uac74 \ubc1b\uc544\ub4e4\uc5ec\uc9c4\ub2e4","\uae30\ud53c \uc81c\ub3c4\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0\ub294 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\uae30\ud53c\ub294 \uc624\uc9c1 \uc704\uc6d0\uc7a5\ub9cc\uc774 \ub2e4\ub978 \uc704\uc6d0\uc5d0 \ub300\ud574 \uc2e0\uccad\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Nt=s(["\uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uac00 \uc704\uc6d0\uc5d0\uac8c \uc2ec\uc758\xb7\uc758\uacb0\uc758 \uacf5\uc815\uc131\uc744 \uae30\ub300\ud558\uae30 \uc5b4\ub824\uc6b4 \uc0ac\uc815\uc774 \uc788\ub2e4\uace0 \uc8fc\uc7a5\ud558\uba70 \uadf8 \uc704\uc6d0\uc758 \ubc30\uc81c\ub97c \uc2e0\uccad\ud558\ub294 \uc81c\ub3c4"],t.s)
B.a9Q=s(["\uae30\ud53c \uc81c\ub3c4"],t.s)
B.ah4=new A.c("gen_ftc_org_recusal_2","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\uc758 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c",'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc5d0 \ub300\ud55c "\uae30\ud53c" \uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Kd,0,"\uae30\ud53c\ub294 \uc0ac\uac74\uc758 \ub2f9\uc0ac\uc790\uac00 \ud2b9\uc815 \uc704\uc6d0\uc5d0\uac8c \uc2ec\uc758\xb7\uc758\uacb0\uc758 \uacf5\uc815\uc131\uc744 \uae30\ub300\ud558\uae30 \uc5b4\ub824\uc6b4 \uc0ac\uc815\uc774 \uc788\ub2e4\uace0 \uc8fc\uc7a5\ud558\uba70 \uadf8 \uc704\uc6d0\uc744 \uc0ac\uac74\uc5d0\uc11c \ubc30\uc81c\ud574 \ub2ec\ub77c\uace0 \uc2e0\uccad\ud558\ub294 \uc81c\ub3c4\ub85c, \uc81c\ucc99 \uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub354\ub77c\ub3c4 \uacf5\uc815\uc131\uc774 \uc758\uc2ec\ub418\ub294 \uacbd\uc6b0\uc5d0 \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.Nt,B.a9Q,null)
B.Yt=s(["\uc704\uc6d0 \uc2a4\uc2a4\ub85c \uc81c\ucc99 \ub610\ub294 \uae30\ud53c \uc0ac\uc720\uac00 \uc788\ub2e4\uace0 \ud310\ub2e8\ud558\uc5ec \uc790\ubc1c\uc801\uc73c\ub85c \ud574\ub2f9 \uc0ac\uac74\uc758 \uc2ec\uc758\xb7\uc758\uacb0\uc5d0\uc11c \ubb3c\ub7ec\ub098\ub294 \uac83\uc744 \ub9d0\ud55c\ub2e4","\ud68c\ud53c\ub294 \ubc18\ub4dc\uc2dc \ub2f9\uc0ac\uc790\uc758 \uc2e0\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \uac00\ub2a5\ud558\ub2e4","\ud68c\ud53c\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc5d0\uac8c\ub294 \uc778\uc815\ub418\uc9c0 \uc54a\ub294 \uc81c\ub3c4\uc774\ub2e4","\ud68c\ud53c\ud55c \uc704\uc6d0\uc740 \uc774\ud6c4 \uc601\uad6c\uc801\uc73c\ub85c \uc704\uc6d0 \uc790\uaca9\uc744 \uc0c1\uc2e4\ud55c\ub2e4","\ud68c\ud53c\ub294 \uc0ac\uac74\uacfc \ubb34\uad00\ud558\uac8c \uc544\ubb34 \ub54c\ub098 \ud560 \uc218 \uc788\ub294 \uac1c\uc778\uc801 \ud734\uac00 \uc81c\ub3c4\uc774\ub2e4"],t.s)
B.QS=s(["\uc704\uc6d0 \uc2a4\uc2a4\ub85c \uc81c\ucc99 \ub610\ub294 \uae30\ud53c \uc0ac\uc720\uac00 \uc788\ub2e4\uace0 \ud310\ub2e8\ud558\uc5ec \uc790\ubc1c\uc801\uc73c\ub85c \ud574\ub2f9 \uc0ac\uac74\uc758 \uc2ec\uc758\xb7\uc758\uacb0\uc5d0\uc11c \ubb3c\ub7ec\ub098\ub294 \uac83"],t.s)
B.a5_=s(["\ud68c\ud53c \uc81c\ub3c4"],t.s)
