B.a83=s(["\uc2ec\uc758\xb7\uc758\uacb0 \uacfc\uc815\uc758 \uacf5\uc815\uc131\uacfc \uc2e0\ub8b0\uc131\uc744 \ud655\ubcf4\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc0ac\uac74 \ucc98\ub9ac \uac74\uc218\ub97c \ub298\ub9ac\uae30 \uc704\ud568\uc774\ub2e4","\uc704\uc6d0\uc758 \uc5c5\ubb34 \ubd80\ub2f4\uc744 \ub298\ub824 \ucc98\ubc8c\ud558\uae30 \uc704\ud568\uc774\ub2e4","\ud2b9\uc815 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud55c \uacb0\ub860\uc744 \uc720\ub3c4\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc608\uc0b0\uc744 \uc808\uac10\ud558\uae30 \uc704\ud568\uc774\ub2e4"],t.s)
B.PM=s(["\uc2ec\uc758\xb7\uc758\uacb0 \uacfc\uc815\uc758 \uacf5\uc815\uc131\uacfc \uc2e0\ub8b0\uc131\uc744 \ud655\ubcf4\ud558\uae30 \uc704\ud568\uc774\ub2e4"],t.s)
B.TB=s(["\uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c \uc81c\ub3c4\uc758 \ucde8\uc9c0"],t.s)
B.amU=new A.c("gen_ftc_org_recusal_4","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\uc758 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c","\uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c \uc81c\ub3c4\ub97c \ud568\uaed8 \ub450\ub294 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a83,0,"\uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c \uc81c\ub3c4\ub294 \uc704\uc6d0\uacfc \uc0ac\uac74 \uc0ac\uc774\uc5d0 \ud2b9\ubcc4\ud55c \uc774\ud574\uad00\uacc4\ub098 \uacf5\uc815\uc131\uc744 \uc758\uc2ec\ud560 \uc0ac\uc815\uc774 \uc788\ub294 \uacbd\uc6b0 \uadf8 \uc704\uc6d0\uc744 \uc2ec\uc758\xb7\uc758\uacb0 \uacfc\uc815\uc5d0\uc11c \ubc30\uc81c\ud568\uc73c\ub85c\uc368, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc2ec\uc758\xb7\uc758\uacb0\uc758 \uacf5\uc815\uc131\uacfc \uc2e0\ub8b0\uc131\uc744 \ud655\ubcf4\ud558\uae30 \uc704\ud55c \ucde8\uc9c0\uc5d0\uc11c \ub9c8\ub828\ub41c \uac83\uc774\ub2e4.",B.PM,B.TB,null)
B.LY=s(["\uc808\ucc28\uc0c1 \ud558\uc790\uac00 \uc788\ub294 \uac83\uc73c\ub85c \ub2e4\ud22c\uc5b4\uc9c8 \uc218 \uc788\ub294 \uc0ac\uc815\uc774 \ub41c\ub2e4","\uc81c\ucc99 \uc0ac\uc720\ub294 \uc2ec\uc758\xb7\uc758\uacb0\uc758 \ud6a8\ub825\uc5d0 \uc544\ubb34\ub7f0 \uc601\ud5a5\uc744 \uc8fc\uc9c0 \uc54a\ub294\ub2e4","\uc81c\ucc99 \uc0ac\uc720\uac00 \uc788\uc5b4\ub3c4 \uc2ec\uc758\xb7\uc758\uacb0\uc740 \ud56d\uc0c1 \uc720\ud6a8\ud558\uba70 \ub2e4\ud234 \uc218 \uc5c6\ub2e4","\uc81c\ucc99 \uc0ac\uc720\ub294 \ud615\uc0ac\ucc98\ubc8c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \uaddc\uc815\uc774\ub2e4","\uc81c\ucc99 \uc0ac\uc720\uac00 \uc788\uc73c\uba74 \uc0ac\uac74 \uc790\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud55c\ub2e4"],t.s)
B.a0n=s(["\uc808\ucc28\uc0c1 \ud558\uc790\uac00 \uc788\ub294 \uac83\uc73c\ub85c \ub2e4\ud22c\uc5b4\uc9c8 \uc218 \uc788\ub294 \uc0ac\uc815\uc774 \ub41c\ub2e4"],t.s)
B.R_=s(["\uc81c\ucc99 \uc0ac\uc720 \uc704\ubc18\uc758 \ud6a8\uacfc"],t.s)
B.amN=new A.c("gen_ftc_org_recusal_5","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\uc758 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c","\uc81c\ucc99 \uc0ac\uc720\uac00 \uc788\ub294 \uc704\uc6d0\uc774 \uadf8\ub300\ub85c \uc2ec\uc758\xb7\uc758\uacb0\uc5d0 \uad00\uc5ec\ud55c \uacbd\uc6b0, \uadf8 \uc2ec\uc758\xb7\uc758\uacb0\uc758 \ud6a8\ub825\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.LY,0,"\uc81c\ucc99 \uc0ac\uc720\uac00 \uc788\ub294 \uc704\uc6d0\uc774 \uadf8 \uc0ac\uc815\uc744 \uc54c\uba74\uc11c\ub3c4 \uc2ec\uc758\xb7\uc758\uacb0\uc5d0 \uad00\uc5ec\ud558\uc600\ub2e4\uba74, \uc774\ub294 \uc2ec\uc758\xb7\uc758\uacb0 \uc808\ucc28\uc758 \uacf5\uc815\uc131\uc744 \ud574\uce58\ub294 \uac83\uc73c\ub85c\uc11c \ud574\ub2f9 \ucc98\ubd84\uc758 \uc808\ucc28\uc0c1 \ud558\uc790\ub85c \ub2e4\ud22c\uc5b4\uc9c8 \uc218 \uc788\ub294 \uc0ac\uc815\uc774 \ub41c\ub2e4.",B.a0n,B.R_,null)
B.Og=s([u.af,"\uae30\ud53c \uc2e0\uccad\uc774 \uc788\uc73c\uba74 \uadf8 \uc989\uc2dc \uc0ac\uac74 \uc804\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \uc885\uacb0\ub41c\ub2e4","\uae30\ud53c \uc2e0\uccad\uc740 \ubc18\ub4dc\uc2dc \uae30\uac01\ub418\uc5b4\uc57c \ud55c\ub2e4","\uae30\ud53c \uc2e0\uccad \uc5ec\ubd80\ub294 \uc0ac\uac74\uc758 \uc0c1\ub300\ubc29 \uc0ac\uc5c5\uc790\uac00 \uacb0\uc815\ud55c\ub2e4","\uae30\ud53c \uc2e0\uccad \uc81c\ub3c4\ub294 \ubc95\ub960\uc5d0 \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc544 \uc2e4\ubb34\uc0c1 \ud65c\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.OJ=s([u.af],t.s)
B.Qe=s(["\uae30\ud53c \uc2e0\uccad\uc758 \ucc98\ub9ac\uc808\ucc28"],t.s)
B.akE=new A.c("gen_ftc_org_recusal_6","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc704\uc6d0\uc758 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c","\uae30\ud53c \uc2e0\uccad\uc774 \uc788\ub294 \uacbd\uc6b0 \ucc98\ub9ac \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Og,0,"\uae30\ud53c \uc2e0\uccad\uc774 \uc81c\uae30\ub418\uba74 \ud574\ub2f9 \uc704\uc6d0\uc744 \uc81c\uc678\ud55c \uc808\ucc28\ub97c \ud1b5\ud574 \uadf8 \uc2e0\uccad\uc758 \ub2f9\ubd80(\uc815\ub2f9\ud55c\uc9c0 \uc5ec\ubd80)\ub97c \uc2ec\uc758\ud558\uc5ec \uc778\uc6a9 \ub610\ub294 \uae30\uac01 \uc5ec\ubd80\ub97c \uacb0\uc815\ud558\uac8c \ub41c\ub2e4. \uae30\ud53c \uc2e0\uccad\uc774 \uc788\ub2e4\uace0 \ud558\uc5ec \uc0ac\uac74 \uc804\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \uc885\uacb0\ub418\uac70\ub098 \ubc18\ub4dc\uc2dc \uae30\uac01\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.OJ,B.Qe,null)
B.Xz=s(["\uc704\uc6d0\ud68c\uc758 \uc0ac\ubb34\ub97c \ucc98\ub9ac\ud558\uae30 \uc704\ud558\uc5ec \uc124\uce58\ub418\uba70, \uc870\uc0ac \ub4f1 \uc2e4\ubb34\ub97c \ub2f4\ub2f9\ud55c\ub2e4","\uc0ac\ubb34\ucc98\ub294 \uc704\uc6d0\ud68c\uc758 \uc758\uacb0 \uc5c6\uc774\ub3c4 \ub3c5\uc790\uc801\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub97c \ud655\uc815\ud560 \uc218 \uc788\ub2e4","\uc0ac\ubb34\ucc98\ub294 \uc704\uc6d0\ud68c\uc640 \uc644\uc804\ud788 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ud589\uc815\uae30\uad00\uc774\ub2e4","\uc0ac\ubb34\ucc98\ub294 \ubc95\uc6d0\uc758 \ud558\uae09\uae30\uad00\uc73c\ub85c \ud3b8\uc131\ub418\uc5b4 \uc788\ub2e4","\uc0ac\ubb34\ucc98\ub294 \uc0ac\uac74\uc758 \ucd5c\uc885 \uc758\uacb0\uad8c\uc744 \uac00\uc9c4\ub2e4"],t.s)
B.YR=s(["\uc704\uc6d0\ud68c\uc758 \uc0ac\ubb34\ub97c \ucc98\ub9ac\ud558\uae30 \uc704\ud558\uc5ec \uc124\uce58\ub418\uba70, \uc870\uc0ac \ub4f1 \uc2e4\ubb34\ub97c \ub2f4\ub2f9\ud55c\ub2e4"],t.s)
B.a91=s(["\uc0ac\ubb34\ucc98\uc758 \uc5ed\ud560"],t.s)
B.aqW=new A.c("gen_ftc_org_office_1","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc0ac\ubb34\ucc98\xb7\uc758\uacb0\uc758 \ud6a8\ub825","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc0ac\ubb34\ucc98\uc758 \uc5ed\ud560\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Xz,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc0ac\ubb34\ucc98\ub294 \uc704\uc6d0\ud68c\uc758 \uc0ac\ubb34\ub97c \ucc98\ub9ac\ud558\uae30 \uc704\ud558\uc5ec \uc124\uce58\ub41c \uc870\uc9c1\uc73c\ub85c, \uc0ac\uac74\uc5d0 \ub300\ud55c \uc870\uc0ac \ub4f1 \uc2e4\ubb34\ub97c \ub2f4\ub2f9\ud55c\ub2e4. \ub2e4\ub9cc \ucd5c\uc885\uc801\uc778 \uc2ec\uc758\xb7\uc758\uacb0\uad8c\uc740 \uc704\uc6d0\ud68c(\uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758)\uc5d0 \uc788\uc73c\uba70, \uc0ac\ubb34\ucc98\uac00 \ub3c5\uc790\uc801\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub97c \ud655\uc815\ud558\uac70\ub098 \ucd5c\uc885 \uc758\uacb0\uad8c\uc744 \uac16\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.YR,B.a91,null)
B.Qf=s(["\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc5d0 \ub530\ub77c \uc791\uc131\ub41c \ucc98\ubd84\uc740 \ubc95\ub839\uc774 \uc815\ud55c \uc808\ucc28(\uc758\uacb0\uc11c \uc791\uc131\xb7\ud1b5\uc9c0 \ub4f1)\ub97c \uac70\uccd0 \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4","\uc704\uc6d0\ud68c\uc758 \uad6c\ub450 \ubc1c\uc5b8\ub9cc\uc73c\ub85c \uc989\uc2dc \ub300\uc678\uc801 \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc740 \uc0ac\uc5c5\uc790\uac00 \ub3d9\uc758\ud574\uc57c\ub9cc \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc740 \uad6d\ud68c\uc758 \ubcc4\ub3c4 \uc2b9\uc778\uc774 \uc788\uc5b4\uc57c \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc740 \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\ub294 \uad8c\uace0\uc801 \uc131\uaca9\ub9cc \uac00\uc9c4\ub2e4"],t.s)
B.UV=s(["\ubc95\ub839\uc774 \uc815\ud55c \uc808\ucc28(\uc758\uacb0\uc11c \uc791\uc131\xb7\ud1b5\uc9c0 \ub4f1)\ub97c \uac70\uccd0 \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4"],t.s)
B.R2=s(["\uc758\uacb0\uc758 \ud6a8\ub825\ubc1c\uc0dd \uc694\uac74"],t.s)
B.alI=new A.c("gen_ftc_org_office_2","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc0ac\ubb34\ucc98\xb7\uc758\uacb0\uc758 \ud6a8\ub825","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc758\uacb0(\ucc98\ubd84)\uc758 \ud6a8\ub825 \ubc1c\uc0dd\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Qf,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc5d0 \ub530\ub978 \ucc98\ubd84\uc740 \uc758\uacb0\uc11c \uc791\uc131, \ub2f9\uc0ac\uc790\uc5d0 \ub300\ud55c \ud1b5\uc9c0 \ub4f1 \ubc95\ub839\uc774 \uc815\ud55c \uc808\ucc28\ub97c \uac70\uccd0 \ub300\uc678\uc801\uc73c\ub85c \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud55c\ub2e4. \ub2e8\uc21c\ud55c \uad6c\ub450 \ubc1c\uc5b8\ub9cc\uc73c\ub85c \uc989\uc2dc \ud6a8\ub825\uc774 \ubc1c\uc0dd\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uc0ac\uc5c5\uc790\uc758 \ub3d9\uc758\ub098 \uad6d\ud68c\uc758 \uc2b9\uc778\uc774 \ucc98\ubd84\uc758 \ud6a8\ub825 \uc694\uac74\uc740 \uc544\ub2c8\ub2e4.",B.UV,B.R2,null)
B.Zs=s(["\ucc98\ubd84\uc744 \ubc1b\uc740 \uc790\ub294 \uc774\uc758\uc2e0\uccad \ub610\ub294 \ud589\uc815\uc18c\uc1a1 \ub4f1 \ubc95\uc774 \uc815\ud55c \ubd88\ubcf5\uc808\ucc28\ub97c \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4","\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc5d0\ub294 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubd88\ubcf5\uc740 \ubc18\ub4dc\uc2dc \uad6d\ud68c\uc5d0 \uccad\uc6d0\ud558\ub294 \ubc29\ubc95\uc73c\ub85c\ub9cc \uac00\ub2a5\ud558\ub2e4","\ubd88\ubcf5 \uc808\ucc28\ub294 \uc874\uc7ac\ud558\uc9c0 \uc54a\uc73c\uba70 \uc758\uacb0\uc740 \ud56d\uc0c1 \ucd5c\uc885\uc801\uc774\ub2e4","\ubd88\ubcf5\uc740 \uc5b8\ub860 \uc81c\ubcf4\ub97c \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4"],t.s)
B.a7h=s(["\uc774\uc758\uc2e0\uccad \ub610\ub294 \ud589\uc815\uc18c\uc1a1 \ub4f1 \ubc95\uc774 \uc815\ud55c \ubd88\ubcf5\uc808\ucc28\ub97c \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4"],t.s)
B.KU=s(["\uc758\uacb0\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc808\ucc28"],t.s)
B.akG=new A.c("gen_ftc_org_office_3","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc0ac\ubb34\ucc98\xb7\uc758\uacb0\uc758 \ud6a8\ub825","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc5d0 \ub300\ud55c \ubd88\ubcf5 \ubc29\ubc95\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zs,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc790\ub294 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1(\uc11c\uc6b8\uace0\ub4f1\ubc95\uc6d0 \uc804\uc18d\uad00\ud560) \ub4f1 \ubc95\uc774 \uc815\ud55c \uc808\ucc28\ub97c \ud1b5\ud574 \uadf8 \ucc98\ubd84\uc744 \ub2e4\ud234 \uc218 \uc788\ub2e4. \uc704\uc6d0\ud68c\uc758 \uc758\uacb0\uc774 \uc808\ub300\uc801\uc73c\ub85c \ud655\uc815\ub418\uc5b4 \uc5b4\ub5a0\ud55c \ubd88\ubcf5\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.a7h,B.KU,null)
B.a1z=s(["\uc2ec\uc758 \uacfc\uc815\uc5d0\uc11c \uc54c\uac8c \ub41c \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00 \ub4f1\uc740 \uc5c5\ubb34\uc0c1 \uc54c\uac8c \ub41c \ube44\ubc00\ub85c\uc11c \ubcf4\ud638\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc2ec\uc758 \uacfc\uc815\uc5d0\uc11c \uc54c\uac8c \ub41c \uc815\ubcf4\ub294 \uc544\ubb34\ub7f0 \uc81c\ud55c \uc5c6\uc774 \uacf5\uac1c\ud560 \uc218 \uc788\ub2e4","\uc601\uc5c5\ube44\ubc00 \ubcf4\ud638\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc808\ucc28\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2ec\uc758\uc5d0 \ucc38\uc5ec\ud55c \uc704\uc6d0\uc740 \ud1f4\uc784 \ud6c4\uc5d0\ub294 \ube44\ubc00\uc720\uc9c0\uc758\ubb34\uac00 \uc804\ud600 \uc5c6\ub2e4","\uc601\uc5c5\ube44\ubc00\uc740 \uc0ac\uac74 \uc885\ub8cc \ud6c4 \uace7\ubc14\ub85c \uc5b8\ub860\uc5d0 \uacf5\uac1c\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.a8V=s(["\uc5c5\ubb34\uc0c1 \uc54c\uac8c \ub41c \ube44\ubc00\ub85c\uc11c \ubcf4\ud638\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.a7l=s(["\uc2ec\uc758 \uc808\ucc28\uc758 \ube44\ubc00\uc720\uc9c0"],t.s)
B.al9=new A.c("gen_ftc_org_office_4","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc0ac\ubb34\ucc98\xb7\uc758\uacb0\uc758 \ud6a8\ub825","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc2ec\ud310\uc815 \ubc0f \uc2ec\uc758 \uc808\ucc28\uc758 \ube44\ubc00\uc720\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1z,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2ec\uc758\xb7\uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \uc54c\uac8c \ub41c \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00 \ub4f1\uc740 \uc5c5\ubb34\uc0c1 \uc54c\uac8c \ub41c \ube44\ubc00\ub85c\uc11c \ubcf4\ud638\ub418\uc5b4\uc57c \ud558\uba70, \uc704\uc6d0\xb7\uc9c1\uc6d0 \ub4f1\uc740 \uc9c1\ubb34\uc0c1 \uc54c\uac8c \ub41c \ube44\ubc00\uc744 \ub204\uc124\ud558\uc5ec\uc11c\ub294 \uc548 \ub418\ub294 \uc758\ubb34\ub97c \uc9c4\ub2e4. \uc774\ub7ec\ud55c \ube44\ubc00\uc720\uc9c0\uc758\ubb34\ub294 \ud1f4\uc784 \ud6c4\uc5d0\ub3c4 \uc77c\uc815 \ubd80\ubd84 \uc720\uc9c0\ub418\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4.",B.a8V,B.a7l,null)
B.M_=s(["\uc704\uc6d0\ud68c\ub294 \ubc95\ub839\uc774 \uc815\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uadf8 \uad8c\ud55c \uc77c\ubd80\ub97c \uc18c\uc18d \uae30\uad00\uc774\ub098 \uc18c\uc18d \uacf5\ubb34\uc6d0\uc5d0\uac8c \uc704\uc784\ud560 \uc218 \uc788\ub2e4","\uc704\uc6d0\ud68c\uc758 \uad8c\ud55c\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc704\uc784\ub420 \uc218 \uc5c6\ub2e4","\uc704\uc6d0\ud68c\uc758 \ubaa8\ub4e0 \uad8c\ud55c\uc740 \ubc18\ub4dc\uc2dc \uc704\uc6d0\uc7a5 \uac1c\uc778\uc774 \uc9c1\uc811 \ud589\uc0ac\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc704\uc6d0\ud68c \uad8c\ud55c\uc758 \uc704\uc784\uc740 \ubc95\ub960\uc0c1 \uc804\ud600 \uadfc\uac70\uac00 \uc5c6\ub294 \uc0ac\uc2e4\uc0c1\uc758 \uad00\ud589\uc77c \ubfd0\uc774\ub2e4","\uc704\uc6d0\ud68c \uad8c\ud55c\uc744 \uc704\uc784\ubc1b\uc740 \uc790\ub294 \uadf8 \uad8c\ud55c\uc744 \ub2e4\uc2dc \uc7ac\uc704\uc784\ud560 \uc218 \uc5c6\ub2e4\ub294 \uaddc\uc815\uc774 \ud56d\uc0c1 \uc808\ub300\uc801\uc774\ub2e4"],t.s)
B.IC=s(["\ubc95\ub839\uc774 \uc815\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uadf8 \uad8c\ud55c \uc77c\ubd80\ub97c \uc18c\uc18d \uae30\uad00\uc774\ub098 \uc18c\uc18d \uacf5\ubb34\uc6d0\uc5d0\uac8c \uc704\uc784\ud560 \uc218 \uc788\ub2e4"],t.s)
B.ZE=s(["\uad8c\ud55c\uc758 \uc704\uc784"],t.s)
B.ahD=new A.c("gen_ftc_org_office_5","economic_law","\uc704\uc6d0\ud68c \uad6c\uc131\xb7\ud68c\uc758","\uc0ac\ubb34\ucc98\xb7\uc758\uacb0\uc758 \ud6a8\ub825","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uad00 \uc0ac\ubb34\uc758 \uc7ac\uc704\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.M_,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc0ac\ubb34\uc758 \ud6a8\uc728\uc801 \ucc98\ub9ac\ub97c \uc704\ud558\uc5ec \ubc95\ub839\uc774 \uc815\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uadf8 \uad8c\ud55c\uc758 \uc77c\ubd80\ub97c \uc18c\uc18d \uae30\uad00\uc758 \uc7a5\uc774\ub098 \uc18c\uc18d \uacf5\ubb34\uc6d0\uc5d0\uac8c \uc704\uc784\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uc77c\ubc18 \ud589\uc815\uae30\uad00\uc758 \uad8c\ud55c\uc704\uc784 \ubc95\ub9ac\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c, \uc704\uc6d0\uc7a5\uc774 \ubaa8\ub4e0 \uad8c\ud55c\uc744 \ubc18\ub4dc\uc2dc \uac1c\uc778\uc801\uc73c\ub85c \ud589\uc0ac\ud574\uc57c \ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\ub294 \uc758\ubbf8\uc774\ub2e4.",B.IC,B.ZE,null)
B.P9=s([u.vw,"\uc704\uc6d0\ud68c\ub294 \ub2e8\ub3c5\uc81c \ud589\uc815\uae30\uad00\uc73c\ub85c \uc704\uc6d0\uc7a5 1\uc778\uc774 \ubaa8\ub4e0 \uac83\uc744 \uacb0\uc815\ud55c\ub2e4","\ud68c\uc758 \uc6b4\uc601\uacfc \uc704\uc6d0 \uad6c\uc131\uc5d0 \uad00\ud55c \uc0ac\ud56d\uc740 \uc804\uc801\uc73c\ub85c \uc704\uc6d0 \uac1c\uc778\uc758 \uc7ac\ub7c9\uc5d0 \ub9e1\uaca8\uc838 \uc788\ub2e4","\uc0ac\ubb34\ucc98\uc640 \uc81c\ucc99\xb7\uae30\ud53c\xb7\ud68c\ud53c \uc81c\ub3c4\ub294 \uc11c\ub85c \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \ubcc4\uac1c\uc758 \uc601\uc5ed\uc774\ub2e4","\uc704\uc6d0\ud68c \uc81c\ub3c4\ub294 \uc624\uc9c1 \ud615\uc2dd\uc801 \uc808\ucc28\uc77c \ubfd0 \uc2e4\uc9c8\uc801 \uae30\ub2a5\uc774 \uc5c6\ub2e4"],t.s)
