B.ac1=s([u.l_,"\uc704 \uc81c\ub3c4\ub4e4\uc740 \uc11c\ub85c \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \uac1c\ubcc4\uc801 \uc81c\ub3c4\uc774\ub2e4","\uc704 \uc81c\ub3c4\ub4e4\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uac8c \uc124\uacc4\ub418\uc5b4 \uc788\ub2e4","\uc704 \uc81c\ub3c4\ub4e4\uc740 \ud615\uc0ac\uc18c\uc1a1\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc704 \uc81c\ub3c4\ub4e4\uc740 \uc2e4\ubb34\uc0c1 \uc804\ud600 \ud65c\uc6a9\ub418\uc9c0 \uc54a\ub294 \uc0ac\ubb38\ud654\ub41c \uaddc\uc815\uc774\ub2e4"],t.s)
