B.NP=s([u.fq,"\uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc800\uac00\ub85c \uacf5\uaca9\ud558\uc5ec \uc2dc\uc7a5\uc5d0\uc11c \ubab0\uc544\ub0b4\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \uc0c1\ud488\uc758 \uad6c\uc785\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uac00 \uc18c\ube44\uc790\uc5d0\uac8c \ubd80\ub2f9\ud55c \ud45c\uc2dc\xb7\uad11\uace0\ub97c \ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790 \uc218\ub97c \uc81c\ud55c\ud558\ub294 \ud589\uc704"],t.s)
