B.ak2=new A.c("gen_sup_type_1","economic_law","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc758 \uc758\uc758\xb7\uc720\ud615","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc758 \uc758\uc758\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.NP,0,"\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub780 \uc0ac\uc5c5\uc790\uac00 \ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ub300\ud558\uc5ec \uc790\uae08\xb7\uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\xb7\uc778\ub825 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\uac70\ub098 \uac70\ub798\ud558\ub294 \ub4f1\uc758 \ubc29\ubc95\uc73c\ub85c \ubd80\ub2f9\ud558\uac8c \uc9c0\uc6d0\ud558\uc5ec, \uc9c0\uc6d0\ubc1b\ub294 \uc790\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \uc774\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \ud55c \uc720\ud615\uc73c\ub85c \uaddc\uc81c\ub41c\ub2e4.",B.a9I,B.Qr,null)
B.Ha=s(["\uac00\uc9c0\uae09\uae08\xb7\ub300\uc5ec\uae08 \ub4f1 \uc790\uae08\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\ubd80\ub3d9\uc0b0\xb7\uc720\uac00\uc99d\uad8c\xb7\uc0c1\ud488 \ub4f1 \uc790\uc0b0\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\uc778\ub825\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\ub97c \ub9e4\uac1c\ub85c \uac70\ub798\ud568\uc73c\ub85c\uc368 \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uacfc \ud1b5\uc0c1\uc801\uc778 \uc2dc\uc7a5\uac00\uaca9\uc73c\ub85c \uc815\uc0c1\uc801\uc778 \uac70\ub798\ub97c \ud558\ub294 \ud589\uc704"],t.s)
B.Kn=s(["\uac70\ub798\uc0c1\ub300\ubc29\uacfc \ud1b5\uc0c1\uc801\uc778 \uc2dc\uc7a5\uac00\uaca9\uc73c\ub85c \uc815\uc0c1\uc801\uc778 \uac70\ub798\ub97c \ud558\ub294 \ud589\uc704"],t.s)
