B.ajI=new A.c("gen_sup_type_2","economic_law","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc758 \uc758\uc758\xb7\uc720\ud615","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc758 \uc720\ud615\uc73c\ub85c \ubc95\ub839\uc774 \uc5f4\uac70\ud558\ub294 \uac83\uacfc \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.Ha,4,'\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc778\ub825\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\uac70\ub098, \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud558\uc5ec \uc774\uc775\uc744 \ubab0\uc544\uc8fc\ub294 \ubc29\uc2dd \ub4f1\uc73c\ub85c \uc720\ud615\ud654\ub418\uc5b4 \uc788\ub2e4. \ubc18\uba74 \uac70\ub798\uc0c1\ub300\ubc29\uacfc \ud1b5\uc0c1\uc801\uc778 \uc2dc\uc7a5\uac00\uaca9\uc5d0 \ub530\ub77c \uc774\ub8e8\uc5b4\uc9c0\ub294 \uc815\uc0c1\uc801\uc778 \uac70\ub798\ub294 \uc560\ucd08\uc5d0 "\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74"\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\uc73c\ubbc0\ub85c \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc758 \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Kn,B.Jg,null)
B.Kv=s(["\uc9c0\uc6d0\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac","\uc9c0\uc6d0\ud558\ub294 \uc0ac\uc5c5\uc790\uc640 \uc544\ubb34\ub7f0 \uad00\uacc4\uac00 \uc5c6\ub294 \uc77c\ubc18 \uc18c\ube44\uc790","\uc9c0\uc6d0\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uacbd\uc7c1\uc0ac\uc5c5\uc790","\uc9c0\uc6d0\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \uc18c\uc18d\ub418\uc9c0 \uc54a\uc740 \uc815\ubd80\uae30\uad00","\uc9c0\uc6d0\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \ud574\uc678 \ud611\ub825\uc5c5\uccb4 \uc804\ubd80"],t.s)
