B.Iz=s(["\uc9c0\uc6d0\uc8fc\uccb4\uc640 \uc9c0\uc6d0\uac1d\uccb4\uc758 \ub300\ud45c\uc774\uc0ac\uac00 \uac19\uc740 \ub300\ud559 \ucd9c\uc2e0\uc778\uc9c0 \uc5ec\ubd80","\uc9c0\uc6d0\ud589\uc704\ub85c \uc778\ud55c \uc774\uc775\uc758 \uaddc\ubaa8\uc640 \ud604\uc800\uc131","\uc9c0\uc6d0\ud589\uc704\uac00 \uc774\ub8e8\uc5b4\uc9c4 \uac70\ub798\uc870\uac74\uacfc \uc815\uc0c1\uac00\uaca9\uc758 \uad34\ub9ac \uc815\ub3c4","\uc9c0\uc6d0\ud589\uc704\uac00 \uad00\ub828 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5","\uc9c0\uc6d0\uc758\ub3c4\ub098 \ubaa9\uc801"],t.s)
