B.Sz=s(["\uc9c0\uc6d0\uae08\uc561\uc758 \uaddc\ubaa8, \uc9c0\uc6d0\ud589\uc704\uc758 \uae30\uac04\xb7\ud69f\uc218 \ub4f1 \uc704\ubc18\ud589\uc704\uc758 \uc911\ub300\uc131","\uc9c0\uc6d0\uac1d\uccb4\uc758 \ucc3d\ub9bd\uae30\ub150\uc77c","\uc9c0\uc6d0\uc8fc\uccb4 \ub300\ud45c\uc774\uc0ac\uc758 \uac1c\uc778 \ucde8\ubbf8","\uc9c0\uc6d0\ud589\uc704\uc640 \ubb34\uad00\ud55c \ubcc4\uac1c \uc0ac\uc5c5 \ubd80\ubb38\uc758 \uc2e4\uc801","\uc9c0\uc6d0\ud589\uc704\uac00 \uc788\uc5c8\ub358 \uc694\uc77c\uc758 \ub0a0\uc528"],t.s)
