B.NA=s([u.vu,"\ub450 \uc81c\ub3c4\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \ub2e4\ub8e8\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \uc2dc\ucc45\uc774 \ub3c4\uc785\ub418\uba74\uc11c \ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\ub294 \ud3d0\uc9c0\ub418\uc5c8\ub2e4","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5 \uaddc\uc81c\ub294 \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \uc2dc\ucc45\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ub450 \uc81c\ub3c4\ub294 \uc11c\ub85c \ubaa8\uc21c\ub418\uc5b4 \ub3d9\uc2dc\uc5d0 \uc801\uc6a9\ub420 \uc218 \uc5c6\ub2e4"],t.s)
